function resolveUserTickerUniverse(db, userId) {
  const silentLogger = { info: () => {}, warn: () => {}, error: () => {} };
  const universe = resolveOwnedTickerUniverse({ db, logger: silentLogger });
  const user = universe.perUserUniverse.find((entry) => entry.userId === userId);
  return new Set(user?.tickerList || []);
}

function resolveUserWatchlistTickerUniverse(db, userId) {
  const tickers = new Set();
  const watchlists = Array.isArray(db?.watchlists) ? db.watchlists : [];
  const watchlistItems = Array.isArray(db?.watchlistItems) ? db.watchlistItems : [];
  const ownedWatchlistIds = new Set(
    watchlists
      .filter((row) => row?.owner_user_id === userId)
      .map((row) => row.id)
      .filter(Boolean)
  );

  for (const item of watchlistItems) {
    if (!ownedWatchlistIds.has(item?.watchlist_id)) continue;
    const normalized = String(item?.canonical_ticker || item?.ticker || '')
      .trim()
      .toUpperCase()
      .replace(/[^A-Z0-9.\\-_]/g, '');
    if (!normalized) continue;
    tickers.add(normalized);
  }
  return tickers;
}

function enqueueNewsNotificationOutboxItem(payload, channel) {
  const db = loadDB();
  ensureNewsEventTables(db);
  const nowIso = new Date().toISOString();
  const item = {
    id: crypto.randomUUID(),
    userId: String(payload?.userId || '').trim(),
    newsEventId: String(payload?.eventId || '').trim(),
    channel,
    payload: payload && typeof payload === 'object' ? payload : {},
    status: 'pending',
    attemptCount: 0,
    maxAttempts: Number.isFinite(Number(payload?.maxAttempts)) ? Math.max(1, Number(payload.maxAttempts)) : 5,
    nextAttemptAt: nowIso,
    claimedAt: null,
    claimedBy: null,
    lastAttemptAt: null,
    sentAt: null,
    lastErrorCode: null,
    lastErrorMessage: null,
    createdAt: nowIso,
    updatedAt: nowIso
  };
  db.newsNotificationOutbox.push(item);
  saveDB(db);
  return { ok: true, channel, messageId: `outbox:${channel}:${item.id}`, queued: true };
}

