function isStrongPassword(password) {
  if (typeof password !== 'string' || password.length < 12) return false;
  const hasUpper = /[A-Z]/.test(password);
  const hasLower = /[a-z]/.test(password);
  const hasNumber = /\d/.test(password);
  const hasSymbol = /[^A-Za-z0-9]/.test(password);
  return hasUpper && hasLower && hasNumber && hasSymbol;
}


function sanitizeAvatarPath(raw) {
  if (typeof raw !== 'string') return '';
  const trimmed = raw.trim();
  if (!trimmed.startsWith(AVATAR_PUBLIC_PREFIX)) return '';
  const filename = path.basename(trimmed);
  return filename ? `${AVATAR_PUBLIC_PREFIX}${filename}` : '';
}

function avatarAbsolutePathFromPublic(raw) {
  const safePublic = sanitizeAvatarPath(raw);
  if (!safePublic) return '';
  const filename = path.basename(safePublic);
  if (!filename) return '';
  return path.join(AVATAR_STORAGE_DIR, filename);
}

function avatarPathExists(publicPath) {
  const absolute = avatarAbsolutePathFromPublic(publicPath);
  return !!absolute && fs.existsSync(absolute);
}

function removeAvatarFile(publicPath) {
  const absolute = avatarAbsolutePathFromPublic(publicPath);
  if (!absolute) return;
  if (fs.existsSync(absolute)) {
    try {
      fs.unlinkSync(absolute);
    } catch (error) {
      console.warn('Unable to remove avatar file:', error);
    }
  }
}

function computeAvatarInitials(rawNickname) {
  if (typeof rawNickname !== 'string') return 'V';
  const cleaned = rawNickname.trim().replace(/\s+/g, ' ');
  if (!cleaned) return 'V';
  const parts = cleaned.split(' ').filter(Boolean);
  if (!parts.length) return 'V';
  const chars = parts.slice(0, 2).map(part => part[0]?.toUpperCase()).filter(Boolean);
  if (!chars.length) return 'V';
  return chars.join('').slice(0, 2);
}

function socialAvatarForUser(user) {
  const avatarUrl = sanitizeAvatarPath(user?.avatarUrl || user?.avatar_url || '');
  const safeAvatarUrl = avatarPathExists(avatarUrl) ? avatarUrl : '';
  return {
    avatar_url: safeAvatarUrl,
    avatar_initials: computeAvatarInitials(getSocialNickname(user))
  };
}

function detectImageExtension(buffer, declaredType = '') {
  const type = String(declaredType || '').toLowerCase().split(';')[0].trim();
  if (AVATAR_ALLOWED_TYPES.has(type)) return AVATAR_ALLOWED_TYPES.get(type);
  if (!Buffer.isBuffer(buffer) || buffer.length < 12) return '';
  if (buffer[0] === 0xff && buffer[1] === 0xd8 && buffer[2] === 0xff) return 'jpg';
  if (buffer[0] === 0x89 && buffer[1] === 0x50 && buffer[2] === 0x4e && buffer[3] === 0x47) return 'png';
  const riff = buffer.toString('ascii', 0, 4);
  const webp = buffer.toString('ascii', 8, 12);
  if (riff === 'RIFF' && webp === 'WEBP') return 'webp';
  return '';
}

function buildAvatarPublicPath(username, extension) {
  const safeUser = String(username || 'user').toLowerCase().replace(/[^a-z0-9_-]/g, '').slice(0, 24) || 'user';
  const unique = `${Date.now()}-${crypto.randomUUID().slice(0, 8)}`;
  return `${AVATAR_PUBLIC_PREFIX}${safeUser}-${unique}.${extension}`;
}


function normalizeNickname(raw) {
  if (typeof raw !== 'string') return { value: '', error: 'Nickname must be a string.' };
  const trimmed = raw.trim();
  if (!trimmed) return { value: '' };
  if (trimmed.length > 20) {
    return { value: '', error: 'Nicknames must be 20 characters or less.' };
  }
  if (!/^[A-Za-z0-9 ]+$/.test(trimmed)) {
    return { value: '', error: 'Nicknames can only contain letters, numbers, and spaces.' };
  }
  return { value: trimmed };
}

function getSocialNickname(user) {
  if (!user || typeof user.nickname !== 'string') return '';
  const normalized = normalizeNickname(user.nickname);
  return normalized.value || '';
}

function requireSocialNickname(db, username, res) {
  const user = db.users?.[username];
  if (!user) {
    res.status(404).json({ error: 'User not found' });
    return null;
  }
  const nickname = getSocialNickname(user);
  if (!nickname) {
    res.status(403).json({
      error: 'Set a nickname on your Profile page before using social features.',
      code: 'nickname_required'
    });
    return null;
  }
  return { user, nickname };
}

function loadIbkrInstallerMeta() {
  let meta = {};
  if (IBKR_CONNECTOR_WINDOWS_META_PATH && fs.existsSync(IBKR_CONNECTOR_WINDOWS_META_PATH)) {
    try {
      const raw = fs.readFileSync(IBKR_CONNECTOR_WINDOWS_META_PATH, 'utf-8');
      meta = JSON.parse(raw || '{}') || {};
    } catch (error) {
      console.warn('[IBKR] Unable to read installer metadata:', error);
    }
  }
  const version = meta.version || IBKR_CONNECTOR_WINDOWS_VERSION || 'latest';
  const publishedAt = meta.publishedAt || IBKR_CONNECTOR_WINDOWS_PUBLISHED_AT || null;
  const sha256 = meta.sha256 || IBKR_CONNECTOR_WINDOWS_SHA256 || null;
  const notes = meta.notes || IBKR_CONNECTOR_WINDOWS_NOTES || '';
  const releaseNotesUrl = meta.releaseNotesUrl || IBKR_CONNECTOR_WINDOWS_RELEASE_NOTES_URL || '';
  const filename = meta.filename || `veracity-ibkr-connector-${version}.exe`;
  let sizeBytes = meta.sizeBytes || null;
  if (!sizeBytes && IBKR_CONNECTOR_WINDOWS_FILE && fs.existsSync(IBKR_CONNECTOR_WINDOWS_FILE)) {
    try {
      const stats = fs.statSync(IBKR_CONNECTOR_WINDOWS_FILE);
      sizeBytes = stats.size;
    } catch (error) {
      sizeBytes = null;
    }
  }
  return {
    version,
    publishedAt,
    sha256,
    notes,
    releaseNotesUrl,
    sizeBytes,
    filename
  };
}

function resolveProjectRoot() {
  let current = path.resolve(__dirname);
  for (let i = 0; i < 6; i += 1) {
    const candidate = path.join(current, 'package.json');
    if (fs.existsSync(candidate)) {
      return current;
    }
    const parent = path.dirname(current);
    if (parent === current) break;
    current = parent;
  }
  return path.resolve(__dirname, '..');
}

function resolveIbkrInstallerPath() {
  if (IBKR_CONNECTOR_WINDOWS_FILE) {
    const absolutePath = path.isAbsolute(IBKR_CONNECTOR_WINDOWS_FILE)
      ? IBKR_CONNECTOR_WINDOWS_FILE
      : path.resolve(resolveProjectRoot(), IBKR_CONNECTOR_WINDOWS_FILE);
    return { source: 'env', path: absolutePath };
  }
  const root = resolveProjectRoot();
  const fallbackPath = path.join(root, 'assets', 'installers', 'VeracityInstaller.exe');
  return { source: 'assets', path: fallbackPath };
}

function isNicknameAvailable(db, nickname, username) {
  if (!nickname) return true;
  const candidate = nickname.toLowerCase();
  return !Object.entries(db.users).some(([key, other]) => {
    if (key === username) return false;
    const otherUsername = typeof other?.username === 'string' ? other.username : key;
    const otherNickname = typeof other?.nickname === 'string' ? other.nickname : '';
    return (otherUsername && otherUsername.toLowerCase() === candidate)
      || (otherNickname && otherNickname.toLowerCase() === candidate);
  });
}

function generateFriendCode(db, currentUsername = null) {
  const users = db?.users || {};
  const existingCodes = new Set();
  for (const [username, user] of Object.entries(users)) {
    if (currentUsername && username === currentUsername) continue;
    if (typeof user?.friendCode === 'string' && user.friendCode.trim()) {
      existingCodes.add(user.friendCode.trim().toUpperCase());
    }
  }

  const alphabet = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let candidate = '';
  do {
    const partA = Array.from({ length: 4 }, () => alphabet[Math.floor(Math.random() * alphabet.length)]).join('');
    const partB = Array.from({ length: 4 }, () => alphabet[Math.floor(Math.random() * alphabet.length)]).join('');
    candidate = `${partA}-${partB}`;
  } while (existingCodes.has(candidate));
  return candidate;
}

