const LEGACY_TRADE_GROUP_NOTIFICATION_TYPE_MAP = {
  alert: 'trade_group_alert',
  invite: 'trade_group_invite',
  announcement: 'trade_group_announcement',
  member_joined: 'trade_group_member_joined',
  watchlist_posted: 'trade_group_watchlist_posted'
};

function normalizeTradeGroupNotificationType(type) {
  if (!type) return '';
  if (TRADE_GROUP_NOTIFICATION_TYPES.includes(type)) return type;
  return LEGACY_TRADE_GROUP_NOTIFICATION_TYPE_MAP[type] || '';
}

function normalizeTradeGroupActivityEvent(alert = {}) {
  const itemType = String(alert?.type || '').trim().toLowerCase();
  if (itemType === 'announcement') return 'announcement';

  const normalizedEventType = String(alert?.normalized_event_type || '').trim().toUpperCase();
  if (normalizedEventType === 'TRADE_TRIMMED') return 'trim';
  if (normalizedEventType === 'TRADE_CLOSED') return 'close';
  if (normalizedEventType === 'TRADE_OPENED') return 'open';

  const positionEventType = String(alert?.position_event_type || '').trim().toUpperCase();
  if (positionEventType === 'POSITION_TRIM') return 'trim';
  if (positionEventType === 'POSITION_CLOSED') return 'close';
  if (positionEventType === 'POSITION_OPENED') return 'open';
  if (positionEventType === 'POSITION_STOP_MOVED' || positionEventType === 'STOP_MOVED') return 'stop_move';

  const explicitSignals = [
    alert?.event_subtype,
    alert?.subtype,
    alert?.action,
    alert?.trade_action,
    alert?.action_type
  ].map((value) => String(value || '').trim().toLowerCase()).filter(Boolean);
  if (explicitSignals.some((value) => /(trim|partial|partial_close|reduce|reduced|scale[_\s-]?out)/.test(value))) return 'trim';
  if (explicitSignals.some((value) => /(full[_\s-]?exit|full[_\s-]?close|close|closed|exit|exited)/.test(value))) return 'close';

  const classification = String(alert?.alert_classification || '').trim().toLowerCase();
  if (classification === 'buy') return 'open';
  if (classification === 'add') return 'open';
  if (classification === 'new_position') return 'open';
  if (classification === 'position_increase') return 'open';
  if (classification === 'partial_sell') return 'trim';
  if (classification === 'full_close') return 'close';

  if (positionEventType === 'NEW_POSITION' || positionEventType === 'POSITION_INCREASE') return 'open';
  if (positionEventType === 'POSITION_REDUCED') return 'trim';

  const side = String(alert?.side || '').trim().toUpperCase();
  if (side === 'BUY') return 'open';

  const trimPct = Number(alert?.trim_pct ?? alert?.trim_percent ?? alert?.percent ?? alert?.percentage);
  if (Number.isFinite(trimPct)) {
    if (trimPct < 100) return 'trim';
    if (trimPct >= 100) return 'close';
  }

  const remainingQty = Number(alert?.remaining_quantity ?? alert?.remainingQuantity ?? alert?.position_remaining_quantity);
  if (Number.isFinite(remainingQty)) {
    if (side === 'SELL' && remainingQty > 0) return 'trim';
    if (side === 'SELL' && remainingQty === 0) return 'close';
  }

  const quantityDelta = Number(alert?.quantity_delta ?? alert?.quantityDelta ?? alert?.delta_quantity);
  if (Number.isFinite(quantityDelta) && quantityDelta < 0 && Number.isFinite(remainingQty)) {
    return remainingQty > 0 ? 'trim' : 'close';
  }

  if (side === 'SELL') return 'close';
  return 'other';
}

function normalizeTradeGroupAlertEventType(alert = {}) {
  const classification = normalizeTradeGroupActivityEvent(alert);
  if (classification === 'trim') return 'TRADE_TRIMMED';
  if (classification === 'close') return 'TRADE_CLOSED';
  if (classification === 'open') return 'TRADE_OPENED';
  return 'TRADE_REDUCED';
}

function buildTradeGroupAlertCopy(alert = {}, { groupName = '', leaderName = 'Leader' } = {}) {
  const ticker = String(alert?.ticker || '').trim().toUpperCase();
  const fillPriceText = Number.isFinite(Number(alert?.fill_price)) ? `$${Number(alert.fill_price).toFixed(2)}` : '';
  const trimPctText = formatTrimPercentForUi(alert?.trim_pct);
  const normalizedEventType = normalizeTradeGroupAlertEventType(alert);
  const positionEventType = String(alert?.position_event_type || alert?.event_type || '').trim().toUpperCase();
  const alertClassification = String(alert?.alert_classification || '').trim().toLowerCase();
  const isIncreaseBuy = positionEventType === 'POSITION_INCREASE' || alertClassification === 'position_increase' || alertClassification === 'add';
  const copyLabel = normalizedEventType === 'TRADE_TRIMMED'
    ? 'reduced'
    : (normalizedEventType === 'TRADE_CLOSED' ? 'closed' : (isIncreaseBuy ? 'added to' : 'opened'));
  console.info('[TradeGroup][AlertCopy]', {
    alertId: alert?.id || null,
    source: 'trade_group_alert',
    side: String(alert?.side || '').trim().toUpperCase() || null,
    classification: String(alert?.alert_classification || '').trim().toLowerCase() || null,
    positionEventType: positionEventType || null,
    quantityDelta: Number.isFinite(Number(alert?.quantity_delta ?? alert?.quantityDelta ?? alert?.delta_quantity))
      ? Number(alert?.quantity_delta ?? alert?.quantityDelta ?? alert?.delta_quantity)
      : null,
    remainingQuantity: Number.isFinite(Number(alert?.remaining_quantity ?? alert?.remainingQuantity ?? alert?.position_remaining_quantity))
      ? Number(alert?.remaining_quantity ?? alert?.remainingQuantity ?? alert?.position_remaining_quantity)
      : null,
    normalizedEventType,
    copyLabel
  });
  console.info('[trade-alert-copy] eventType and chosen copy label', { eventType: positionEventType || null, copyLabel });
  if (normalizedEventType === 'TRADE_OPENED') {
    console.info('[trade-alert-copy] buy-path', { path: isIncreaseBuy ? 'POSITION_INCREASE' : 'NEW_POSITION', eventType: positionEventType || null });
  }
  if (normalizedEventType === 'TRADE_TRIMMED') {
    return {
      normalizedEventType,
      body: `${groupName || 'Trade group'}: ${leaderName || 'Leader'} trimmed ${trimPctText || 'part of'}${ticker ? ` ${ticker}` : ' a position'}${fillPriceText ? ` at ${fillPriceText}` : ''}.`
    };
  }
  if (normalizedEventType === 'TRADE_CLOSED') {
    return {
      normalizedEventType,
      body: `${groupName || 'Trade group'}: ${leaderName || 'Leader'} closed ${ticker || 'a position'}${fillPriceText ? ` at ${fillPriceText}` : ''}.`
    };
  }
  if (normalizedEventType === 'TRADE_REDUCED') {
    return {
      normalizedEventType,
      body: `${groupName || 'Trade group'}: ${leaderName || 'Leader'} reduced ${ticker || 'a position'}${fillPriceText ? ` at ${fillPriceText}` : ''}.`
    };
  }
  if (isIncreaseBuy) {
    return {
      normalizedEventType,
      body: `${groupName || 'Trade group'}: ${leaderName || 'Leader'} added to ${ticker || 'a position'}${fillPriceText ? ` at ${fillPriceText}` : ''}.`
    };
  }
  return {
    normalizedEventType,
    body: `${groupName || 'Trade group'}: ${leaderName || 'Leader'} opened ${ticker || 'a position'}${fillPriceText ? ` at ${fillPriceText}` : ''}.`
  };
}

function getTradeGroupsLedByUser(db, username) {
  ensureSocialTables(db);
  return db.tradeGroups.filter(group => group.leader_user_id === username && group.is_active !== false);
}

function userLeadsTradeGroups(db, username) {
  return getTradeGroupsLedByUser(db, username).length > 0;
}

function getTradeGroupMembers(db, groupId, { status = 'active' } = {}) {
  ensureSocialTables(db);
  return db.tradeGroupMembers.filter(member => (
    member.group_id === groupId
    && TRADE_GROUP_MEMBER_STATUS_VALUES.includes(member.status)
    && (status ? member.status === status : true)
  ));
}

function isTradeGroupMember(db, groupId, username) {
  return db.tradeGroupMembers.some(member => (
    member.group_id === groupId
    && member.user_id === username
    && member.status === 'active'
  ));
}

function sanitizeTradeGroupForViewer(db, group, viewerUsername) {
  const leaderIdentity = socialIdentityForUser(db, group.leader_user_id);
  const members = getTradeGroupMembers(db, group.id, { status: 'active' });
  const isLeader = group.leader_user_id === viewerUsername;
  return {
    id: group.id,
    name: group.name,
    is_private: true,
    is_active: group.is_active !== false,
    created_at: group.created_at,
    leader: {
      nickname: leaderIdentity.nickname || 'Unknown trader',
      avatar_url: leaderIdentity.avatar_url,
      avatar_initials: leaderIdentity.avatar_initials
    },
    role: isLeader ? 'leader' : 'member',
    member_count: members.length
  };
}

function sanitizeTradeGroupMemberRow(db, member) {
  const identity = socialIdentityForUser(db, member.user_id);
  return {
    user_id: member.user_id,
    nickname: identity.nickname || 'Unknown trader',
    avatar_url: identity.avatar_url,
    avatar_initials: identity.avatar_initials,
    role: TRADE_GROUP_ROLE_VALUES.includes(member.role) ? member.role : 'member',
    status: member.status,
    joined_at: member.joined_at
  };
}

const ANNOUNCEMENT_PIPELINE_SEND_DEDUPE_WINDOW_MS = 30 * 60 * 1000;
const announcementPipelineStageCounters = new Map();

function nextAnnouncementStageCount(stage, { correlationId = '', announcementId = '', recipientUserId = '', deviceRowId = '' } = {}) {
  const key = `${stage}|${correlationId || 'none'}|${announcementId || 'none'}|${recipientUserId || 'none'}|${deviceRowId || 'none'}`;
  const next = (announcementPipelineStageCounters.get(key) || 0) + 1;
  announcementPipelineStageCounters.set(key, next);
  return next;
}

function logAnnouncementPipelineStage(stage, {
  correlationId = null,
  announcementId = null,
  recipientUserId = null,
  deviceRowId = null,
  tokenFingerprint = null,
  sourceHandler = null,
  details = {}
} = {}) {
  const at = new Date().toISOString();
  const stageCount = nextAnnouncementStageCount(stage, { correlationId, announcementId, recipientUserId, deviceRowId });
  console.info('[TradeGroup][AnnouncementPipeline][Stage]', {
    stage,
    stageCount,
    at,
    correlationId: correlationId || null,
    announcementId: announcementId || null,
    recipientUserId: recipientUserId || null,
    deviceRowId: deviceRowId || null,
    tokenFingerprint: tokenFingerprint || null,
    sourceHandler: sourceHandler || null,
    ...details
  });
}


function createTradeGroupNotification(db, { userId, groupId, type, alertId = null, inviteId = null, announcementId = null, groupWatchlistId = null, dedupeKey = '', correlationId = '' }) {
  const normalizedType = normalizeTradeGroupNotificationType(type);
  if (!normalizedType) return null;
  ensureSocialTables(db);
  if (dedupeKey) {
    const duplicate = db.tradeGroupNotifications.find(notification => (
      notification.user_id === userId
      && notification.group_id === groupId
      && normalizeTradeGroupNotificationType(notification.type) === normalizedType
      && notification.dedupe_key === dedupeKey
    ));
    if (duplicate) {
      console.info('[TradeGroup][Notifications] Existing in-app notification matched dedupe key; skipping create.', {
        userId,
        groupId,
        type: normalizedType,
        dedupeKey,
        notificationId: duplicate.id,
        duplicateReadState: duplicate.is_read === true ? 'read' : 'unread'
      });
      return null;
    }
  }
  const nowIso = new Date().toISOString();
  const notification = {
    id: crypto.randomUUID(),
    user_id: userId,
    group_id: groupId,
    type: normalizedType,
    alert_id: alertId,
    invite_id: inviteId,
    announcement_id: announcementId,
    group_watchlist_id: groupWatchlistId,
    dedupe_key: dedupeKey || '',
    correlation_id: correlationId || '',
    is_read: false,
    created_at: nowIso
  };
  db.tradeGroupNotifications.push(notification);
  const sourceAlert = normalizedType === 'trade_group_alert'
    ? db.tradeGroupAlerts.find((item) => item.id === alertId)
    : null;
  const normalizedAlertEventType = sourceAlert ? normalizeTradeGroupAlertEventType(sourceAlert) : null;
  console.info('[TradeGroup][Notifications] In-app banner notification created.', {
    notificationId: notification.id,
    userId,
    groupId,
    type: normalizedType,
    sourceEventId: alertId || inviteId || announcementId || groupWatchlistId || null,
    rawEventType: sourceAlert?.position_event_type || null,
    normalizedEventType: normalizedAlertEventType,
    alertId,
    inviteId,
    announcementId,
    groupWatchlistId,
    dedupeKey: dedupeKey || null,
    correlationId: correlationId || null
  });
  if (normalizedType === 'trade_group_announcement') {
    logAnnouncementPipelineStage('2.in_app_banner_notification_created', {
      correlationId: correlationId || null,
      announcementId: announcementId || null,
      recipientUserId: userId,
      sourceHandler: 'server.js#createTradeGroupNotification',
      details: {
        notificationId: notification.id,
        groupId
      }
    });
  }
  return notification;
}

function summarizeTradeGroupAnnouncementText(text, maxLength = 140) {
  const cleaned = String(text || '').replace(/\s+/g, ' ').trim();
  if (!cleaned) return 'A new trading group announcement is available.';
  if (cleaned.length <= maxLength) return cleaned;
  return `${cleaned.slice(0, Math.max(1, maxLength - 1)).trimEnd()}…`;
}

function buildTradeGroupNotificationPushContext(db, notification, { group = null } = {}) {
  if (!notification) return null;
  ensureSocialTables(db);
  const normalizedType = normalizeTradeGroupNotificationType(notification.type);
  const resolvedGroup = group || db.tradeGroups.find((item) => item.id === notification.group_id && item.is_active !== false);
  if (!resolvedGroup) return null;
  const fallbackLink = `/social/groups?group=${encodeURIComponent(resolvedGroup.id)}`;
  if (normalizedType === 'trade_group_alert') {
    const alert = db.tradeGroupAlerts.find((item) => item.id === notification.alert_id);
    const leaderIdentity = socialIdentityForUser(db, alert?.leader_user_id || '');
    const copy = buildTradeGroupAlertCopy(alert, {
      groupName: resolvedGroup.name,
      leaderName: leaderIdentity?.nickname || 'Leader'
    });
    console.info('[TradeGroup][Notifications] Alert push template selected.', {
      notificationId: notification.id,
      groupId: resolvedGroup.id,
      sourceAlertId: alert?.id || null,
      rawEventType: alert?.position_event_type || null,
      normalizedEventType: copy.normalizedEventType,
      template: 'trade_group_alert'
    });
    return {
      eventType: 'trade_group_alert',
      context: {
        groupId: resolvedGroup.id,
        groupName: resolvedGroup.name,
        body: copy.body,
        normalizedEventType: copy.normalizedEventType,
        link: fallbackLink,
        tag: `trade-group-alert:${resolvedGroup.id}:${notification.alert_id || notification.id}`
      }
    };
  }
  if (normalizedType === 'trade_group_announcement') {
    const announcement = db.tradeGroupAnnouncements.find((item) => item.id === notification.announcement_id);
    return {
      eventType: 'trade_group_announcement',
      context: {
        eventId: `trade_group_announcement:${notification.announcement_id || notification.id}`,
        source: 'triggerPushForTradeGroupNotification',
        correlationId: notification.correlation_id || `corr:${notification.id}`,
        groupId: resolvedGroup.id,
        groupName: resolvedGroup.name,
        announcementId: notification.announcement_id || null,
        announcementText: summarizeTradeGroupAnnouncementText(announcement?.text || ''),
        link: fallbackLink,
        tag: `trade-group-announcement:${notification.announcement_id || notification.id}`
      }
    };
  }
  if (normalizedType === 'trade_group_invite') {
    return {
      eventType: 'trade_group_invite',
      context: {
        groupId: resolvedGroup.id,
        groupName: resolvedGroup.name,
        link: fallbackLink,
        tag: `trade-group-invite:${resolvedGroup.id}:${notification.invite_id || notification.id}`
      }
    };
  }
  if (normalizedType === 'trade_group_member_joined') {
    const invite = db.tradeGroupInvites.find((item) => item.id === notification.invite_id);
    const joinedIdentity = socialIdentityForUser(db, invite?.invitee_user_id || '');
    return {
      eventType: 'trade_group_member_joined',
      context: {
        groupId: resolvedGroup.id,
        groupName: resolvedGroup.name,
        joinedNickname: joinedIdentity?.nickname || '',
        link: fallbackLink,
        tag: `trade-group-member-joined:${resolvedGroup.id}:${notification.invite_id || notification.id}`
      }
    };
  }
  if (normalizedType === 'trade_group_watchlist_posted') {
    const groupWatchlist = db.tradeGroupWatchlists.find((item) => item.id === notification.group_watchlist_id);
    const sourceWatchlist = groupWatchlist ? db.watchlists.find((item) => item.id === groupWatchlist.source_watchlist_id) : null;
    return {
      eventType: 'trade_group_watchlist_posted',
      context: {
        groupId: resolvedGroup.id,
        groupName: resolvedGroup.name,
        watchlistName: sourceWatchlist?.name || 'Shared Watchlist',
        groupWatchlistId: groupWatchlist?.id || notification.group_watchlist_id || '',
        link: `/social/groups?group=${encodeURIComponent(resolvedGroup.id)}&tab=watchlists&watchlist=${encodeURIComponent(groupWatchlist?.id || notification.group_watchlist_id || '')}`,
        tag: `trade-group-watchlist:${resolvedGroup.id}:${groupWatchlist?.id || notification.id}`
      }
    };
  }
  if (normalizedType === 'trade_group_chat_mention') {
    return {
      eventType: 'trade_group_chat_mention',
      context: {
        groupId: resolvedGroup.id,
        groupName: resolvedGroup.name,
        link: `${fallbackLink}&chat=1`,
        tag: `trade-group-chat-mention:${resolvedGroup.id}:${notification.id}`
      }
    };
  }
  return null;
}

function triggerPushForTradeGroupNotification(db, notification, { group = null } = {}) {
  const pushConfig = buildTradeGroupNotificationPushContext(db, notification, { group });
  if (!pushConfig) {
    console.info('[TradeGroup][Notifications] No push mapping for in-app notification.', {
      notificationId: notification?.id || null,
      userId: notification?.user_id || null,
      groupId: notification?.group_id || null,
      type: notification?.type || null
    });
    return;
  }
  console.info('[TradeGroup][Notifications] Push event created from in-app notification.', {
    notificationId: notification.id,
    userId: notification.user_id,
    groupId: notification.group_id,
    eventType: pushConfig.eventType,
    correlationId: pushConfig.context?.correlationId || notification.correlation_id || null
  });
  if (pushConfig.eventType === 'trade_group_announcement') {
    logAnnouncementPipelineStage('3.push_event_created', {
      correlationId: pushConfig.context?.correlationId || notification.correlation_id || null,
      announcementId: notification.announcement_id || pushConfig.context?.announcementId || null,
      recipientUserId: notification.user_id || null,
      sourceHandler: 'server.js#triggerPushForTradeGroupNotification',
      details: {
        notificationId: notification.id,
        groupId: notification.group_id || null,
        eventType: pushConfig.eventType
      }
    });
  }
  sendNotificationEvent(db, {
    userId: notification.user_id,
    eventType: pushConfig.eventType,
    context: {
      ...pushConfig.context,
      eventId: pushConfig.context?.eventId || `trade_group_notification:${notification.id}`,
      correlationId: pushConfig.context?.correlationId || notification.correlation_id || `trade_group_notification:${notification.id}`,
      invocationSource: 'server.js#triggerPushForTradeGroupNotification'
    }
  })
    .then((log) => {
      const targeted = Array.isArray(log?.deliveries) ? log.deliveries.length : 0;
      const successCount = Array.isArray(log?.deliveries) ? log.deliveries.filter((entry) => entry?.ok).length : 0;
      const failedCount = Math.max(0, targeted - successCount);
      console.info('[TradeGroup][Notifications] Push send attempted for trade-group in-app notification.', {
        notificationId: notification.id,
        userId: notification.user_id,
        groupId: notification.group_id,
        eventType: pushConfig.eventType,
        normalizedEventType: pushConfig.context?.normalizedEventType || null,
        targetedDevices: targeted,
        successfulDeliveries: successCount,
        failedDeliveries: failedCount
      });
      saveDB(db);
    })
    .catch((error) => {
      console.warn('[TradeGroup][Notifications] Push send failed for trade-group in-app notification.', {
        notificationId: notification.id,
        userId: notification.user_id,
        groupId: notification.group_id,
        eventType: pushConfig.eventType,
        message: error?.message || String(error)
      });
      saveDB(db);
    });
}

function cancelPendingInviteNotifications(db, inviteId) {
  ensureSocialTables(db);
  db.tradeGroupNotifications.forEach(notification => {
    if (notification.invite_id === inviteId && normalizeTradeGroupNotificationType(notification.type) === 'trade_group_invite' && !notification.is_read) {
      notification.is_read = true;
      notification.read_at = new Date().toISOString();
    }
  });
}

function buildGroupCurrentPositions(db, group) {
  const user = db?.users?.[group?.leader_user_id];
  if (!user) return [];
  const journal = ensureTradeJournal(user);
  const positions = [];
  for (const [dateKey, trades] of Object.entries(journal || {})) {
    for (const trade of (trades || [])) {
      if (!trade || trade.status === 'closed' || Number.isFinite(Number(trade.closePrice))) continue;
      const entry = Number(trade.entry);
      if (!Number.isFinite(entry) || entry <= 0) continue;
      const stop = Number(trade.stop);
      const riskPct = Number(trade.riskPct);
      const livePrice = Number(trade.lastSyncPrice);
      const direction = trade.direction === 'short' ? 'short' : 'long';
      const gainLossPct = (Number.isFinite(livePrice) && livePrice > 0)
        ? (direction === 'short'
          ? ((entry - livePrice) / entry) * 100
          : ((livePrice - entry) / entry) * 100)
        : null;
      const mappedTrade = applyInstrumentMappingToTrade(trade, db, group.leader_user_id) || trade;
      const ticker = resolveCanonicalTickerForTrade(mappedTrade);
      positions.push({
        id: trade.id,
        ticker,
        entry_price: entry,
        stop_price: (Number.isFinite(stop) && stop > 0) ? stop : null,
        risk_pct: (Number.isFinite(riskPct) && riskPct > 0) ? riskPct : null,
        gain_loss_pct: gainLossPct,
        created_at: trade.createdAt || trade.created_at || dateKey,
        updated_at: trade.updatedAt || trade.updated_at || null
      });
    }
  }
  return positions
    .filter(item => !!item.ticker)
    .sort((a, b) => String(b.updated_at || b.created_at || '').localeCompare(String(a.updated_at || a.created_at || '')))
    .slice(0, 50);
}

function resolveCanonicalTickerForTrade(trade) {
  if (!trade || typeof trade !== 'object') return '';
  const mappedTicker = typeof trade.displayTicker === 'string' ? trade.displayTicker.trim().toUpperCase() : '';
  if (mappedTicker) return mappedTicker;
  const internalTicker = typeof trade.displaySymbol === 'string' ? trade.displaySymbol.trim().toUpperCase() : '';
  if (internalTicker) return internalTicker;
  const canonicalStoredTicker = typeof trade.symbol === 'string' ? trade.symbol.trim().toUpperCase() : '';
  if (canonicalStoredTicker) return canonicalStoredTicker;
  const rawTicker = normalizeTrading212Symbol(normalizeTrading212TickerValue(trade.trading212Ticker || ''));
  return rawTicker || '';
}

function buildTradeGroupAlertPayload(db, leaderUsername, trade, { requireStopAndRisk = true } = {}) {
  const mappedTrade = applyInstrumentMappingToTrade(trade, db, leaderUsername) || trade;
  const ticker = resolveCanonicalTickerForTrade(mappedTrade);
  const entry = Number(trade.entry);
  const stop = Number(trade.stop);
  const riskPct = Number(trade.riskPct);
  if (!ticker || !Number.isFinite(entry) || entry <= 0) return null;
  if (requireStopAndRisk && (!Number.isFinite(stop) || stop <= 0 || !Number.isFinite(riskPct) || riskPct <= 0)) return null;
  return {
    ticker,
    entry_price: entry,
    stop_price: Number.isFinite(stop) && stop > 0 ? stop : null,
    risk_pct: Number.isFinite(riskPct) && riskPct > 0 ? riskPct : null,
    direction: trade.direction === 'short' ? 'short' : 'long',
    risk_amount_gbp: Number.isFinite(Number(trade.riskAmountGBP)) ? Number(trade.riskAmountGBP) : null
  };
}

function isQualifyingTradeForGroupAlert(trade) {
  if (!trade || typeof trade !== 'object') return false;
  const ticker = resolveCanonicalTickerForTrade(trade);
  const entry = Number(trade.entry);
  const stop = Number(trade.stop);
  const riskPct = Number(trade.riskPct);
  return Boolean(ticker)
    && Number.isFinite(entry)
    && entry > 0
    && Number.isFinite(stop)
    && stop > 0
    && Number.isFinite(riskPct)
    && riskPct > 0;
}

function createTradeGroupAlertsForNewTrade(db, leaderUsername, trade) {
  ensureSocialTables(db);
  if (!isQualifyingTradeForGroupAlert(trade)) return { alertsCreated: 0, notificationsCreated: 0 };
  const payload = buildTradeGroupAlertPayload(db, leaderUsername, trade, { requireStopAndRisk: true });
  if (!payload) return { alertsCreated: 0, notificationsCreated: 0 };
  const groups = getTradeGroupsLedByUser(db, leaderUsername);
  if (!groups.length) return { alertsCreated: 0, notificationsCreated: 0 };
  const nowIso = new Date().toISOString();
  let alertsCreated = 0;
  let notificationsCreated = 0;
  for (const group of groups) {
    const duplicate = db.tradeGroupAlerts.find(alert => alert.group_id === group.id && alert.source_trade_id === trade.id);
    if (duplicate) continue;
    const alert = {
      id: crypto.randomUUID(),
      group_id: group.id,
      leader_user_id: leaderUsername,
      source_trade_id: trade.id,
      side: 'BUY',
      alert_classification: 'buy',
      position_event_type: 'POSITION_OPENED',
      normalized_event_type: 'TRADE_OPENED',
      ticker: payload.ticker,
      entry_price: payload.entry_price,
      stop_price: payload.stop_price,
      risk_pct: payload.risk_pct,
      direction: payload.direction,
      risk_amount_gbp: payload.risk_amount_gbp,
      created_at: nowIso
    };
    db.tradeGroupAlerts.push(alert);
    console.info('[TradeGroup][AlertClassifier]', {
      source: 'new_trade_create',
      leader: leaderUsername,
      groupId: group.id,
      tradeId: trade?.id || null,
      alertId: alert.id,
      side: alert.side,
      classification: alert.alert_classification,
      positionEventType: alert.position_event_type,
      normalizedEventType: alert.normalized_event_type
    });
    createGroupTradeEventSystemMessage(db, group.id, leaderUsername, { ...alert, side: 'BUY', position_event_type: 'POSITION_OPENED' });
    alertsCreated += 1;
    const activeMembers = getTradeGroupMembers(db, group.id, { status: 'active' })
      .filter(member => member.user_id !== leaderUsername);
    if (!activeMembers.length) {
      console.info('[TradeGroup][Notifications] Fan-out skipped: no eligible members.', {
        sourceAlertId: alert.id,
        groupId: group.id,
        rawEventType: alert.position_event_type,
        normalizedEventType: normalizeTradeGroupAlertEventType(alert),
        skipReason: 'no_active_members'
      });
    }
    for (const member of activeMembers) {
      const created = createTradeGroupNotification(db, {
        userId: member.user_id,
        groupId: group.id,
        type: 'trade_group_alert',
        alertId: alert.id,
        dedupeKey: `alert:${alert.id}`
      });
      if (created) {
        notificationsCreated += 1;
        triggerPushForTradeGroupNotification(db, created, { group });
      }
    }
  }
  return { alertsCreated, notificationsCreated };
}

function buildTradeGroupClosureEventKey(trade, reason = 'snapshot_disappearance') {
  const normalizedReason = String(reason || 'snapshot_disappearance').trim().toLowerCase() || 'snapshot_disappearance';
  return `${String(trade?.id || '').trim() || 'unknown-trade'}:${normalizedReason}`;
}

function hasTradeGroupSellAlertBeenEmittedForTrade(trade, closureEventKey = '') {
  if (!trade || typeof trade !== 'object') return false;
  if (trade.tradeGroupSellAlertEmitted === true) return true;
  const emittedEventKey = String(trade.tradeGroupSellAlertEventKey || '').trim();
  return Boolean(closureEventKey && emittedEventKey && emittedEventKey === closureEventKey);
}

function markTradeGroupSellAlertEmittedForTrade(trade, closureEventKey = '') {
  if (!trade || typeof trade !== 'object') return;
  trade.tradeGroupSellAlertEmitted = true;
  trade.tradeGroupSellAlertEventKey = closureEventKey || String(trade.tradeGroupSellAlertEventKey || '').trim() || null;
  trade.tradeGroupSellAlertEmittedAt = new Date().toISOString();
}

function emitTradeGroupSellAlertForClosedTrade(db, leaderUsername, trade, {
  reason = 'snapshot_disappearance',
  classification = 'full_close'
} = {}) {
  ensureSocialTables(db);
  const closureEventKey = buildTradeGroupClosureEventKey(trade, reason);
  const snapshotNowIso = new Date().toISOString();
  const closeFingerprintMeta = buildTrading212CloseBusinessFingerprint({
    accountId: String(trade?.trading212AccountId || '').trim(),
    canonicalTicker: resolveCanonicalTickerForTrade(trade) || '',
    brokerTicker: String(trade?.symbol || trade?.trading212Ticker || '').trim(),
    isin: String(trade?.isin || trade?.instrumentIsin || '').trim(),
    instrumentId: String(trade?.trading212Id || trade?.trading212PositionKey || '').trim(),
    side: 'SELL',
    classification,
    quantity: Number(trade?.sizeUnits),
    remainingQuantity: 0,
    sourceTradeId: String(trade?.id || '').trim(),
    providerEventId: '',
    providerOrderId: '',
    providerEventKey: closureEventKey,
    filledAt: String(trade?.closedAt || trade?.closeDate || '').trim(),
    reconciliationTimestamp: snapshotNowIso
  });
  const businessFingerprint = closeFingerprintMeta.fingerprint;
  if (hasTradeGroupSellAlertBeenEmittedForTrade(trade, closureEventKey)) {
    console.info('[TradeGroup][SellAlert]', {
      stage: 'sell_alert_skipped',
      leader: leaderUsername,
      tradeId: trade?.id || null,
      ticker: resolveCanonicalTickerForTrade(trade) || null,
      reason: 'duplicate',
      skipReason: 'trade_already_marked_emitted',
      closureEventKey,
      reconciliationPath: 'snapshot_disappearance',
      businessFingerprint: businessFingerprint || null,
      fingerprintInputs: closeFingerprintMeta.components
    });
    return { alertsCreated: 0, notificationsCreated: 0, duplicates: 1 };
  }
  const groups = getTradeGroupsLedByUser(db, leaderUsername);
  if (!groups.length) {
    console.info('[TradeGroup][SellAlert]', {
      stage: 'sell_alert_skipped',
      leader: leaderUsername,
      tradeId: trade?.id || null,
      ticker: resolveCanonicalTickerForTrade(trade) || null,
      reason: 'no_groups_led',
      closureEventKey
    });
    markTradeGroupSellAlertEmittedForTrade(trade, closureEventKey);
    return { alertsCreated: 0, notificationsCreated: 0, duplicates: 0 };
  }
  const ticker = resolveCanonicalTickerForTrade(trade);
  if (!ticker) return { alertsCreated: 0, notificationsCreated: 0, duplicates: 0 };
  let alertsCreated = 0;
  let notificationsCreated = 0;
  let duplicates = 0;
  for (const group of groups) {
    const duplicate = db.tradeGroupAlerts.find((alert) => (
      alert.group_id === group.id
      && (
        (businessFingerprint && String(alert.business_event_fingerprint || '') === businessFingerprint)
        || (
          alert.source_trade_id === trade.id
          && String(alert.side || '').toUpperCase() === 'SELL'
          && String(alert.closure_event_key || '') === closureEventKey
        )
      )
    ));
    if (duplicate) {
      duplicates += 1;
      console.info('[TradeGroup][SellAlert]', {
        stage: 'sell_alert_deduped',
        reconciliationPath: 'snapshot_disappearance',
        leader: leaderUsername,
        groupId: group.id,
        sourceTradeLinked: true,
        businessFingerprint: businessFingerprint || null,
        fingerprintInputs: closeFingerprintMeta.components,
        duplicateAlertId: duplicate.id,
        emissionDecision: 'deduped'
      });
      continue;
    }
    const alert = {
      id: crypto.randomUUID(),
      group_id: group.id,
      leader_user_id: leaderUsername,
      source_trade_id: trade.id,
      broker_source: trade?.source === 'trading212' || trade?.trading212Id ? 'trading212' : null,
      ticker,
      side: 'SELL',
      alert_classification: classification || 'full_close',
      position_event_type: 'POSITION_CLOSED',
      business_event_fingerprint: businessFingerprint || null,
      closure_event_key: closureEventKey,
      closure_reason: String(reason || '').trim() || null,
      created_at: snapshotNowIso
    };
    db.tradeGroupAlerts.push(alert);
    createGroupTradeEventSystemMessage(db, group.id, leaderUsername, alert);
    alertsCreated += 1;
    const activeMembers = getTradeGroupMembers(db, group.id, { status: 'active' })
      .filter(member => member.user_id !== leaderUsername);
    if (!activeMembers.length) {
      console.info('[TradeGroup][Notifications] Fan-out skipped: no eligible members.', {
        sourceAlertId: alert.id,
        groupId: group.id,
        rawEventType: alert.position_event_type,
        normalizedEventType: normalizeTradeGroupAlertEventType(alert),
        skipReason: 'no_active_members'
      });
    }
    for (const member of activeMembers) {
      const created = createTradeGroupNotification(db, {
        userId: member.user_id,
        groupId: group.id,
        type: 'trade_group_alert',
        alertId: alert.id,
        dedupeKey: businessFingerprint
          ? `trade-close:${businessFingerprint}:${group.id}`
          : `trade-close:${closureEventKey}:${group.id}`
      });
      if (created) {
        notificationsCreated += 1;
        triggerPushForTradeGroupNotification(db, created, { group });
      }
    }
  }
  if (alertsCreated > 0 || duplicates > 0) {
    markTradeGroupSellAlertEmittedForTrade(trade, closureEventKey);
  }
  console.info('[TradeGroup][SellAlert]', {
    stage: alertsCreated > 0 ? 'sell_alert_emitted' : 'sell_alert_skipped',
    reconciliationPath: 'snapshot_disappearance',
    leader: leaderUsername,
    tradeId: trade?.id || null,
    ticker,
    reason: String(reason || '').trim() || null,
    closureEventKey,
    businessFingerprint: businessFingerprint || null,
    fingerprintInputs: closeFingerprintMeta.components,
    alertsCreated,
    notificationsCreated,
    duplicates,
    skipReason: alertsCreated > 0 ? null : (duplicates > 0 ? 'duplicate' : 'unknown')
  });
  return { alertsCreated, notificationsCreated, duplicates };
}

function emitTradeGroupTrimAlertForTrade(db, leaderUsername, trade, {
  previousQty = null,
  newQty = null,
  fillPrice = null,
  trimDate = '',
  reason = 'manual_trim',
  eventKey = ''
} = {}) {
  ensureSocialTables(db);
  const groups = getTradeGroupsLedByUser(db, leaderUsername);
  if (!groups.length) return { alertsCreated: 0, notificationsCreated: 0, duplicates: 0 };
  const ticker = resolveCanonicalTickerForTrade(trade);
  if (!ticker) return { alertsCreated: 0, notificationsCreated: 0, duplicates: 0 };
  const trimPct = computeTrimPercent(previousQty, newQty);
  if (!Number.isFinite(trimPct) || trimPct <= 0) return { alertsCreated: 0, notificationsCreated: 0, duplicates: 0 };
  const resolvedFillPrice = Number.isFinite(Number(fillPrice)) ? Number(fillPrice) : null;
  const brokerEventKey = String(eventKey || `${trade?.id || 'unknown'}|trim|${trimDate || ''}|${trimPct}|${resolvedFillPrice || 'n/a'}`).trim();
  const nowIso = new Date().toISOString();
  const trimmedQuantity = Number(previousQty) - Number(newQty);
  const closeFingerprintMeta = buildTrading212CloseBusinessFingerprint({
    accountId: String(trade?.trading212AccountId || '').trim(),
    canonicalTicker: ticker,
    brokerTicker: String(trade?.symbol || trade?.trading212Ticker || '').trim(),
    isin: String(trade?.isin || trade?.instrumentIsin || '').trim(),
    instrumentId: String(trade?.trading212Id || trade?.trading212PositionKey || '').trim(),
    side: 'SELL',
    classification: 'partial_sell',
    quantity: Number.isFinite(trimmedQuantity) ? trimmedQuantity : null,
    remainingQuantity: Number(newQty),
    sourceTradeId: String(trade?.id || '').trim(),
    providerEventId: '',
    providerOrderId: '',
    providerEventKey: brokerEventKey,
    filledAt: String(trimDate || '').trim(),
    reconciliationTimestamp: nowIso
  });
  const businessFingerprint = closeFingerprintMeta.fingerprint;
  let alertsCreated = 0;
  let notificationsCreated = 0;
  let duplicates = 0;
  for (const group of groups) {
    const duplicate = db.tradeGroupAlerts.find((alert) => (
      alert.group_id === group.id
      && (
        (businessFingerprint && String(alert.business_event_fingerprint || '') === businessFingerprint)
        || (
          String(alert.side || '').toUpperCase() === 'SELL'
          && String(alert.broker_event_key || '') === brokerEventKey
        )
      )
    ));
    if (duplicate) {
      duplicates += 1;
      console.info('[TradeGroup][TrimAlert]', {
        stage: 'trim_alert_deduped',
        leader: leaderUsername,
        groupId: group.id,
        duplicateAlertId: duplicate.id,
        businessFingerprint: businessFingerprint || null,
        fingerprintInputs: closeFingerprintMeta.components
      });
      continue;
    }
    const alert = {
      id: crypto.randomUUID(),
      group_id: group.id,
      leader_user_id: leaderUsername,
      source_trade_id: trade?.id || null,
      broker_source: trade?.source === 'trading212' || trade?.trading212Id ? 'trading212' : 'manual',
      broker_event_key: brokerEventKey,
      ticker,
      side: 'SELL',
      alert_classification: 'partial_sell',
      position_event_type: 'POSITION_TRIM',
      business_event_fingerprint: businessFingerprint || null,
      trim_pct: trimPct,
      fill_price: resolvedFillPrice,
      closure_reason: String(reason || '').trim() || null,
      filled_at: trimDate || null,
      created_at: nowIso
    };
    db.tradeGroupAlerts.push(alert);
    createGroupTradeEventSystemMessage(db, group.id, leaderUsername, alert);
    alertsCreated += 1;
    const activeMembers = getTradeGroupMembers(db, group.id, { status: 'active' })
      .filter(member => member.user_id !== leaderUsername);
    for (const member of activeMembers) {
      const created = createTradeGroupNotification(db, {
        userId: member.user_id,
        groupId: group.id,
        type: 'trade_group_alert',
        alertId: alert.id,
        dedupeKey: businessFingerprint
          ? `trade-trim:${businessFingerprint}:${group.id}`
          : `trade-trim:${brokerEventKey}:${group.id}`
      });
      if (created) {
        notificationsCreated += 1;
        triggerPushForTradeGroupNotification(db, created, { group });
      }
    }
  }
  console.info('[TradeGroup][TrimAlert]', {
    stage: alertsCreated > 0 ? 'trim_alert_emitted' : 'trim_alert_skipped',
    leader: leaderUsername,
    tradeId: trade?.id || null,
    ticker,
    previousQty: Number(previousQty) || null,
    newQty: Number(newQty) || null,
    trimPct,
    selectedFillPrice: resolvedFillPrice,
    brokerEventKey,
    businessFingerprint: businessFingerprint || null,
    fingerprintInputs: closeFingerprintMeta.components,
    alertsCreated,
    notificationsCreated,
    duplicates
  });
  return { alertsCreated, notificationsCreated, duplicates };
}

function classifyTrading212SellAlert({ matchedQuantity = null, remainingQuantity = null, tradeStatus = '' } = {}) {
  if (Number.isFinite(remainingQuantity) && remainingQuantity <= 1e-8) return 'full_close';
  if (String(tradeStatus || '').toLowerCase() === 'closed') return 'full_close';
  if (Number.isFinite(matchedQuantity) && matchedQuantity > 0) return 'partial_sell';
  return 'sell';
}

function classifyPositionDeltaEvent({ previousQty = null, nextQty = null } = {}) {
  const prev = Number(previousQty);
  const next = Number(nextQty);
  if (!Number.isFinite(prev) || prev <= 1e-8) {
    if (Number.isFinite(next) && next > 1e-8) return 'NEW_POSITION';
    return '';
  }
  if (!Number.isFinite(next) || next <= 1e-8) return 'POSITION_CLOSED';
  if (next > prev + 1e-8) return 'POSITION_INCREASE';
  if (next < prev - 1e-8) return 'POSITION_TRIM';
  return '';
}

function isCanonicallyClosedTrade(trade = {}) {
  return trade?.status === 'closed' || Boolean(trade?.closedAt);
}

function computeTrimPercent(previousQty, nextQty) {
  const prev = Number(previousQty);
  const next = Number(nextQty);
  if (!Number.isFinite(prev) || prev <= 0 || !Number.isFinite(next)) return null;
  const raw = ((prev - next) / prev) * 100;
  if (!Number.isFinite(raw) || raw <= 0) return null;
  return Number(raw.toFixed(raw % 1 === 0 ? 0 : 2));
}

function formatTrimPercentForUi(percent) {
  const value = Number(percent);
  if (!Number.isFinite(value) || value <= 0) return '';
  if (Math.abs(value - Math.round(value)) <= 1e-6) return `${Math.round(value)}%`;
  if (Math.abs((value * 10) - Math.round(value * 10)) <= 1e-6) return `${value.toFixed(1)}%`;
  return `${value.toFixed(2).replace(/0+$/, '').replace(/\.$/, '')}%`;
}

function coalesceTrading212FillEvents(fillEvents = [], { windowMs = 15000 } = {}) {
  if (!Array.isArray(fillEvents) || !fillEvents.length) return [];
  const sorted = fillEvents
    .filter(Boolean)
    .slice()
    .sort((a, b) => Date.parse(a?.filledAt || '') - Date.parse(b?.filledAt || ''));
  const coalesced = [];
  for (const event of sorted) {
    const side = String(event?.side || '').toUpperCase();
    const classification = side === 'SELL'
      ? classifyTrading212SellAlert({
        matchedQuantity: event?.quantity,
        remainingQuantity: event?.remainingQuantity,
        tradeStatus: event?.tradeStatus
      })
      : 'buy';
    if (side !== 'SELL' || classification !== 'partial_sell') {
      coalesced.push(event);
      continue;
    }
    const eventTs = Date.parse(event?.filledAt || '');
    const key = [
      String(event?.accountId || '').trim(),
      String(event?.sourceTradeId || '').trim(),
      String(event?.orderId || '').trim(),
      String(event?.ticker || '').trim().toUpperCase(),
      side,
      classification
    ].join('|');
    const last = coalesced[coalesced.length - 1];
    if (!last) {
      coalesced.push({ ...event, _coalesceKey: key, _fillIds: [String(event?.fillId || '').trim()].filter(Boolean) });
      continue;
    }
    const lastTs = Date.parse(last?.filledAt || '');
    const canMerge = last._coalesceKey === key
      && Number.isFinite(eventTs)
      && Number.isFinite(lastTs)
      && Math.abs(eventTs - lastTs) <= windowMs;
    if (!canMerge) {
      coalesced.push({ ...event, _coalesceKey: key, _fillIds: [String(event?.fillId || '').trim()].filter(Boolean) });
      continue;
    }
    const previousQty = Number(last.quantity) || 0;
    const incomingQty = Number(event.quantity) || 0;
    const mergedQty = previousQty + incomingQty;
    const previousValue = previousQty * (Number(last.fillPrice) || 0);
    const incomingValue = incomingQty * (Number(event.fillPrice) || 0);
    const mergedFillIds = Array.from(new Set([...(last._fillIds || []), String(event?.fillId || '').trim()].filter(Boolean)));
    last.quantity = mergedQty;
    if (mergedQty > 0 && Number.isFinite(previousValue + incomingValue)) {
      last.fillPrice = (previousValue + incomingValue) / mergedQty;
    }
    last.fillId = mergedFillIds.join(',');
    last._fillIds = mergedFillIds;
    if (Number.isFinite(eventTs) && (!Number.isFinite(lastTs) || eventTs >= lastTs)) {
      last.filledAt = event.filledAt || last.filledAt;
      last.remainingQuantity = event.remainingQuantity ?? last.remainingQuantity;
      last.tradeStatus = event.tradeStatus || last.tradeStatus;
      last.stopTriggered = event.stopTriggered === true || last.stopTriggered === true;
    }
  }
  return coalesced.map((event) => {
    const clean = { ...event };
    delete clean._coalesceKey;
    delete clean._fillIds;
    return clean;
  });
}

function buildTrading212FillEventKey(fillEvent = {}) {
  const fillId = String(fillEvent?.fillId || '').trim();
  if (fillId) return `fill:${fillId}`;
  const orderId = String(fillEvent?.orderId || '').trim();
  const side = String(fillEvent?.side || '').trim().toUpperCase();
  const ticker = String(fillEvent?.ticker || '').trim().toUpperCase();
  const filledAt = String(fillEvent?.filledAt || '').trim();
  const sourceTradeId = String(fillEvent?.sourceTradeId || '').trim();
  if (!side) return '';
  return [
    'derived',
    orderId || 'no-order',
    side,
    ticker || 'no-ticker',
    filledAt || 'no-filled-at',
    sourceTradeId || 'no-trade'
  ].join('|');
}

function normalizeTrading212CloseFingerprintQuantity(value) {
  const num = Number(value);
  if (!Number.isFinite(num) || num < 0) return 'na';
  return String(Number(num.toFixed(6)));
}

function buildTrading212CloseBusinessFingerprint({
  accountId = '',
  canonicalTicker = '',
  brokerTicker = '',
  isin = '',
  instrumentId = '',
  side = '',
  classification = '',
  quantity = null,
  remainingQuantity = null,
  sourceTradeId = '',
  providerEventId = '',
  providerOrderId = '',
  providerEventKey = '',
  filledAt = '',
  reconciliationTimestamp = ''
} = {}) {
  const normalizedSide = String(side || '').trim().toUpperCase();
  if (normalizedSide !== 'SELL') {
    return {
      fingerprint: '',
      components: { reason: 'non_sell' }
    };
  }
  const normalizedClassification = String(classification || '').trim().toLowerCase() || 'sell';
  const instrumentIdentity = (() => {
    const canonical = String(canonicalTicker || '').trim().toUpperCase();
    if (canonical) return `canonical:${canonical}`;
    const normalizedIsin = String(isin || '').trim().toUpperCase();
    if (normalizedIsin) return `isin:${normalizedIsin}`;
    const normalizedInstrumentId = String(instrumentId || '').trim();
    if (normalizedInstrumentId) return `instrument:${normalizedInstrumentId}`;
    const normalizedBrokerTicker = String(brokerTicker || '').trim().toUpperCase();
    if (normalizedBrokerTicker) return `broker_ticker:${normalizedBrokerTicker}`;
    return 'unknown-instrument';
  })();
  const fillTs = String(filledAt || '').trim();
  const reconcileTs = String(reconciliationTimestamp || '').trim();
  const eventDateIso = (() => {
    const parsedFill = Date.parse(fillTs);
    if (Number.isFinite(parsedFill)) return new Date(parsedFill).toISOString().slice(0, 10);
    const parsedReconcile = Date.parse(reconcileTs);
    if (Number.isFinite(parsedReconcile)) return new Date(parsedReconcile).toISOString().slice(0, 10);
    return 'unknown-date';
  })();
  const quantityKey = normalizeTrading212CloseFingerprintQuantity(quantity);
  const remainingKey = normalizeTrading212CloseFingerprintQuantity(remainingQuantity);
  const sourceTradeKey = String(sourceTradeId || '').trim();
  const providerKey = String(providerEventId || providerEventKey || '').trim();
  const providerOrderKey = String(providerOrderId || '').trim();
  const accountKey = String(accountId || '').trim() || 'default';
  const components = {
    accountKey,
    instrumentIdentity,
    side: normalizedSide,
    classification: normalizedClassification,
    quantityKey,
    remainingKey,
    eventDateIso,
    sourceTradeKey: sourceTradeKey || null,
    providerKey: providerKey || null,
    providerOrderKey: providerOrderKey || null
  };
  // Keep canonical business key stable across snapshot-disappearance and history-fill paths.
  // Trim-vs-close remains distinct via `classification` plus `remainingKey` (trim > 0, close = 0),
  // and sequential trims on the same symbol avoid collapse when their resulting remaining size differs.
  // Source/provider identifiers are retained for observability but not required for equality.
  const fingerprint = [
    't212-close-biz-v1',
    accountKey,
    instrumentIdentity,
    normalizedSide,
    normalizedClassification,
    quantityKey,
    remainingKey,
    eventDateIso
  ].join('|');
  return { fingerprint, components };
}

function logTrading212SellAlertLifecycle(leaderUsername, fillEvent = {}, stage = '', extras = {}) {
  if (String(fillEvent?.side || '').toUpperCase() !== 'SELL') return;
  const payload = {
    leader: leaderUsername,
    stage: String(stage || 'unknown'),
    fillId: String(fillEvent?.fillId || '').trim() || 'n/a',
    eventKey: buildTrading212FillEventKey(fillEvent) || 'n/a',
    matchedTradeId: String(fillEvent?.sourceTradeId || '').trim() || 'n/a',
    classification: String(fillEvent?.classification || '').trim() || 'n/a',
    accountId: String(fillEvent?.accountId || '').trim() || 'default',
    ticker: String(fillEvent?.ticker || '').trim().toUpperCase() || 'n/a',
    ...extras
  };
  const details = Object.entries(payload)
    .map(([key, value]) => `${key}=${value}`)
    .join(' ');
  console.info(`[TradeGroup][SellAlert] ${details}`);
}

function emitTradeGroupAlertFromTrading212Fill(db, leaderUsername, fillEvent = {}) {
  ensureSocialTables(db);
  const groups = getTradeGroupsLedByUser(db, leaderUsername);
  if (!groups.length) {
    logTrading212SellAlertLifecycle(leaderUsername, fillEvent, 'eligible_groups_lookup', { eligibleGroups: 0, skipped: 'true', skipReason: 'no_groups_led' });
    console.info(`[TradeGroup][LeaderSync] alert skipped leader=${leaderUsername} reason=no_groups_led`);
    return { alertsCreated: 0, notificationsCreated: 0, duplicates: 0 };
  }
  const fillId = String(fillEvent?.fillId || '').trim();
  const brokerEventKey = buildTrading212FillEventKey(fillEvent);
  if (!brokerEventKey) {
    logTrading212SellAlertLifecycle(leaderUsername, fillEvent, 'fill_detected', { skipped: 'true', skipReason: 'missing_fill_identity' });
    console.info(`[TradeGroup][LeaderSync] alert skipped leader=${leaderUsername} reason=missing_fill_identity side=${String(fillEvent?.side || '').toUpperCase()}`);
    return { alertsCreated: 0, notificationsCreated: 0, duplicates: 0 };
  }
  const side = String(fillEvent?.side || '').toUpperCase();
  if (side !== 'BUY' && side !== 'SELL') {
    console.info(`[TradeGroup][LeaderSync] alert skipped leader=${leaderUsername} reason=invalid_side side=${side || 'n/a'} eventKey=${brokerEventKey}`);
    return { alertsCreated: 0, notificationsCreated: 0, duplicates: 0 };
  }
  const quantity = Number.isFinite(Number(fillEvent?.quantity)) ? Number(fillEvent.quantity) : null;
  const remainingQuantity = Number.isFinite(Number(fillEvent?.remainingQuantity)) ? Number(fillEvent.remainingQuantity) : null;
  const previousQuantity = Number.isFinite(Number(fillEvent?.previousQuantity)) ? Number(fillEvent.previousQuantity) : null;
  const quantityDelta = (Number.isFinite(previousQuantity) && Number.isFinite(remainingQuantity))
    ? Number((remainingQuantity - previousQuantity).toFixed(8))
    : null;
  const deltaType = classifyPositionDeltaEvent({ previousQty: previousQuantity, nextQty: remainingQuantity });
  let classification = side === 'BUY'
    ? 'buy'
    : classifyTrading212SellAlert({
      matchedQuantity: fillEvent?.quantity,
      remainingQuantity: fillEvent?.remainingQuantity,
      tradeStatus: fillEvent?.tradeStatus
    });
  let positionEventType = side === 'BUY'
    ? 'NEW_POSITION'
    : (classification === 'full_close' ? 'POSITION_CLOSED' : (classification === 'partial_sell' ? 'POSITION_TRIM' : 'POSITION_REDUCED'));
  if (deltaType === 'POSITION_INCREASE') {
    classification = side === 'BUY' ? 'add' : classification;
    positionEventType = 'POSITION_INCREASE';
  } else if (deltaType === 'NEW_POSITION') {
    classification = side === 'BUY' ? 'buy' : classification;
    positionEventType = 'NEW_POSITION';
  } else if (deltaType === 'POSITION_TRIM') {
    classification = side === 'SELL' ? 'partial_sell' : classification;
    positionEventType = 'POSITION_TRIM';
  } else if (deltaType === 'POSITION_CLOSED') {
    classification = side === 'SELL' ? 'full_close' : classification;
    positionEventType = 'POSITION_CLOSED';
  }
  console.info('[TradeGroup][AlertClassifier]', {
    source: 'trading212_fill',
    leader: leaderUsername,
    side,
    classification,
    positionEventType,
    quantity,
    previousQuantity,
    remainingQuantity,
    quantityDelta,
    sourceTradeId: String(fillEvent?.sourceTradeId || '').trim() || null,
    brokerEventKey
  });
  console.info('[trade-alert-classify]', {
    source: 'emitTradeGroupAlertFromTrading212Fill',
    leader: leaderUsername,
    tradeId: String(fillEvent?.sourceTradeId || '').trim() || null,
    groupId: null,
    ticker: String(fillEvent?.ticker || '').trim().toUpperCase() || null,
    preQty: previousQuantity,
    postQty: remainingQuantity,
    delta: quantityDelta,
    deltaType: deltaType || null,
    chosenEventType: positionEventType,
    classification
  });
  if (positionEventType === 'POSITION_TRIM' || positionEventType === 'POSITION_REDUCED') {
    console.info('[trade-alert-classify]', {
      source: 'emitTradeGroupAlertFromTrading212Fill',
      reason: 'post_qty_below_pre_qty',
      ticker: String(fillEvent?.ticker || '').trim().toUpperCase() || null,
      preQty: previousQuantity,
      postQty: remainingQuantity
    });
  }
  const fillPrice = Number.isFinite(Number(fillEvent?.fillPrice)) ? Number(fillEvent.fillPrice) : null;
  const trimPercent = side === 'SELL' && classification === 'partial_sell'
    ? computeTrimPercent(fillEvent?.previousQuantity, fillEvent?.remainingQuantity)
    : null;
  if (side === 'SELL') {
    logTrading212SellAlertLifecycle(leaderUsername, { ...fillEvent, classification }, 'fill_detected', {
      eligibleGroups: groups.length,
      skipped: 'false',
      positionEventType,
      previousQty: Number(fillEvent?.previousQuantity) || null,
      newQty: Number(fillEvent?.remainingQuantity) || null,
      trimPct: trimPercent,
      selectedFillPrice: fillPrice
    });
  }
  const nowIso = new Date().toISOString();
  const sourceTradeId = String(fillEvent?.sourceTradeId || '').trim();
  const leaderUser = db.users?.[leaderUsername];
  const sourceTrade = sourceTradeId && leaderUser ? findTradeById(leaderUser, sourceTradeId)?.trade : null;
  const closeFingerprintMeta = buildTrading212CloseBusinessFingerprint({
    accountId: String(fillEvent?.accountId || '').trim(),
    canonicalTicker: String(fillEvent?.ticker || '').trim(),
    brokerTicker: String(fillEvent?.ticker || '').trim(),
    isin: String(fillEvent?.instrumentIsin || fillEvent?.isin || '').trim(),
    instrumentId: String(fillEvent?.instrumentId || fillEvent?.providerInstrumentId || '').trim(),
    side,
    classification,
    quantity: fillEvent?.quantity,
    remainingQuantity: fillEvent?.remainingQuantity,
    sourceTradeId,
    providerEventId: fillId,
    providerOrderId: String(fillEvent?.orderId || '').trim(),
    providerEventKey: brokerEventKey,
    filledAt: String(fillEvent?.filledAt || '').trim(),
    reconciliationTimestamp: nowIso
  });
  const businessFingerprint = closeFingerprintMeta.fingerprint;
  if (side === 'SELL' && !sourceTradeId) {
    console.info('[TradeGroup][SellAlert]', {
      stage: 'sell_fill_missing_source_trade',
      leader: leaderUsername,
      ticker: String(fillEvent?.ticker || '').trim().toUpperCase() || null,
      fillId: fillId || null,
      brokerEventKey,
      risk: 'cannot_link_fill_to_trade_for_cross-path_dedupe',
      businessFingerprint: businessFingerprint || null,
      fingerprintInputs: closeFingerprintMeta.components
    });
  }
  if (side === 'SELL' && sourceTrade && hasTradeGroupSellAlertBeenEmittedForTrade(sourceTrade)) {
    logTrading212SellAlertLifecycle(leaderUsername, { ...fillEvent, classification }, 'alert_skipped', { skipped: 'true', skipReason: 'trade_close_alert_already_emitted' });
    console.info('[TradeGroup][SellAlert]', {
      stage: 'sell_alert_skipped',
      leader: leaderUsername,
      tradeId: sourceTrade.id,
      ticker: resolveCanonicalTickerForTrade(sourceTrade) || fillEvent?.ticker || null,
      reason: 'duplicate',
      skipReason: 'trade_close_alert_already_emitted'
    });
    return { alertsCreated: 0, notificationsCreated: 0, duplicates: 1 };
  }
  let alertsCreated = 0;
  let notificationsCreated = 0;
  let duplicates = 0;
  for (const group of groups) {
    const duplicate = db.tradeGroupAlerts.find(alert => (
      alert.group_id === group.id
      && (
        (businessFingerprint && String(alert.business_event_fingerprint || '') === businessFingerprint)
        || (
          alert.broker_source === 'trading212'
          && (
            (fillId && alert.broker_fill_id === fillId)
            || alert.broker_event_key === brokerEventKey
          )
        )
      )
    ));
    if (duplicate) {
      duplicates += 1;
      logTrading212SellAlertLifecycle(leaderUsername, { ...fillEvent, classification }, 'alert_skipped', {
        groupId: group.id,
        skipped: 'true',
        skipReason: businessFingerprint && String(duplicate.business_event_fingerprint || '') === businessFingerprint
          ? 'business_fingerprint_duplicate'
          : 'duplicate'
      });
      console.info(`[TradeGroup][LeaderSync] alert skipped as duplicate leader=${leaderUsername} group=${group.id} fillId=${fillId || 'n/a'} eventKey=${brokerEventKey}`);
      console.info('[TradeGroup][SellAlert]', {
        stage: 'sell_alert_deduped',
        reconciliationPath: 'history_fill',
        leader: leaderUsername,
        groupId: group.id,
        sourceTradeLinked: Boolean(sourceTradeId),
        businessFingerprint: businessFingerprint || null,
        fingerprintInputs: closeFingerprintMeta.components,
        duplicateAlertId: duplicate.id
      });
      continue;
    }
    const alert = {
      id: crypto.randomUUID(),
      group_id: group.id,
      leader_user_id: leaderUsername,
      source_trade_id: fillEvent?.sourceTradeId || null,
      broker_source: 'trading212',
      broker_fill_id: fillId,
      broker_event_key: brokerEventKey,
      broker_order_id: String(fillEvent?.orderId || '').trim() || null,
      business_event_fingerprint: businessFingerprint || null,
      account_id: String(fillEvent?.accountId || '').trim() || null,
      ticker: fillEvent?.ticker || '',
      side,
      alert_classification: classification,
      position_event_type: positionEventType,
      fill_price: fillPrice,
      trim_pct: trimPercent,
      quantity: side === 'SELL' ? null : quantity,
      remaining_quantity: side === 'SELL' ? null : remainingQuantity,
      realized_pnl_gbp: Number.isFinite(Number(fillEvent?.realizedPnlGbp)) ? Number(fillEvent.realizedPnlGbp) : null,
      realized_return_pct: Number.isFinite(Number(fillEvent?.realizedReturnPct)) ? Number(fillEvent.realizedReturnPct) : null,
      stop_triggered: fillEvent?.stopTriggered === true,
      filled_at: fillEvent?.filledAt || null,
      created_at: nowIso
    };
    db.tradeGroupAlerts.push(alert);
    alertsCreated += 1;
    logTrading212SellAlertLifecycle(leaderUsername, { ...fillEvent, classification }, 'alert_emitted', {
      groupId: group.id,
      skipped: 'false',
      positionEventType,
      previousQty: Number(fillEvent?.previousQuantity) || null,
      newQty: Number(fillEvent?.remainingQuantity) || null,
      trimPct: trimPercent,
      selectedFillPrice: fillPrice
    });
    if (side === 'SELL') {
      console.info('[TradeGroup][SellAlert]', {
        stage: 'sell_alert_emitted',
        reconciliationPath: 'history_fill',
        leader: leaderUsername,
        groupId: group.id,
        sourceTradeLinked: Boolean(sourceTradeId),
        businessFingerprint: businessFingerprint || null,
        fingerprintInputs: closeFingerprintMeta.components,
        emissionDecision: 'emitted'
      });
    }
    console.info(`[TradeGroup][LeaderSync] alert emitted leader=${leaderUsername} group=${group.id} fillId=${fillId || 'n/a'} eventKey=${brokerEventKey} side=${side} classification=${classification}`);
    const activeMembers = getTradeGroupMembers(db, group.id, { status: 'active' })
      .filter(member => member.user_id !== leaderUsername);
    for (const member of activeMembers) {
      const created = createTradeGroupNotification(db, {
        userId: member.user_id,
        groupId: group.id,
        type: 'trade_group_alert',
        alertId: alert.id,
        dedupeKey: side === 'SELL' && businessFingerprint
          ? `t212-close:${businessFingerprint}:${group.id}`
          : `t212-fill:${brokerEventKey}:${group.id}`
      });
      if (created) {
        notificationsCreated += 1;
        triggerPushForTradeGroupNotification(db, created, { group });
      }
    }
  }
  if (side === 'SELL' && alertsCreated === 0 && duplicates === 0) {
    logTrading212SellAlertLifecycle(leaderUsername, { ...fillEvent, classification }, 'alert_skipped', { eligibleGroups: groups.length, skipped: 'true', skipReason: 'no_eligible_groups' });
    console.info(`[TradeGroup][LeaderSync] sell alert skipped leader=${leaderUsername} reason=no_eligible_groups eventKey=${brokerEventKey}`);
  } else if (side === 'SELL' && alertsCreated === 0 && duplicates > 0) {
    logTrading212SellAlertLifecycle(leaderUsername, { ...fillEvent, classification }, 'alert_skipped', { eligibleGroups: groups.length, skipped: 'true', skipReason: 'all_duplicates' });
  }
  if (side === 'SELL' && sourceTrade && (alertsCreated > 0 || duplicates > 0)) {
    markTradeGroupSellAlertEmittedForTrade(sourceTrade, buildTradeGroupClosureEventKey(sourceTrade, 'history_reconcile'));
  }
  return { alertsCreated, notificationsCreated, duplicates };
}

function createTrading212PendingAlertKey(leaderUsername, groupId, trade) {
  const brokerPositionKey = String(trade?.trading212PositionKey || trade?.trading212Id || trade?.trading212Ticker || trade?.symbol || '').trim();
  const openedAt = String(trade?.createdAt || trade?.created_at || '').trim();
  return `${leaderUsername}|${groupId}|trading212|${brokerPositionKey}|${openedAt}`;
}

function schedulePendingTradeGroupAlertTimer(pendingId, delayMs) {
  if (!pendingId) return;
  const existing = pendingTradeGroupAlertTimers.get(pendingId);
  if (existing) clearTimeout(existing);
  const handle = setTimeout(() => {
    pendingTradeGroupAlertTimers.delete(pendingId);
    const db = loadDB();
    ensureSocialTables(db);
    const changed = processPendingTrading212GroupAlerts(db, { pendingId, now: new Date() });
    if (changed) saveDB(db);
  }, Math.max(0, Number(delayMs) || 0));
  pendingTradeGroupAlertTimers.set(pendingId, handle);
}

function scheduleTrading212TradeGroupAlertsForNewPosition(db, leaderUsername, trade, detectedAt = new Date()) {
  ensureSocialTables(db);
  const groups = getTradeGroupsLedByUser(db, leaderUsername);
  if (!groups.length) return 0;
  const detectedIso = detectedAt.toISOString();
  const scheduledFor = new Date(detectedAt.getTime() + TRADE_GROUP_BROKER_ALERT_DELAY_MS).toISOString();
  let created = 0;
  for (const group of groups) {
    const dedupeKey = createTrading212PendingAlertKey(leaderUsername, group.id, trade);
    const alreadySent = db.tradeGroupPendingAlerts.find(item => item.group_id === group.id && item.dedupe_key === dedupeKey && item.status === 'sent');
    const alreadyPending = db.tradeGroupPendingAlerts.find(item => item.group_id === group.id && item.dedupe_key === dedupeKey && item.status === 'pending');
    if (alreadySent || alreadyPending) {
      console.info(`[TradeGroup][T212] duplicate suppressed leader=${leaderUsername} group=${group.id} key=${dedupeKey}`);
      continue;
    }
    const pending = {
      id: crypto.randomUUID(),
      leader_user_id: leaderUsername,
      group_id: group.id,
      broker_source: 'trading212',
      broker_position_key: String(trade?.trading212PositionKey || trade?.trading212Id || trade?.trading212Ticker || trade?.symbol || '').trim(),
      dedupe_key: dedupeKey,
      first_detected_at: detectedIso,
      scheduled_for: scheduledFor,
      status: 'pending',
      linked_trade_id: trade?.id || null,
      created_at: detectedIso,
      updated_at: detectedIso
    };
    db.tradeGroupPendingAlerts.push(pending);
    schedulePendingTradeGroupAlertTimer(pending.id, Date.parse(scheduledFor) - Date.now());
    created += 1;
    console.info(`[TradeGroup][T212] delayed group alert scheduled leader=${leaderUsername} group=${group.id} pending=${pending.id}`);
  }
  return created;
}

function processPendingTrading212GroupAlerts(db, { now = new Date(), pendingId = null } = {}) {
  ensureSocialTables(db);
  const nowMs = now.getTime();
  let mutated = false;
  for (const pending of db.tradeGroupPendingAlerts) {
    if (pending.status !== 'pending') continue;
    if (pendingId && pending.id !== pendingId) continue;
    const scheduledMs = Date.parse(pending.scheduled_for || '');
    if (!Number.isFinite(scheduledMs) || scheduledMs > nowMs) continue;
    const user = db.users?.[pending.leader_user_id];
    const group = db.tradeGroups.find(item => item.id === pending.group_id && item.is_active !== false);
    const trades = Object.values(ensureTradeJournal(user || {})).flat().filter(Boolean);
    const linkedTrade = trades.find(trade => trade.id === pending.linked_trade_id);
    const isOpen = linkedTrade && linkedTrade.status !== 'closed' && !Number.isFinite(Number(linkedTrade.closePrice));
    if (!group || !user || !isOpen) {
      pending.status = 'cancelled';
      pending.updated_at = new Date(nowMs).toISOString();
      mutated = true;
      console.info(`[TradeGroup][T212] delayed group alert cancelled pending=${pending.id}`);
      continue;
    }
    const duplicate = db.tradeGroupAlerts.find(alert => alert.group_id === group.id && alert.pending_dedupe_key === pending.dedupe_key);
    if (duplicate) {
      pending.status = 'sent';
      pending.alert_id = duplicate.id;
      pending.updated_at = new Date(nowMs).toISOString();
      mutated = true;
      console.info(`[TradeGroup][T212] duplicate suppressed pending=${pending.id}`);
      continue;
    }
    const payload = buildTradeGroupAlertPayload(db, pending.leader_user_id, linkedTrade, { requireStopAndRisk: false });
    if (!payload) {
      pending.status = 'failed';
      pending.updated_at = new Date(nowMs).toISOString();
      mutated = true;
      continue;
    }
    const alert = {
      id: crypto.randomUUID(),
      group_id: group.id,
      leader_user_id: pending.leader_user_id,
      source_trade_id: linkedTrade.id,
      pending_dedupe_key: pending.dedupe_key,
      side: 'BUY',
      alert_classification: 'buy',
      position_event_type: 'POSITION_OPENED',
      normalized_event_type: 'TRADE_OPENED',
      ticker: payload.ticker,
      entry_price: payload.entry_price,
      stop_price: payload.stop_price,
      risk_pct: payload.risk_pct,
      direction: payload.direction,
      risk_amount_gbp: payload.risk_amount_gbp,
      created_at: new Date(nowMs).toISOString()
    };
    db.tradeGroupAlerts.push(alert);
    console.info('[TradeGroup][AlertClassifier]', {
      source: 'pending_t212_new_position',
      leader: pending.leader_user_id,
      groupId: group.id,
      tradeId: linkedTrade?.id || null,
      pendingId: pending.id,
      alertId: alert.id,
      side: alert.side,
      classification: alert.alert_classification,
      positionEventType: alert.position_event_type,
      normalizedEventType: alert.normalized_event_type
    });
    const activeMembers = getTradeGroupMembers(db, group.id, { status: 'active' })
      .filter(member => member.user_id !== pending.leader_user_id);
    for (const member of activeMembers) {
      const created = createTradeGroupNotification(db, {
        userId: member.user_id,
        groupId: group.id,
        type: 'trade_group_alert',
        alertId: alert.id,
        dedupeKey: `alert:${alert.id}`
      });
      if (created) triggerPushForTradeGroupNotification(db, created, { group });
    }
    pending.status = 'sent';
    pending.alert_id = alert.id;
    pending.updated_at = new Date(nowMs).toISOString();
    pending.sent_at = alert.created_at;
    mutated = true;
    console.info(`[TradeGroup][T212] delayed group alert emitted pending=${pending.id} alert=${alert.id}`);
  }
  return mutated;
}

function defaultSocialProfile(username, friendCode) {
  const nowIso = new Date().toISOString();
  return {
    id: crypto.randomUUID(),
    user_id: username,
    friend_code: friendCode,
    display_name_override: null,
    avatar_url: null,
    bio: null,
    social_visibility: 'private',
    created_at: nowIso,
    updated_at: nowIso
  };
}

function defaultSocialSettings(username) {
  const nowIso = new Date().toISOString();
  return {
    id: crypto.randomUUID(),
    user_id: username,
    leaderboard_enabled: false,
    leaderboard_visibility: 'private',
    trade_sharing_enabled: false,
    trade_sharing_scope: 'private',
    share_open_trades: false,
    share_closed_trades: false,
    show_pnl_percent: true,
    show_pnl_currency: false,
    show_position_size: false,
    allow_friend_requests: true,
    verification_status: 'none',
    verification_source: null,
    leaderboard_data_source: 'auto',
    created_at: nowIso,
    updated_at: nowIso
  };
}

function getSocialProfile(db, username) {
  ensureSocialTables(db);
  const user = db.users?.[username];
  if (!user) return null;
  if (!user.friendCode) {
    user.friendCode = generateFriendCode(db, username);
  }
  let profile = db.socialProfiles.find(p => p.user_id === username);
  if (!profile) {
    profile = defaultSocialProfile(username, user.friendCode);
    db.socialProfiles.push(profile);
  }
  if (profile.friend_code !== user.friendCode) {
    profile.friend_code = user.friendCode;
    profile.updated_at = new Date().toISOString();
  }
  if (!SOCIAL_VISIBILITY_VALUES.includes(profile.social_visibility)) {
    profile.social_visibility = 'private';
    profile.updated_at = new Date().toISOString();
  }
  return profile;
}

function getSocialSettings(db, username) {
  ensureSocialTables(db);
  let settings = db.socialSettings.find(s => s.user_id === username);
  if (!settings) {
    settings = defaultSocialSettings(username);
    db.socialSettings.push(settings);
  }
  if (!SOCIAL_VISIBILITY_VALUES.includes(settings.leaderboard_visibility)) settings.leaderboard_visibility = 'private';
  if (!SOCIAL_VISIBILITY_VALUES.includes(settings.trade_sharing_scope)) settings.trade_sharing_scope = 'private';
  if (!VERIFICATION_STATUS_VALUES.includes(settings.verification_status)) settings.verification_status = 'none';
  if (settings.verification_source && !VERIFICATION_SOURCE_VALUES.includes(settings.verification_source)) settings.verification_source = 'manual';
  if (!LEADERBOARD_DATA_SOURCE_VALUES.includes(settings.leaderboard_data_source)) settings.leaderboard_data_source = 'auto';
  return settings;
}

function logSocialEvent(db, { userId, actorUserId = null, eventType, entityType, entityId = null, metadata = {} }) {
  ensureSocialTables(db);
  db.socialEventLog.push({
    id: crypto.randomUUID(),
    user_id: userId,
    actor_user_id: actorUserId,
    event_type: eventType,
    entity_type: entityType,
    entity_id: entityId,
    metadata_json: metadata,
    created_at: new Date().toISOString()
  });
}

function normalizeFriendshipPair(a, b) {
  return [a, b].sort((x, y) => x.localeCompare(y));
}

function areFriends(db, a, b) {
  const [u1, u2] = normalizeFriendshipPair(a, b);
  return db.friendships.some(f => f.user_one_id === u1 && f.user_two_id === u2);
}

function socialIdentityForUser(db, username) {
  const user = db.users?.[username] || null;
  const profile = getSocialProfile(db, username);
  const avatar = socialAvatarForUser(user);
  return {
    nickname: getSocialNickname(user),
    friend_code: profile?.friend_code || '',
    avatar_url: avatar.avatar_url,
    avatar_initials: avatar.avatar_initials
  };
}

function sanitizeFriendRequestForViewer(db, request, viewerUsername) {
  const isIncoming = request.recipient_user_id === viewerUsername;
  const counterpartyUsername = isIncoming ? request.sender_user_id : request.recipient_user_id;
  const identity = socialIdentityForUser(db, counterpartyUsername);
  return {
    id: request.id,
    status: request.status,
    direction: isIncoming ? 'incoming' : 'outgoing',
    counterparty_nickname: identity.nickname || 'Unknown trader',
    counterparty_friend_code: identity.friend_code,
    counterparty_avatar_url: identity.avatar_url,
    counterparty_avatar_initials: identity.avatar_initials,
    created_at: request.created_at,
    updated_at: request.updated_at
  };
}

function ensureTradeShareSettings(db, username, tradeId) {
  ensureSocialTables(db);
  let record = db.tradeShareSettings.find(r => r.user_id === username && r.trade_id === tradeId);
  if (!record) {
    const nowIso = new Date().toISOString();
    record = {
      id: crypto.randomUUID(),
      trade_id: tradeId,
      user_id: username,
      is_shared: false,
      shared_scope: 'private',
      share_after_close_only: true,
      hide_position_size: true,
      hide_cash_pnl: true,
      created_at: nowIso,
      updated_at: nowIso
    };
    db.tradeShareSettings.push(record);
  }
  return record;
}

function isBrokerConnected(user) {
  return !!(user?.trading212?.enabled || user?.ibkr?.enabled);
}

function canBePlatformVerified(user) {
  const trades = Array.isArray(user?.trades) ? user.trades : [];
  let closedWithPnL = 0;
  for (const trade of trades) {
    if (trade?.status === 'closed' && Number.isFinite(Number(trade?.realizedPnlGBP))) {
      closedWithPnL += 1;
    }
  }
  return closedWithPnL >= 5;
}

function computeEligibilityReason(settings, stats, mode = 'trade') {
  if (!settings.leaderboard_enabled) return 'leaderboard_disabled';
  if (settings.verification_status === 'none') return 'unverified';
  if (!Number.isFinite(Number(stats.return_pct))) return 'return_unavailable';
  if (mode === 'trade' && stats.trade_count < 3) return 'insufficient_trades';
  return null;
}

function periodStartDate(period) {
  const now = new Date();
  if (period === 'ALL') return new Date(0);
  if (period === 'YTD') return new Date(now.getFullYear(), 0, 1);
  const days = { '7D': 7, '30D': 30, '90D': 90 }[period] || 30;
  return new Date(now.getTime() - days * 24 * 60 * 60 * 1000);
}

function normalizeTradeSource(trade = {}) {
  const sourceRaw = typeof trade.source === 'string' ? trade.source.trim().toLowerCase() : '';
  return sourceRaw === 'trading212'
    ? 'trading212'
    : sourceRaw === 'ibkr'
      ? 'ibkr'
      : 'manual';
}

function getAvailableLeaderboardSources(trades = []) {
  const available = new Set();
  for (const trade of trades) {
    const source = normalizeTradeSource(trade);
    if (source) available.add(source);
  }
  return Array.from(available);
}

function resolveLeaderboardDataSource(settings, availableSources = []) {
  const preferred = settings?.leaderboard_data_source || 'auto';
  const availableSet = new Set(availableSources);
  if (preferred !== 'auto') {
    return {
      requested: preferred,
      selected: preferred,
      isAuto: false,
      autoReason: null,
      available: availableSources,
      ignored: availableSources.filter(source => source !== preferred)
    };
  }

  const priority = ['trading212', 'ibkr', 'manual'];
  const selected = priority.find(source => availableSet.has(source)) || 'manual';
  const autoReason = availableSet.has(selected)
    ? `auto_priority_${selected}`
    : 'auto_default_manual_no_trade_data';
  return {
    requested: preferred,
    selected,
    isAuto: true,
    autoReason,
    available: availableSources,
    ignored: availableSources.filter(source => source !== selected)
  };
}

function dateKeyFromDate(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (!(date instanceof Date) || Number.isNaN(date.getTime())) return null;
  return date.toISOString().slice(0, 10);
}

function getWeekRangeFromDateKey(dateKey) {
  if (typeof dateKey !== 'string' || !/^\d{4}-\d{2}-\d{2}$/.test(dateKey)) return null;
  const date = new Date(`${dateKey}T00:00:00.000Z`);
  if (Number.isNaN(date.getTime())) return null;
  const day = date.getUTCDay();
  const offsetToMonday = (day + 6) % 7;
  const start = new Date(date);
  start.setUTCDate(date.getUTCDate() - offsetToMonday);
  const end = new Date(start);
  end.setUTCDate(start.getUTCDate() + 6);
  return {
    weekKey: dateKeyFromDate(start),
    weekStart: dateKeyFromDate(start),
    weekEnd: dateKeyFromDate(end)
  };
}

function getLastCompletedWeekRange() {
  const now = new Date();
  const todayUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
  const day = todayUtc.getUTCDay();
  const offsetToMonday = (day + 6) % 7;
  const currentWeekStart = new Date(todayUtc);
  currentWeekStart.setUTCDate(todayUtc.getUTCDate() - offsetToMonday);
  const lastWeekStart = new Date(currentWeekStart);
  lastWeekStart.setUTCDate(currentWeekStart.getUTCDate() - 7);
  const lastWeekEnd = new Date(lastWeekStart);
  lastWeekEnd.setUTCDate(lastWeekStart.getUTCDate() + 6);
  return {
    weekKey: dateKeyFromDate(lastWeekStart),
    weekStart: dateKeyFromDate(lastWeekStart),
    weekEnd: dateKeyFromDate(lastWeekEnd)
  };
}

function formatWeekLabel(weekStart, weekEnd) {
  const start = new Date(`${weekStart}T00:00:00.000Z`);
  const end = new Date(`${weekEnd}T00:00:00.000Z`);
  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return '';
  const monthFmt = new Intl.DateTimeFormat('en-GB', { month: 'short', timeZone: 'UTC' });
  const dayFmt = new Intl.DateTimeFormat('en-GB', { day: '2-digit', timeZone: 'UTC' });
  const yearFmt = new Intl.DateTimeFormat('en-GB', { year: 'numeric', timeZone: 'UTC' });
  return `${monthFmt.format(start)} ${dayFmt.format(start)} – ${monthFmt.format(end)} ${dayFmt.format(end)}, ${yearFmt.format(end)}`;
}

function buildWeeklyInsightLine(metrics) {
  if (!metrics.closedTrades) return 'No closed trades were recorded for this week.';
  if (metrics.weeklyRealisedPnlGBP < 0 && Number(metrics.largestLossShareOfLossesPct) >= 55) {
    return 'One outsized loss accounted for most of the week’s downside.';
  }
  if (metrics.weeklyRealisedPnlGBP > 0 && Number(metrics.averageWinnerGBP) > Math.abs(Number(metrics.averageLoserGBP) || 0)) {
    return 'Profitable week driven by strong average winners.';
  }
  if (metrics.weeklyRealisedPnlGBP < 0 && Number(metrics.winRatePct) >= 40) {
    return 'Losses outweighed gains despite a moderate win rate.';
  }
  if (metrics.weeklyRealisedPnlGBP > 0) return 'Profitable week overall with disciplined execution.';
  if (metrics.weeklyRealisedPnlGBP < 0) return 'Drawdown week; risk control and selectivity matter next week.';
  return 'A relatively flat trading week.';
}

function calculateWeeklyPortfolioReturnDetails(user, weekRange) {
  const history = ensurePortfolioHistory(user);
  const entries = listChronologicalEntries(history);
  if (!entries.length) return { returnPct: null, reason: 'missing_history_entries', details: null };

  const startCandidates = entries.filter(entry => typeof entry?.date === 'string' && entry.date < weekRange.weekStart);
  const endCandidates = entries.filter(entry => typeof entry?.date === 'string' && entry.date <= weekRange.weekEnd);
  if (!startCandidates.length || !endCandidates.length) {
    return { returnPct: null, reason: 'insufficient_history_window', details: null };
  }

  const startEntry = startCandidates[startCandidates.length - 1];
  const endEntry = endCandidates[endCandidates.length - 1];
  const startEquity = Number(startEntry?.end);
  const endEquity = Number(endEntry?.end);
  if (!Number.isFinite(startEquity) || startEquity <= 0 || !Number.isFinite(endEquity)) {
    return { returnPct: null, reason: 'invalid_history_equity', details: null };
  }

  const dayDiff = (laterKey, earlierKey) => {
    const later = new Date(`${laterKey}T00:00:00.000Z`).getTime();
    const earlier = new Date(`${earlierKey}T00:00:00.000Z`).getTime();
    if (!Number.isFinite(later) || !Number.isFinite(earlier)) return null;
    return Math.round((later - earlier) / 86400000);
  };

  const startGapDays = dayDiff(weekRange.weekStart, startEntry.date);
  const endGapDays = dayDiff(weekRange.weekEnd, endEntry.date);
  const isReliableWindow = Number.isFinite(startGapDays) && Number.isFinite(endGapDays) && startGapDays <= 3 && endGapDays <= 1;
  if (!isReliableWindow) {
    return {
      returnPct: null,
      reason: 'stale_history_window',
      details: {
        start_entry_date: startEntry.date || null,
        end_entry_date: endEntry.date || null,
        start_gap_days: startGapDays,
        end_gap_days: endGapDays
      }
    };
  }

  const inWindow = entries.filter(entry => entry.date >= weekRange.weekStart && entry.date <= endEntry.date);
  const deposits = inWindow.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashIn) || 0), 0);
  const withdrawals = inWindow.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashOut) || 0), 0);
  const netFlows = deposits - withdrawals;
  const pnl = endEquity - startEquity - netFlows;

  return {
    returnPct: (pnl / Math.abs(startEquity)) * 100,
    reason: null,
    details: {
      denominator_base: startEquity,
      denominator_label: 'week_start_portfolio_value',
      start_entry_date: startEntry.date,
      end_entry_date: endEntry.date,
      deposits_in_week: deposits,
      withdrawals_in_week: withdrawals,
      net_cash_flow_adjustment: netFlows,
      formula_used: '(week_end_equity - week_start_equity - net_cash_flows) / abs(week_start_equity) * 100'
    }
  };
}

function calculateWeeklyRecap(user, weekRange, rates = { GBP: 1 }) {
  const allTrades = flattenTrades(user, rates);
  const closedTrades = allTrades.filter((trade) => (
    trade?.status === 'closed'
    && Number.isFinite(Number(trade?.realizedPnlGBP))
    && typeof trade?.closeDate === 'string'
    && trade.closeDate >= weekRange.weekStart
    && trade.closeDate <= weekRange.weekEnd
  ));
  const closedCount = closedTrades.length;
  const winners = closedTrades.filter(trade => Number(trade.realizedPnlGBP) > 0);
  const losers = closedTrades.filter(trade => Number(trade.realizedPnlGBP) < 0);
  const netPnlGBP = closedTrades.reduce((sum, trade) => sum + (Number(trade.realizedPnlGBP) || 0), 0);
  const totalGainsGBP = winners.reduce((sum, trade) => sum + (Number(trade.realizedPnlGBP) || 0), 0);
  const totalLossesGBP = losers.reduce((sum, trade) => sum + (Number(trade.realizedPnlGBP) || 0), 0);
  const largestLoserAbs = losers.length ? Math.abs(Math.min(...losers.map(trade => Number(trade.realizedPnlGBP) || 0))) : 0;
  const totalLossAbs = Math.abs(totalLossesGBP);
  const largestLossShareOfLossesPct = totalLossAbs > 0 ? (largestLoserAbs / totalLossAbs) * 100 : null;
  // Closed-trade return % is realized PnL divided by closed-trade capital basis.
  // Denominator = sum of valid trade-level capital basis values (entryValue/positionGBP/entry*size fallbacks).
  const closedTradeReturn = computeTradeDeployedReturnDetails(closedTrades);
  // Portfolio return % is a separate concept:
  // denominator = starting portfolio value immediately before the recap week, cash-flow adjusted.
  const portfolioReturn = calculateWeeklyPortfolioReturnDetails(user, weekRange);
  const findHighlight = (list, mode = 'best') => {
    if (!list.length) return null;
    const sorted = list.slice().sort((a, b) => mode === 'best'
      ? Number(b.realizedPnlGBP) - Number(a.realizedPnlGBP)
      : Number(a.realizedPnlGBP) - Number(b.realizedPnlGBP));
    const trade = sorted[0];
    return {
      tradeId: trade.id || null,
      ticker: trade.displayTicker || trade.displaySymbol || trade.symbol || '—',
      direction: trade.direction === 'short' ? 'SHORT' : 'LONG',
      realizedPnlGBP: Number(trade.realizedPnlGBP) || 0,
      closeDate: trade.closeDate || null
    };
  };
  const metrics = {
    weekKey: weekRange.weekKey,
    weekStart: weekRange.weekStart,
    weekEnd: weekRange.weekEnd,
    weekLabel: formatWeekLabel(weekRange.weekStart, weekRange.weekEnd),
    closedTrades: closedCount,
    winRatePct: closedCount ? (winners.length / closedCount) * 100 : null,
    netPnlGBP,
    weeklyRealisedPnlGBP: netPnlGBP,
    portfolioReturnPct: portfolioReturn.returnPct,
    portfolioReturnDetails: portfolioReturn.details,
    portfolioReturnReason: portfolioReturn.reason,
    closedTradeReturnPct: closedTradeReturn.returnPct,
    closedTradeReturnDetails: closedTradeReturn.details,
    closedTradeReturnReason: closedTradeReturn.reason,
    largestLossShareOfLossesPct,
    averageWinnerGBP: winners.length ? totalGainsGBP / winners.length : null,
    averageLoserGBP: losers.length ? totalLossesGBP / losers.length : null,
    totalRealisedGainsGBP: totalGainsGBP,
    totalRealisedLossesGBP: totalLossesGBP,
    bestTrade: findHighlight(closedTrades, 'best'),
    worstTrade: findHighlight(closedTrades, 'worst')
  };
  return {
    generatedAt: new Date().toISOString(),
    metrics,
    notes: buildWeeklyInsightLine(metrics),
    tradeCountSource: closedTrades.length
  };
}

function getLatestWeeklyRecap(user) {
  const recaps = Array.isArray(user?.weeklyRecaps) ? user.weeklyRecaps : [];
  if (!recaps.length) return null;
  return recaps.slice().sort((a, b) => String(b.weekKey || '').localeCompare(String(a.weekKey || '')))[0] || null;
}

function normalizeWeeklyRecapLifecycleTimestamps(recap = {}) {
  const sanitize = (value) => (typeof value === 'string' && value.trim() ? value : null);
  return {
    readyAt: sanitize(recap.readyAt) || sanitize(recap.generatedAt),
    pushSentAt: sanitize(recap.pushSentAt),
    viewedAt: sanitize(recap.viewedAt),
    dismissedAt: sanitize(recap.dismissedAt)
  };
}

function upsertWeeklyRecap(user, recap) {
  if (!Array.isArray(user.weeklyRecaps)) user.weeklyRecaps = [];
  const index = user.weeklyRecaps.findIndex(item => item && item.weekKey === recap.weekKey);
  if (index >= 0) {
    user.weeklyRecaps[index] = recap;
  } else {
    user.weeklyRecaps.push(recap);
  }
}

function getWeekStartKeyFromDate(date = new Date()) {
  const current = new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()));
  const day = current.getUTCDay();
  const diff = day === 0 ? -6 : 1 - day;
  current.setUTCDate(current.getUTCDate() + diff);
  return current.toISOString().slice(0, 10);
}

function createDefaultReviewPlanning(weekKey = getWeekStartKeyFromDate()) {
  return {
    weekKey,
    gamePlan: {
      weekLabel: formatWeekLabel(weekKey, weekKey),
      weeklyFocus: '',
      primaryTheme: '',
      riskMode: 'Normal',
      mainObjective: ''
    },
    setups: [],
    levels: [],
    risks: []
  };
}

function normalizeReviewPlanning(input = {}, fallbackWeekKey = getWeekStartKeyFromDate()) {
  const weekKeyRaw = typeof input.weekKey === 'string' ? input.weekKey.trim() : '';
  const weekKey = /^\d{4}-\d{2}-\d{2}$/.test(weekKeyRaw) ? weekKeyRaw : fallbackWeekKey;
  const gamePlanRaw = input?.gamePlan && typeof input.gamePlan === 'object' ? input.gamePlan : {};
  const riskModeRaw = typeof gamePlanRaw.riskMode === 'string' ? gamePlanRaw.riskMode.trim() : '';
  const riskMode = ['Conservative', 'Normal', 'Aggressive'].includes(riskModeRaw) ? riskModeRaw : 'Normal';
  const asCleanText = (value, max = 500) => (typeof value === 'string' ? value.trim().slice(0, max) : '');
  const normalizeSetup = (item = {}) => ({
    id: typeof item.id === 'string' && item.id.trim() ? item.id.trim() : crypto.randomUUID(),
    ticker: asCleanText(item.ticker, 24).toUpperCase(),
    direction: item.direction === 'bearish' ? 'bearish' : 'bullish',
    setupType: asCleanText(item.setupType, 120),
    entryIdea: asCleanText(item.entryIdea, 240),
    invalidation: asCleanText(item.invalidation, 160),
    target: asCleanText(item.target, 160),
    notes: asCleanText(item.notes, 1000),
    status: typeof item.status === 'string' && item.status.trim() ? item.status.trim().toLowerCase() : 'active'
  });
  const normalizeLevel = (item = {}) => ({
    id: typeof item.id === 'string' && item.id.trim() ? item.id.trim() : crypto.randomUUID(),
    ticker: asCleanText(item.ticker, 24).toUpperCase(),
    triggerLevel: asCleanText(item.triggerLevel, 80),
    reason: asCleanText(item.reason, 320),
    action: asCleanText(item.action, 320)
  });
  const normalizeRisk = (item = {}) => ({
    id: typeof item.id === 'string' && item.id.trim() ? item.id.trim() : crypto.randomUUID(),
    text: asCleanText(item.text, 320),
    done: item.done === true
  });
  return {
    weekKey,
    gamePlan: {
      weekLabel: asCleanText(gamePlanRaw.weekLabel, 120) || formatWeekLabel(weekKey, weekKey),
      weeklyFocus: asCleanText(gamePlanRaw.weeklyFocus, 320),
      primaryTheme: asCleanText(gamePlanRaw.primaryTheme, 320),
      riskMode,
      mainObjective: asCleanText(gamePlanRaw.mainObjective, 320)
    },
    setups: Array.isArray(input.setups) ? input.setups.map(normalizeSetup) : [],
    levels: Array.isArray(input.levels) ? input.levels.map(normalizeLevel) : [],
    risks: Array.isArray(input.risks) ? input.risks.map(normalizeRisk) : []
  };
}

function upsertReviewPlanning(user, planning) {
  if (!user.reviewPlanning || typeof user.reviewPlanning !== 'object') {
    user.reviewPlanning = { currentWeekKey: planning.weekKey, plans: [planning] };
    return;
  }
  if (!Array.isArray(user.reviewPlanning.plans)) user.reviewPlanning.plans = [];
  const index = user.reviewPlanning.plans.findIndex(item => item && item.weekKey === planning.weekKey);
  if (index >= 0) {
    user.reviewPlanning.plans[index] = planning;
  } else {
    user.reviewPlanning.plans.push(planning);
  }
  user.reviewPlanning.currentWeekKey = planning.weekKey;
}


function computeHistoryPeriodReturnDetails(user, periodKey) {
  const history = ensurePortfolioHistory(user);
  const entries = listChronologicalEntries(history);
  if (!entries.length) {
    return { returnPct: null, reason: 'missing_history_entries', details: null };
  }

  if (periodKey === 'ALL') {
    if (entries.length < 2) {
      return { returnPct: null, reason: 'insufficient_history_points', details: null };
    }
    const startEquity = Number(entries[0].end);
    const endEquity = Number(entries[entries.length - 1].end);
    if (!Number.isFinite(startEquity) || startEquity <= 0 || !Number.isFinite(endEquity)) {
      return { returnPct: null, reason: 'invalid_history_equity', details: null };
    }
    const inPeriod = entries.slice(1);
    const deposits = inPeriod.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashIn) || 0), 0);
    const withdrawals = inPeriod.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashOut) || 0), 0);
    const netFlows = deposits - withdrawals;
    const pnl = endEquity - startEquity - netFlows;
    return {
      returnPct: (pnl / Math.abs(startEquity)) * 100,
      reason: null,
      details: {
        start_equity: startEquity,
        end_equity: endEquity,
        deposits_in_period: deposits,
        withdrawals_in_period: withdrawals,
        net_cash_flow_adjustment: netFlows,
        formula_used: '(end_equity - start_equity - net_cash_flows) / abs(start_equity) * 100'
      }
    };
  }

  const startKey = dateKeyFromDate(periodStartDate(periodKey));
  if (!startKey) return { returnPct: null, reason: 'invalid_period_start', details: null };
  const priorEntries = entries.filter(entry => entry.date < startKey);
  const periodEntries = entries.filter(entry => entry.date >= startKey);
  if (!priorEntries.length || !periodEntries.length) {
    return { returnPct: null, reason: 'insufficient_history_window', details: null };
  }

  const startEquity = Number(priorEntries[priorEntries.length - 1].end);
  const endEquity = Number(periodEntries[periodEntries.length - 1].end);
  if (!Number.isFinite(startEquity) || startEquity <= 0 || !Number.isFinite(endEquity)) {
    return { returnPct: null, reason: 'invalid_history_equity', details: null };
  }
  const deposits = periodEntries.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashIn) || 0), 0);
  const withdrawals = periodEntries.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashOut) || 0), 0);
  const netFlows = deposits - withdrawals;
  const pnl = endEquity - startEquity - netFlows;
  return {
    returnPct: (pnl / Math.abs(startEquity)) * 100,
    reason: null,
    details: {
      start_equity: startEquity,
      end_equity: endEquity,
      deposits_in_period: deposits,
      withdrawals_in_period: withdrawals,
      net_cash_flow_adjustment: netFlows,
      formula_used: '(end_equity - start_equity - net_cash_flows) / abs(start_equity) * 100'
    }
  };
}

function getTradeCapitalBasis(trade) {
  const candidates = [
    { method: 'entry_value_field', value: Number(trade.entryValue) },
    { method: 'position_gbp', value: Number(trade.positionGBP) },
    {
      method: 'entry_x_total_entered_qty',
      value: Number(trade.entry) * Number(trade.totalEnteredQuantity ?? trade.enteredUnits ?? trade.initialSizeUnits)
    },
    {
      method: 'avg_entry_x_total_entered_qty',
      value: Number(trade.avgEntryPrice) * Number(trade.totalEnteredQuantity ?? trade.enteredUnits ?? trade.initialSizeUnits)
    },
    {
      method: 'entry_x_position_size',
      value: Number(trade.entry) * Number(trade.sizeUnits ?? trade.quantity ?? trade.units ?? trade.shares)
    }
  ];

  for (const candidate of candidates) {
    const value = Math.abs(Number(candidate.value));
    if (Number.isFinite(value) && value > 0) {
      return { value, method: candidate.method };
    }
  }
  return { value: null, method: null };
}

function computeTradeDeployedReturnDetails(trades = []) {
  const realizedPnl = trades.reduce((acc, trade) => acc + (Number(trade.realizedPnlGBP) || 0), 0);
  const capitalBreakdown = [];
  let denominator = 0;
  let validCapitalTradeCount = 0;
  for (const trade of trades) {
    const basis = getTradeCapitalBasis(trade);
    if (Number.isFinite(basis.value) && basis.value > 0) {
      denominator += basis.value;
      validCapitalTradeCount += 1;
    }
    capitalBreakdown.push({
      trade_id: trade.id || null,
      capital_basis: Number.isFinite(basis.value) ? basis.value : null,
      capital_basis_method: basis.method,
      has_capital_basis: Number.isFinite(basis.value) && basis.value > 0
    });
  }

  if (!trades.length) {
    return {
      returnPct: null,
      reason: 'no_closed_trades_in_period',
      details: {
        denominator_base: null,
        base_capital_method: 'sum(trade_capital_basis)',
        realized_pnl_in_period: realizedPnl,
        valid_capital_trade_count: 0,
        capital_basis_breakdown: capitalBreakdown,
        formula_used: '(realized_pnl_in_period / denominator_base) * 100'
      }
    };
  }

  if (!Number.isFinite(denominator) || denominator < 1) {
    return {
      returnPct: null,
      reason: 'invalid_or_near_zero_denominator',
      details: {
        denominator_base: Number.isFinite(denominator) ? denominator : null,
        base_capital_method: 'sum(trade_capital_basis)',
        realized_pnl_in_period: realizedPnl,
        valid_capital_trade_count: validCapitalTradeCount,
        capital_basis_breakdown: capitalBreakdown,
        formula_used: '(realized_pnl_in_period / denominator_base) * 100'
      }
    };
  }

  const returnPct = (realizedPnl / denominator) * 100;
  if (!Number.isFinite(returnPct) || Math.abs(returnPct) > 10000) {
    return {
      returnPct: null,
      reason: 'absurd_return_guard_triggered',
      details: {
        denominator_base: denominator,
        base_capital_method: 'sum(trade_capital_basis)',
        realized_pnl_in_period: realizedPnl,
        valid_capital_trade_count: validCapitalTradeCount,
        capital_basis_breakdown: capitalBreakdown,
        formula_used: '(realized_pnl_in_period / denominator_base) * 100'
      }
    };
  }

  return {
    returnPct,
    reason: null,
    details: {
      denominator_base: denominator,
      base_capital_method: 'sum(trade_capital_basis)',
      realized_pnl_in_period: realizedPnl,
      valid_capital_trade_count: validCapitalTradeCount,
      capital_basis_breakdown: capitalBreakdown,
      formula_used: '(realized_pnl_in_period / denominator_base) * 100'
    }
  };
}

function explainFormula(periodKey, path, diagnostics = {}) {
  if (path === 'history_based') {
    const start = diagnostics?.period_start || 'unknown';
    const end = diagnostics?.period_end || currentDateKey();
    return `Using portfolio history from ${start} to ${end}, adjusted for net deposits and withdrawals.`;
  }
  if (path === 'account_source_equity_history') {
    return 'Using source-specific account equity history adjusted for net cash flows.';
  }
  if (path === 'trade_deployed_capital') {
    return 'Using closed trades in the selected window with realized PnL divided by deployed trade capital.';
  }
  if (path === 'return_unavailable') {
    return 'No trustworthy denominator was available for this period, so return was withheld.';
  }
  return `Using ${path} leaderboard methodology.`;
}

function buildAccountModeReturnFromEntries(entries, periodKey) {
  if (!Array.isArray(entries) || !entries.length) {
    return { returnPct: null, reason: 'missing_source_history_entries', details: null };
  }

  if (periodKey === 'ALL') {
    if (entries.length < 2) {
      return { returnPct: null, reason: 'insufficient_source_history_points', details: null };
    }
    const startEquity = Number(entries[0].end);
    const endEquity = Number(entries[entries.length - 1].end);
    if (!Number.isFinite(startEquity) || startEquity === 0 || !Number.isFinite(endEquity)) {
      return { returnPct: null, reason: 'invalid_source_history_equity', details: null };
    }
    const inPeriod = entries.slice(1);
    const deposits = inPeriod.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashIn) || 0), 0);
    const withdrawals = inPeriod.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashOut) || 0), 0);
    const netFlows = deposits - withdrawals;
    const pnl = endEquity - startEquity - netFlows;
    return {
      returnPct: (pnl / Math.abs(startEquity)) * 100,
      reason: null,
      details: {
        start_equity: startEquity,
        end_equity: endEquity,
        deposits_in_period: deposits,
        withdrawals_in_period: withdrawals,
        net_cash_flow_adjustment: netFlows,
        formula_used: '(end_equity - start_equity - net_cash_flows) / abs(start_equity) * 100'
      }
    };
  }

  const startKey = dateKeyFromDate(periodStartDate(periodKey));
  if (!startKey) return { returnPct: null, reason: 'invalid_period_start', details: null };
  const priorEntries = entries.filter(entry => entry.date < startKey);
  const periodEntries = entries.filter(entry => entry.date >= startKey);
  if (!priorEntries.length || !periodEntries.length) {
    return { returnPct: null, reason: 'insufficient_source_history_window', details: null };
  }
  const startEquity = Number(priorEntries[priorEntries.length - 1].end);
  const endEquity = Number(periodEntries[periodEntries.length - 1].end);
  if (!Number.isFinite(startEquity) || startEquity === 0 || !Number.isFinite(endEquity)) {
    return { returnPct: null, reason: 'invalid_source_history_equity', details: null };
  }
  const deposits = periodEntries.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashIn) || 0), 0);
  const withdrawals = periodEntries.reduce((sum, entry) => sum + Math.max(0, Number(entry.cashOut) || 0), 0);
  const netFlows = deposits - withdrawals;
  const pnl = endEquity - startEquity - netFlows;
  return {
    returnPct: (pnl / Math.abs(startEquity)) * 100,
    reason: null,
    details: {
      start_equity: startEquity,
      end_equity: endEquity,
      deposits_in_period: deposits,
      withdrawals_in_period: withdrawals,
      net_cash_flow_adjustment: netFlows,
      formula_used: '(end_equity - start_equity - net_cash_flows) / abs(start_equity) * 100'
    }
  };
}

function buildLeaderboardStatDiagnostics(db, username, periodKey, mode = 'trade', options = {}) {
  const user = db.users?.[username];
  if (!user) return null;
  const includeTrades = options.includeTrades === true;
  const selectedMode = LEADERBOARD_MODE_VALUES.includes(mode) ? mode : 'trade';
  const settings = getSocialSettings(db, username);
  const rates = { GBP: 1 };
  const allTrades = flattenTrades(user, rates);
  const availableSources = getAvailableLeaderboardSources(allTrades);
  const sourceResolution = resolveLeaderboardDataSource(settings, availableSources);
  const selectedSource = sourceResolution.selected;

  const startKey = dateKeyFromDate(periodStartDate(periodKey));
  const endKey = currentDateKey();
  const includedTrades = [];
  const excludedTrades = [];
  const closedForPeriod = [];
  const pushTradeView = (trade, reason, included) => {
    const realized = Number(trade.realizedPnlGBP);
    const pct = Number(trade.pnlPct ?? trade.returnPct);
    const capitalBasis = getTradeCapitalBasis(trade);
    const row = {
      trade_id: trade.id || null,
      ticker: trade.displayTicker || trade.displaySymbol || trade.symbol || null,
      source: normalizeTradeSource(trade),
      open_date: trade.openDate || trade.date || null,
      close_date: trade.closeDate || null,
      status: trade.status || null,
      entry_value: Number.isFinite(Number(trade.entry)) && Number.isFinite(Number(trade.sizeUnits))
        ? Number(trade.entry) * Number(trade.sizeUnits)
        : (Number.isFinite(Number(trade.entryValue)) ? Number(trade.entryValue) : null),
      capital_basis: Number.isFinite(capitalBasis.value) ? capitalBasis.value : null,
      capital_basis_method: capitalBasis.method,
      realized_pnl: Number.isFinite(realized) ? realized : null,
      pnl_pct: Number.isFinite(pct) ? pct : null,
      counted_toward_trade_count: included,
      counted_toward_win_rate: included,
      reason
    };
    (included ? includedTrades : excludedTrades).push(row);
  };

  for (const trade of allTrades) {
    const source = normalizeTradeSource(trade);
    if (source !== selectedSource) {
      pushTradeView(trade, 'wrong_data_source', false);
      continue;
    }
    if (trade.status !== 'closed') {
      pushTradeView(trade, 'trade_still_open', false);
      continue;
    }
    if (!Number.isFinite(Number(trade.realizedPnlGBP))) {
      pushTradeView(trade, 'missing_required_fields', false);
      continue;
    }
    const closeDate = typeof trade.closeDate === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(trade.closeDate)
      ? trade.closeDate
      : null;
    if (!closeDate) {
      pushTradeView(trade, 'missing_required_fields', false);
      continue;
    }
    if (periodKey !== 'ALL' && closeDate < startKey) {
      pushTradeView(trade, 'outside_selected_period', false);
      continue;
    }
    closedForPeriod.push(trade);
    pushTradeView(trade, 'included', true);
  }

  const winners = closedForPeriod.filter(t => Number(t.realizedPnlGBP) > 0).length;
  const winRate = closedForPeriod.length ? (winners / closedForPeriod.length) * 100 : null;

  const historyResult = computeHistoryPeriodReturnDetails(user, periodKey);
  const tradeResult = computeTradeDeployedReturnDetails(closedForPeriod);
  const sourceHistory = listChronologicalEntriesForSource(user, selectedSource);
  const accountResult = buildAccountModeReturnFromEntries(sourceHistory.entries, periodKey);

  let resolvedReturnPct = null;
  let calculationPath = 'return_unavailable';
  if (selectedMode === 'account') {
    resolvedReturnPct = Number.isFinite(accountResult.returnPct) ? accountResult.returnPct : null;
    calculationPath = Number.isFinite(accountResult.returnPct)
      ? 'account_source_equity_history'
      : 'return_unavailable';
  } else {
    const usingHistory = Number.isFinite(historyResult.returnPct);
    const usingTradeDeployed = !usingHistory && Number.isFinite(tradeResult.returnPct);
    resolvedReturnPct = usingHistory
      ? historyResult.returnPct
      : (usingTradeDeployed ? tradeResult.returnPct : null);
    calculationPath = usingHistory
      ? 'history_based'
      : (usingTradeDeployed ? 'trade_deployed_capital' : 'return_unavailable');
  }

  const nowIso = new Date().toISOString();
  const stat = {
    user_id: username,
    period_key: periodKey,
    leaderboard_mode: selectedMode,
    leaderboard_source: selectedSource,
    verification_status: settings.verification_status,
    return_pct: Number.isFinite(resolvedReturnPct) ? resolvedReturnPct : null,
    realized_return_pct: Number.isFinite(tradeResult.returnPct) ? tradeResult.returnPct : null,
    trade_count: closedForPeriod.length,
    win_rate: Number.isFinite(winRate) ? winRate : null,
    computed_at: nowIso,
    updated_at: nowIso,
    eligible: false,
    ineligibility_reason: 'unknown'
  };
  const reason = computeEligibilityReason(settings, stat, selectedMode);
  stat.eligible = reason === null;
  stat.ineligibility_reason = reason;

  const diagnostics = {
    period_key: periodKey,
    leaderboard_mode: selectedMode,
    period_start: startKey,
    period_end: endKey,
    selected_leaderboard_source: selectedSource,
    requested_leaderboard_source: sourceResolution.requested,
    auto_selected: sourceResolution.isAuto,
    auto_selection_reason: sourceResolution.autoReason,
    available_sources: sourceResolution.available,
    ignored_sources: sourceResolution.ignored,
    verification_status: settings.verification_status,
    verification_source: settings.verification_source || null,
    eligible: stat.eligible,
    ineligibility_reason: stat.ineligibility_reason,
    calculation_path: calculationPath,
    return_pct: stat.return_pct,
    realized_return_pct: stat.realized_return_pct,
    trade_count: stat.trade_count,
    win_rate: stat.win_rate,
    formula: {
      method: calculationPath,
      explanation: ''
    },
    unavailable_reason: null,
    history_details: null,
    account_history_details: null,
    account_history_account_id: sourceHistory.accountId,
    account_history_account_ids: Array.isArray(sourceHistory.accountIds) ? sourceHistory.accountIds : [],
    account_history_reason: sourceHistory.reason,
    trade_fallback_details: null,
    trade_return_details: null,
    included_trades: includeTrades ? includedTrades : undefined,
    excluded_trades: includeTrades ? excludedTrades : undefined
  };

  if (selectedMode === 'account') {
    diagnostics.account_history_details = accountResult.details;
    diagnostics.unavailable_reason = accountResult.reason || sourceHistory.reason || null;
  } else if (calculationPath === 'history_based') {
    diagnostics.history_details = historyResult.details;
    diagnostics.trade_return_details = tradeResult.details;
    diagnostics.trade_fallback_details = tradeResult.details;
  } else if (calculationPath === 'trade_deployed_capital') {
    diagnostics.history_details = historyResult.details;
    diagnostics.trade_return_details = tradeResult.details;
    diagnostics.trade_fallback_details = tradeResult.details;
  } else {
    diagnostics.unavailable_reason = historyResult.reason || tradeResult.reason || 'no_trustworthy_method';
    diagnostics.history_details = historyResult.details;
    diagnostics.trade_return_details = tradeResult.details;
    diagnostics.trade_fallback_details = tradeResult.details;
  }

  diagnostics.formula.explanation = explainFormula(periodKey, calculationPath, diagnostics);
  return { stat, diagnostics };
}

function computeLeaderboardStatForUser(db, username, periodKey, mode = 'trade') {
  const built = buildLeaderboardStatDiagnostics(db, username, periodKey, mode);
  return built?.stat || null;
}

function upsertLeaderboardStat(db, stat) {
  ensureSocialTables(db);
  const index = db.leaderboardStats.findIndex(s => (
    s.user_id === stat.user_id
    && s.period_key === stat.period_key
    && (s.leaderboard_mode || 'trade') === (stat.leaderboard_mode || 'trade')
  ));
  if (index >= 0) db.leaderboardStats[index] = { ...db.leaderboardStats[index], ...stat };
  else db.leaderboardStats.push({ id: crypto.randomUUID(), ...stat });
}

function recomputeLeaderboardStatsForUser(db, username) {
  let changed = false;
  const settings = getSocialSettings(db, username);
  const user = db.users?.[username];
  if (user) {
    let nextStatus = 'none';
    let nextSource = settings.verification_source;
    if (isBrokerConnected(user)) {
      nextStatus = 'broker_verified';
      nextSource = user?.ibkr?.enabled ? 'ibkr' : 'trading212';
    } else if (canBePlatformVerified(user)) {
      nextStatus = 'platform_verified';
      nextSource = 'platform_locked';
    } else {
      nextSource = settings.verification_source || 'manual';
    }
    if (settings.verification_status !== nextStatus || settings.verification_source !== nextSource) {
      settings.verification_status = nextStatus;
      settings.verification_source = nextSource;
      settings.updated_at = new Date().toISOString();
      changed = true;
      logSocialEvent(db, {
        userId: username,
        actorUserId: null,
        eventType: 'verification.status_changed',
        entityType: 'social_settings',
        entityId: settings.id,
        metadata: { verification_status: nextStatus, verification_source: nextSource }
      });
    }
  }
  for (const mode of LEADERBOARD_MODE_VALUES) {
    for (const period of LEADERBOARD_PERIOD_KEYS) {
      const stat = computeLeaderboardStatForUser(db, username, period, mode);
      if (stat) {
        upsertLeaderboardStat(db, stat);
        changed = true;
      }
    }
  }
  return changed;
}

function sanitizeSocialTradePayload(owner, trade, settings, tradeShare) {
  const isOpen = trade.status !== 'closed';
  const pnlPct = Number(trade.pnlPct ?? trade.returnPct);
  const payload = {
    id: trade.id,
    ownerNickname: getSocialNickname(owner) || 'Unknown trader',
    symbol: trade.displaySymbol || trade.symbol || null,
    direction: trade.direction || null,
    status: trade.status,
    openDate: trade.openDate || trade.date || null,
    closeDate: trade.closeDate || null,
    entry: Number.isFinite(Number(trade.entry)) ? Number(trade.entry) : null,
    closePrice: Number.isFinite(Number(trade.closePrice)) ? Number(trade.closePrice) : null,
    pnlPercent: settings.show_pnl_percent && Number.isFinite(pnlPct) ? pnlPct : null,
    pnlCurrency: null,
    positionSize: null,
    sharedScope: tradeShare.shared_scope,
    isOpen,
    verificationStatus: settings.verification_status,
    verificationSource: settings.verification_source || null
  };
  if (!tradeShare.hide_cash_pnl && settings.show_pnl_currency) {
    payload.pnlCurrency = Number.isFinite(Number(trade.realizedPnlGBP)) ? Number(trade.realizedPnlGBP) : null;
  }
  if (!tradeShare.hide_position_size && settings.show_position_size) {
    payload.positionSize = Number.isFinite(Number(trade.sizeUnits)) ? Number(trade.sizeUnits) : null;
  }
  return payload;
}

function checkIbkrRateLimit(key, res) {
  const now = Date.now();
  const entry = ibkrRateLimit.get(key) || { count: 0, resetAt: now + IBKR_RATE_LIMIT_WINDOW_MS };
  if (now > entry.resetAt) {
    entry.count = 0;
    entry.resetAt = now + IBKR_RATE_LIMIT_WINDOW_MS;
  }
  entry.count += 1;
  ibkrRateLimit.set(key, entry);
  if (entry.count > IBKR_RATE_LIMIT_MAX) {
    const retryAfter = Math.ceil((entry.resetAt - now) / 1000);
    res.set('Retry-After', String(retryAfter));
    res.status(429).json({ error: 'Too many IBKR requests. Please retry shortly.' });
    return false;
  }
  return true;
}

const NOTIFICATION_CATEGORIES = Object.freeze([
  'criticalRiskAlerts',
  'tradeAlerts',
  'tradeGroupAlerts',
  'socialInvestorNotifications',
  'brokerSyncFailures',
  'dailyRecap',
  'soundEnabled'
]);

const NOTIFICATION_DELIVERY_METHODS = Object.freeze(['push', 'email', 'both', 'disabled']);

function defaultNotificationCategories() {
  return {
    criticalRiskAlerts: true,
    tradeAlerts: true,
    tradeGroupAlerts: true,
    socialInvestorNotifications: true,
    brokerSyncFailures: true,
    dailyRecap: false,
    soundEnabled: true
  };
}

function normalizeNotificationCategories(raw) {
  const defaults = defaultNotificationCategories();
  if (!raw || typeof raw !== 'object') return defaults;
  const normalized = { ...defaults };
  for (const key of NOTIFICATION_CATEGORIES) {
    if (typeof raw[key] === 'boolean') normalized[key] = raw[key];
  }
  return normalized;
}

function defaultNotificationDelivery() {
  return {
    criticalRiskAlerts: 'push',
    tradeAlerts: 'push',
    tradeGroupAlerts: 'push',
    socialInvestorNotifications: 'push',
    brokerSyncFailures: 'push',
    dailyRecap: 'push',
    soundEnabled: 'push'
  };
}

function normalizeNotificationDelivery(raw) {
  const defaults = defaultNotificationDelivery();
  if (!raw || typeof raw !== 'object') return defaults;
  const normalized = { ...defaults };
  for (const key of NOTIFICATION_CATEGORIES) {
    const candidate = String(raw[key] || '').trim().toLowerCase();
    if (NOTIFICATION_DELIVERY_METHODS.includes(candidate)) {
      normalized[key] = candidate;
    }
  }
  return normalized;
}

function buildNotificationPreferencesRecord(userId, existing = null) {
  const nowIso = new Date().toISOString();
  const categories = normalizeNotificationCategories(existing?.categories);
  const delivery = normalizeNotificationDelivery(existing?.delivery);
  return {
    id: existing?.id || crypto.randomUUID(),
    userId,
    categories,
    delivery,
    createdAt: existing?.createdAt || nowIso,
    updatedAt: nowIso
  };
}

function getNotificationPreferences(db, userId) {
  ensureNotificationTables(db);
  let existing = db.notificationPreferences.find((item) => item.userId === userId);
  if (!existing) {
    existing = buildNotificationPreferencesRecord(userId);
    db.notificationPreferences.push(existing);
  } else {
    const next = buildNotificationPreferencesRecord(userId, existing);
    Object.assign(existing, next);
  }
  return existing;
}


function ensureNewsEventTables(db) {
  if (!Array.isArray(db.newsEvents)) db.newsEvents = [];
  if (!Array.isArray(db.newsSourceRegistry)) db.newsSourceRegistry = [];
  if (!Array.isArray(db.userNewsPreferences)) db.userNewsPreferences = [];
  if (!Array.isArray(db.userEventDeliveryLog)) db.userEventDeliveryLog = [];
  if (!Array.isArray(db.newsNotificationOutbox)) db.newsNotificationOutbox = [];
  if (!Array.isArray(db.newsInAppNotifications)) db.newsInAppNotifications = [];
  const nowIso = new Date().toISOString();
  db.newsNotificationOutbox = db.newsNotificationOutbox.map((row) => {
    const statusCandidate = String(row?.status || '').trim();
    const status = ['pending', 'processing', 'sent', 'failed', 'dead_letter'].includes(statusCandidate)
      ? statusCandidate
      : (statusCandidate === 'ready' ? 'pending' : 'pending');
    const attemptCount = Number.isFinite(Number(row?.attemptCount)) ? Math.max(0, Math.floor(Number(row.attemptCount))) : 0;
    const maxAttempts = Number.isFinite(Number(row?.maxAttempts)) && Number(row.maxAttempts) > 0
      ? Math.floor(Number(row.maxAttempts))
      : 5;
    return {
      id: row?.id || crypto.randomUUID(),
      userId: String(row?.userId || row?.payload?.userId || ''),
      newsEventId: String(row?.newsEventId || row?.payload?.eventId || ''),
      channel: String(row?.channel || row?.payload?.channel || ''),
      payload: row?.payload && typeof row.payload === 'object' ? row.payload : {},
      status,
      attemptCount,
      maxAttempts,
      nextAttemptAt: row?.nextAttemptAt || row?.createdAt || nowIso,
      claimedAt: row?.claimedAt || null,
      claimedBy: row?.claimedBy || null,
      lastAttemptAt: row?.lastAttemptAt || null,
      sentAt: row?.sentAt || null,
      lastErrorCode: row?.lastErrorCode || null,
      lastErrorMessage: row?.lastErrorMessage || null,
      createdAt: row?.createdAt || nowIso,
      updatedAt: row?.updatedAt || row?.createdAt || nowIso
    };
  });
  if (!db.newsNotificationStatus || typeof db.newsNotificationStatus !== 'object') {
    db.newsNotificationStatus = {
      lastAttemptedRunAt: null,
      lastSuccessfulRunAt: null,
      outboxLastAttemptedRunAt: null,
      outboxLastSuccessfulRunAt: null,
      lastDiagnostics: null,
      lastOutboxDiagnostics: null,
      recentErrorSummaries: []
    };
  }
  db.newsNotificationStatus.outboxLastAttemptedRunAt ||= null;
  db.newsNotificationStatus.outboxLastSuccessfulRunAt ||= null;
  db.newsNotificationStatus.lastOutboxDiagnostics ||= null;
  if (!db.newsDiagnosticsSnapshots || typeof db.newsDiagnosticsSnapshots !== 'object') {
    db.newsDiagnosticsSnapshots = {
      ranking: [],
      thresholds: [],
      notifications: []
    };
  }
  db.newsDiagnosticsSnapshots.ranking = Array.isArray(db.newsDiagnosticsSnapshots.ranking) ? db.newsDiagnosticsSnapshots.ranking : [];
  db.newsDiagnosticsSnapshots.thresholds = Array.isArray(db.newsDiagnosticsSnapshots.thresholds) ? db.newsDiagnosticsSnapshots.thresholds : [];
  db.newsDiagnosticsSnapshots.notifications = Array.isArray(db.newsDiagnosticsSnapshots.notifications) ? db.newsDiagnosticsSnapshots.notifications : [];
  if (!db.newsEventIndexCatalog || typeof db.newsEventIndexCatalog !== 'object') {
    db.newsEventIndexCatalog = {
      sourceType: true,
      eventType: true,
      scheduledAt: true,
      publishedAt: true,
      canonicalTicker: true,
      dedupeKey: true
    };
  }
  if (!db.newsIngestionStatus || typeof db.newsIngestionStatus !== 'object') {
    db.newsIngestionStatus = {
      macro: {
        lastAttemptedRunAt: null,
        lastSuccessfulRunAt: null,
        lastDiagnostics: null,
        lastProviderStatuses: []
      },
      earnings: {
        lastAttemptedRunAt: null,
        lastSuccessfulRunAt: null,
        lastDiagnostics: null,
        lastProviderStatuses: []
      },
      headlines: {
        lastAttemptedRunAt: null,
        lastSuccessfulRunAt: null,
        lastDiagnostics: null,
        lastProviderStatuses: [],
        providerStates: {}
      }
    };
  } else if (!db.newsIngestionStatus.macro || typeof db.newsIngestionStatus.macro !== 'object') {
    db.newsIngestionStatus.macro = {
      lastAttemptedRunAt: null,
      lastSuccessfulRunAt: null,
      lastDiagnostics: null,
      lastProviderStatuses: []
    };
  }
  if (!db.newsIngestionStatus.earnings || typeof db.newsIngestionStatus.earnings !== 'object') {
    db.newsIngestionStatus.earnings = {
      lastAttemptedRunAt: null,
      lastSuccessfulRunAt: null,
      lastDiagnostics: null,
      lastProviderStatuses: []
    };
  }
  if (!db.newsIngestionStatus.headlines || typeof db.newsIngestionStatus.headlines !== 'object') {
    db.newsIngestionStatus.headlines = {
      lastAttemptedRunAt: null,
      lastSuccessfulRunAt: null,
      lastDiagnostics: null,
      lastProviderStatuses: [],
      providerStates: {}
    };
  } else {
    db.newsIngestionStatus.headlines.providerStates ||= {};
    db.newsIngestionStatus.headlines.lastProviderStatuses ||= [];
  }
}

function resolveDiagnosticsTimeRange(rawValue) {
  const value = String(rawValue || '').trim().toLowerCase();
  return ['1h', '24h', '7d', '30d'].includes(value) ? value : '24h';
}

function appendBoundedSnapshot(list, snapshot, max = 336) {
  const next = Array.isArray(list) ? list : [];
  next.push(snapshot);
  if (next.length > max) {
    next.splice(0, next.length - max);
  }
  return next;
}

function buildNewsDiagnosticsServiceOptions(now, db) {
  return {
    now: now || new Date().toISOString(),
    loadDB: () => db,
    listNewsSourceProfiles: () => newsSourceRegistryService.listSources(),
    resolveUserTickerUniverse: (userId) => resolveUserTickerUniverse(db, userId),
    resolveUserWatchlistTickerUniverse: (userId) => resolveUserWatchlistTickerUniverse(db, userId)
  };
}

function appendUserEventDeliveryLog(db, payload = {}) {
  ensureNewsEventTables(db);
  const userId = typeof payload.userId === 'string' ? payload.userId.trim() : '';
  const newsEventId = typeof payload.newsEventId === 'string' ? payload.newsEventId.trim() : '';
  const deliveryChannel = typeof payload.deliveryChannel === 'string' ? payload.deliveryChannel.trim() : '';
  const deliveryWindowKey = typeof payload.deliveryWindowKey === 'string' ? payload.deliveryWindowKey.trim() : '';
  if (!userId || !newsEventId || !deliveryChannel || !deliveryWindowKey) {
    return { inserted: false, reason: 'invalid_payload', row: null };
  }
  const existing = db.userEventDeliveryLog.find((item) => item.userId === userId
    && item.newsEventId === newsEventId
    && item.deliveryChannel === deliveryChannel
    && item.deliveryWindowKey === deliveryWindowKey);
  if (existing) {
    console.info('[NewsEvents][DeliveryLog] duplicate prevented.', {
      userId,
      newsEventId,
      deliveryChannel,
      deliveryWindowKey
    });
    return { inserted: false, reason: 'duplicate', row: existing };
  }
  const nowIso = new Date().toISOString();
  const row = {
    id: payload.id || crypto.randomUUID(),
    userId,
    newsEventId,
    deliveryChannel,
    deliveryReason: typeof payload.deliveryReason === 'string' ? payload.deliveryReason : null,
    deliveryWindowKey,
    deliveredAt: payload.deliveredAt || nowIso,
    createdAt: nowIso
  };
  db.userEventDeliveryLog.push(row);
  return { inserted: true, reason: 'inserted', row };
}

function ensureNotificationTables(db) {
  if (!Array.isArray(db.notificationDevices)) db.notificationDevices = [];
  if (!Array.isArray(db.notificationEvents)) db.notificationEvents = [];
  if (!Array.isArray(db.notificationPushDedupe)) db.notificationPushDedupe = [];
  if (!Array.isArray(db.notificationPreferences)) db.notificationPreferences = [];
  backfillNotificationDeviceCompatibility(db);
}

function getEffectiveNotificationPermissionState(device) {
  const permission = String(device?.permissionState || '').trim().toLowerCase();
  if (permission === 'granted' || permission === 'denied' || permission === 'default') return permission;
  if (device?.isActive !== false && String(device?.token || '').trim()) return 'granted';
  return 'default';
}

function backfillNotificationDeviceCompatibility(db) {
  if (!Array.isArray(db?.notificationDevices)) return;
  const nowIso = new Date().toISOString();
  db.notificationDevices.forEach((device) => {
    if (!device || typeof device !== 'object') return;
    let changed = false;
    if (!device.categories || typeof device.categories !== 'object') {
      device.categories = defaultNotificationCategories();
      changed = true;
    } else {
      const normalizedCategories = normalizeNotificationCategories(device.categories);
      if (JSON.stringify(normalizedCategories) !== JSON.stringify(device.categories)) {
        device.categories = normalizedCategories;
        changed = true;
      }
    }
    if (!device.delivery || typeof device.delivery !== 'object') {
      device.delivery = defaultNotificationDelivery();
      changed = true;
    } else {
      const normalizedDelivery = normalizeNotificationDelivery(device.delivery);
      if (JSON.stringify(normalizedDelivery) !== JSON.stringify(device.delivery)) {
        device.delivery = normalizedDelivery;
        changed = true;
      }
    }
    const effectivePermission = getEffectiveNotificationPermissionState(device);
    if (device.permissionState !== effectivePermission) {
      device.permissionState = effectivePermission;
      changed = true;
    }
    if (changed) {
      device.updatedAt ||= nowIso;
      console.info('[Notifications][Compatibility] Backfilled legacy device row.', {
        userId: device.userId || null,
        deviceRowId: device.id || null,
        permissionState: device.permissionState,
        categoryCount: Object.keys(device.categories || {}).length,
        deliveryCount: Object.keys(device.delivery || {}).length
      });
    }
  });
}

function ensureSiteAnnouncementTables(db) {
  if (!Array.isArray(db.siteAnnouncements)) db.siteAnnouncements = [];
  if (!Array.isArray(db.siteAnnouncementStates)) db.siteAnnouncementStates = [];
}

function getNotificationConfig() {
  return {
    apiKey: FCM_API_KEY,
    authDomain: FCM_AUTH_DOMAIN,
    projectId: FIREBASE_PROJECT_ID,
    messagingSenderId: FCM_MESSAGING_SENDER_ID,
    appId: FCM_APP_ID,
    vapidKey: FCM_VAPID_KEY
  };
}

function missingNotificationConfigKeys(config = getNotificationConfig()) {
  const requiredKeys = ['apiKey', 'authDomain', 'projectId', 'messagingSenderId', 'appId', 'vapidKey'];
  return requiredKeys.filter((key) => !config[key]);
}

function hasNotificationConfig() {
  return missingNotificationConfigKeys().length === 0;
}

let firebaseAdminReady = false;
let firebaseAdmin = null;
function ensureFirebaseAdmin() {
  if (firebaseAdminReady) return;
  if (!FIREBASE_PROJECT_ID || !FIREBASE_CLIENT_EMAIL || !FIREBASE_PRIVATE_KEY) {
    throw new Error('Firebase Admin SDK configuration is missing (FIREBASE_PROJECT_ID, FIREBASE_CLIENT_EMAIL, FIREBASE_PRIVATE_KEY).');
  }
  if (!firebaseAdmin) {
    try {
      firebaseAdmin = require('firebase-admin');
    } catch (error) {
      throw new Error(`firebase-admin package is not installed: ${error?.message || String(error)}`);
    }
  }
  if (!firebaseAdmin.apps.length) {
    firebaseAdmin.initializeApp({
      credential: firebaseAdmin.credential.cert({
        projectId: FIREBASE_PROJECT_ID,
        clientEmail: FIREBASE_CLIENT_EMAIL,
        privateKey: FIREBASE_PRIVATE_KEY
      })
    });
  }
  firebaseAdminReady = true;
}

function detectBrowserFromUserAgent(userAgent) {
  const ua = String(userAgent || '').toLowerCase();
  if (ua.includes('edg/')) return 'edge';
  if (ua.includes('opr/') || ua.includes('opera')) return 'opera';
  if (ua.includes('chrome/') || ua.includes('crios/')) return 'chrome';
  if (ua.includes('firefox/') || ua.includes('fxios/')) return 'firefox';
  if (ua.includes('safari/') && !ua.includes('chrome/') && !ua.includes('crios/')) return 'safari';
  return 'unknown';
}

function resolveDeviceRecord(db, { userId, deviceId, token }) {
  return db.notificationDevices.find((item) => item.userId === userId
    && ((deviceId && item.deviceId === deviceId) || (token && item.token === token)));
}

function redactToken(token) {
  const raw = String(token || '').trim();
  if (!raw) return '';
  if (raw.length <= 12) return `${raw.slice(0, 4)}…${raw.slice(-2)}`;
  return `${raw.slice(0, 8)}…${raw.slice(-6)}`;
}

function fingerprintToken(token) {
  const raw = String(token || '').trim();
  if (!raw) return '';
  return crypto.createHash('sha1').update(raw).digest('hex').slice(0, 12);
}

function normalizeDeviceTargetIdentity(device) {
  if (!device || typeof device !== 'object') return '';
  const platform = String(device.platform || '').trim().toLowerCase();
  const browser = String(device.browser || '').trim().toLowerCase() || 'unknown';
  const normalizedDeviceId = String(device.deviceId || '').trim().toLowerCase();
  const mobilePlatform = platform.includes('ios') || platform.includes('android') || platform.includes('mobile');
  if (mobilePlatform) {
    const platformFamily = platform.includes('ios') ? 'ios' : (platform.includes('android') ? 'android' : 'mobile');
    return `mobile:${platformFamily}`;
  }
  return `desktop:${platform || 'desktop'}:${browser}:${normalizedDeviceId || 'unknown'}`;
}

function buildPushTargetKey(device) {
  const tokenPart = fingerprintToken(device?.token);
  const identityPart = normalizeDeviceTargetIdentity(device);
  if (tokenPart) return `token:${tokenPart}`;
  return `identity:${identityPart || 'unknown'}`;
}

function selectMostRecentDeviceRecord(current, candidate) {
  if (!current) return candidate;
  const currentTs = Date.parse(current.updatedAt || current.lastRegistrationAt || current.createdAt || 0) || 0;
  const candidateTs = Date.parse(candidate.updatedAt || candidate.lastRegistrationAt || candidate.createdAt || 0) || 0;
  if (candidateTs >= currentTs) return candidate;
  return current;
}

function getDeviceRecencyTs(device) {
  return Date.parse(device?.updatedAt || device?.lastRegistrationAt || device?.createdAt || 0) || 0;
}

function buildFinalPhysicalTargetKey(device) {
  const tokenKey = fingerprintToken(device?.token);
  if (tokenKey) return `token:${tokenKey}`;
  const normalizedIdentity = normalizeDeviceTargetIdentity(device);
  if (normalizedIdentity.startsWith('mobile:')) return `mobile-identity:${normalizedIdentity}`;
  const normalizedDeviceId = String(device?.deviceId || '').trim().toLowerCase();
  if (normalizedDeviceId) return `desktop-device:${normalizedDeviceId}`;
  return `identity:${normalizedIdentity || 'unknown'}`;
}

function notificationDeviceDebugShape(device) {
  return {
    id: device.id,
    userId: device.userId,
    deviceId: device.deviceId || null,
    platform: device.platform || null,
    browser: device.browser || null,
    tokenFingerprint: fingerprintToken(device.token),
    tokenPreview: redactToken(device.token),
    isActive: device.isActive !== false,
    createdAt: device.createdAt || null,
    updatedAt: device.updatedAt || null,
    lastRegistrationAt: device.lastRegistrationAt || null,
    revokedAt: device.revokedAt || null,
    normalizedIdentity: normalizeDeviceTargetIdentity(device),
    finalPhysicalTargetKey: buildFinalPhysicalTargetKey(device)
  };
}

function cleanupDuplicateNotificationDevices(db, { userId = null } = {}) {
  ensureNotificationTables(db);
  const nowIso = new Date().toISOString();
  const duplicateIndexes = new Set();

  const byToken = new Map();
  const byUserDevice = new Map();
  const byUserMobileIdentity = new Map();
  for (const item of db.notificationDevices) {
    if (!item) continue;
    if (item.isActive === false) continue;
    const tokenKey = String(item.token || '').trim();
    const deviceKey = String(item.deviceId || '').trim();
    if (tokenKey) {
      const key = tokenKey.toLowerCase();
      byToken.set(key, selectMostRecentDeviceRecord(byToken.get(key), item));
    }
    if (item.userId && deviceKey) {
      const key = `${item.userId}::${deviceKey.toLowerCase()}`;
      byUserDevice.set(key, selectMostRecentDeviceRecord(byUserDevice.get(key), item));
    }
    const identity = normalizeDeviceTargetIdentity(item);
    if (item.userId && identity.startsWith('mobile:')) {
      const key = `${item.userId}::${identity}`;
      byUserMobileIdentity.set(key, selectMostRecentDeviceRecord(byUserMobileIdentity.get(key), item));
    }
  }

  db.notificationDevices.forEach((item, index) => {
    if (!item || item.isActive === false) return;
    if (userId && item.userId !== userId) return;
    const tokenKey = String(item.token || '').trim().toLowerCase();
    const deviceKey = String(item.deviceId || '').trim().toLowerCase();
    if (tokenKey) {
      const winner = byToken.get(tokenKey);
      if (winner && winner.id !== item.id) duplicateIndexes.add(index);
    }
    if (item.userId && deviceKey) {
      const winner = byUserDevice.get(`${item.userId}::${deviceKey}`);
      if (winner && winner.id !== item.id) duplicateIndexes.add(index);
    }
    const identity = normalizeDeviceTargetIdentity(item);
    if (item.userId && identity.startsWith('mobile:')) {
      const winner = byUserMobileIdentity.get(`${item.userId}::${identity}`);
      if (winner && winner.id !== item.id) duplicateIndexes.add(index);
    }
  });

  duplicateIndexes.forEach((index) => {
    const item = db.notificationDevices[index];
    if (!item || item.isActive === false) return;
    item.isActive = false;
    item.revokedAt ||= nowIso;
    item.updatedAt = nowIso;
    console.info('[Notifications] Deactivated duplicate device row.', {
      deviceRowId: item.id,
      userId: item.userId,
      deviceId: item.deviceId || null,
      tokenFingerprint: fingerprintToken(item.token),
      targetIdentity: normalizeDeviceTargetIdentity(item),
      reason: 'duplicate-token-device-or-mobile-identity'
    });
  });
}

function upsertNotificationDevice(db, payload) {
  ensureNotificationTables(db);
  const nowIso = new Date().toISOString();
  const existing = resolveDeviceRecord(db, payload);
  const existingTokenFingerprint = existing ? fingerprintToken(existing.token) : '';
  const incomingTokenFingerprint = fingerprintToken(payload.token);
  const wasInactive = existing ? existing.isActive === false : false;
  const userPreferences = getNotificationPreferences(db, payload.userId);
  const mergedCategories = normalizeNotificationCategories(payload.categories || existing?.categories || userPreferences.categories);
  const mergedDelivery = normalizeNotificationDelivery(payload.delivery || existing?.delivery || userPreferences.delivery);
  const next = {
    id: existing?.id || crypto.randomUUID(),
    userId: payload.userId,
    deviceId: payload.deviceId,
    platform: payload.platform || 'unknown',
    browser: payload.browser || detectBrowserFromUserAgent(payload.userAgent),
    userAgent: payload.userAgent || '',
    token: payload.token,
    providerType: payload.providerType || 'fcm-web',
    permissionState: payload.permissionState || 'default',
    isActive: payload.isActive !== false,
    installedAsPwa: !!payload.installedAsPwa,
    categories: mergedCategories,
    delivery: mergedDelivery,
    createdAt: existing?.createdAt || nowIso,
    updatedAt: nowIso,
    lastSeenAt: nowIso,
    lastSentAt: existing?.lastSentAt || null,
    lastErrorAt: existing?.lastErrorAt || null,
    lastRegistrationAt: nowIso,
    lastReceivedAt: existing?.lastReceivedAt || null,
    revokedAt: payload.isActive === false ? nowIso : null
  };
  if (existing) {
    Object.assign(existing, next);
  } else {
    db.notificationDevices.push(next);
  }
  const action = !existing
    ? 'token_created'
    : (existingTokenFingerprint !== incomingTokenFingerprint
      ? 'token_refreshed'
      : (wasInactive && next.isActive !== false ? 'current_device_reenabled' : 'token_updated'));
  console.info('[Notifications][DeviceLifecycle] Device token lifecycle event.', {
    action,
    userId: payload.userId,
    deviceRowId: next.id,
    deviceId: next.deviceId || null,
    platform: next.platform || null,
    browser: next.browser || null,
    previousTokenFingerprint: existingTokenFingerprint || null,
    tokenFingerprint: incomingTokenFingerprint || null,
    tokenSuffix: String(payload.token || '').slice(-8) || '',
    normalizedTargetIdentity: normalizeDeviceTargetIdentity(next),
    isActive: next.isActive !== false
  });
  // Deactivate duplicate token/device rows for same user.
  db.notificationDevices.forEach((item) => {
    if (item.id === next.id) return;
    if (item.userId !== next.userId) return;
    if ((item.deviceId && item.deviceId === next.deviceId) || item.token === next.token) {
      item.isActive = false;
      item.revokedAt ||= nowIso;
      item.updatedAt = nowIso;
    }
  });
  cleanupDuplicateNotificationDevices(db, { userId: payload.userId });
  return next;
}

const DEFAULT_NOTIFICATION_ICON = '/static/Veracity-notification-logo.png';

function checkNotificationTestRateLimit(req, res) {
  const key = `${req.username}:${getClientIp(req)}`;
  const now = Date.now();
  const entry = notificationTestRateLimit.get(key) || { count: 0, resetAt: now + NOTIFICATION_TEST_RATE_LIMIT_WINDOW_MS };
  if (now > entry.resetAt) {
    entry.count = 0;
    entry.resetAt = now + NOTIFICATION_TEST_RATE_LIMIT_WINDOW_MS;
  }
  entry.count += 1;
  notificationTestRateLimit.set(key, entry);
  if (entry.count > NOTIFICATION_TEST_RATE_LIMIT_MAX) {
    const retryAfter = Math.ceil((entry.resetAt - now) / 1000);
    res.set('Retry-After', String(retryAfter));
    res.status(429).json({ error: `Too many test notifications. Retry in ${retryAfter} seconds.` });
    return false;
  }
  return true;
}

async function sendNotificationToDevice(db, device, payload) {
  if (!device?.token) {
    console.warn('[Notifications] Skipping push send because device token is missing.', {
      deviceId: device?.id || null,
      userId: device?.userId || null
    });
    return null;
  }
  ensureFirebaseAdmin();
  console.info('[Notifications] Sending Firebase push notification.', {
    correlationId: payload?.data?.correlationId || payload?.correlationId || null,
    eventId: payload?.data?.eventId || null,
    announcementId: payload?.data?.announcementId || null,
    groupId: payload?.data?.groupId || null,
    recipientUserId: device.userId,
    targetDeviceRowId: device.id,
    tokenPreview: redactToken(device.token),
    tokenFingerprint: fingerprintToken(device.token),
    platform: device.platform || null,
    browser: device.browser || null,
    normalizedTargetIdentity: normalizeDeviceTargetIdentity(device),
    invocationSource: payload?.invocationSource || payload?.source || 'server.js#sendNotificationToDevice',
    skipped: false
  });
  const baseData = Object.fromEntries(Object.entries(payload.data || {}).map(([key, value]) => [key, String(value)]));
  const dataPayload = {
    ...baseData,
    title: String(payload.title || baseData.title || 'Veracity Trading Suite'),
    body: String(payload.body || baseData.body || 'New Veracity notification'),
    icon: String(payload.icon || baseData.icon || DEFAULT_NOTIFICATION_ICON),
    badge: String(payload.badge || baseData.badge || DEFAULT_NOTIFICATION_ICON),
    tag: String(payload.tag || baseData.tag || 'veracity-alert'),
    requireInteraction: String(!!payload.requireInteraction),
    link: String(payload.link || baseData.link || '/')
  };
  if (payload.image) {
    dataPayload.image = String(payload.image);
  }
  if (Array.isArray(payload.actions) && payload.actions.length) {
    dataPayload.actions = JSON.stringify(payload.actions);
  }
  const message = {
    token: device.token,
    webpush: {
      headers: payload.requireInteraction ? { Urgency: 'high' } : undefined,
      fcmOptions: payload.link ? { link: payload.link } : undefined
    },
    data: dataPayload
  };
  try {
    console.info('[Notifications] DATA-ONLY PUSH SENT', {
      correlationId: payload?.data?.correlationId || payload?.correlationId || null,
      eventId: payload?.data?.eventId || null,
      announcementId: payload?.data?.announcementId || null,
      groupId: payload?.data?.groupId || null,
      recipientUserId: device.userId,
      targetDeviceRowId: device.id,
      tokenFingerprint: fingerprintToken(device.token),
      hasNotificationPayload: false
    });
    const messageId = await firebaseAdmin.messaging().send(message);
    const sentAt = new Date().toISOString();
    device.lastSentAt = sentAt;
    device.updatedAt = sentAt;
    console.info('[Notifications] Firebase push sent successfully.', {
      correlationId: payload?.data?.correlationId || payload?.correlationId || null,
      eventId: payload?.data?.eventId || null,
      announcementId: payload?.data?.announcementId || null,
      groupId: payload?.data?.groupId || null,
      recipientUserId: device.userId,
      targetDeviceRowId: device.id,
      tokenFingerprint: fingerprintToken(device.token),
      providerMessageId: messageId
    });
    return messageId;
  } catch (error) {
    console.error('[Notifications] Firebase push send failed.', {
      correlationId: payload?.data?.correlationId || payload?.correlationId || null,
      eventId: payload?.data?.eventId || null,
      announcementId: payload?.data?.announcementId || null,
      groupId: payload?.data?.groupId || null,
      recipientUserId: device.userId,
      targetDeviceRowId: device.id,
      tokenFingerprint: fingerprintToken(device.token),
      code: error?.code || null,
      message: error?.message || String(error),
      stack: error?.stack || null
    });
    const wrapped = new Error(error?.message || 'Firebase push send failed.');
    wrapped.code = error?.code || '';
    wrapped.details = error?.errorInfo?.message || '';
    wrapped.stack = error?.stack || wrapped.stack;
    throw wrapped;
  }
}

function buildNotificationEvent(type, context = {}) {
  const base = {
    icon: DEFAULT_NOTIFICATION_ICON,
    badge: DEFAULT_NOTIFICATION_ICON,
    requireInteraction: false
  };
  const builders = {
    missing_stop_loss_warning: () => ({
      ...base, category: 'criticalRiskAlerts', title: 'Missing stop loss detected', body: `${context.symbol || 'An active trade'} has no stop loss set.`, link: context.link || '/trades.html?filter=active'
    }),
    risk_threshold_breached: () => ({
      ...base, category: 'criticalRiskAlerts', title: 'Risk threshold breached', body: `${context.symbol || 'Trade'} risk exceeded your configured threshold.`, link: context.link || '/trades.html?filter=risk'
    }),
    trade_opened: () => ({
      ...base, category: 'tradeAlerts', title: 'Trade opened', body: `${context.symbol || 'A trade'} was opened.`, link: context.link || `/trades.html${context.tradeId ? `?trade=${encodeURIComponent(context.tradeId)}` : ''}`
    }),
    trade_closed: () => ({
      ...base, category: 'tradeAlerts', title: 'Trade closed', body: `${context.symbol || 'A trade'} was closed.`, link: context.link || `/trades.html${context.tradeId ? `?trade=${encodeURIComponent(context.tradeId)}` : ''}`
    }),
    leader_new_position: () => ({
      ...base, category: 'tradeGroupAlerts', title: 'New leader position', body: `${context.leader || 'Group leader'} opened a new position in ${context.groupName || 'your trading group'}.`, link: context.link || `/social/groups${context.groupId ? `?group=${encodeURIComponent(context.groupId)}` : ''}`
    }),
    trade_group_alert: () => ({
      ...base,
      category: 'tradeGroupAlerts',
      title: `${context.groupName || 'Trade group'} alert`,
      body: context.body || 'A new group alert is available.',
      link: context.link || `/social/groups${context.groupId ? `?group=${encodeURIComponent(context.groupId)}` : ''}`
    }),
    trade_group_alert_banner: () => ({
      ...base,
      category: 'tradeGroupAlerts',
      title: `${context.groupName || 'Trade group'} alert`,
      body: context.body || 'A new group alert is available.',
      link: context.link || `/social/groups${context.groupId ? `?group=${encodeURIComponent(context.groupId)}` : ''}`
    }),
    trade_group_announcement: () => ({
      ...base,
      category: 'tradeGroupAlerts',
      title: `${context.groupName || 'Trading group'} announcement`,
      body: context.announcementText || context.body || 'A new group announcement is available.',
      link: context.link || `/social/groups${context.groupId ? `?group=${encodeURIComponent(context.groupId)}` : ''}`
    }),
    trade_group_invite: () => ({
      ...base,
      category: 'tradeGroupAlerts',
      title: 'Trading group invite',
      body: `You were invited to join ${context.groupName || 'a trading group'}.`,
      link: context.link || `/social/groups${context.groupId ? `?group=${encodeURIComponent(context.groupId)}` : ''}`
    }),
    trade_group_member_joined: () => ({
      ...base,
      category: 'tradeGroupAlerts',
      title: `${context.groupName || 'Trading group'} update`,
      body: `${context.joinedNickname || 'A member'} joined your trading group.`,
      link: context.link || `/social/groups${context.groupId ? `?group=${encodeURIComponent(context.groupId)}` : ''}`
    }),
    trade_group_watchlist_posted: () => ({
      ...base,
      category: 'tradeGroupAlerts',
      title: `${context.groupName || 'Trading group'} watchlist`,
      body: context.body || `New shared watchlist: ${context.watchlistName || 'Watchlist'}.`,
      link: context.link || `/social/groups${context.groupId ? `?group=${encodeURIComponent(context.groupId)}&tab=watchlists&watchlist=${encodeURIComponent(context.groupWatchlistId || '')}` : ''}`
    }),
    broker_sync_failed: () => ({
      ...base, category: 'brokerSyncFailures', title: 'Broker sync failed', body: context.body || 'Broker integration sync failed. Review settings.', link: context.link || '/profile.html#integration-section', requireInteraction: true
    }),
    broker_reconnected: () => ({
      ...base, category: 'brokerSyncFailures', title: 'Broker reconnected', body: context.body || 'Broker integration is connected again.', link: context.link || '/profile.html#integration-section'
    }),
    investor_valuation_updated: () => ({
      ...base, category: 'socialInvestorNotifications', title: 'Investor valuation updated', body: context.body || 'Investor valuation has been updated.', link: context.link || '/profile.html#investor-section'
    }),
    daily_recap_ready: () => ({
      ...base, category: 'dailyRecap', title: 'Daily recap ready', body: context.body || 'Your daily recap is ready.', link: context.link || '/analytics.html?panel=daily-recap'
    }),
    weekly_recap_ready: () => ({
      ...base,
      category: 'dailyRecap',
      title: context.title || 'Your weekly recap is ready',
      body: context.body || 'Review last week’s performance, wins, losses, and key takeaways.',
      link: context.link || '/review?openWeeklyRecap=latest&source=push'
    })
  };
  if (!builders[type]) return null;
  const built = builders[type]();
  return {
    ...built,
    type,
    tag: context.tag || `veracity-${type}`,
    data: {
      type,
      link: built.link,
      userId: context.userId || '',
      groupId: context.groupId || '',
      announcementId: context.announcementId || '',
      eventId: context.eventId || '',
      correlationId: context.correlationId || ''
    }
  };
}

async function sendNotificationEvent(db, { userId, eventType, context = {}, onlyDeviceId = null, criticalOnly = false }) {
  ensureNotificationTables(db);
  cleanupDuplicateNotificationDevices(db, { userId });
  const userPreferences = getNotificationPreferences(db, userId);
  const correlationId = String(context?.correlationId || `${eventType}:${crypto.randomUUID()}`);
  const payload = buildNotificationEvent(eventType, { ...context, userId, correlationId });
  if (!payload) {
    throw new Error(`Unsupported notification event type: ${eventType}`);
  }
  payload.correlationId = correlationId;
  payload.eventId = String(context?.eventId || `${eventType}:${context?.announcementId || crypto.randomUUID()}`);
  payload.groupId = context?.groupId || '';
  payload.announcementId = context?.announcementId || '';
  payload.invocationSource = String(context?.invocationSource || context?.source || 'server.js#sendNotificationEvent');
  const category = payload.category;
  const categoryEnabled = !!userPreferences?.categories?.[category];
  const userDelivery = String(userPreferences?.delivery?.[category] || 'push');
  console.info('[Notifications][Pipeline] Preference fetch result.', {
    correlationId,
    eventType,
    eventId: payload.eventId,
    recipientUserId: userId,
    category,
    categoryEnabled,
    userDelivery,
    categoryCount: Object.keys(userPreferences?.categories || {}).length,
    deliveryCount: Object.keys(userPreferences?.delivery || {}).length
  });
  console.info('[Notifications][Pipeline] Category mapping result.', {
    correlationId,
    eventType,
    eventId: payload.eventId,
    recipientUserId: userId,
    mappedCategory: category
  });
  console.info('[Notifications][Pipeline] Push event creation requested.', {
    correlationId,
    eventType,
    eventId: payload.eventId,
    announcementId: context?.announcementId || null,
    groupId: context?.groupId || null,
    recipientUserId: userId,
    invocationSource: payload.invocationSource
  });
  if (!categoryEnabled || userDelivery === 'disabled' || userDelivery === 'email') {
    console.info('[Notifications][Pipeline] Event skipped by user preferences before device routing.', {
      correlationId,
      eventType,
      eventId: payload.eventId,
      recipientUserId: userId,
      category,
      categoryEnabled,
      userDelivery
    });
    const nowIso = new Date().toISOString();
    const skippedLog = {
      id: crypto.randomUUID(),
      userId,
      eventType,
      category,
      title: payload.title,
      body: payload.body,
      link: payload.link,
      targetDeviceId: onlyDeviceId || null,
      source: String(context?.source || ''),
      context: {
        correlationId,
        groupId: context?.groupId || null,
        announcementId: context?.announcementId || null,
        eventId: payload.eventId,
        invocationSource: payload.invocationSource
      },
      attemptedAt: nowIso,
      deliveries: [{
        deviceId: null,
        ok: true,
        skipped: true,
        reason: 'user_preference_blocked',
        categoryEnabled,
        userDelivery,
        at: nowIso
      }]
    };
    db.notificationEvents.push(skippedLog);
    return skippedLog;
  }
  const eligibleDevices = [];
  db.notificationDevices.forEach((item) => {
    if (item.userId !== userId) return;
    const suppressionReasons = [];
    if (!item.isActive) suppressionReasons.push('inactive_device');
    const permissionState = getEffectiveNotificationPermissionState(item);
    if (permissionState !== 'granted') suppressionReasons.push(`permission_${permissionState}`);
    if (onlyDeviceId && item.id !== onlyDeviceId) suppressionReasons.push('not_target_device');
    if (criticalOnly && category !== 'criticalRiskAlerts') suppressionReasons.push('critical_only_filter');
    if (!item.categories?.[category]) suppressionReasons.push('category_disabled_on_device');
    const deliveryState = String(item.delivery?.[category] || 'push');
    if (!['push', 'both'].includes(deliveryState)) suppressionReasons.push(`delivery_${deliveryState}`);
    if (!String(item.token || '').trim()) suppressionReasons.push('missing_push_token');
    if (suppressionReasons.length) {
      console.info('[Notifications][Pipeline] Suppression reason(s) for device.', {
        correlationId,
        eventType,
        eventId: payload.eventId,
        recipientUserId: userId,
        deviceRowId: item.id || null,
        deviceId: item.deviceId || null,
        suppressionReasons
      });
      return;
    }
    eligibleDevices.push(item);
  });
  console.info('[Notifications][Pipeline] Delivery routing decision.', {
    correlationId,
    eventType,
    eventId: payload.eventId,
    recipientUserId: userId,
    registeredDeviceCount: db.notificationDevices.filter((item) => item.userId === userId).length,
    eligibleDeviceCount: eligibleDevices.length
  });
  if (eventType === 'trade_group_announcement') {
    logAnnouncementPipelineStage('5.candidate_devices_resolved', {
      correlationId,
      announcementId: context?.announcementId || null,
      recipientUserId: userId,
      sourceHandler: 'server.js#sendNotificationEvent',
      details: {
        candidateDeviceCount: eligibleDevices.length,
        eventId: payload.eventId
      }
    });
  }
  if (eventType === 'trade_group_announcement') {
    console.info('[TradeGroup][AnnouncementRecipientRowsBeforeSend]', {
      announcementId: context?.announcementId || null,
      eventId: context?.eventId || null,
      recipientUserId: userId,
      rows: db.notificationDevices
        .filter((item) => item.userId === userId)
        .sort((a, b) => getDeviceRecencyTs(b) - getDeviceRecencyTs(a))
        .map(notificationDeviceDebugShape)
    });
  }
  eligibleDevices.forEach((device) => {
    if (eventType === 'trade_group_announcement') {
      logAnnouncementPipelineStage('5.candidate_devices_resolved', {
        correlationId,
        announcementId: context?.announcementId || null,
        recipientUserId: userId,
        deviceRowId: device.id,
        tokenFingerprint: fingerprintToken(device.token),
        sourceHandler: 'server.js#sendNotificationEvent',
        details: {
          platform: device.platform || null,
          browser: device.browser || null,
          finalPhysicalTargetKey: buildFinalPhysicalTargetKey(device)
        }
      });
    }
    console.info('[Notifications][SendCandidate]', {
      eventType,
      recipientUserId: userId,
      deviceRowId: device.id,
      deviceId: device.deviceId || null,
      platform: device.platform || null,
      browser: device.browser || null,
      tokenPreview: redactToken(device.token),
      tokenFingerprint: fingerprintToken(device.token),
      createdAt: device.createdAt || null,
      updatedAt: device.updatedAt || null,
      isActive: device.isActive !== false,
      normalizedTarget: buildPushTargetKey(device)
    });
  });
  eligibleDevices.sort((a, b) => getDeviceRecencyTs(b) - getDeviceRecencyTs(a));
  const dedupedDevices = [];
  const seenTokens = new Set();
  const seenIdentities = new Set();
  const seenPhysicalTargets = new Set();
  for (const device of eligibleDevices) {
    const tokenKey = fingerprintToken(device.token);
    if (tokenKey && seenTokens.has(tokenKey)) {
      if (eventType === 'trade_group_announcement') {
        logAnnouncementPipelineStage('6.final_deduped_targets_resolved', {
          correlationId,
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          tokenFingerprint: tokenKey,
          sourceHandler: 'server.js#sendNotificationEvent',
          details: {
            selected: false,
            reason: 'duplicate-token',
            finalPhysicalTargetKey: buildFinalPhysicalTargetKey(device)
          }
        });
      }
      console.info('[Notifications] Skipping duplicate target prior to send.', {
        eventType,
        userId,
        deviceRowId: device.id,
        reason: 'duplicate-token',
        tokenFingerprint: tokenKey
      });
      if (eventType === 'trade_group_announcement') {
        console.info('[TradeGroup][AnnouncementFinalTarget]', {
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          deviceId: device.deviceId || null,
          platform: device.platform || null,
          browser: device.browser || null,
          normalizedTargetIdentity: normalizeDeviceTargetIdentity(device),
          tokenFingerprint: tokenKey,
          tokenSuffix: String(device.token || '').slice(-8) || '',
          skipped: true,
          reason: 'duplicate-token',
          finalPhysicalTargetKey: buildFinalPhysicalTargetKey(device)
        });
      }
      continue;
    }
    const identityKey = normalizeDeviceTargetIdentity(device);
    if (identityKey && seenIdentities.has(identityKey)) {
      if (eventType === 'trade_group_announcement') {
        logAnnouncementPipelineStage('6.final_deduped_targets_resolved', {
          correlationId,
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          tokenFingerprint: fingerprintToken(device.token),
          sourceHandler: 'server.js#sendNotificationEvent',
          details: {
            selected: false,
            reason: 'duplicate-normalized-identity',
            finalPhysicalTargetKey: buildFinalPhysicalTargetKey(device)
          }
        });
      }
      console.info('[Notifications] Skipping duplicate target prior to send.', {
        eventType,
        userId,
        deviceRowId: device.id,
        reason: 'duplicate-normalized-identity',
        normalizedIdentity: identityKey
      });
      if (eventType === 'trade_group_announcement') {
        console.info('[TradeGroup][AnnouncementFinalTarget]', {
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          deviceId: device.deviceId || null,
          platform: device.platform || null,
          browser: device.browser || null,
          normalizedTargetIdentity: identityKey,
          tokenFingerprint: fingerprintToken(device.token),
          tokenSuffix: String(device.token || '').slice(-8) || '',
          skipped: true,
          reason: 'duplicate-normalized-identity',
          finalPhysicalTargetKey: buildFinalPhysicalTargetKey(device)
        });
      }
      continue;
    }
    const physicalTargetKey = buildFinalPhysicalTargetKey(device);
    if (physicalTargetKey && seenPhysicalTargets.has(physicalTargetKey)) {
      if (eventType === 'trade_group_announcement') {
        logAnnouncementPipelineStage('6.final_deduped_targets_resolved', {
          correlationId,
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          tokenFingerprint: fingerprintToken(device.token),
          sourceHandler: 'server.js#sendNotificationEvent',
          details: {
            selected: false,
            reason: 'duplicate-physical-target-key',
            finalPhysicalTargetKey: physicalTargetKey
          }
        });
      }
      console.info('[Notifications] Skipping duplicate target prior to send.', {
        eventType,
        userId,
        deviceRowId: device.id,
        reason: 'duplicate-physical-target-key',
        finalPhysicalTargetKey: physicalTargetKey
      });
      if (eventType === 'trade_group_announcement') {
        console.info('[TradeGroup][AnnouncementFinalTarget]', {
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          deviceId: device.deviceId || null,
          platform: device.platform || null,
          browser: device.browser || null,
          normalizedTargetIdentity: normalizeDeviceTargetIdentity(device),
          tokenFingerprint: fingerprintToken(device.token),
          tokenSuffix: String(device.token || '').slice(-8) || '',
          skipped: true,
          reason: 'duplicate-physical-target-key',
          finalPhysicalTargetKey: physicalTargetKey
        });
      }
      continue;
    }
    if (tokenKey) seenTokens.add(tokenKey);
    if (identityKey) seenIdentities.add(identityKey);
    if (physicalTargetKey) seenPhysicalTargets.add(physicalTargetKey);
    if (eventType === 'trade_group_announcement') {
      logAnnouncementPipelineStage('6.final_deduped_targets_resolved', {
        correlationId,
        announcementId: context?.announcementId || null,
        recipientUserId: userId,
        deviceRowId: device.id,
        tokenFingerprint: fingerprintToken(device.token),
        sourceHandler: 'server.js#sendNotificationEvent',
        details: {
          selected: true,
          reason: 'selected-after-dedupe',
          finalPhysicalTargetKey: physicalTargetKey
        }
      });
      console.info('[TradeGroup][AnnouncementFinalTarget]', {
        announcementId: context?.announcementId || null,
        recipientUserId: userId,
        deviceRowId: device.id,
        deviceId: device.deviceId || null,
        platform: device.platform || null,
        browser: device.browser || null,
        normalizedTargetIdentity: normalizeDeviceTargetIdentity(device),
        tokenFingerprint: fingerprintToken(device.token),
        tokenSuffix: String(device.token || '').slice(-8) || '',
        skipped: false,
        reason: 'selected-after-dedupe',
        finalPhysicalTargetKey: physicalTargetKey
      });
    }
    dedupedDevices.push(device);
  }
  if (eventType === 'trade_group_announcement') {
    logAnnouncementPipelineStage('6.final_deduped_targets_resolved', {
      correlationId,
      announcementId: context?.announcementId || null,
      recipientUserId: userId,
      sourceHandler: 'server.js#sendNotificationEvent',
      details: {
        finalTargetCount: dedupedDevices.length,
        eventId: payload.eventId
      }
    });
  }
  const nowIso = new Date().toISOString();
  const dedupeWindowMs = ANNOUNCEMENT_PIPELINE_SEND_DEDUPE_WINDOW_MS;
  const log = {
    id: crypto.randomUUID(),
    userId,
    eventType,
    category,
    title: payload.title,
    body: payload.body,
    link: payload.link,
    targetDeviceId: onlyDeviceId || null,
    source: String(context?.source || ''),
    context: {
      correlationId,
      groupId: context?.groupId || null,
      announcementId: context?.announcementId || null,
      eventId: payload.eventId,
      invocationSource: payload.invocationSource
    },
    attemptedAt: nowIso,
    deliveries: []
  };
  db.notificationEvents.push(log);
  if (eventType === 'trade_group_announcement') {
    logAnnouncementPipelineStage('4.notification_event_persisted', {
      correlationId,
      announcementId: context?.announcementId || null,
      recipientUserId: userId,
      sourceHandler: 'server.js#sendNotificationEvent',
      details: {
        eventLogId: log.id,
        deliveriesPersisted: log.deliveries.length,
        persistedAt: nowIso
      }
    });
  }
  for (const device of dedupedDevices) {
    const finalPhysicalTarget = buildFinalPhysicalTargetKey(device) || buildPushTargetKey(device);
    const dedupeKey = `hard:${correlationId}:${userId}:${finalPhysicalTarget || 'unknown_target'}`;
    const existingDedupe = db.notificationPushDedupe.find((item) => item.key === dedupeKey);
    const nowTs = Date.now();
    const shouldSkipForDedupe = existingDedupe && (nowTs - Date.parse(existingDedupe.sentAt || 0)) < dedupeWindowMs;
    if (eventType === 'trade_group_announcement') {
      console.info('[TradeGroup][AnnouncementPushAttempt]', {
        eventId: context?.eventId || `trade_group_announcement:${context?.announcementId || 'unknown'}`,
        announcementId: context?.announcementId || null,
        groupId: context?.groupId || null,
        recipientUserId: userId,
        targetDeviceId: device.id,
        notificationType: eventType,
        source: payload.invocationSource,
        normalizedTargetIdentity: normalizeDeviceTargetIdentity(device),
        tokenFingerprint: fingerprintToken(device.token),
        tokenSuffix: String(device.token || '').slice(-8) || '',
        finalPhysicalTargetKey: buildFinalPhysicalTargetKey(device),
        skipped: !!shouldSkipForDedupe,
        reason: shouldSkipForDedupe ? 'event-device-deduped' : 'executed'
      });
    }
    if (shouldSkipForDedupe) {
      if (eventType === 'trade_group_announcement') {
        logAnnouncementPipelineStage('7.actual_provider_send_invoked', {
          correlationId,
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          tokenFingerprint: fingerprintToken(device.token),
          sourceHandler: 'server.js#sendNotificationEvent',
          details: {
            invoked: false,
            skipped: true,
            reason: 'hard_dedupe_gate',
            dedupeKey
          }
        });
      }
      log.deliveries.push({
        deviceId: device.id,
        ok: true,
        skipped: true,
        reason: 'event-device-deduped',
        dedupeKey,
        at: new Date().toISOString()
      });
      continue;
    }
    try {
      if (eventType === 'trade_group_announcement') {
        logAnnouncementPipelineStage('7.actual_provider_send_invoked', {
          correlationId,
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          tokenFingerprint: fingerprintToken(device.token),
          sourceHandler: 'server.js#sendNotificationEvent',
          details: {
            invoked: true,
            skipped: false,
            dedupeKey
          }
        });
      }
      const messageId = await sendNotificationToDevice(db, device, payload);
      if (eventType === 'trade_group_announcement') {
        logAnnouncementPipelineStage('8.provider_response_returned', {
          correlationId,
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          tokenFingerprint: fingerprintToken(device.token),
          sourceHandler: 'server.js#sendNotificationEvent',
          details: {
            ok: !!messageId,
            messageId: messageId || null
          }
        });
      }
      if (!messageId) {
        log.deliveries.push({
          deviceId: device.id,
          ok: false,
          skipped: true,
          error: 'Device token missing. Push send skipped.',
          code: 'missing-token',
          at: new Date().toISOString()
        });
        continue;
      }
      log.deliveries.push({ deviceId: device.id, ok: true, messageId, providerMessageId: messageId, at: new Date().toISOString() });
      if (existingDedupe) {
        existingDedupe.sentAt = new Date().toISOString();
      } else {
        db.notificationPushDedupe.push({
          key: dedupeKey,
          eventType,
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceId: device.id,
          finalPhysicalTarget,
          normalizedTarget: buildPushTargetKey(device),
          sentAt: new Date().toISOString()
        });
      }
    } catch (error) {
      if (eventType === 'trade_group_announcement') {
        logAnnouncementPipelineStage('8.provider_response_returned', {
          correlationId,
          announcementId: context?.announcementId || null,
          recipientUserId: userId,
          deviceRowId: device.id,
          tokenFingerprint: fingerprintToken(device.token),
          sourceHandler: 'server.js#sendNotificationEvent',
          details: {
            ok: false,
            error: error?.message || String(error),
            code: String(error?.code || '')
          }
        });
      }
      device.lastErrorAt = new Date().toISOString();
      device.updatedAt = device.lastErrorAt;
      const code = String(error?.code || '');
      if (code.includes('registration-token-not-registered') || code.includes('invalid-registration-token')) {
        device.isActive = false;
        device.revokedAt = new Date().toISOString();
      }
      log.deliveries.push({
        deviceId: device.id,
        ok: false,
        error: error?.message || String(error),
        details: error?.details || '',
        code,
        stack: error?.stack || '',
        at: new Date().toISOString()
      });
    }
  }
  const cutoffTs = Date.now() - (24 * 60 * 60 * 1000);
  db.notificationPushDedupe = db.notificationPushDedupe.filter((item) => Date.parse(item.sentAt || 0) >= cutoffTs);
  console.info('[Notifications][Pipeline] Notification event persisted.', {
    correlationId,
    eventLogId: log.id,
    eventType,
    eventId: payload.eventId,
    announcementId: context?.announcementId || null,
    groupId: context?.groupId || null,
    recipientUserId: userId,
    attemptedDeliveries: log.deliveries.length,
    executedSends: log.deliveries.filter((entry) => entry.ok && !entry.skipped).length,
    skippedSends: log.deliveries.filter((entry) => entry.skipped).length
  });
  return log;
}

function buildNewsInAppRecord(payload = {}) {
  const nowIso = new Date().toISOString();
  return {
    id: crypto.randomUUID(),
    userId: String(payload.userId || '').trim(),
    newsEventId: String(payload.eventId || ''),
    title: String(payload.title || 'Market update'),
    summary: String(payload.summary || payload.body || ''),
    body: String(payload.body || payload.summary || ''),
    deepLinkUrl: String(payload.deepLinkUrl || '/news.html?tab=for-you'),
    type: String(payload.eventType || 'news_update'),
    badge: String(payload.metadata?.digest ? 'Digest' : 'News'),
    channel: 'in_app',
    metadata: payload.metadata && typeof payload.metadata === 'object' ? payload.metadata : {},
    isRead: false,
    readAt: null,
    deliveredAt: nowIso,
    createdAt: nowIso,
    updatedAt: nowIso
  };
}

async function deliverNewsOutboxInApp(payload) {
  const db = loadDB();
  ensureNewsEventTables(db);
  const record = buildNewsInAppRecord(payload);
  if (!record.userId) {
    return { ok: false, retryable: false, provider: 'in_app', statusCode: 'missing_user', details: 'Missing userId for in-app notification.' };
  }
  db.newsInAppNotifications.push(record);
  saveDB(db);
  return { ok: true, provider: 'in_app', messageId: record.id };
}

function buildNewsPushPayload(payload = {}) {
  return {
    title: String(payload.title || 'Market update'),
    body: String(payload.body || payload.summary || 'New market update is available.'),
    icon: DEFAULT_NOTIFICATION_ICON,
    badge: DEFAULT_NOTIFICATION_ICON,
    tag: `news-${String(payload.eventId || crypto.randomUUID())}`,
    link: String(payload.deepLinkUrl || '/news.html?tab=for-you'),
    data: {
      type: 'news_update',
      eventId: String(payload.eventId || ''),
      userId: String(payload.userId || ''),
      link: String(payload.deepLinkUrl || '/news.html?tab=for-you'),
      category: 'news'
    }
  };
}

async function deliverNewsOutboxPush(payload) {
  const db = loadDB();
  ensureNotificationTables(db);
  const userId = String(payload?.userId || '');
  const devices = db.notificationDevices.filter((item) => item.userId === userId
    && item.isActive !== false
    && getEffectiveNotificationPermissionState(item) === 'granted'
    && String(item.token || '').trim());
  if (!devices.length) {
    return {
      ok: false,
      retryable: false,
      provider: 'push',
      statusCode: 'no_active_devices',
      details: 'No active push devices available.'
    };
  }

  const pushPayload = buildNewsPushPayload(payload);
  const deliveries = [];
  for (const device of devices) {
    try {
      const messageId = await sendNotificationToDevice(db, device, pushPayload);
      deliveries.push({ ok: true, deviceId: device.id, messageId });
    } catch (error) {
      deliveries.push({
        ok: false,
        deviceId: device.id,
        code: String(error?.code || 'push_send_failed'),
        message: error?.message || String(error)
      });
    }
  }
  saveDB(db);
  const success = deliveries.some((item) => item.ok);
  if (!success) {
    const first = deliveries[0] || {};
    const retryable = /unavailable|timeout|quota|internal|temporar/i.test(`${first.code || ''}:${first.message || ''}`);
    return {
      ok: false,
      retryable,
      provider: 'push',
      statusCode: first.code || 'push_send_failed',
      details: first.message || 'Push provider failure.'
    };
  }
  return {
    ok: true,
    provider: 'push',
    messageId: deliveries.find((item) => item.ok)?.messageId || null,
    details: `${deliveries.filter((item) => item.ok).length}/${deliveries.length} device deliveries succeeded.`
  };
}

async function deliverNewsOutboxEmail(payload) {
  const emailAddress = String(loadDB()?.users?.[String(payload?.userId || '')]?.email || '').trim();
  if (!emailAddress) {
    return { ok: false, retryable: false, provider: 'email', statusCode: 'missing_email', details: 'User email unavailable.' };
  }
  if (!nodemailer || !process.env.EMAIL_SERVER || !process.env.EMAIL_PORT || !process.env.EMAIL_USERNAME || !process.env.EMAIL_PASSWORD) {
    console.info('[NewsOutbox][Email] delivery adapter is stubbed due to missing provider configuration.', {
      userId: payload?.userId || null
    });
    return { ok: false, retryable: false, provider: 'email', statusCode: 'provider_not_configured', details: 'Email provider not configured.' };
  }

  const transporter = nodemailer.createTransport({
    host: process.env.EMAIL_SERVER,
    port: Number(process.env.EMAIL_PORT),
    secure: false,
    auth: { user: process.env.EMAIL_USERNAME, pass: process.env.EMAIL_PASSWORD }
  });

  const isDigest = !!payload?.metadata?.digest;
  const subject = isDigest
    ? `Veracity daily digest: ${payload.title || 'News updates'}`
    : `Veracity news alert: ${payload.title || 'Market update'}`;
  try {
    const info = await transporter.sendMail({
      from: process.env.EMAIL_FROM || process.env.EMAIL_USERNAME,
      to: emailAddress,
      subject,
      text: `${payload.body || payload.summary || ''}\n\nOpen in Veracity: ${payload.deepLinkUrl || '/news.html?tab=for-you'}`
    });
    return { ok: true, provider: 'email', messageId: info?.messageId || null };
  } catch (error) {
    const code = String(error?.code || 'email_send_failed');
    const retryable = /timeout|temporar|unavailable|rate|connection/i.test(`${code}:${error?.message || ''}`);
    return { ok: false, retryable, provider: 'email', statusCode: code, details: error?.message || String(error) };
  }
}

async function dispatchNewsOutboxChannel(payload) {
  const channel = String(payload?.channel || '').trim();
  if (channel === 'in_app') return deliverNewsOutboxInApp(payload);
  if (channel === 'push') return deliverNewsOutboxPush(payload);
  if (channel === 'email') return deliverNewsOutboxEmail(payload);
  return { ok: false, retryable: false, provider: channel || 'unknown', statusCode: 'unsupported_channel', details: `Unsupported channel ${channel}` };
}

function buildNewsOutboxStatusSnapshot(db) {
  ensureNewsEventTables(db);
  const rows = Array.isArray(db.newsNotificationOutbox) ? db.newsNotificationOutbox : [];
  const counts = { pending: 0, processing: 0, sent: 0, failed: 0, dead_letter: 0 };
  const countsByChannel = { in_app: 0, push: 0, email: 0 };
  const retryBuckets = { attempts_1: 0, attempts_2_3: 0, attempts_4_plus: 0 };
  const recentErrors = [];

  rows.forEach((row) => {
    const status = String(row?.status || 'pending');
    counts[status] = (counts[status] || 0) + 1;
    const channel = String(row?.channel || 'unknown');
    countsByChannel[channel] = (countsByChannel[channel] || 0) + 1;
    const attempts = Number(row?.attemptCount || 0);
    if (attempts >= 4) retryBuckets.attempts_4_plus += 1;
    else if (attempts >= 2) retryBuckets.attempts_2_3 += 1;
    else if (attempts >= 1) retryBuckets.attempts_1 += 1;
    if (row?.lastErrorCode || row?.lastErrorMessage) {
      recentErrors.push({
        id: row.id,
        channel,
        status,
        lastErrorCode: row.lastErrorCode || null,
        lastErrorMessage: row.lastErrorMessage || null,
        attemptCount: attempts,
        updatedAt: row.updatedAt || null
      });
    }
  });

  return {
    counts,
    countsByChannel,
    retryBuckets,
    recentErrorSummaries: recentErrors
      .sort((a, b) => Date.parse(b.updatedAt || 0) - Date.parse(a.updatedAt || 0))
      .slice(0, 10)
  };
}

// --- helpers ---
function loadDB() {
  try {
    const raw = fs.readFileSync(DB_PATH, 'utf-8');
    const db = JSON.parse(raw);
    db.users ||= {};
    db.sessions ||= {};
    db.verifications ||= {};
    db.emailChangeRequests ||= {};
    if (!Array.isArray(db.instrumentMappings)) {
      db.instrumentMappings = [];
    }
    if (!Array.isArray(db.brokerInstrumentRegistry)) {
      db.brokerInstrumentRegistry = [];
    }
    if (!Array.isArray(db.instrumentResolutionHistory)) {
      db.instrumentResolutionHistory = [];
    }
    if (!Array.isArray(db.brokerSnapshots)) {
      db.brokerSnapshots = [];
    }
    if (!Array.isArray(db.ibkrConnectorTokens)) {
      db.ibkrConnectorTokens = [];
    }
    if (!Array.isArray(db.ibkrConnectorKeys)) {
      db.ibkrConnectorKeys = [];
    }
    if (!Array.isArray(db.investorProfiles)) {
      db.investorProfiles = [];
    }
    if (!Array.isArray(db.investorLogins)) {
      db.investorLogins = [];
    }
    if (!Array.isArray(db.investorProfitSplits)) {
      db.investorProfitSplits = [];
    }
    if (!Array.isArray(db.investorCashflows)) {
      db.investorCashflows = [];
    }
    if (!Array.isArray(db.masterValuations)) {
      db.masterValuations = [];
    }
    if (!Array.isArray(db.investorInvites)) {
      db.investorInvites = [];
    }
    db.investorSessions ||= {};
    ensureTwoFactorTables(db);
    ensureNotificationTables(db);
    ensureNewsEventTables(db);
    ensureSiteAnnouncementTables(db);
    ensureSocialTables(db);
    let mutated = reconcileIbkrTokenSecret(db);
    for (const [username, user] of Object.entries(db.users)) {
      if (ensureUserShape(user, username)) {
        mutated = true;
      }
      if (!user.friendCode) {
        user.friendCode = generateFriendCode(db, username);
        mutated = true;
      }
      const profile = getSocialProfile(db, username);
      const settings = getSocialSettings(db, username);
      if (profile && !db.socialEventLog.some(e => e.event_type === 'social.profile_created' && e.user_id === username)) {
        logSocialEvent(db, { userId: username, actorUserId: username, eventType: 'social.profile_created', entityType: 'social_profile', entityId: profile.id, metadata: { friend_code: profile.friend_code } });
        mutated = true;
      }
    }
    const ownerUsernames = Object.entries(db.users)
      .filter(([username, user]) => getUserRole(user, username) === 'owner')
      .map(([username]) => username);
    if (ownerUsernames.length > 1) {
      console.error(`[Auth] Invalid owner role configuration: multiple owners detected (${ownerUsernames.join(', ')}).`);
    }
    if (mutated) {
      try {
        saveDB(db);
      } catch (error) {
        console.warn('Unable to persist IBKR connector secret migration:', error);
      }
    }
    return db;
  } catch (e) {
    console.warn('Falling back to empty database in loadDB:', e?.message || e);
    return {
      users: {},
      sessions: {},
      instrumentMappings: [],
      brokerInstrumentRegistry: [],
      instrumentResolutionHistory: [],
      brokerSnapshots: [],
      ibkrConnectorTokens: [],
      ibkrConnectorKeys: [],
      investorProfiles: [],
      investorLogins: [],
      investorProfitSplits: [],
      investorCashflows: [],
      masterValuations: [],
      investorInvites: [],
      investorSessions: {},
      twoFactorSetups: {},
      twoFactorLoginChallenges: {},
      notificationDevices: [],
      notificationEvents: [],
      newsEvents: [],
      userNewsPreferences: [],
      userEventDeliveryLog: [],
      newsNotificationOutbox: [],
      newsInAppNotifications: [],
      siteAnnouncements: [],
      siteAnnouncementStates: [],
      socialProfiles: [],
      socialSettings: [],
      friendRequests: [],
      friendships: [],
      tradeShareSettings: [],
      leaderboardStats: [],
      socialEventLog: [],
      watchlists: [],
      watchlistItems: [],
      tradeGroupWatchlists: [],
      watchlistPreviousCloseReferences: {}
    };
  }
}

function saveDB(db) {
  const dir = path.dirname(DB_PATH);
  fs.mkdirSync(dir, { recursive: true });
  const tmp = path.join(
    dir,
    `.tmp-${Date.now()}-${process.pid}-${crypto.randomBytes(4).toString('hex')}`
  );

  const payload = JSON.stringify(db, null, 2);
  try {
    fs.writeFileSync(tmp, payload, 'utf-8');
    fs.renameSync(tmp, DB_PATH);
  } catch (error) {
    console.error('Failed to persist database snapshot:', error);
    throw error;
  } finally {
    if (fs.existsSync(tmp)) {
      try {
        fs.unlinkSync(tmp);
      } catch (cleanupError) {
        console.warn('Could not remove temporary data file:', cleanupError);
      }
    }
  }
  sqliteDb.shadowWrite(db);
}

function getClientIp(req) {
  const forwarded = req.headers['x-forwarded-for'];
  if (typeof forwarded === 'string' && forwarded.length) {
    return forwarded.split(',')[0].trim();
  }
  return req.ip || req.connection?.remoteAddress || 'unknown';
}

function getSessionIdForLogs(token) {
  if (typeof token !== 'string' || !token) return null;
  if (token.length <= 12) return token;
  return `${token.slice(0, 6)}...${token.slice(-4)}`;
}

function applyGuestRateLimit(req) {
  const key = getClientIp(req);
  const now = Date.now();
  const entry = guestRateLimit.get(key);
  if (!entry || entry.resetAt <= now) {
    guestRateLimit.set(key, { count: 1, resetAt: now + GUEST_RATE_LIMIT_WINDOW_MS });
    return null;
  }
  if (entry.count >= GUEST_RATE_LIMIT_MAX) {
    return entry.resetAt - now;
  }
  entry.count += 1;
  return null;
}

function clearSessionsForUser(db, username) {
  const tokens = Object.keys(db.sessions);
  for (const token of tokens) {
    if (db.sessions[token] === username) {
      delete db.sessions[token];
      if (db.sessionMetadata && typeof db.sessionMetadata === 'object') {
        delete db.sessionMetadata[token];
      }
    }
  }
}

function cleanupExpiredGuests(db, now = new Date()) {
  if (!db?.users) return false;
  const nowMs = now.getTime();
  let mutated = false;
  for (const [username, user] of Object.entries(db.users)) {
    if (!user?.guest) continue;
    const expiresAt = Date.parse(user.expiresAt);
    if (Number.isNaN(expiresAt) || expiresAt > nowMs) continue;
    delete db.users[username];
    clearSessionsForUser(db, username);
    mutated = true;
  }
  return mutated;
}

function auth(req, res, next) {
  const token = req.cookies?.[AUTH_COOKIE_NAME];
  if (!token) {
    console.info('[auth] protected request rejected', {
      path: req.originalUrl?.split('?')[0] || req.path,
      reason: 'missing_cookie',
      hasAuthCookie: false
    });
    return res.status(401).json({ error: 'Unauthenticated' });
  }
  const db = loadDB();
  db.sessionMetadata ||= {};
  const username = db.sessions[token];
  if (!username) {
    console.info('[auth] protected request rejected', {
      path: req.originalUrl?.split('?')[0] || req.path,
      reason: 'unknown_session',
      hasAuthCookie: true
    });
    return res.status(401).json({ error: 'Unauthenticated' });
  }
  const user = db.users[username];
  if (!user) {
    console.info('[auth] protected request rejected', {
      path: req.originalUrl?.split('?')[0] || req.path,
      reason: 'missing_user',
      hasAuthCookie: true,
      username
    });
    return res.status(401).json({ error: 'Unauthenticated' });
  }
  if (user.guest && user.expiresAt) {
    const expiresAt = Date.parse(user.expiresAt);
    if (!Number.isNaN(expiresAt) && expiresAt <= Date.now()) {
      delete db.users[username];
      clearSessionsForUser(db, username);
      saveDB(db);
      res.clearCookie(AUTH_COOKIE_NAME, AUTH_COOKIE_OPTIONS);
      return res.status(401).json({
        error: 'Guest session expired. Continue as Guest again or sign up.'
      });
    }
  }
  req.username = username;
  req.user = user;
  req.isGuest = !!user.guest;
  req.authToken = token;
  const sessionMeta = db.sessionMetadata[token];
  if (sessionMeta && typeof sessionMeta === 'object') {
    req.sessionMeta = sessionMeta;
  }
  next();
}

function rejectGuest(req, res) {
  if (req.user?.guest) {
    res.status(403).json({ error: 'Guests cannot perform this action. Please create an account.' });
    return true;
  }
  return false;
}

function asyncHandler(fn) {
  return function wrapped(req, res, next) {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

function ensureInvestorTables(db) {
  db.investorProfiles ||= [];
  db.investorLogins ||= [];
  db.investorProfitSplits ||= [];
  db.investorCashflows ||= [];
  db.masterValuations ||= [];
  db.investorInvites ||= [];
  db.investorSessions ||= {};

  for (const login of db.investorLogins) {
    if (login.password_hash && !login.passwordHash) login.passwordHash = login.password_hash;
    if (login.last_login_at && !login.lastLoginAt) login.lastLoginAt = login.last_login_at;
    if (login.investor_profile_id && !login.investorProfileId) login.investorProfileId = login.investor_profile_id;
  }

  for (const invite of db.investorInvites) {
    if (invite.token_hash && !invite.tokenHash) invite.tokenHash = invite.token_hash;
    if (invite.expires_at && !invite.expiresAt) invite.expiresAt = invite.expires_at;
    if (invite.used_at && !invite.usedAt) invite.usedAt = invite.used_at;
    if (invite.investor_profile_id && !invite.investorProfileId) invite.investorProfileId = invite.investor_profile_id;
  }
}

function appBaseUrl(req) {
  const forwardedProto = typeof req.headers['x-forwarded-proto'] === 'string' ? req.headers['x-forwarded-proto'].split(',')[0].trim() : '';
  const proto = forwardedProto || req.protocol || 'http';
  const host = req.get('host');
  if (!host) return INVESTOR_INVITE_BASE_URL;
  return `${proto}://${host}`;
}

function createSignedToken(payload, ttlMs) {
  const fullPayload = { ...payload, exp: Date.now() + ttlMs };
  const encoded = Buffer.from(JSON.stringify(fullPayload)).toString('base64url');
  const signature = crypto.createHmac('sha256', INVESTOR_TOKEN_SECRET).update(encoded).digest('base64url');
  return `${encoded}.${signature}`;
}

function verifySignedToken(token) {
  if (typeof token !== 'string' || !token.includes('.')) return null;
  const [encoded, signature] = token.split('.');
  if (!encoded || !signature) return null;
  const expected = crypto.createHmac('sha256', INVESTOR_TOKEN_SECRET).update(encoded).digest('base64url');
  if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))) return null;
  let payload;
  try {
    payload = JSON.parse(Buffer.from(encoded, 'base64url').toString('utf8'));
  } catch (error) {
    return null;
  }
  if (!payload?.exp || payload.exp < Date.now()) return null;
  return payload;
}

function hashInviteToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

function normalizeIsoDateInput(input) {
  if (typeof input !== 'string') return null;
  const trimmed = input.trim();
  const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(trimmed);
  if (!match) return null;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  const utcDate = new Date(Date.UTC(year, month - 1, day));
  if (
    utcDate.getUTCFullYear() !== year
    || utcDate.getUTCMonth() !== month - 1
    || utcDate.getUTCDate() !== day
  ) {
    return null;
  }
  return `${match[1]}-${match[2]}-${match[3]}`;
}

function parseInvestorShareBps(rawValue) {
  const parsed = Number(rawValue);
  if (!Number.isInteger(parsed) || parsed < 0 || parsed > 10000) return null;
  return parsed;
}

function findMasterInvestorProfile(db, investorId, masterUserId) {
  const profile = db.investorProfiles.find(p => p.id === investorId);
  if (!profile) return { error: { status: 404, message: 'Investor not found.' } };
  if (profile.masterUserId !== masterUserId) return { error: { status: 403, message: 'Forbidden' } };
  return { profile };
}

function getInvestorProfitSplit(db, investorProfileId) {
  const split = db.investorProfitSplits.find(p => p.investorProfileId === investorProfileId);
  if (split && Number(split.investorShareBps) + Number(split.masterShareBps) === 10000) {
    return split;
  }
  return {
    investorProfileId,
    investorShareBps: 8000,
    masterShareBps: 2000,
    effectiveFrom: new Date().toISOString().slice(0, 10),
    createdAt: new Date().toISOString()
  };
}

function findNavForDate(db, masterUserId, date) {
  const valuations = db.masterValuations
    .filter(v => v.masterUserId === masterUserId && v.valuationDate <= date)
    .sort((a, b) => String(b.valuationDate).localeCompare(String(a.valuationDate)));
  return valuations[0] || null;
}

function latestMasterNav(db, masterUserId) {
  const valuations = db.masterValuations
    .filter(v => v.masterUserId === masterUserId)
    .sort((a, b) => String(a.valuationDate).localeCompare(String(b.valuationDate)));
  return valuations[valuations.length - 1] || null;
}

function roundTo(value, places = 4) {
  if (!Number.isFinite(value)) return 0;
  const factor = 10 ** places;
  return Math.round(value * factor) / factor;
}

function computeInvestorPerformance({ db, masterUserId, investorId }) {
  const profile = db.investorProfiles.find(p => p.id === investorId && p.masterUserId === masterUserId);
  if (!profile) return { error: 'Investor not found.' };
  const navTodayRecord = latestMasterNav(db, masterUserId);
  if (!navTodayRecord) return { error: 'No master valuations recorded yet.' };

  const cashflows = db.investorCashflows
    .filter(c => c.investorProfileId === profile.id)
    .sort((a, b) => String(a.effectiveDate).localeCompare(String(b.effectiveDate)));

  const navToday = Number(navTodayRecord.nav) || 0;
  let totalUnits = 0;
  let depositsTotal = 0;
  let withdrawalsTotal = 0;
  let feesTotal = 0;

  for (const flow of cashflows) {
    const amount = Number(flow.amount) || 0;
    if (amount <= 0) continue;
    const navLookupDate = flow.navReferenceDate || flow.effectiveDate;
    const navRecord = findNavForDate(db, masterUserId, navLookupDate);
    const navAtReference = Number(navRecord?.nav) || 0;
    if (navAtReference <= 0) continue;

    if (flow.type === 'deposit') {
      totalUnits += amount / navAtReference;
      depositsTotal += amount;
    } else if (flow.type === 'withdrawal') {
      totalUnits -= amount / navAtReference;
      withdrawalsTotal += amount;
    } else if (flow.type === 'fee') {
      totalUnits -= amount / navAtReference;
      feesTotal += amount;
    }
  }

  const currentValueGross = totalUnits * navToday;
  const netContributions = depositsTotal - withdrawalsTotal - feesTotal;
  const grossPnl = currentValueGross - netContributions;
  const split = getInvestorProfitSplit(db, profile.id);
  const investorShareBps = Number(split.investorShareBps) || 0;
  const masterShareBps = Number(split.masterShareBps) || 0;
  const investorProfitShare = grossPnl * (investorShareBps / 10000);
  const masterProfitShare = grossPnl - investorProfitShare;
  const investorNetValue = netContributions + investorProfitShare;
  const investorReturnPct = netContributions > 0 ? (investorProfitShare / netContributions) : 0;

  return {
    nav_today: roundTo(navToday),
    total_units: roundTo(totalUnits),
    net_contributions: roundTo(netContributions),
    current_value_gross: roundTo(currentValueGross),
    gross_pnl: roundTo(grossPnl),
    investor_share_bps: investorShareBps,
    master_share_bps: masterShareBps,
    investor_profit_share: roundTo(investorProfitShare),
    master_profit_share: roundTo(masterProfitShare),
    investor_net_value: roundTo(investorNetValue),
    investor_return_pct: roundTo(investorReturnPct)
  };
}

function computeInvestorEquityCurve({ db, masterUserId, investorId, range = 'ALL' }) {
  const profile = db.investorProfiles.find(p => p.id === investorId && p.masterUserId === masterUserId);
  if (!profile) return { error: 'Investor not found.' };

  const rangeDays = range === '1M' ? 31 : range === '3M' ? 93 : range === '1Y' ? 366 : null;
  const minDate = rangeDays
    ? new Date(Date.now() - (rangeDays * 24 * 60 * 60 * 1000)).toISOString().slice(0, 10)
    : null;

  const valuations = db.masterValuations
    .filter(v => v.masterUserId === masterUserId)
    .map(v => ({ date: String(v.valuationDate || ''), nav: Number(v.nav) || 0 }))
    .filter(v => /^\d{4}-\d{2}-\d{2}$/.test(v.date) && v.nav > 0)
    .sort((a, b) => a.date.localeCompare(b.date));

  if (!valuations.length) return { points: [] };

  const cashflows = db.investorCashflows
    .filter(c => c.investorProfileId === profile.id)
    .map(c => ({
      type: c.type,
      amount: Number(c.amount) || 0,
      effectiveDate: String(c.effectiveDate || ''),
      navReferenceDate: String(c.navReferenceDate || c.effectiveDate || '')
    }))
    .filter(c => c.amount > 0 && /^\d{4}-\d{2}-\d{2}$/.test(c.effectiveDate) && /^\d{4}-\d{2}-\d{2}$/.test(c.navReferenceDate))
    .sort((a, b) => a.effectiveDate.localeCompare(b.effectiveDate));

  const navByDate = new Map(valuations.map(v => [v.date, v.nav]));
  const split = getInvestorProfitSplit(db, profile.id);
  const investorShareBps = Number(split.investorShareBps) || 0;
  const points = [];
  let totalUnits = 0;
  let depositsTotal = 0;
  let withdrawalsTotal = 0;
  let feesTotal = 0;
  let flowIndex = 0;

  for (const valuation of valuations) {
    while (flowIndex < cashflows.length && cashflows[flowIndex].effectiveDate <= valuation.date) {
      const flow = cashflows[flowIndex];
      const navAtReference = findNavForDate(db, masterUserId, flow.navReferenceDate)?.nav ?? navByDate.get(flow.navReferenceDate);
      const nav = Number(navAtReference) || 0;
      if (nav > 0) {
        if (flow.type === 'deposit') {
          totalUnits += flow.amount / nav;
          depositsTotal += flow.amount;
        } else if (flow.type === 'withdrawal') {
          totalUnits -= flow.amount / nav;
          withdrawalsTotal += flow.amount;
        } else if (flow.type === 'fee') {
          totalUnits -= flow.amount / nav;
          feesTotal += flow.amount;
        }
      }
      flowIndex += 1;
    }

    const currentValueGross = totalUnits * valuation.nav;
    const netContributions = depositsTotal - withdrawalsTotal - feesTotal;
    const grossPnl = currentValueGross - netContributions;
    const investorProfitShare = grossPnl * (investorShareBps / 10000);
    const investorNetValue = netContributions + investorProfitShare;
    if (!minDate || valuation.date >= minDate) {
      points.push({ date: valuation.date, value: roundTo(investorNetValue) });
    }
  }

  return { points };
}

function requireMasterAuth(req, res, next) {
  return auth(req, res, next);
}

function requireMasterInvestorAccess(req, res, next) {
  if (req.user?.guest) return res.status(403).json({ error: 'Guests cannot perform this action. Please create an account.' });
  if (!req.user?.investorAccountsEnabled) {
    return res.status(403).json({ error: 'Investor accounts are not enabled for this account.' });
  }
  return next();
}

function requireInvestorAuth(req, res, next) {
  const db = loadDB();
  ensureInvestorTables(db);
  let authContext = null;
  const bearer = typeof req.headers.authorization === 'string' && req.headers.authorization.startsWith('Bearer ')
    ? req.headers.authorization.slice(7).trim()
    : '';
  if (bearer) {
    const payload = verifySignedToken(bearer);
    if (payload && payload.role === 'investor_preview') {
      authContext = payload;
    }
  }
  if (!authContext) {
    const investorToken = req.cookies?.investor_session;
    const investorSession = investorToken ? db.investorSessions[investorToken] : null;
    if (investorSession) authContext = investorSession;
  }
  if (!authContext?.investorProfileId) return res.status(401).json({ error: 'Unauthenticated investor session.' });
  const profile = db.investorProfiles.find(p => p.id === authContext.investorProfileId);
  if (!profile || profile.status !== 'active') return res.status(403).json({ error: 'Investor account inactive.' });
  req.investorAuth = authContext;
  req.investorProfile = profile;
  req.investorDb = db;
  next();
}

function ensurePortfolioHistory(user) {
  if (!user) return {};
  if (!user.portfolioHistory || typeof user.portfolioHistory !== 'object') {
    user.portfolioHistory = user.profits && typeof user.profits === 'object'
      ? user.profits
      : {};
    delete user.profits;
  }
  return user.portfolioHistory;
}

function normalizeTradingAccountLabel(value, fallback = '') {
  if (typeof value !== 'string') return fallback;
  return value.trim().slice(0, 40);
}

function ensureTradingAccounts(user) {
  if (!user || typeof user !== 'object') {
    return { mutated: false, accounts: [] };
  }
  let mutated = false;
  if (typeof user.multiTradingAccountsEnabled !== 'boolean') {
    user.multiTradingAccountsEnabled = false;
    mutated = true;
  }
  const existing = Array.isArray(user.tradingAccounts) ? user.tradingAccounts : [];
  const normalized = [];
  const seen = new Set();
  existing.forEach((account, index) => {
    if (!account || typeof account !== 'object') return;
    const rawId = typeof account.id === 'string' ? account.id.trim() : '';
    const id = rawId || crypto.randomBytes(6).toString('hex');
    if (!id || seen.has(id)) return;
    seen.add(id);
    const currentValueRaw = Number(account.currentValue);
    const portfolioValueRaw = Number(account.portfolioValue);
    const currentNetDepositsRaw = Number(account.currentNetDeposits);
    const integrationProviderRaw = typeof account.integrationProvider === 'string' ? account.integrationProvider.trim().toLowerCase() : '';
    const integrationProvider = integrationProviderRaw === 'trading212' || integrationProviderRaw === 'ibkr'
      ? integrationProviderRaw
      : null;
    const integrationEnabled = !!integrationProvider && account.integrationEnabled !== false;
    normalized.push({
      id,
      label: normalizeTradingAccountLabel(account.label, `Account ${index + 1}`),
      accountType: normalizeTradingAccountLabel(account.accountType, 'Trading account'),
      brokerDisplayLabel: normalizeTradingAccountLabel(account.brokerDisplayLabel, ''),
      currentValue: Number.isFinite(currentValueRaw) && currentValueRaw >= 0 ? currentValueRaw : 0,
      portfolioValue: Number.isFinite(portfolioValueRaw) && portfolioValueRaw >= 0
        ? portfolioValueRaw
        : (Number.isFinite(currentValueRaw) && currentValueRaw >= 0 ? currentValueRaw : 0),
      currentNetDeposits: Number.isFinite(currentNetDepositsRaw) ? currentNetDepositsRaw : 0,
      integrationProvider,
      integrationEnabled,
      linkedBrokerAccountId: typeof account.linkedBrokerAccountId === 'string' ? account.linkedBrokerAccountId.trim() : '',
      providerAccountId: typeof account.providerAccountId === 'string' ? account.providerAccountId.trim() : ''
    });
  });
  if (!Array.isArray(user.tradingAccounts) || JSON.stringify(existing) !== JSON.stringify(normalized)) {
    user.tradingAccounts = normalized;
    mutated = true;
  }
  if (!user.multiTradingAccountsEnabled && normalized.length > 1) {
    user.multiTradingAccountsEnabled = true;
    mutated = true;
  }
  return { mutated, accounts: normalized };
}

function resolveTradingAccountId(user, accountId) {
  const { accounts } = ensureTradingAccounts(user);
  const candidate = typeof accountId === 'string' ? accountId.trim() : '';
  if (candidate && accounts.some(account => account.id === candidate)) return candidate;
  return accounts[0]?.id || '';
}

function buildAccountAggregates(accounts = {}) {
  const aggregates = [];
  let end = null;
  let cashIn = 0;
  let cashOut = 0;
  for (const [accountId, raw] of Object.entries(accounts || {})) {
    if (!raw || typeof raw !== 'object') continue;
    const accountEnd = Number(raw.end);
    const accountCashIn = Number(raw.cashIn ?? 0);
    const accountCashOut = Number(raw.cashOut ?? 0);
    const note = typeof raw.note === 'string' ? raw.note.trim() : '';
    const payload = {
      accountId,
      end: Number.isFinite(accountEnd) && accountEnd >= 0 ? accountEnd : null,
      cashIn: Number.isFinite(accountCashIn) && accountCashIn >= 0 ? accountCashIn : 0,
      cashOut: Number.isFinite(accountCashOut) && accountCashOut >= 0 ? accountCashOut : 0,
      note: note || undefined
    };
    if (payload.end !== null || payload.cashIn > 0 || payload.cashOut > 0 || payload.note) {
      aggregates.push(payload);
      if (payload.end !== null) end = (end ?? 0) + payload.end;
      cashIn += payload.cashIn;
      cashOut += payload.cashOut;
    }
  }
  return {
    accounts: aggregates,
    end,
    cashIn,
    cashOut
  };
}

function getIntegratedTradingAccount(user, provider) {
  const { accounts } = ensureTradingAccounts(user);
  const normalizedProvider = provider === 'trading212' || provider === 'ibkr' ? provider : null;
  if (!normalizedProvider) return null;
  if (normalizedProvider === 'trading212') {
    const canonical = resolveCanonicalTrading212OwnerAccount(user);
    if (canonical) return canonical;
  }
  return accounts.find(account => account.integrationEnabled && account.integrationProvider === normalizedProvider) || null;
}

function normalizeCanonicalAccountLabel(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function resolveCanonicalTrading212OwnerAccount(user, options = {}) {
  if (!user || typeof user !== 'object') return null;
  const { accounts } = ensureTradingAccounts(user);
  const cfg = user.trading212 || {};
  const linkedBrokerAccountId = String(options?.brokerAccountId || '').trim();
  const activeBrokerAccounts = getTrading212Accounts(cfg);
  const activeBrokerIdSet = new Set(activeBrokerAccounts.map(account => String(account.id || '').trim()).filter(Boolean));

  const candidates = accounts.filter((account) => {
    if (!account || typeof account !== 'object') return false;
    const provider = String(account.integrationProvider || '').toLowerCase();
    const linkedId = String(account.linkedBrokerAccountId || account.providerAccountId || '').trim();
    if (provider === 'trading212' && account.integrationEnabled) {
      if (!linkedBrokerAccountId) return true;
      return linkedId === linkedBrokerAccountId || (!linkedId && activeBrokerIdSet.size === 1);
    }
    return false;
  });
  if (linkedBrokerAccountId) {
    const linkedMatch = candidates.find((account) => (
      String(account.linkedBrokerAccountId || account.providerAccountId || '').trim() === linkedBrokerAccountId
    ));
    if (linkedMatch) return linkedMatch;
  }

  const brokerAccountLabel = normalizeCanonicalAccountLabel(
    activeBrokerAccounts.find(account => String(account.id || '').trim() === linkedBrokerAccountId)?.label
    || activeBrokerAccounts[0]?.label
    || ''
  );
  if (brokerAccountLabel) {
    const labelMatched = accounts.find((account) => normalizeCanonicalAccountLabel(account.label) === brokerAccountLabel);
    if (labelMatched) return labelMatched;
  }

  if (candidates.length) return candidates[0];
  if (linkedBrokerAccountId) {
    const idMatched = accounts.find(account => account.id === linkedBrokerAccountId);
    if (idMatched) return idMatched;
  }
  return null;
}

function reconcileTrading212IntegrationOwnership(user, options = {}) {
  if (!user || typeof user !== 'object') return { mutated: false, migrations: [], canonicalOwnerAccountId: null };
  ensureTradingAccounts(user);
  ensureTrading212Config(user);
  const cfg = user.trading212 || {};
  let tradingAccounts = Array.isArray(user.tradingAccounts) ? user.tradingAccounts : [];
  const activeBrokerAccounts = getTrading212Accounts(cfg);
  const activeBrokerIdSet = new Set(activeBrokerAccounts.map(account => String(account.id || '').trim()).filter(Boolean));
  const migrations = [];
  let mutated = false;

  const ensureCanonicalOwnerForBrokerAccount = (brokerAccount) => {
    tradingAccounts = Array.isArray(user.tradingAccounts) ? user.tradingAccounts : [];
    const brokerAccountId = String(brokerAccount?.id || '').trim();
    if (!brokerAccountId) return null;
    const ownerCandidates = tradingAccounts.filter((account) => (
      account
      && String(account.integrationProvider || '').toLowerCase() === 'trading212'
      && account.integrationEnabled
      && String(account.linkedBrokerAccountId || account.providerAccountId || '').trim() === brokerAccountId
    ));
    let canonical = ownerCandidates[0] || null;
    if (!canonical) {
      const normalizedBrokerLabel = normalizeCanonicalAccountLabel(brokerAccount?.label || '');
      if (normalizedBrokerLabel) {
        canonical = tradingAccounts.find(account => normalizeCanonicalAccountLabel(account?.label) === normalizedBrokerLabel) || null;
      }
    }
    if (!canonical) {
      canonical = tradingAccounts.find(account => account?.id === brokerAccountId) || null;
    }
    if (!canonical) {
      canonical = {
        id: crypto.randomBytes(6).toString('hex'),
        label: brokerAccount.label || 'Trading 212',
        accountType: 'Trading account',
        brokerDisplayLabel: 'Trading 212',
        currentValue: 0,
        currentNetDeposits: 0,
        integrationProvider: 'trading212',
        integrationEnabled: true,
        linkedBrokerAccountId: brokerAccountId,
        providerAccountId: brokerAccountId
      };
      tradingAccounts.push(canonical);
      mutated = true;
      migrations.push({ type: 'create_owner', brokerAccountId, toAccountId: canonical.id });
    }

    const canonicalLinkedId = String(canonical.linkedBrokerAccountId || canonical.providerAccountId || '').trim();
    if (String(canonical.integrationProvider || '').toLowerCase() !== 'trading212' || canonical.integrationEnabled !== true || canonicalLinkedId !== brokerAccountId) {
      canonical.integrationProvider = 'trading212';
      canonical.integrationEnabled = true;
      canonical.linkedBrokerAccountId = brokerAccountId;
      canonical.providerAccountId = brokerAccountId;
      if (!String(canonical.brokerDisplayLabel || '').trim()) canonical.brokerDisplayLabel = 'Trading 212';
      mutated = true;
      migrations.push({ type: 'promote_owner', brokerAccountId, toAccountId: canonical.id });
    }

    tradingAccounts.forEach((account) => {
      if (!account || account.id === canonical.id) return;
      const linkedId = String(account.linkedBrokerAccountId || account.providerAccountId || '').trim();
      const isDuplicateOwner = String(account.integrationProvider || '').toLowerCase() === 'trading212'
        && account.integrationEnabled
        && linkedId === brokerAccountId;
      if (!isDuplicateOwner) return;
      account.integrationProvider = null;
      account.integrationEnabled = false;
      account.linkedBrokerAccountId = '';
      account.providerAccountId = '';
      mutated = true;
      migrations.push({ type: 'demote_duplicate_owner', brokerAccountId, fromAccountId: account.id, toAccountId: canonical.id });
    });
    return canonical;
  };

  const canonicalOwners = activeBrokerAccounts
    .map(ensureCanonicalOwnerForBrokerAccount)
    .filter(Boolean);

  const canonicalOwnerAccountId = canonicalOwners[0]?.id || null;
  if (canonicalOwnerAccountId && activeBrokerAccounts.length === 1) {
    const history = ensurePortfolioHistory(user);
    const knownLocalAccountIds = new Set(tradingAccounts.map(account => account.id));
    for (const days of Object.values(history || {})) {
      for (const record of Object.values(days || {})) {
        if (!record || typeof record !== 'object' || !record.accounts || typeof record.accounts !== 'object') continue;
        const accountEntries = record.accounts;
        const canonicalEntry = accountEntries[canonicalOwnerAccountId];
        if (canonicalEntry && typeof canonicalEntry === 'object') continue;
        for (const [candidateId, candidateEntry] of Object.entries(accountEntries)) {
          if (candidateId === canonicalOwnerAccountId) continue;
          if (knownLocalAccountIds.has(candidateId)) continue;
          if (!candidateEntry || typeof candidateEntry !== 'object') continue;
          const end = Number(candidateEntry.end);
          if (!Number.isFinite(end) || end < 0) continue;
          accountEntries[canonicalOwnerAccountId] = {
            end,
            cashIn: Number.isFinite(Number(candidateEntry.cashIn)) ? Number(candidateEntry.cashIn) : 0,
            cashOut: Number.isFinite(Number(candidateEntry.cashOut)) ? Number(candidateEntry.cashOut) : 0
          };
          delete accountEntries[candidateId];
          mutated = true;
          migrations.push({ type: 'history_relink', fromAccountId: candidateId, toAccountId: canonicalOwnerAccountId });
          break;
        }
      }
    }
  }

  tradingAccounts.forEach((account) => {
    if (!account) return;
    if (String(account.integrationProvider || '').toLowerCase() !== 'trading212') return;
    const linkedId = String(account.linkedBrokerAccountId || account.providerAccountId || '').trim();
    if (!linkedId) return;
    if (activeBrokerIdSet.has(linkedId)) return;
    account.integrationProvider = null;
    account.integrationEnabled = false;
    account.linkedBrokerAccountId = '';
    account.providerAccountId = '';
    mutated = true;
    migrations.push({ type: 'remove_stale_owner_link', fromAccountId: account.id, brokerAccountId: linkedId });
  });

  if (migrations.length || options.logDiagnostics) {
    const valuationOwner = getIntegratedTradingAccount(user, 'trading212');
    console.info('[T212][ownership]', {
      reason: options.reason || 'unspecified',
      canonicalOwnerAccountId,
      valuationOwnerAccountId: valuationOwner?.id || null,
      brokerAccounts: activeBrokerAccounts.map(account => ({ id: account.id, label: account.label })),
      migrations,
      tradingAccounts: tradingAccounts.map((account) => ({
        id: account.id,
        label: account.label,
        provider: account.integrationProvider,
        integrationEnabled: !!account.integrationEnabled,
        linkedBrokerAccountId: account.linkedBrokerAccountId || '',
        providerAccountId: account.providerAccountId || ''
      }))
    });
  }
  return { mutated, migrations, canonicalOwnerAccountId };
}

function applyAccountAggregatesToHistoryEntry(entry = {}) {
  const nextEntry = entry && typeof entry === 'object' ? entry : {};
  const accountMap = nextEntry.accounts && typeof nextEntry.accounts === 'object' ? nextEntry.accounts : null;
  if (!accountMap) return nextEntry;
  const aggregate = buildAccountAggregates(accountMap);
  if (aggregate.end !== null) {
    nextEntry.end = aggregate.end;
  }
  nextEntry.cashIn = aggregate.cashIn;
  nextEntry.cashOut = aggregate.cashOut;
  return nextEntry;
}

function findLatestAccountEndBeforeDate(history, accountId, beforeDateKey) {
  let latest = null;
  for (const days of Object.values(history || {})) {
    for (const [dateKey, record] of Object.entries(days || {})) {
      if (!record || typeof record !== 'object' || dateKey >= beforeDateKey) continue;
      const accountMap = record.accounts && typeof record.accounts === 'object' ? record.accounts : null;
      if (!accountMap) continue;
      const accountRecord = accountMap[accountId];
      if (!accountRecord || typeof accountRecord !== 'object') continue;
      const end = Number(accountRecord.end);
      if (!Number.isFinite(end) || end < 0) continue;
      if (!latest || dateKey > latest.dateKey) {
        latest = { dateKey, end };
      }
    }
  }
  return latest;
}

function carryForwardTradingAccountDayValues(user, history, dateKey, payload, sourceAccountId) {
  if (!payload || typeof payload !== 'object') return false;
  ensureTradingAccounts(user);
  const accounts = Array.isArray(user.tradingAccounts) ? user.tradingAccounts : [];
  if (!accounts.length) return false;

  const existingAccounts = payload.accounts && typeof payload.accounts === 'object' ? payload.accounts : {};
  const nextAccounts = { ...existingAccounts };
  let mutated = false;

  for (const account of accounts) {
    if (!account?.id || account.id === sourceAccountId) continue;
    const currentRecord = nextAccounts[account.id] && typeof nextAccounts[account.id] === 'object'
      ? nextAccounts[account.id]
      : null;
    const currentEnd = Number(currentRecord?.end);
    if (Number.isFinite(currentEnd) && currentEnd >= 0) continue;

    const latest = findLatestAccountEndBeforeDate(history, account.id, dateKey);
    if (!latest) continue;

    nextAccounts[account.id] = {
      ...currentRecord,
      end: latest.end,
      cashIn: Number.isFinite(Number(currentRecord?.cashIn)) && Number(currentRecord.cashIn) >= 0 ? Number(currentRecord.cashIn) : 0,
      cashOut: Number.isFinite(Number(currentRecord?.cashOut)) && Number(currentRecord.cashOut) >= 0 ? Number(currentRecord.cashOut) : 0
    };
    mutated = true;
  }

  if (!mutated) return false;
  payload.accounts = nextAccounts;
  return true;
}

function syncIntegratedTradingAccountValuesFromHistory(user, history = ensurePortfolioHistory(user)) {
  if (!user || typeof user !== 'object') return false;
  ensureTradingAccounts(user);
  const accountList = Array.isArray(user.tradingAccounts) ? user.tradingAccounts : [];
  const integratedAccounts = accountList.filter(account => account.integrationEnabled && account.integrationProvider);
  if (!integratedAccounts.length) return false;

  const latestEndByAccount = new Map();
  for (const days of Object.values(history || {})) {
    for (const [dateKey, record] of Object.entries(days || {})) {
      if (!record || typeof record !== 'object') continue;
      const accountMap = record.accounts && typeof record.accounts === 'object' ? record.accounts : null;
      if (!accountMap) continue;
      integratedAccounts.forEach(account => {
        const accountRecord = accountMap[account.id];
        if (!accountRecord || typeof accountRecord !== 'object') return;
        const endRaw = Number(accountRecord.end);
        if (!Number.isFinite(endRaw) || endRaw < 0) return;
        const existing = latestEndByAccount.get(account.id);
        if (!existing || dateKey > existing.dateKey) {
          latestEndByAccount.set(account.id, { dateKey, end: endRaw });
        }
      });
    }
  }

  let mutated = false;
  integratedAccounts.forEach(account => {
    const latest = latestEndByAccount.get(account.id);
    if (!latest) return;
    if (Number(account.currentValue) !== latest.end) {
      account.currentValue = latest.end;
      mutated = true;
    }
  });
  return mutated;
}

function logPortfolioAttribution(stage, user, extra = {}) {
  try {
    const accounts = Array.isArray(user?.tradingAccounts)
      ? user.tradingAccounts.map(account => ({
        id: account?.id || '',
        provider: account?.integrationProvider || null,
        integrationEnabled: !!account?.integrationEnabled,
        currentValue: Number(account?.currentValue) || 0
      }))
      : [];
    const aggregateFromAccounts = accounts.reduce((sum, account) => sum + (Number(account.currentValue) || 0), 0);
    console.info(`[portfolio][attribution][${stage}]`, {
      aggregateFromAccounts,
      accounts,
      ...extra
    });
  } catch (error) {
    console.warn('[portfolio][attribution] failed to serialize attribution log', error);
  }
}


function buildProfileCompletionSummary(user, portfolioValue, netDepositsTotal) {
  const accountList = Array.isArray(user?.tradingAccounts) ? user.tradingAccounts : [];
  const linkedTradingAccounts = accountList.filter(account => account?.integrationEnabled && (account?.integrationProvider === 'trading212' || account?.integrationProvider === 'ibkr'));
  const linkedTradingAccountsCount = linkedTradingAccounts.length;
  const hasTradingAccount = linkedTradingAccountsCount > 0;
  const checklist = [
    { key: 'username', ok: Boolean(user?.username) },
    { key: 'nickname', ok: Boolean(String(user?.nickname || user?.displayName || '').trim()) },
    { key: 'avatar', ok: Boolean(socialAvatarForUser(user).avatar_url) },
    { key: 'portfolio baseline', ok: Number.isFinite(Number(portfolioValue)) && Number.isFinite(Number(netDepositsTotal)) },
    { key: 'trading account', ok: hasTradingAccount }
  ];
  const completed = checklist.filter(item => item.ok).length;
  const profileCompletionPercent = Math.round((completed / checklist.length) * 100);
  const missingProfileFields = checklist.filter(item => !item.ok).map(item => item.key);
  return {
    linkedTradingAccountsCount,
    hasTradingAccount,
    profileCompletionPercent,
    missingProfileFields
  };
}

function ensureTradeJournal(user) {
  if (!user) return {};
  if (!user.tradeJournal || typeof user.tradeJournal !== 'object') {
    user.tradeJournal = {};
  }
  return user.tradeJournal;
}

function extractTradeOpenDate(trade) {
  if (!trade || typeof trade !== 'object') return '';
  const cleanDate = /^\d{4}-\d{2}-\d{2}$/;
  if (typeof trade.openDate === 'string' && cleanDate.test(trade.openDate)) return trade.openDate;
  if (typeof trade.entryDate === 'string' && cleanDate.test(trade.entryDate)) return trade.entryDate;
  if (typeof trade.createdAt === 'string' && trade.createdAt.length >= 10) return trade.createdAt.slice(0, 10);
  return '';
}

function buildJournalViewFromTrades(user) {
  const out = {};
  for (const trade of (Array.isArray(user?.trades) ? user.trades : [])) {
    if (!trade || typeof trade !== 'object') continue;
    const dateKey = extractTradeOpenDate(trade);
    if (!dateKey) continue;
    if (!out[dateKey]) out[dateKey] = [];
    out[dateKey].push(trade);
  }
  return out;
}

function ensureImportBatches(user) {
  if (!user) return [];
  if (!Array.isArray(user.importBatches)) {
    user.importBatches = [];
  }
  return user.importBatches;
}

function ensureTrading212Config(user) {
  if (!user) return { mutated: false, config: {} };
  let mutated = false;
  if (!user.trading212 || typeof user.trading212 !== 'object') {
    user.trading212 = {};
    mutated = true;
  }
  const cfg = user.trading212;
  if (!Array.isArray(cfg.accounts)) {
    cfg.accounts = [];
    mutated = true;
  }
  if (typeof cfg.enabled !== 'boolean') {
    cfg.enabled = false;
    mutated = true;
  }
  if (typeof cfg.apiKey !== 'string') {
    cfg.apiKey = '';
    mutated = true;
  }
  if (typeof cfg.apiSecret !== 'string') {
    cfg.apiSecret = '';
    mutated = true;
  }
  if (typeof cfg.baseUrl !== 'string') {
    cfg.baseUrl = '';
    mutated = true;
  }
  if (typeof cfg.endpoint !== 'string' || !cfg.endpoint.trim()) {
    cfg.endpoint = '/api/v0/equity/portfolio/summary';
    mutated = true;
  } else if (!cfg.endpoint.startsWith('/')) {
    cfg.endpoint = `/${cfg.endpoint.replace(/^\/+/, '')}`;
    mutated = true;
  }
  if (typeof cfg.snapshotTime !== 'string' || !/^([01]\d|2[0-3]):[0-5]\d$/.test(cfg.snapshotTime)) {
    cfg.snapshotTime = '21:00';
    mutated = true;
  }
  if (typeof cfg.mode !== 'string' || !['live', 'practice'].includes(cfg.mode)) {
    cfg.mode = 'live';
    mutated = true;
  }
  if (typeof cfg.timezone !== 'string' || !cfg.timezone) {
    cfg.timezone = 'Europe/London';
    mutated = true;
  }
  if (cfg.cooldownUntil !== undefined) {
    const ts = Date.parse(cfg.cooldownUntil);
    if (Number.isNaN(ts)) {
      delete cfg.cooldownUntil;
      mutated = true;
    }
  }
  if (cfg.lastBaseUrl !== undefined && typeof cfg.lastBaseUrl !== 'string') {
    delete cfg.lastBaseUrl;
    mutated = true;
  }
  if (cfg.lastEndpoint !== undefined && typeof cfg.lastEndpoint !== 'string') {
    delete cfg.lastEndpoint;
    mutated = true;
  }
  if (cfg.lastNetDeposits !== undefined && !Number.isFinite(Number(cfg.lastNetDeposits))) {
    delete cfg.lastNetDeposits;
    mutated = true;
  }
  // Legacy Trading 212 cashflow automation markers are intentionally removed.
  // Historical cashflow rows are preserved as-is to avoid destructive migration.
  ['processedReferences', 'lastTransactionAt', 'integrationEnabledAt'].forEach((legacyKey) => {
    if (legacyKey in cfg) {
      delete cfg[legacyKey];
      mutated = true;
    }
  });
  if (!cfg.symbolOverrides || typeof cfg.symbolOverrides !== 'object' || Array.isArray(cfg.symbolOverrides)) {
    cfg.symbolOverrides = {};
    mutated = true;
  }
  if (!cfg.historySync || typeof cfg.historySync !== 'object' || Array.isArray(cfg.historySync)) {
    cfg.historySync = { accounts: {} };
    mutated = true;
  } else if (!cfg.historySync.accounts || typeof cfg.historySync.accounts !== 'object' || Array.isArray(cfg.historySync.accounts)) {
    cfg.historySync.accounts = {};
    mutated = true;
  }
  if (!cfg.syncState || typeof cfg.syncState !== 'object' || Array.isArray(cfg.syncState)) {
    cfg.syncState = { accounts: {} };
    mutated = true;
  } else if (!cfg.syncState.accounts || typeof cfg.syncState.accounts !== 'object' || Array.isArray(cfg.syncState.accounts)) {
    cfg.syncState.accounts = {};
    mutated = true;
  }
  const accounts = Array.isArray(cfg.accounts) ? cfg.accounts : [];
  const normalizedAccounts = accounts
    .filter(account => account && typeof account === 'object')
    .map(account => ({
      id: typeof account.id === 'string' && account.id.trim() ? account.id.trim() : crypto.randomBytes(6).toString('hex'),
      label: typeof account.label === 'string' ? account.label.trim() : (typeof account.accountLabel === 'string' ? account.accountLabel.trim() : ''),
      encryptedApiKey: typeof account.encryptedApiKey === 'string' ? account.encryptedApiKey : encryptBrokerCredential(account.apiKey),
      encryptedApiSecret: typeof account.encryptedApiSecret === 'string' ? account.encryptedApiSecret : encryptBrokerCredential(account.apiSecret),
      connectionStatus: typeof account.connectionStatus === 'string' ? account.connectionStatus : (account.apiKey && account.apiSecret ? 'connected' : 'disconnected'),
      syncStatus: typeof account.syncStatus === 'string' ? account.syncStatus : 'idle',
      lastSyncAt: typeof account.lastSyncAt === 'string' ? account.lastSyncAt : null,
      providerAccountType: typeof account.providerAccountType === 'string' ? account.providerAccountType : '',
      providerMetadata: account.providerMetadata && typeof account.providerMetadata === 'object' && !Array.isArray(account.providerMetadata)
        ? account.providerMetadata
        : {},
      createdAt: typeof account.createdAt === 'string' ? account.createdAt : new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      active: typeof account.active === 'boolean' ? account.active : true,
      mode: typeof account.mode === 'string' && ['live', 'practice'].includes(account.mode) ? account.mode : undefined,
      baseUrl: typeof account.baseUrl === 'string' ? account.baseUrl.trim() : ''
    }))
    .filter(account => account.encryptedApiKey || account.encryptedApiSecret || account.label);
  if (normalizedAccounts.length !== accounts.length) {
    cfg.accounts = normalizedAccounts;
    mutated = true;
  } else {
    cfg.accounts = normalizedAccounts;
  }
  if (!cfg.accounts.length && (cfg.apiKey || cfg.apiSecret)) {
    cfg.accounts = [{
      id: 'primary',
      label: '',
      encryptedApiKey: encryptBrokerCredential(cfg.apiKey),
      encryptedApiSecret: encryptBrokerCredential(cfg.apiSecret),
      connectionStatus: cfg.apiKey && cfg.apiSecret ? 'connected' : 'disconnected',
      syncStatus: 'idle',
      lastSyncAt: cfg.lastSyncAt || null,
      providerAccountType: '',
      providerMetadata: {},
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      active: true
    }];
    mutated = true;
  }
  if (cfg.accounts.length) {
    if (cfg.apiKey || cfg.apiSecret) {
      mutated = true;
    }
    cfg.apiKey = '';
    cfg.apiSecret = '';
  }
  return { mutated, config: cfg };
}

function getTrading212Accounts(cfg) {
  if (!cfg) return [];
  const accounts = Array.isArray(cfg.accounts) ? cfg.accounts : [];
  return accounts
    .map((account, index) => {
      const apiKey = decryptBrokerCredential(account?.encryptedApiKey || account?.apiKey || '');
      const apiSecret = decryptBrokerCredential(account?.encryptedApiSecret || account?.apiSecret || '');
      return {
        ...account,
        id: account?.id || `account-${index + 1}`,
        label: account?.label || account?.accountLabel || '',
        apiKey,
        apiSecret,
        active: account?.active !== false
      };
    })
    .filter(account => account.active && account.apiKey && account.apiSecret);
}

function resolveTrading212AccountForTrade(cfg, trade) {
  const accounts = getTrading212Accounts(cfg);
  if (!accounts.length) return null;
  const accountId = trade?.trading212AccountId;
  if (accountId) {
    const matched = accounts.find(account => account?.id === accountId);
    return matched || accounts[0];
  }
  return accounts[0];
}

function toBrokerAccountSummary(username, provider, account, integrationCfg = {}) {
  const accountId = account?.id || crypto.randomBytes(6).toString('hex');
  const syncState = integrationCfg?.syncState?.accounts?.[accountId] || {};
  const accountLastStatus = syncState?.lastStatus || null;
  return {
    userId: username,
    provider,
    brokerAccountId: accountId,
    accountLabel: account?.label || '',
    hasApiKey: !!decryptBrokerCredential(account?.encryptedApiKey || account?.apiKey || ''),
    hasApiSecret: !!decryptBrokerCredential(account?.encryptedApiSecret || account?.apiSecret || ''),
    credentialsMasked: {
      apiKey: account?.encryptedApiKey ? '••••••••' : '',
      apiSecret: account?.encryptedApiSecret ? '••••••••' : ''
    },
    connectionStatus: account?.connectionStatus || (account?.active === false ? 'disconnected' : 'connected'),
    accountType: account?.providerAccountType || '',
    lastSyncAt: account?.lastSyncAt || syncState?.lastSuccessfulSyncAt || null,
    syncStatus: account?.syncStatus || syncState?.status || 'idle',
    syncDiagnostics: {
      lastStatus: accountLastStatus,
      cooldownUntil: syncState?.endpoints?.historyOrders?.cooldownUntil || syncState?.endpoints?.orders?.cooldownUntil || null,
      lastFailureAt: syncState?.lastFailureAt || null,
      lastSuccessAt: syncState?.lastSuccessfulSyncAt || null
    },
    active: account?.active !== false,
    createdAt: account?.createdAt || null,
    updatedAt: account?.updatedAt || null,
    providerMetadata: account?.providerMetadata && typeof account.providerMetadata === 'object' ? account.providerMetadata : {}
  };
}

