function upsertIbkrStopOrders(user, ordersPayload) {
  const orders = parseIbkrOrders(ordersPayload);
  const journal = ensureTradeJournal(user);
  let updated = 0;
  for (const items of Object.values(journal)) {
    for (const trade of items || []) {
      if (!trade || trade.status === 'closed') continue;
      if (trade.source !== 'ibkr' && !trade.ibkrPositionId) continue;
      const matched = matchIbkrStopOrderForTrade(trade, orders);
      const shouldAutoSync = trade.currentStopSource !== 'manual';
      if (!matched || !Number.isFinite(matched.stopPrice)) {
        if (!shouldAutoSync) continue;
        const hadStop = Number.isFinite(Number(trade.currentStop));
        if (!hadStop && trade.currentStopStale === true) continue;
        delete trade.currentStop;
        trade.currentStopSource = 'ibkr';
        trade.currentStopLastSyncedAt = new Date().toISOString();
        trade.currentStopStale = true;
        trade.ibkrStopOrderId = '';
        updated += 1;
        continue;
      }
      const stopPrice = Number(matched.stopPrice);
      const shouldUpdate = shouldAutoSync
        && (!Number.isFinite(Number(trade.currentStop))
          || Number(trade.currentStop) !== stopPrice
          || trade.currentStopStale === true
          || trade.ibkrStopOrderId !== (matched.id || ''));
      if (!shouldUpdate) continue;
      trade.currentStop = stopPrice;
      trade.currentStopSource = 'ibkr';
      trade.currentStopLastSyncedAt = new Date().toISOString();
      trade.currentStopStale = false;
      trade.ibkrStopOrderId = matched.id || '';
      updated += 1;
    }
  }
  return { updated, orders };
}

function resolveMappedBrokerTicker(db, username, displayTicker) {
  const trimmed = String(displayTicker || '').trim().toUpperCase();
  if (!trimmed) return '';
  const mappings = ensureInstrumentMappings(db);
  const userMapping = mappings.find(mapping => (
    mapping?.status === 'active'
    && mapping.scope === 'user'
    && mapping.user_id === username
    && String(mapping.canonical_ticker || '').toUpperCase() === trimmed
  ));
  if (userMapping?.broker_ticker) return String(userMapping.broker_ticker).trim().toUpperCase();
  const globalMapping = mappings.find(mapping => (
    mapping?.status === 'active'
    && mapping.scope === 'global'
    && !mapping.user_id
    && String(mapping.canonical_ticker || '').toUpperCase() === trimmed
  ));
  return globalMapping?.broker_ticker ? String(globalMapping.broker_ticker).trim().toUpperCase() : '';
}

function pickBestStopOrder(orders, trade) {
  if (!orders.length) return null;
  const tradeQty = Number(trade.sizeUnits);
  const scored = orders.map(order => {
    const orderQty = Number.isFinite(order.quantity) ? Math.abs(order.quantity) : null;
    const qtyDiff = (Number.isFinite(tradeQty) && Number.isFinite(orderQty))
      ? Math.abs(orderQty - tradeQty)
      : Infinity;
    const createdAt = Date.parse(order.createdAt || '');
    return {
      order,
      qtyDiff,
      createdAt: Number.isFinite(createdAt) ? createdAt : 0
    };
  });
  scored.sort((a, b) => {
    if (a.qtyDiff !== b.qtyDiff) return a.qtyDiff - b.qtyDiff;
    return b.createdAt - a.createdAt;
  });
  return scored[0]?.order || null;
}

function normalizeOrderQuantity(value) {
  const qty = Number(value);
  return Number.isFinite(qty) ? Math.abs(qty) : null;
}

function quantitiesMatch(a, b) {
  const left = Number(a);
  const right = Number(b);
  if (!Number.isFinite(left) || !Number.isFinite(right)) return false;
  return Math.abs(left - right) <= 1e-8;
}

function findRelatedTrading212Trades(openTrades, trade, accountId = '') {
  const allTrades = Array.isArray(openTrades) ? openTrades : [];
  return allTrades.filter(candidate => {
    if (!candidate || candidate.id === trade.id) return false;
    if (accountId && candidate.trading212AccountId && candidate.trading212AccountId !== accountId) return false;
    const samePositionKey = trade.trading212PositionKey && candidate.trading212PositionKey && trade.trading212PositionKey === candidate.trading212PositionKey;
    const sameTicker = normalizeTrading212TickerValue(trade.trading212Ticker || '')
      && normalizeTrading212TickerValue(trade.trading212Ticker || '') === normalizeTrading212TickerValue(candidate.trading212Ticker || '');
    const sameIsin = trade.trading212Isin && candidate.trading212Isin && String(trade.trading212Isin).toUpperCase() === String(candidate.trading212Isin).toUpperCase();
    const sameSymbol = trade.symbol && candidate.symbol && String(trade.symbol).toUpperCase() === String(candidate.symbol).toUpperCase();
    return samePositionKey || sameTicker || sameIsin || sameSymbol;
  });
}

function matchStopOrderForTrade(trade, orders, context = {}) {
  if (!trade || !orders.length) return null;
  if (trade.t212StopOrderId) {
    const found = orders.find(order => order.id && order.id === trade.t212StopOrderId);
    if (found) return found;
  }
  const tradeTicker = normalizeTrading212TickerValue(trade.trading212Ticker || '');
  const tradeSymbol = normalizeTrading212Symbol(
    trade.trading212Ticker || trade.symbol || trade.displaySymbol || ''
  );
  const tradeIsin = String(trade.trading212Isin || '').trim().toUpperCase();
  const filtered = orders.filter(order => {
    const orderTicker = normalizeTrading212TickerValue(order.instrumentTicker || '');
    const orderSymbol = normalizeTrading212Symbol(order.instrumentTicker || '');
    if (tradeTicker && orderTicker && orderTicker === tradeTicker) return true;
    if (tradeSymbol && orderSymbol && orderSymbol === tradeSymbol) return true;
    if (tradeIsin && String(order.instrumentIsin || '').trim().toUpperCase() === tradeIsin) return true;
    return false;
  });
  if (!filtered.length) return null;
  const tradeQty = normalizeOrderQuantity(trade.sizeUnits);
  const exactQtyOrders = Number.isFinite(tradeQty)
    ? filtered.filter(order => quantitiesMatch(normalizeOrderQuantity(order.quantity), tradeQty))
    : [];
  if (exactQtyOrders.length) {
    return pickBestStopOrder(exactQtyOrders, trade);
  }
  const relatedTrades = Array.isArray(context.relatedTrades) ? context.relatedTrades : [];
  if (relatedTrades.length > 1) {
    const combinedQty = relatedTrades.reduce((sum, item) => {
      const units = Number(item?.sizeUnits);
      return Number.isFinite(units) && units > 0 ? sum + units : sum;
    }, 0);
    const combinedQtyOrders = combinedQty > 0
      ? filtered.filter(order => quantitiesMatch(normalizeOrderQuantity(order.quantity), combinedQty))
      : [];
    if (combinedQtyOrders.length) {
      return pickBestStopOrder(combinedQtyOrders, { ...trade, sizeUnits: combinedQty });
    }
  }
  return pickBestStopOrder(filtered, trade);
}

async function fetchTrading212Orders(config, username, { bypassCache = false, accountId = '' } = {}) {
  if (!config?.apiKey || !config?.apiSecret) {
    throw new Trading212AuthError('Trading 212 credentials are incomplete.', { status: 401 });
  }
  const baseUrl = resolveTrading212BaseUrl(config);
  const endpoint = '/api/v0/equity/orders';
  const cacheKey = `${String(username || '')}|${String(accountId || '')}|${baseUrl}|${endpoint}`;
  const cached = trading212OrdersCache.get(cacheKey);
  if (!bypassCache && cached && Date.now() - cached.fetchedAt < TRADING212_ORDERS_CACHE_MS) {
    console.info(`[T212] cache hit orders key=${cacheKey}`);
    return {
      raw: cached.raw,
      orders: cached.orders,
      rawCount: cached.rawCount,
      filteredCount: cached.filteredCount,
      fromCache: true
    };
  }
  console.info(`[T212] cache miss orders key=${cacheKey}`);
  const headers = buildTrading212AuthHeaders(config);
  const url = `${baseUrl}${endpoint}`;
  console.info(`[T212] baseUrl=${baseUrl} endpoint=${endpoint}`);
  const upstream = await requestTrading212RawEndpoint(url, headers, {
    includeMeta: true,
    signal: AbortSignal.timeout(15000),
    accountId,
    endpoint
  });
  const payload = upstream?.payload ?? null;
  console.info(`[T212][orders][raw] account=${accountId || 'default'} url=${upstream?.url || url} status=${upstream?.status ?? 'unknown'} body=${String(upstream?.bodyText || '').slice(0, 2000)}`);
  if (payload === null) {
    throw new Trading212ParseError('Trading 212 orders response was empty.', { status: 200 });
  }
  const rawOrders = extractTrading212Orders(payload);
  if (!Array.isArray(rawOrders)) {
    throw new Trading212ParseError('Trading 212 orders response was in an unexpected format.', {
      status: 200,
      details: { sample: JSON.stringify(payload).slice(0, 500) }
    });
  }
  const orders = parseTrading212Orders(payload);
  const rawCount = rawOrders.length;
  const filteredCount = orders.length;
  trading212OrdersCache.set(cacheKey, {
    fetchedAt: Date.now(),
    raw: payload,
    orders,
    rawCount,
    filteredCount
  });
  console.info(`[T212] orders rawCount=${rawCount} filteredCount=${filteredCount}`);
  return {
    raw: payload,
    debug: {
      requestUrl: upstream?.url || url,
      status: upstream?.status ?? null,
      headers: upstream?.headers || null,
      bodyText: upstream?.bodyText || ''
    },
    orders,
    rawCount,
    filteredCount,
    fromCache: false
  };
}

function buildTrading212HistoryOrdersEndpoint({ pageLimit = 50, cursor = '' } = {}) {
  const safeLimit = Math.min(50, Math.max(1, Number(pageLimit) || 50));
  const params = new URLSearchParams();
  params.set('limit', String(safeLimit));
  if (cursor) params.set('cursor', String(cursor));
  return `/api/v0/equity/history/orders?${params.toString()}`;
}

function resolveTrading212HistoryNextPagePath(payload = {}) {
  if (!payload || typeof payload !== 'object') return '';
  const nextPagePath = payload.nextPagePath ?? '';
  if (!nextPagePath || typeof nextPagePath !== 'string') return '';
  return String(nextPagePath).trim();
}

async function fetchTrading212HistoryOrders(config, username, {
  accountId = '',
  pageLimit = 50,
  ticker = '',
  cursor = '',
  bypassCache = false,
  checkpoint = null,
  maxPages = 20
} = {}) {
  if (!config?.apiKey || !config?.apiSecret) {
    throw new Trading212AuthError('Trading 212 credentials are incomplete.', { status: 401 });
  }
  const baseUrl = resolveTrading212BaseUrl(config);
  const headers = buildTrading212AuthHeaders(config);
  const safeLimit = Math.min(50, Math.max(1, Number(pageLimit) || 50));
  const endpointBase = '/api/v0/equity/history/orders';
  const cacheKey = `${String(username || '')}|${String(accountId || '')}|${baseUrl}|${safeLimit}|${String(ticker || '').trim().toUpperCase()}|${String(cursor || '')}`;
  const cached = trading212HistoryOrdersCache.get(cacheKey);
  if (!bypassCache && cached && Date.now() - cached.fetchedAt < TRADING212_HISTORY_ORDERS_CACHE_MS) {
    console.info(`[T212] cache hit history orders key=${cacheKey}`);
    return { ...cached.payload, fromCache: true };
  }
  console.info(`[T212] cache miss history orders key=${cacheKey}`);
  const rawItems = [];
  const pages = [];
  let nextPagePath = '';
  const knownOrderIds = new Set(Array.isArray(checkpoint?.importedOrderIds) ? checkpoint.importedOrderIds.map(item => String(item)) : []);
  const knownFillIds = new Set(Array.isArray(checkpoint?.importedFillIds) ? checkpoint.importedFillIds.map(item => String(item)) : []);
  const lastFilledAtTs = Date.parse(checkpoint?.lastFilledAt || '');
  const firstParams = new URLSearchParams();
  firstParams.set('limit', String(safeLimit));
  if (ticker) firstParams.set('ticker', String(ticker));
  if (cursor) firstParams.set('cursor', String(cursor));
  let endpointPath = `${endpointBase}?${firstParams.toString()}`;
  let pageCount = 0;
  const debug = {
    historyOrdersRequestUrl: '',
    historyOrdersStatus: null,
    historyOrdersRawBody: '',
    historyOrdersHeaders: null,
    historyOrdersError: null,
    historyOrdersItemCount: 0,
    historyOrdersNextPagePath: '',
    upstreamRequestAttempted: false,
    upstreamRequestSucceeded: false,
    upstreamRateLimited: false,
    returnedDataSource: 'none',
    cooldownUntil: null
  };
  do {
    const normalizedPath = endpointPath.startsWith('http')
      ? (() => {
          const parsed = new URL(endpointPath);
          return `${parsed.pathname}${parsed.search}`;
        })()
      : endpointPath;
    if (!normalizedPath.startsWith(endpointBase)) {
      const err = new Trading212ParseError(`Trading 212 history next page path must target ${endpointBase}.`, {
        status: 200,
        details: { endpointPath: normalizedPath }
      });
      err.debug = { ...debug, historyOrdersError: err.message };
      throw err;
    }
    const url = `${baseUrl}${normalizedPath}`;
    console.info(`[T212] history orders fetch account=${accountId || 'default'} page=${pageCount + 1} endpoint=${normalizedPath}`);
    let upstream;
    try {
      debug.upstreamRequestAttempted = true;
      upstream = await requestTrading212RawEndpoint(url, headers, {
        includeMeta: true,
        signal: AbortSignal.timeout(15000),
        accountId,
        endpoint: endpointBase
      });
    } catch (error) {
      debug.historyOrdersRequestUrl = url;
      debug.historyOrdersStatus = Number.isFinite(error?.status) ? Number(error.status) : null;
      debug.historyOrdersError = error?.message || 'Trading 212 history orders request failed.';
      if (rawItems.length > 0 && error instanceof Trading212RateLimitError) {
        debug.upstreamRateLimited = true;
        const retryAfter = Number.isFinite(error?.retryAfter) ? Number(error.retryAfter) : null;
        if (Number.isFinite(retryAfter) && retryAfter > 0) {
          debug.cooldownUntil = new Date(Date.now() + retryAfter * 1000).toISOString();
        }
        console.info(`[T212][history] account=${accountId || 'default'} preserving_partial_payload=true reason=rate_limited_after_success`);
        break;
      }
      error.debug = { ...(error?.debug || {}), ...debug };
      throw error;
    }
    const payload = upstream?.payload ?? null;
    const pageItems = extractTrading212HistoryOrders(payload);
    const nextRaw = resolveTrading212HistoryNextPagePath(payload);
    debug.historyOrdersRequestUrl = upstream?.url || url;
    debug.historyOrdersStatus = upstream?.status ?? null;
    debug.historyOrdersRawBody = upstream?.bodyText || '';
    debug.historyOrdersHeaders = upstream?.headers || null;
    debug.historyOrdersItemCount = Array.isArray(pageItems) ? pageItems.length : 0;
    debug.historyOrdersNextPagePath = nextRaw || '';
    debug.upstreamRequestSucceeded = true;
    if (debug.upstreamRequestSucceeded) {
      debug.returnedDataSource = 'fresh_upstream';
    }
    if (payload === null || !Array.isArray(pageItems)) {
      const err = new Trading212ParseError('Trading 212 history orders response was in an unexpected format.', {
        status: upstream?.status ?? 200,
        details: { sample: String(upstream?.bodyText || '').slice(0, 500) }
      });
      debug.historyOrdersError = err.message;
      err.debug = { ...debug };
      throw err;
    }
    rawItems.push(...pageItems);
    pages.push({
      page: pageCount + 1,
      url: upstream?.url || url,
      status: upstream?.status ?? null,
      bodyText: upstream?.bodyText || '',
      count: pageItems.length,
      nextPagePath: nextRaw || ''
    });
    nextPagePath = nextRaw || '';
    endpointPath = nextPagePath;
    pageCount += 1;
    const pageHasOnlyKnownItems = Array.isArray(pageItems) && pageItems.length > 0 && pageItems.every(item => {
      const orderId = String(item?.id ?? item?.orderId ?? '');
      const fillId = String(item?.fillId ?? item?.executionId ?? item?.tradeId ?? item?.dealId ?? '');
      const filledAt = Date.parse(item?.filledAt ?? item?.updatedAt ?? item?.executedAt ?? item?.dateExecuted ?? '');
      const isKnown = (orderId && knownOrderIds.has(orderId)) || (fillId && knownFillIds.has(fillId));
      const isOld = Number.isFinite(lastFilledAtTs) && Number.isFinite(filledAt) && filledAt <= lastFilledAtTs;
      return isKnown || isOld;
    });
    if (pageHasOnlyKnownItems) {
      console.info(`[T212] history orders incremental stop account=${accountId || 'default'} page=${pageCount + 1} reason=checkpoint_reached`);
      break;
    }
    if (pageCount >= Math.max(1, Number(maxPages) || 1)) {
      console.warn(`[T212] history orders pagination stopped after ${pageCount} pages for account=${accountId || 'default'}`);
      break;
    }
    if (nextPagePath) {
      await sleep(TRADING212_LIST_ENDPOINT_THROTTLE_MS);
    }
  } while (nextPagePath);
  const payload = {
    items: rawItems,
    pageLimit: safeLimit,
    pages
  };
  const rawOrders = extractTrading212HistoryOrders(payload);
  if (!Array.isArray(rawOrders)) {
    throw new Trading212ParseError('Trading 212 history orders response was in an unexpected format.', {
      status: 200,
      details: { sample: JSON.stringify(payload).slice(0, 500) }
    });
  }
  const orders = parseTrading212HistoryOrders(payload);
  const importedOrderIds = orders.map(item => String(item.orderId || item.id || '')).filter(Boolean);
  const importedFillIds = orders.map(item => String(item.fillId || item.fill?.id || '')).filter(Boolean);
  const parsedPreview = orders.slice(0, 5).map(item => ({
    orderId: item.orderId || item.id || '',
    fillId: item.fillId || item.fill?.id || '',
    side: item.side || '',
    status: item.status || '',
    filledAt: item.filledAt || ''
  }));
  const firstPage = pages[0] || {};
  const firstPageHeaders = debug.historyOrdersHeaders || null;
  console.info(`[T212][history][summary] account=${accountId || 'default'} requestUrl=${firstPage.url || debug.historyOrdersRequestUrl || ''} status=${firstPage.status ?? debug.historyOrdersStatus ?? 'unknown'} x-ratelimit-limit=${firstPageHeaders?.['x-ratelimit-limit'] ?? 'n/a'} x-ratelimit-remaining=${firstPageHeaders?.['x-ratelimit-remaining'] ?? 'n/a'} x-ratelimit-reset=${firstPageHeaders?.['x-ratelimit-reset'] ?? 'n/a'} rawItemCount=${rawOrders.length} parsedItemCount=${orders.length} parsedPreview=${JSON.stringify(parsedPreview)}`);
  console.info(`[T212] history orders fetched account=${accountId || 'default'} rawCount=${rawOrders.length} completedCount=${orders.length}`);
  const response = {
    raw: payload,
    orders,
    importedOrderIds,
    importedFillIds,
    lastFilledAt: orders.length ? (orders[orders.length - 1]?.filledAt || '') : '',
    debug: {
      pageLimit: safeLimit,
      pages,
      parsedPreview,
      rawItemCount: rawOrders.length,
      parsedItemCount: orders.length,
      ...debug
    },
    fromCache: false
  };
  trading212HistoryOrdersCache.set(cacheKey, {
    fetchedAt: Date.now(),
    payload: response
  });
  return response;
}

function ensureTrading212HistorySyncState(cfg) {
  if (!cfg || typeof cfg !== 'object') return {};
  if (!cfg.historySync || typeof cfg.historySync !== 'object' || Array.isArray(cfg.historySync)) {
    cfg.historySync = {};
  }
  if (!cfg.historySync.accounts || typeof cfg.historySync.accounts !== 'object' || Array.isArray(cfg.historySync.accounts)) {
    cfg.historySync.accounts = {};
  }
  return cfg.historySync.accounts;
}

function buildTrading212HistoryFillKey(fill = {}, accountId = '') {
  const orderId = fill.orderId || fill.order?.id || fill.id || '';
  const normalizedFillId = fill.fill?.id || fill.fillId || '';
  const normalizedSide = fill.order?.side || fill.side || '';
  const instrumentKey = fill.order?.instrumentUid
    || fill.instrumentUid
    || fill.order?.instrumentIsin
    || fill.instrumentIsin
    || fill.order?.ticker
    || fill.instrumentTicker
    || '';
  const quantity = fill.fill?.quantity ?? fill.quantity ?? '';
  const price = fill.fill?.price ?? fill.fillPrice ?? '';
  const filledAt = fill.fill?.filledAt ?? fill.filledAt ?? '';
  return [
    accountId || '',
    orderId,
    normalizedFillId,
    normalizedSide,
    instrumentKey,
    quantity,
    price,
    filledAt
  ].join('|');
}

function coalesceTrading212HistoryFills(fills = [], { windowMs = 30000 } = {}) {
  if (!Array.isArray(fills) || !fills.length) return [];
  const sorted = fills.slice().sort((a, b) => Date.parse(a?.filledAt || '') - Date.parse(b?.filledAt || ''));
  const coalesced = [];
  for (const fill of sorted) {
    const orderId = String(fill?.orderId || fill?.order?.id || fill?.id || '').trim();
    const side = String(fill?.side || '').trim().toUpperCase();
    const ticker = String(fill?.instrumentTicker || '').trim().toUpperCase();
    const isin = String(fill?.instrumentIsin || '').trim().toUpperCase();
    const uid = String(fill?.instrumentUid || '').trim();
    const optionIdentity = [
      String(fill?.optionType || '').trim().toLowerCase(),
      String(fill?.optionExpiration || '').trim(),
      Number.isFinite(Number(fill?.optionStrike)) ? Number(fill.optionStrike) : ''
    ].join('|');
    const fillTs = Date.parse(fill?.filledAt || '');
    const key = [orderId, side, ticker, isin, uid, optionIdentity].join('|');
    const last = coalesced[coalesced.length - 1];
    const lastTs = Date.parse(last?.filledAt || '');
    const canMerge = Boolean(last)
      && key === last._coalesceKey
      && Number.isFinite(fillTs)
      && Number.isFinite(lastTs)
      && Math.abs(fillTs - lastTs) <= windowMs;
    if (!canMerge) {
      coalesced.push({
        ...fill,
        _coalesceKey: key,
        _fillIds: [String(fill?.fillId || '').trim()].filter(Boolean)
      });
      continue;
    }
    const prevQty = Number(last.quantity) || 0;
    const nextQty = Number(fill.quantity) || 0;
    const mergedQty = prevQty + nextQty;
    const prevValue = prevQty * (Number(last.fillPrice) || 0);
    const nextValue = nextQty * (Number(fill.fillPrice) || 0);
    last.quantity = mergedQty;
    if (mergedQty > 0) last.fillPrice = (prevValue + nextValue) / mergedQty;
    last._fillIds = Array.from(new Set([...(last._fillIds || []), String(fill?.fillId || '').trim()].filter(Boolean)));
    last.fillId = last._fillIds.join(',');
    if (Number.isFinite(fillTs) && (!Number.isFinite(lastTs) || fillTs >= lastTs)) {
      last.filledAt = fill.filledAt || last.filledAt;
    }
  }
  return coalesced.map((fill) => {
    const next = { ...fill };
    delete next._coalesceKey;
    delete next._fillIds;
    return next;
  });
}

function tradeMatchesTrading212HistoryFill(trade, fill, accountId = '') {
  if (!trade || !fill) return false;
  if (trade.status === 'closed') return false;
  if (accountId && trade.trading212AccountId && trade.trading212AccountId !== accountId) return false;
  const direction = trade.direction === 'short' ? 'short' : 'long';
  const expectedExitSide = direction === 'short' ? 'BUY' : 'SELL';
  if (fill.side !== expectedExitSide) return false;
  const tradeTicker = normalizeTrading212TickerValue(trade.trading212Ticker || '');
  const tradeIsin = String(trade.trading212Isin || '').trim().toUpperCase();
  const tradeUid = String(trade.trading212Id || '').trim();
  const tickerMatch = tradeTicker && fill.instrumentTicker && tradeTicker === fill.instrumentTicker;
  const isinMatch = tradeIsin && fill.instrumentIsin && tradeIsin === fill.instrumentIsin;
  const uidMatch = tradeUid && fill.instrumentUid && (tradeUid === fill.instrumentUid || tradeUid.endsWith(`:${fill.instrumentUid}`));
  if (!(tickerMatch || isinMatch || uidMatch)) return false;
  const tradeOptionType = String(trade.optionType || '').trim().toLowerCase();
  const tradeOptionExpiry = String(trade.optionExpiration || '').trim();
  const tradeOptionStrike = Number(trade.optionStrike);
  const fillHasOptionIdentity = !!(fill.optionType || fill.optionExpiration || Number.isFinite(fill.optionStrike));
  const tradeHasOptionIdentity = !!(tradeOptionType || tradeOptionExpiry || Number.isFinite(tradeOptionStrike));
  if (fillHasOptionIdentity || tradeHasOptionIdentity) {
    if ((tradeOptionType || '') !== (fill.optionType || '')) return false;
    if ((tradeOptionExpiry || '') !== (fill.optionExpiration || '')) return false;
    if (Number.isFinite(tradeOptionStrike) || Number.isFinite(fill.optionStrike)) {
      if (!Number.isFinite(tradeOptionStrike) || !Number.isFinite(fill.optionStrike)) return false;
      if (Math.abs(tradeOptionStrike - fill.optionStrike) > 1e-8) return false;
    }
  }
  return true;
}

function applyTrading212ExecutionSummary(trade, rates = {}) {
  const executionSummary = summarizeExecutionLegs(trade, rates);
  trade.executions = executionSummary.executions;
  trade.sizeUnits = Math.max(0, executionSummary.openQuantity);
  trade.status = executionSummary.status === 'closed' ? 'closed' : 'open';
  if (Number.isFinite(executionSummary.avgExit) && executionSummary.avgExit > 0) {
    trade.closePrice = executionSummary.avgExit;
  }
  if (executionSummary.lastExitDate) {
    trade.closeDate = executionSummary.lastExitDate;
  }
  if (trade.status === 'closed') {
    trade.closedAt = trade.closedAt || new Date().toISOString();
  }
  const pnl = computeRealizedPnl(trade, rates);
  if (pnl) {
    trade.realizedPnlGBP = pnl.realizedPnlGBP;
    trade.realizedPnlCurrency = pnl.realizedPnlCurrency;
    trade.rMultiple = pnl.rMultiple;
  }
}

function reconcileTrading212HistoricalExits(user, cfg, historyOrdersPayload, accountId = '', activeOrdersPayload = null, rates = {}) {
  const rawFills = Array.isArray(historyOrdersPayload?.orders) ? historyOrdersPayload.orders : [];
  const fills = coalesceTrading212HistoryFills(rawFills);
  const historyState = ensureTrading212HistorySyncState(cfg);
  const stateKey = accountId || '__default__';
  const accountState = historyState[stateKey] && typeof historyState[stateKey] === 'object'
    ? historyState[stateKey]
    : { importedFillKeys: [], lastFilledAt: '' };
  const importedKeys = new Set(Array.isArray(accountState.importedFillKeys) ? accountState.importedFillKeys : []);
  const lastFilledAtTs = Date.parse(accountState.lastFilledAt || '');
  const journal = ensureTradeJournal(user);
  const openEntries = [];
  for (const [tradeDate, items] of Object.entries(journal)) {
    for (const trade of items || []) {
      if (!trade || trade.status === 'closed') continue;
      if (trade.source !== 'trading212' && !trade.trading212Id) continue;
      openEntries.push({ tradeDate, trade });
    }
  }
  const activeOrders = Array.isArray(activeOrdersPayload?.orders) ? activeOrdersPayload.orders : [];
  let imported = 0;
  let skipped = 0;
  let maxFilledAt = Number.isFinite(lastFilledAtTs) ? lastFilledAtTs : 0;
  const importedOrderIds = new Set();
  const importedFillIds = new Set();
  const importedFillEvents = [];
  console.info(`[T212] history reconcile account=${accountId || 'default'} fills=${fills.length} rawFills=${rawFills.length}`);
  for (const fill of fills) {
    const fillKey = buildTrading212HistoryFillKey(fill, accountId);
    const fillTs = Date.parse(fill.filledAt || '');
    if (importedKeys.has(fillKey)) {
      skipped += 1;
      continue;
    }
    if (Number.isFinite(lastFilledAtTs) && Number.isFinite(fillTs) && fillTs < lastFilledAtTs) {
      skipped += 1;
      continue;
    }
    let remaining = Number(fill.quantity);
    if (!Number.isFinite(remaining) || remaining <= 0) {
      skipped += 1;
      continue;
    }
    const baseFillId = String(fill.fillId || fill.fill?.id || '');
    const baseOrderId = String(fill.orderId || fill.order?.id || fill.id || '');
    const baseTicker = normalizeTrading212Symbol(fill.instrumentTicker || '');
    if (fill.side === 'SELL') {
      console.info(`[TradeGroup][SellAlert] stage=fill_detected accountId=${accountId || 'default'} fillId=${baseFillId || 'n/a'} orderId=${baseOrderId || 'n/a'} ticker=${baseTicker || 'n/a'} quantity=${Number(fill.quantity) || 0}`);
    }
    if (fill.side === 'BUY') {
      importedFillEvents.push({
        fillId: baseFillId,
        orderId: baseOrderId,
        accountId,
        side: fill.side,
        ticker: baseTicker,
        instrumentIsin: String(fill.instrumentIsin || fill.fill?.instrument?.isin || '').trim(),
        instrumentId: String(fill.instrumentId || fill.fill?.instrument?.id || '').trim(),
        fillPrice: Number(fill.fillPrice),
        quantity: Number(fill.quantity),
        remainingQuantity: null,
        realizedPnlGbp: null,
        tradeStatus: '',
        stopTriggered: false,
        filledAt: fill.filledAt || '',
        sourceTradeId: null
      });
      importedKeys.add(fillKey);
      if (Number.isFinite(fillTs) && fillTs > maxFilledAt) maxFilledAt = fillTs;
      continue;
    }
    const candidates = openEntries
      .filter(entry => tradeMatchesTrading212HistoryFill(entry.trade, fill, accountId))
      .sort((a, b) => Date.parse(a.trade?.createdAt || a.tradeDate || '') - Date.parse(b.trade?.createdAt || b.tradeDate || ''));
    if (!candidates.length) {
      console.info(`[T212] history fill skipped no-match fillKey=${fillKey}`);
      if (fill.side === 'SELL') {
        importedFillEvents.push({
          fillId: baseFillId,
          orderId: baseOrderId,
          accountId,
          side: fill.side,
          ticker: baseTicker,
          instrumentIsin: String(fill.instrumentIsin || fill.fill?.instrument?.isin || '').trim(),
          instrumentId: String(fill.instrumentId || fill.fill?.instrument?.id || '').trim(),
          fillPrice: Number(fill.fillPrice),
          quantity: Number(fill.quantity),
          remainingQuantity: null,
          realizedPnlGbp: null,
          tradeStatus: '',
          stopTriggered: false,
          filledAt: fill.filledAt || '',
          sourceTradeId: null
        });
        console.info(`[TradeGroup][SellAlert] stage=fill_matched matchedTradeId=n/a accountId=${accountId || 'default'} fillId=${baseFillId || 'n/a'} skipReason=no_matching_open_trade`);
      }
      skipped += 1;
      continue;
    }
    console.info(`[T212] history fill candidate fillKey=${fillKey} candidates=${candidates.length}`);
    for (const candidate of candidates) {
      if (remaining <= 1e-8) break;
      const trade = candidate.trade;
      const summary = summarizeExecutionLegs(trade, rates);
      const openQty = Number(summary.openQuantity);
      if (!Number.isFinite(openQty) || openQty <= 1e-8) continue;
      const matchedQty = Math.min(openQty, remaining);
      if (matchedQty <= 1e-8) continue;
      const executionFingerprint = `${fillKey}|trade:${trade.id}|qty:${matchedQty}`;
      const existing = Array.isArray(summary.executions)
        ? summary.executions.find(leg => leg.side === 'exit' && leg.importFingerprint === executionFingerprint)
        : null;
      if (existing) {
        console.info(`[T212][trim] duplicate_suppressed account=${accountId || 'default'} tradeId=${trade.id} fillKey=${fillKey} created=false`);
        remaining -= matchedQty;
        continue;
      }
      const fillOrderId = fill.orderId || fill.order?.id || fill.id || '';
      if (fillOrderId) importedOrderIds.add(String(fillOrderId));
      const normalizedFillId = String(fill.fillId || fill.fill?.id || '');
      if (normalizedFillId) importedFillIds.add(normalizedFillId);
      const stopTriggered = (trade.t212StopOrderId && fillOrderId && trade.t212StopOrderId === fillOrderId)
        || activeOrders.some(order => {
          const orderIsStop = order.type === 'STOP' || order.type === 'STOP_LIMIT';
          if (!orderIsStop) return false;
          const tickerMatch = order.instrumentTicker && fill.instrumentTicker && order.instrumentTicker === fill.instrumentTicker;
          const isinMatch = order.instrumentIsin && fill.instrumentIsin && order.instrumentIsin === fill.instrumentIsin;
          return tickerMatch || isinMatch;
        });
      const executionDate = Number.isFinite(fillTs)
        ? getNyDateKeyForDate(new Date(fillTs), false)
        : currentDateKey();
      const nextExecutions = Array.isArray(summary.executions) ? summary.executions.slice() : [];
      nextExecutions.push({
        id: crypto.randomBytes(8).toString('hex'),
        side: 'exit',
        quantity: matchedQty,
        price: Number(fill.fillPrice),
        date: executionDate,
        brokerTradeId: fillOrderId || undefined,
        importSource: 'trading212_history',
        importFingerprint: executionFingerprint,
        note: stopTriggered ? 'stop-triggered' : undefined
      });
      trade.executions = nextExecutions;
      if (Number.isFinite(fill.optionMultiplier) && fill.optionMultiplier > 0) {
        trade.optionMultiplier = fill.optionMultiplier;
      }
      applyTrading212ExecutionSummary(trade, rates);
      const remainingQuantity = Number(trade.sizeUnits);
      const previousQuantity = Number(openQty);
      const ticker = resolveCanonicalTickerForTrade(trade) || normalizeTrading212Symbol(fill.instrumentTicker || '');
      importedFillEvents.push({
        fillId: normalizedFillId,
        orderId: fillOrderId || '',
        accountId,
        side: fill.side,
        ticker,
        instrumentIsin: String(fill.instrumentIsin || fill.fill?.instrument?.isin || '').trim(),
        instrumentId: String(fill.instrumentId || fill.fill?.instrument?.id || '').trim(),
        fillPrice: Number(fill.fillPrice),
        quantity: matchedQty,
        remainingQuantity: Number.isFinite(remainingQuantity) ? remainingQuantity : null,
        realizedPnlGbp: Number.isFinite(Number(trade.realizedPnlGBP)) ? Number(trade.realizedPnlGBP) : null,
        tradeStatus: trade.status || '',
        stopTriggered,
        filledAt: fill.filledAt || '',
        sourceTradeId: trade.id
      });
      if (fill.side === 'SELL') {
        const classification = classifyTrading212SellAlert({
          matchedQuantity: matchedQty,
          remainingQuantity: Number.isFinite(remainingQuantity) ? remainingQuantity : null,
          tradeStatus: trade.status || ''
        });
        if (classification === 'partial_sell') {
          console.info(`[T212][trim] detected account=${accountId || 'default'} tradeId=${trade.id} previousQty=${previousQuantity} newQty=${remainingQuantity} trimQty=${matchedQty} fillPrice=${Number(fill.fillPrice)} created=true`);
        }
        console.info(`[TradeGroup][SellAlert] stage=fill_matched matchedTradeId=${trade.id} accountId=${accountId || 'default'} fillId=${normalizedFillId || baseFillId || 'n/a'} classification=${classification} matchedQty=${matchedQty} remainingQty=${Number.isFinite(remainingQuantity) ? remainingQuantity : 'n/a'} tradeStatus=${trade.status || ''}`);
      }
      console.info(`[T212] history fill matched trade=${trade.id} qty=${matchedQty} remainingAfter=${Math.max(0, Number(summary.openQuantity) - matchedQty)} status=${trade.status}`);
      remaining -= matchedQty;
      imported += 1;
    }
    importedKeys.add(fillKey);
    if (Number.isFinite(fillTs) && fillTs > maxFilledAt) maxFilledAt = fillTs;
  }
  const retainedKeys = Array.from(importedKeys).slice(-5000);
  historyState[stateKey] = {
    importedFillKeys: retainedKeys,
    lastFilledAt: maxFilledAt ? new Date(maxFilledAt).toISOString() : (accountState.lastFilledAt || '')
  };
  console.info(`[T212] history reconcile account=${accountId || 'default'} imported=${imported} skipped=${skipped}`);
  return {
    imported,
    skipped,
    importedOrderIds: Array.from(importedOrderIds),
    importedFillIds: Array.from(importedFillIds),
    lastFilledAt: maxFilledAt ? new Date(maxFilledAt).toISOString() : (accountState.lastFilledAt || ''),
    importedFillEvents
  };
}

function computeSourceKey(instrument = {}) {
  if (instrument.uid) {
    return `TRADING212|UID:${instrument.uid}`;
  }
  if (instrument.isin) {
    return `TRADING212|ISIN:${instrument.isin}`;
  }
  if (instrument.name) {
    return `TRADING212|NAME:${normalizeTrading212Name(instrument.name)}|CCY:${String(instrument.currency || '').toUpperCase()}`;
  }
  return `TRADING212|TICKER:${instrument.ticker}|CCY:${instrument.currency}`;
}

function ensureInstrumentMappings(db) {
  if (!db.instrumentMappings || !Array.isArray(db.instrumentMappings)) {
    db.instrumentMappings = [];
  }
  return db.instrumentMappings;
}

const REGISTRY_RESOLUTION_STATUSES = new Set(['resolved', 'unresolved', 'ambiguous', 'manual_override']);
const REGISTRY_RESOLUTION_SOURCES = new Set(['isin_lookup', 'name_lookup', 'manual_override', 'unresolved']);
const KNOWN_TICKER_ALIASES = new Map([
  ['SOI', { canonicalTicker: 'SEI', canonicalName: 'Solaris Energy Infrastructure', source: 'name_lookup', confidence: 0.7 }],
  ['YNDX', { canonicalTicker: 'NBIS', canonicalName: 'Nebius Group', source: 'name_lookup', confidence: 0.7 }],
  ['DMYI', { canonicalTicker: 'IONQ', canonicalName: 'IonQ', source: 'name_lookup', confidence: 0.95 }],
  ['APPLE', { canonicalTicker: 'AAPL', canonicalName: 'Apple Inc.', source: 'name_lookup', confidence: 0.99 }]
]);

function ensureInstrumentRegistry(db) {
  if (!Array.isArray(db.brokerInstrumentRegistry)) {
    db.brokerInstrumentRegistry = [];
  }
  if (!Array.isArray(db.instrumentResolutionHistory)) {
    db.instrumentResolutionHistory = [];
  }
  return db.brokerInstrumentRegistry;
}

function nextBrokerInstrumentRegistryId(rows) {
  return rows.reduce((max, row) => Math.max(max, Number(row?.id) || 0), 0) + 1;
}

function nextInstrumentResolutionHistoryId(rows) {
  return rows.reduce((max, row) => Math.max(max, Number(row?.id) || 0), 0) + 1;
}

function normalizeRegistryStatus(status) {
  const normalized = String(status || '').trim().toLowerCase();
  return REGISTRY_RESOLUTION_STATUSES.has(normalized) ? normalized : 'unresolved';
}

function normalizeRegistrySource(source) {
  const normalized = String(source || '').trim().toLowerCase();
  return REGISTRY_RESOLUTION_SOURCES.has(normalized) ? normalized : 'unresolved';
}

function normalizeRegistryInput(instrument = {}) {
  const rawName = String(instrument.rawName || instrument.name || '').trim();
  const rawTicker = normalizeTrading212TickerValue(String(instrument.rawTicker || instrument.ticker || '').trim());
  const brokerInstrumentId = String(instrument.brokerInstrumentId || instrument.uid || '').trim();
  const isin = String(instrument.isin || '').trim().toUpperCase();
  const rawCurrency = String(instrument.rawCurrency || instrument.currency || '').trim().toUpperCase();
  return {
    broker: String(instrument.broker || 'trading212').trim().toLowerCase(),
    brokerInstrumentId,
    rawTicker,
    rawName,
    normalizedRawName: normalizeTrading212Name(rawName),
    isin,
    rawCurrency,
    rawExchange: String(instrument.rawExchange || instrument.exchange || '').trim().toUpperCase(),
    instrumentType: String(instrument.instrumentType || '').trim().toLowerCase()
  };
}

function getRegistryLookupKey(data) {
  if (data.brokerInstrumentId) return `uid:${data.broker}|${data.brokerInstrumentId}`;
  if (data.isin) return `isin:${data.broker}|${data.isin}`;
  if (data.normalizedRawName) return `name:${data.broker}|${data.normalizedRawName}|${data.rawCurrency}`;
  if (data.rawTicker) return `ticker:${data.broker}|${data.rawTicker}|${data.rawCurrency}`;
  return '';
}

function findRegistryEntry(db, instrument = {}) {
  const registry = ensureInstrumentRegistry(db);
  const normalized = normalizeRegistryInput(instrument);
  if (normalized.brokerInstrumentId) {
    const byUid = registry.find(row => row.broker === normalized.broker && row.brokerInstrumentId === normalized.brokerInstrumentId);
    if (byUid) return byUid;
  }
  if (normalized.isin) {
    const byIsin = registry.find(row => row.broker === normalized.broker && row.isin === normalized.isin);
    if (byIsin) return byIsin;
  }
  if (normalized.normalizedRawName) {
    const byName = registry.find(row => row.broker === normalized.broker && row.normalizedRawName === normalized.normalizedRawName && row.rawCurrency === normalized.rawCurrency);
    if (byName) return byName;
  }
  if (normalized.rawTicker) {
    return registry.find(row => row.broker === normalized.broker && row.rawTicker === normalized.rawTicker && row.rawCurrency === normalized.rawCurrency) || null;
  }
  return null;
}

function addResolutionHistory(db, registryEntry, patch = {}, reason = '', changedBy = 'system') {
  const history = Array.isArray(db.instrumentResolutionHistory) ? db.instrumentResolutionHistory : [];
  db.instrumentResolutionHistory = history;
  history.push({
    id: nextInstrumentResolutionHistoryId(history),
    instrumentRegistryId: registryEntry.id,
    previousCanonicalTicker: registryEntry.canonicalTicker || '',
    newCanonicalTicker: patch.canonicalTicker || '',
    previousStatus: registryEntry.resolutionStatus || 'unresolved',
    newStatus: patch.resolutionStatus || registryEntry.resolutionStatus || 'unresolved',
    reason: String(reason || '').trim() || 'update',
    changedAt: new Date().toISOString(),
    changedBy: String(changedBy || 'system')
  });
}

function upsertRegistryEntry(db, instrument = {}, options = {}) {
  const registry = ensureInstrumentRegistry(db);
  const normalized = normalizeRegistryInput(instrument);
  const nowIso = new Date().toISOString();
  let entry = findRegistryEntry(db, normalized);
  if (entry) {
    entry.lastSeenAt = nowIso;
    if (normalized.rawTicker) entry.rawTicker = normalized.rawTicker;
    if (normalized.rawName) entry.rawName = normalized.rawName;
    if (normalized.normalizedRawName) entry.normalizedRawName = normalized.normalizedRawName;
    if (normalized.isin) entry.isin = normalized.isin;
    if (normalized.rawCurrency) entry.rawCurrency = normalized.rawCurrency;
    if (normalized.rawExchange) entry.rawExchange = normalized.rawExchange;
    if (normalized.instrumentType) entry.instrumentType = normalized.instrumentType;
    if (normalized.brokerInstrumentId) entry.brokerInstrumentId = normalized.brokerInstrumentId;
    return { entry, created: false };
  }
  entry = {
    id: nextBrokerInstrumentRegistryId(registry),
    broker: normalized.broker,
    brokerInstrumentId: normalized.brokerInstrumentId,
    rawTicker: normalized.rawTicker,
    rawName: normalized.rawName,
    normalizedRawName: normalized.normalizedRawName,
    isin: normalized.isin,
    rawCurrency: normalized.rawCurrency,
    rawExchange: normalized.rawExchange,
    instrumentType: normalized.instrumentType,
    canonicalTicker: '',
    canonicalName: '',
    canonicalExchange: '',
    resolutionStatus: normalizeRegistryStatus(options.resolutionStatus || 'unresolved'),
    resolutionSource: normalizeRegistrySource(options.resolutionSource || 'unresolved'),
    confidenceScore: 0,
    manualOverride: false,
    firstSeenAt: nowIso,
    lastSeenAt: nowIso,
    lastVerifiedAt: '',
    notes: options.notes || '',
    lookupKey: getRegistryLookupKey(normalized)
  };
  registry.push(entry);
  return { entry, created: true };
}

function applyRegistryResolution(db, entry, resolution = {}, reason = 'resolver_update', changedBy = 'system') {
  if (!entry) return entry;
  const patch = {
    canonicalTicker: String(resolution.canonicalTicker || '').trim().toUpperCase(),
    canonicalName: String(resolution.canonicalName || '').trim(),
    canonicalExchange: String(resolution.canonicalExchange || resolution.exchange || '').trim().toUpperCase(),
    resolutionStatus: normalizeRegistryStatus(resolution.status),
    resolutionSource: normalizeRegistrySource(resolution.resolutionSource),
    confidenceScore: Number.isFinite(Number(resolution.confidenceScore)) ? Number(resolution.confidenceScore) : 0
  };
  const changed = (
    entry.canonicalTicker !== patch.canonicalTicker
    || entry.resolutionStatus !== patch.resolutionStatus
    || entry.resolutionSource !== patch.resolutionSource
    || Number(entry.confidenceScore || 0) !== patch.confidenceScore
    || entry.canonicalName !== patch.canonicalName
  );
  if (changed) {
    addResolutionHistory(db, entry, patch, reason, changedBy);
  }
  entry.canonicalTicker = patch.canonicalTicker;
  entry.canonicalName = patch.canonicalName;
  entry.canonicalExchange = patch.canonicalExchange;
  entry.resolutionStatus = patch.resolutionStatus;
  entry.resolutionSource = patch.resolutionSource;
  entry.confidenceScore = patch.confidenceScore;
  entry.lastVerifiedAt = new Date().toISOString();
  return entry;
}

async function runYahooSearchLookup(query) {
  const q = String(query || '').trim();
  if (!q) return [];
  try {
    const url = `https://query1.finance.yahoo.com/v1/finance/search?q=${encodeURIComponent(q)}&quotesCount=8&newsCount=0`;
    const response = await fetch(url, { method: 'GET', signal: AbortSignal.timeout(2500) });
    if (!response.ok) return [];
    const payload = await response.json().catch(() => null);
    const quotes = Array.isArray(payload?.quotes) ? payload.quotes : [];
    return quotes
      .map(item => ({
        symbol: String(item?.symbol || '').trim().toUpperCase(),
        shortname: String(item?.shortname || item?.longname || '').trim(),
        exchange: String(item?.exchange || item?.exchDisp || '').trim().toUpperCase(),
        type: String(item?.quoteType || '').trim().toUpperCase()
      }))
      .filter(item => !!item.symbol);
  } catch (error) {
    return [];
  }
}

function chooseLookupCandidate(candidates = [], rawName = '') {
  if (!candidates.length) return null;
  const normalizedRawName = normalizeTrading212Name(rawName || '');
  const filtered = candidates.filter(item => item.type === 'EQUITY' || item.type === 'ETF' || !item.type);
  const scored = (filtered.length ? filtered : candidates).map(item => {
    const normalizedCandidate = normalizeTrading212Name(item.shortname || '');
    const nameExact = normalizedRawName && normalizedCandidate && normalizedRawName === normalizedCandidate;
    const nameContains = normalizedRawName && normalizedCandidate
      ? (normalizedCandidate.includes(normalizedRawName) || normalizedRawName.includes(normalizedCandidate))
      : false;
    const confidence = nameExact ? 0.92 : (nameContains ? 0.78 : 0.55);
    return { ...item, confidence };
  }).sort((a, b) => b.confidence - a.confidence);
  if (scored.length > 1 && scored[0].confidence - scored[1].confidence < 0.1) return { ambiguous: true };
  return scored[0];
}

async function lookupCanonicalInstrument(instrument = {}, db) {
  const normalized = normalizeRegistryInput(instrument);
  const alias = KNOWN_TICKER_ALIASES.get(normalizeTrading212Symbol(normalized.rawTicker || ''));
  if (alias) {
    return {
      canonicalTicker: alias.canonicalTicker,
      canonicalName: alias.canonicalName,
      canonicalExchange: '',
      confidenceScore: alias.confidence,
      resolutionSource: alias.source,
      status: alias.confidence >= 0.7 ? 'resolved' : 'ambiguous'
    };
  }
  if (normalized.isin) {
    const existing = ensureInstrumentRegistry(db).find(row => row.isin === normalized.isin && (row.resolutionStatus === 'resolved' || row.resolutionStatus === 'manual_override') && row.canonicalTicker);
    if (existing) {
      return {
        canonicalTicker: existing.canonicalTicker,
        canonicalName: existing.canonicalName,
        canonicalExchange: existing.canonicalExchange,
        confidenceScore: 0.98,
        resolutionSource: 'isin_lookup',
        status: existing.resolutionStatus === 'manual_override' ? 'manual_override' : 'resolved'
      };
    }
    const isinCandidates = await runYahooSearchLookup(normalized.isin);
    const chosenByIsin = chooseLookupCandidate(isinCandidates, normalized.rawName);
    if (chosenByIsin?.ambiguous) {
      return { canonicalTicker: '', canonicalName: '', confidenceScore: 0.4, resolutionSource: 'isin_lookup', status: 'ambiguous' };
    }
    if (chosenByIsin?.symbol) {
      return {
        canonicalTicker: chosenByIsin.symbol,
        canonicalName: chosenByIsin.shortname || normalized.rawName,
        canonicalExchange: chosenByIsin.exchange || '',
        confidenceScore: chosenByIsin.confidence,
        resolutionSource: 'isin_lookup',
        status: chosenByIsin.confidence >= 0.7 ? 'resolved' : 'ambiguous'
      };
    }
  }
  if (normalized.rawName) {
    const nameCandidates = await runYahooSearchLookup(normalized.rawName);
    const chosenByName = chooseLookupCandidate(nameCandidates, normalized.rawName);
    if (chosenByName?.ambiguous) {
      return { canonicalTicker: '', canonicalName: '', confidenceScore: 0.35, resolutionSource: 'name_lookup', status: 'ambiguous' };
    }
    if (chosenByName?.symbol) {
      return {
        canonicalTicker: chosenByName.symbol,
        canonicalName: chosenByName.shortname || normalized.rawName,
        canonicalExchange: chosenByName.exchange || '',
        confidenceScore: chosenByName.confidence,
        resolutionSource: 'name_lookup',
        status: chosenByName.confidence >= 0.7 ? 'resolved' : 'ambiguous'
      };
    }
  }
  return { canonicalTicker: '', canonicalName: '', canonicalExchange: '', confidenceScore: 0, resolutionSource: 'unresolved', status: 'unresolved' };
}

function parseSourceKey(sourceKey) {
  if (typeof sourceKey !== 'string') return { source: 'TRADING212', sourceKey: '' };
  const trimmed = sourceKey.trim();
  if (!trimmed) return { source: 'TRADING212', sourceKey: '' };
  const [source] = trimmed.split('|');
  return { source: source || 'TRADING212', sourceKey: trimmed };
}

function nextInstrumentMappingId(mappings) {
  const maxId = mappings.reduce((max, m) => Math.max(max, Number(m.id) || 0), 0);
  return maxId + 1;
}

function isAdminUser(user, username) {
  const role = getUserRole(user, username);
  return role === 'admin' || role === 'owner';
}

function normalizeUserRole(role) {
  const normalized = typeof role === 'string' ? role.trim().toLowerCase() : '';
  return USER_ROLES.includes(normalized) ? normalized : 'user';
}

function legacyAdminUsersList() {
  return String(process.env.ADMIN_USERS || '')
    .split(',')
    .map(item => item.trim())
    .filter(Boolean);
}

function getUserRole(user, username) {
  const normalized = normalizeUserRole(user?.role);
  if (normalized === 'admin' || normalized === 'owner') return normalized;
  if (user?.isAdmin === true) return 'admin';
  const adminList = legacyAdminUsersList();
  if (adminList.includes(username)) return 'admin';
  return 'user';
}

function requireAuthenticatedUser(req, res, next) {
  if (!req.username || !req.user) {
    return res.status(401).json({ error: 'Unauthenticated' });
  }
  return next();
}

const SITE_ANNOUNCEMENT_TYPES = ['maintenance', 'update', 'warning', 'info'];
function normalizeSiteAnnouncementInput(raw = {}, { partial = false } = {}) {
  const pick = (key, fallback) => (Object.prototype.hasOwnProperty.call(raw, key) ? raw[key] : fallback);
  const payload = {
    title: pick('title', partial ? undefined : ''),
    body: pick('body', partial ? undefined : ''),
    type: pick('type', undefined),
    priority: pick('priority', undefined),
    isPublished: pick('isPublished', undefined),
    startsAt: pick('startsAt', undefined),
    endsAt: pick('endsAt', undefined),
    requireAcknowledgement: pick('requireAcknowledgement', undefined),
    ctaLabel: pick('ctaLabel', undefined),
    ctaUrl: pick('ctaUrl', undefined)
  };
  if (payload.priority !== undefined && payload.priority !== null && payload.priority !== '') payload.priority = Number(payload.priority);
  if (payload.isPublished !== undefined) payload.isPublished = payload.isPublished === true || payload.isPublished === 'true' || payload.isPublished === 1 || payload.isPublished === '1';
  if (payload.requireAcknowledgement !== undefined) payload.requireAcknowledgement = payload.requireAcknowledgement === true || payload.requireAcknowledgement === 'true' || payload.requireAcknowledgement === 1 || payload.requireAcknowledgement === '1';
  if (payload.startsAt === '') payload.startsAt = null;
  if (payload.endsAt === '') payload.endsAt = null;
  if (payload.ctaLabel === '') payload.ctaLabel = null;
  if (payload.ctaUrl === '') payload.ctaUrl = null;
  return payload;
}

function validateSiteAnnouncementInput(raw = {}, { partial = false } = {}) {
  const payload = normalizeSiteAnnouncementInput(raw, { partial });
  if (!partial || payload.title !== undefined) {
    if (!String(payload.title || '').trim() || String(payload.title).trim().length > 180) {
      return { success: false, error: 'Title is required and must be 180 characters or fewer.' };
    }
  }
  if (!partial || payload.body !== undefined) {
    if (!String(payload.body || '').trim() || String(payload.body).trim().length > 12000) {
      return { success: false, error: 'Body is required and must be 12000 characters or fewer.' };
    }
  }
  if (payload.type !== undefined && payload.type !== null && !SITE_ANNOUNCEMENT_TYPES.includes(payload.type)) {
    return { success: false, error: `type must be one of: ${SITE_ANNOUNCEMENT_TYPES.join(', ')}.` };
  }
  if (payload.priority !== undefined && payload.priority !== null) {
    if (!Number.isFinite(payload.priority) || payload.priority < 0 || payload.priority > 1000 || Math.floor(payload.priority) !== payload.priority) {
      return { success: false, error: 'Priority must be an integer between 0 and 1000.' };
    }
  }
  if (payload.startsAt) {
    const startTs = Date.parse(payload.startsAt);
    if (Number.isNaN(startTs)) return { success: false, error: 'startsAt must be a valid datetime.' };
  }
  if (payload.endsAt) {
    const endTs = Date.parse(payload.endsAt);
    if (Number.isNaN(endTs)) return { success: false, error: 'endsAt must be a valid datetime.' };
  }
  if (payload.startsAt && payload.endsAt && Date.parse(payload.endsAt) < Date.parse(payload.startsAt)) {
    return { success: false, error: 'endsAt must be after startsAt.' };
  }
  if ((payload.ctaLabel && !payload.ctaUrl) || (!payload.ctaLabel && payload.ctaUrl)) {
    return { success: false, error: 'ctaLabel and ctaUrl must be provided together.' };
  }
  if (payload.ctaLabel && String(payload.ctaLabel).trim().length > 80) {
    return { success: false, error: 'ctaLabel must be 80 characters or fewer.' };
  }
  if (payload.ctaUrl && String(payload.ctaUrl).length > 2000) {
    return { success: false, error: 'ctaUrl must be 2000 characters or fewer.' };
  }
  return { success: true, data: payload };
}

function requireAdmin(req, res, next) {
  if (!req.username || !req.user) {
    return res.status(401).json({ error: 'Unauthenticated' });
  }
  const db = loadDB();
  const user = db.users[req.username];
  if (!isAdminUser(user, req.username)) {
    return res.status(403).json({ error: 'Admin access required.' });
  }
  req.authUser = user;
  return next();
}

function requireOwner(req, res, next) {
  if (!req.username || !req.user) {
    return res.status(401).json({ error: 'Unauthenticated' });
  }
  const db = loadDB();
  const user = db.users[req.username];
  if (getUserRole(user, req.username) !== 'owner') {
    return res.status(403).json({ error: 'Owner access required.' });
  }
  req.authUser = user;
  return next();
}

function normalizeOptionalDate(value) {
  if (value === undefined || value === null || value === '') return null;
  const parsed = Date.parse(value);
  if (Number.isNaN(parsed)) return null;
  return new Date(parsed).toISOString();
}

function sanitizeSiteAnnouncement(record) {
  return {
    id: String(record.id),
    title: String(record.title || ''),
    body: String(record.body || ''),
    type: SITE_ANNOUNCEMENT_TYPES.includes(record.type) ? record.type : 'info',
    priority: Number.isFinite(Number(record.priority)) ? Number(record.priority) : 0,
    isPublished: !!record.isPublished,
    startsAt: normalizeOptionalDate(record.startsAt),
    endsAt: normalizeOptionalDate(record.endsAt),
    requireAcknowledgement: !!record.requireAcknowledgement,
    ctaLabel: record.ctaLabel ? String(record.ctaLabel) : null,
    ctaUrl: record.ctaUrl ? String(record.ctaUrl) : null,
    createdBy: String(record.createdBy || ''),
    createdAt: normalizeOptionalDate(record.createdAt) || new Date().toISOString(),
    updatedAt: normalizeOptionalDate(record.updatedAt) || new Date().toISOString()
  };
}

function isSiteAnnouncementActive(record, now = Date.now()) {
  if (!record?.isPublished) return false;
  const startTs = record.startsAt ? Date.parse(record.startsAt) : NaN;
  const endTs = record.endsAt ? Date.parse(record.endsAt) : NaN;
  if (!Number.isNaN(startTs) && now < startTs) return false;
  if (!Number.isNaN(endTs) && now > endTs) return false;
  return true;
}

function getUserAnnouncementStateMap(db, username) {
  ensureSiteAnnouncementTables(db);
  const map = new Map();
  for (const row of db.siteAnnouncementStates) {
    if (row?.userId !== username) continue;
    map.set(String(row.announcementId), row);
  }
  return map;
}

function canAccessDevtools(user, username) {
  if (isAdminUser(user, username)) return true;
  return username === 'mevs.0404@gmail.com' || username === 'dummy1';
}

function resolveInstrumentMapping(db, instrument, username) {
  if ((instrument?.broker || 'trading212') === 'trading212') {
    const registryEntry = findRegistryEntry(db, {
      broker: 'trading212',
      brokerInstrumentId: instrument.uid || '',
      isin: instrument.isin || '',
      rawName: instrument.name || '',
      rawTicker: instrument.ticker || '',
      rawCurrency: instrument.currency || ''
    });
    if (registryEntry && (registryEntry.resolutionStatus === 'resolved' || registryEntry.resolutionStatus === 'manual_override') && registryEntry.canonicalTicker) {
      const alias = KNOWN_TICKER_ALIASES.get(registryEntry.canonicalTicker);
      const effectiveTicker = alias ? alias.canonicalTicker : registryEntry.canonicalTicker;
      const effectiveName = alias ? (alias.canonicalName || registryEntry.canonicalName || instrument.name || '') : (registryEntry.canonicalName || instrument.name || '');
      return {
        sourceKey: registryEntry.lookupKey || computeSourceKey(instrument),
        displayTicker: effectiveTicker,
        displayName: effectiveName,
        scope: registryEntry.resolutionStatus === 'manual_override' ? 'manual_override' : 'registry',
        mapping: registryEntry
      };
    }
  }
  const mappings = ensureInstrumentMappings(db);
  const sourceKey = computeSourceKey(instrument);
  if (!sourceKey) {
    return {
      sourceKey: null,
      displayTicker: instrument.ticker || '',
      displayName: instrument.name || '',
      scope: 'broker'
    };
  }
  const { source, sourceKey: normalizedKey } = parseSourceKey(sourceKey);
  const userMapping = mappings.find(mapping => (
    mapping?.status === 'active'
    && mapping.source === source
    && mapping.source_key === normalizedKey
    && mapping.scope === 'user'
    && mapping.user_id === username
  ));
  if (userMapping) {
    return {
      sourceKey: normalizedKey,
      displayTicker: userMapping.canonical_ticker,
      displayName: userMapping.canonical_name || userMapping.broker_name || instrument.name || '',
      scope: 'user',
      mapping: userMapping
    };
  }
  const globalMapping = mappings.find(mapping => (
    mapping?.status === 'active'
    && mapping.source === source
    && mapping.source_key === normalizedKey
    && mapping.scope === 'global'
    && !mapping.user_id
  ));
  if (globalMapping) {
    return {
      sourceKey: normalizedKey,
      displayTicker: globalMapping.canonical_ticker,
      displayName: globalMapping.canonical_name || globalMapping.broker_name || instrument.name || '',
      scope: 'global',
      mapping: globalMapping
    };
  }
  return {
    sourceKey: normalizedKey,
    displayTicker: instrument.ticker || '',
    displayName: instrument.name || '',
    scope: 'broker'
  };
}

function buildInstrumentFromTrade(trade = {}) {
  const brokerTicker = normalizeTrading212TickerValue(
    trade.trading212Ticker ?? trade.symbol ?? ''
  );
  return {
    broker: trade.source === 'ibkr' || trade.ibkrPositionId ? 'ibkr' : 'trading212',
    isin: trade.trading212Isin || '',
    uid: trade.trading212Id || '',
    ticker: brokerTicker,
    currency: trade.currency || '',
    name: trade.trading212Name || ''
  };
}

function getDisplayInstrumentIdentity(record = {}, db, username = '') {
  const isTrading212 = record.source === 'trading212' || record.trading212Id;
  const manualDisplayName = typeof record?.displayName === 'string' ? record.displayName.trim() : '';
  if (!isTrading212) {
    const fallback = record.displaySymbol || record.symbol || '';
    return {
      displayTicker: fallback,
      displayName: manualDisplayName || record.trading212Name || '',
      canonicalTicker: fallback,
      rawTicker: record.symbol || '',
      resolutionStatus: 'resolved',
      isCanonical: true,
      mappingScope: null,
      mappingId: null,
      sourceKey: null
    };
  }
  if (manualDisplayName) {
    console.info('[display-name]', {
      stage: 'resolver_bypass_manual_override',
      tradeId: record?.id || null,
      nameSource: 'manual_override'
    });
  }
  const instrument = buildInstrumentFromTrade(record);
  const resolved = resolveInstrumentMapping(db, instrument, username);
  const fallbackTicker = record.displaySymbol || record.symbol || instrument.ticker || '';
  const displayTicker = resolved.scope === 'broker'
    ? fallbackTicker
    : (resolved.displayTicker || fallbackTicker);
  const resolutionStatus = resolved.scope === 'broker'
    ? 'unresolved'
    : (resolved.scope === 'manual_override' ? 'manual_override' : 'resolved');
  const nameSource = manualDisplayName
    ? 'manual_override'
    : (resolved.displayName ? 'canonical' : 'fallback');
  console.info('[display-name]', {
    stage: 'serialize_trade_display_name',
    tradeId: record?.id || null,
    nameSource
  });
  return {
    displayTicker,
    displayName: manualDisplayName || resolved.displayName || record.trading212Name || '',
    canonicalTicker: resolved.scope === 'broker' ? '' : (resolved.displayTicker || ''),
    rawTicker: instrument.ticker || record.symbol || '',
    resolutionStatus,
    isCanonical: resolutionStatus === 'resolved' || resolutionStatus === 'manual_override',
    mappingScope: resolved.scope === 'broker' ? null : resolved.scope,
    mappingId: resolved.mapping?.id,
    sourceKey: resolved.sourceKey
  };
}

function applyInstrumentMappingToTrade(trade, db, username) {
  if (!trade || typeof trade !== 'object') return trade;
  const identity = getDisplayInstrumentIdentity(trade, db, username);
  return {
    ...trade,
    displayTicker: identity.displayTicker,
    displaySymbol: identity.displayTicker || trade.displaySymbol || trade.symbol || '',
    displayName: identity.displayName,
    canonicalTicker: identity.canonicalTicker,
    resolutionStatus: identity.resolutionStatus,
    isCanonicalInstrument: identity.isCanonical,
    mappingScope: identity.mappingScope,
    mappingId: identity.mappingId,
    sourceKey: identity.sourceKey,
    brokerTicker: identity.rawTicker || trade.symbol || ''
  };
}

function createTradeInstrumentMapper(db, username = '') {
  const identityCache = new Map();
  const buildCacheKey = (trade = {}) => [
    trade.source === 'ibkr' || trade.ibkrPositionId ? 'ibkr' : 'trading212',
    String(trade.trading212Id || ''),
    String(trade.trading212Isin || ''),
    String(trade.symbol || ''),
    String(trade.currency || ''),
    String(trade.trading212Name || ''),
    String(trade.displaySymbol || ''),
    String(trade.displayName || '')
  ].join('|');
  return (trade) => {
    if (!trade || typeof trade !== 'object') return trade;
    const cacheKey = buildCacheKey(trade);
    let identity = identityCache.get(cacheKey);
    if (!identity) {
      identity = getDisplayInstrumentIdentity(trade, db, username);
      identityCache.set(cacheKey, identity);
    }
    return {
      ...trade,
      displayTicker: identity.displayTicker,
      displaySymbol: identity.displayTicker || trade.displaySymbol || trade.symbol || '',
      displayName: identity.displayName,
      canonicalTicker: identity.canonicalTicker,
      resolutionStatus: identity.resolutionStatus,
      isCanonicalInstrument: identity.isCanonical,
      mappingScope: identity.mappingScope,
      mappingId: identity.mappingId,
      sourceKey: identity.sourceKey,
      brokerTicker: identity.rawTicker || trade.symbol || ''
    };
  };
}

function deriveTrading212Root(endpointPath) {
  if (typeof endpointPath !== 'string') return '/api/v0';
  const trimmed = endpointPath.trim();
  if (!trimmed) return '/api/v0';
  const match = trimmed.match(/(\/api\/v\d+)/i);
  if (match && match[1]) {
    return match[1].toLowerCase();
  }
  return '/api/v0';
}

async function requestTrading212Endpoint(url, headers, options = {}) {
  const maxAttempts = 3;
  let attempt = 0;
  let lastError = null;
  while (attempt < maxAttempts) {
    attempt += 1;
    let res;
    try {
      res = await fetch(url, { method: 'GET', headers, signal: options.signal });
    } catch (networkErr) {
      const code = networkErr?.code || networkErr?.cause?.code || networkErr?.name;
      const isNetwork = ['ENOTFOUND', 'ECONNRESET', 'ETIMEDOUT', 'EAI_AGAIN', 'ECONNREFUSED', 'ERR_TLS_CERT_ALTNAME_INVALID', 'AbortError'].includes(code);
      lastError = isNetwork
        ? new Trading212NetworkError('Unable to reach Trading 212', { code: 'network_error' })
        : new Trading212Error('Trading 212 request failed.', { code: 'trading212_error' });
      await sleep(Math.min(1000 * attempt, 3000));
      continue;
    }
    const status = res.status;
    const headerMap = {};
    for (const [key, value] of res.headers.entries()) {
      headerMap[key] = value;
    }
    const rateLimitHeaders = parseTrading212RateLimitHeaders(headerMap);
    const contentType = res.headers.get('content-type') || '';
    const bodyText = await res.text().catch(() => '');
    console.info(`[T212][upstream] endpoint=${url} account=${options?.accountId || 'default'} url=${url} status=${status} x-ratelimit-limit=${rateLimitHeaders.limit ?? 'n/a'} x-ratelimit-remaining=${rateLimitHeaders.remaining ?? 'n/a'} x-ratelimit-reset=${rateLimitHeaders.reset ?? 'n/a'}`);
    if (status === 429) {
      const retryAfter = parseRetryAfter(res.headers.get('retry-after'));
      lastError = new Trading212RateLimitError('Trading 212 rate limited the request. Please try again later.', {
        status,
        retryAfter
      });
      throw lastError;
    }
    if (status === 401 || status === 403) {
      console.warn(`Trading 212 auth failure ${status} for ${url}: ${bodyText.slice(0, 500)}`);
      throw new Trading212AuthError('Invalid API key or missing Orders Read permission.', { status });
    }
    if (!res.ok) {
      console.warn(`Trading 212 non-OK ${status} for ${url}: ${bodyText.slice(0, 500)}`);
      throw new Trading212HttpError(bodyText || `Trading 212 responded with ${status}`, { status });
    }
    let data = {};
    if (bodyText) {
      if (!contentType.includes('application/json')) {
        throw new Trading212HttpError('Trading 212 returned an unexpected response format.', {
          status,
          code: 'invalid_payload'
        });
      }
      try {
        data = JSON.parse(bodyText);
      } catch (e) {
        throw new Trading212HttpError('Trading 212 returned an unexpected response format.', {
          status,
          code: 'invalid_payload'
        });
      }
    }
    const portfolioCandidates = [
      data?.totalValue?.value,
      data?.totalValue?.amount,
      data?.totalValue,
      data?.total?.portfolioValue,
      data?.portfolioValue,
      data?.portfolio?.totalValue,
      data?.summary?.totalValue,
      data?.summary?.equity,
      data?.summary?.total?.value,
      data?.summary?.total?.amount,
      data?.overall?.portfolioValue,
      data?.overall?.totalValue,
      data?.accountValue,
      data?.netLiq,
      data?.equity?.value,
      data?.equity?.amount,
      data?.equityValue,
      data?.portfolio?.value,
      data?.portfolio?.amount,
      data?.portfolio?.total?.value,
      data?.portfolio?.total?.amount,
      data?.portfolio?.equity?.value,
      data?.portfolio?.equity?.amount
    ];
    const netDepositsCandidates = [
      data?.totalNetDeposits,
      data?.netDeposits,
      data?.total?.netDeposits,
      data?.summary?.netDeposits,
      data?.summary?.netDeposits?.value,
      data?.summary?.netDeposits?.amount,
      data?.overall?.netDeposits,
      data?.cashFlows?.net,
      data?.cashFlows?.net?.value,
      data?.cashFlows?.net?.amount,
      data?.netCash
    ];
    let portfolioValue = portfolioCandidates
      .map(parseTradingNumber)
      .find(value => Number.isFinite(value));
    const netDeposits = netDepositsCandidates
      .map(parseTradingNumber)
      .find(value => Number.isFinite(value));
    if (!Number.isFinite(portfolioValue)) {
      const account = data?.account || data?.portfolio || data?.summary || data?.total || data?.overall;
      if (account && typeof account === 'object') {
        const numericValues = Object.values(account)
          .map(parseTradingNumber)
          .filter(value => Number.isFinite(value));
        if (numericValues.length) {
          portfolioValue = Math.max(...numericValues);
        }
      }
    }
    if (!Number.isFinite(portfolioValue)) {
      const err = new Trading212Error('Trading 212 payload was missing a portfolio value.', {
        status,
        code: 'invalid_payload'
      });
      err.raw = data;
      throw err;
    }
        return {
          portfolioValue,
          netDeposits: Number.isFinite(netDeposits) ? netDeposits : null,
          raw: data
        };
      }
      throw lastError || new Trading212Error('Trading 212 request failed.');
    }

async function requestTrading212RawEndpoint(url, headers, options = {}) {
  const includeMeta = options?.includeMeta === true;
  const maxAttempts = 3;
  let attempt = 0;
  let lastError = null;
  while (attempt < maxAttempts) {
    attempt += 1;
    let res;
    try {
      res = await fetch(url, { method: 'GET', headers, signal: options.signal });
    } catch (networkErr) {
      const code = networkErr?.code || networkErr?.cause?.code || networkErr?.name;
      const isNetwork = ['ENOTFOUND', 'ECONNRESET', 'ETIMEDOUT', 'EAI_AGAIN', 'ECONNREFUSED', 'ERR_TLS_CERT_ALTNAME_INVALID', 'AbortError'].includes(code);
      lastError = isNetwork
        ? new Trading212NetworkError('Unable to reach Trading 212', { code: 'network_error' })
        : new Trading212Error('Trading 212 request failed.', { code: 'trading212_error' });
      await sleep(Math.min(1000 * attempt, 3000));
      continue;
    }
    const status = res.status;
    const contentType = res.headers.get('content-type') || '';
    const bodyText = await res.text().catch(() => '');
    const responseHeaders = {};
    for (const [key, value] of res.headers.entries()) {
      responseHeaders[key] = value;
    }
    const rateLimitHeaders = parseTrading212RateLimitHeaders(responseHeaders);
    const accountId = options?.accountId || 'default';
    const endpointLabel = options?.endpoint || '';
    console.info(`[T212][upstream] endpoint=${endpointLabel || url} account=${accountId} url=${url} status=${status} x-ratelimit-limit=${rateLimitHeaders.limit ?? 'n/a'} x-ratelimit-remaining=${rateLimitHeaders.remaining ?? 'n/a'} x-ratelimit-reset=${rateLimitHeaders.reset ?? 'n/a'}`);
    console.info(`[T212] status=${status} content-type=${contentType}`);
    if (status === 429) {
      const retryAfter = parseRetryAfter(res.headers.get('retry-after'));
      const headerResetSeconds = Number.isFinite(rateLimitHeaders.reset) ? rateLimitHeaders.reset : null;
      const effectiveRetryAfter = headerResetSeconds !== null && headerResetSeconds > 0 ? headerResetSeconds : retryAfter;
      lastError = new Trading212RateLimitError('Trading 212 rate limited the request. Please try again later.', {
        status,
        retryAfter: effectiveRetryAfter
      });
      throw lastError;
    }
    if (status === 401 || status === 403) {
      console.warn(`Trading 212 auth failure ${status} for ${url}: ${bodyText.slice(0, 500)}`);
      throw new Trading212AuthError('Invalid API key or missing Orders Read permission.', { status });
    }
    if (!res.ok) {
      console.warn(`Trading 212 non-OK ${status} for ${url}: ${bodyText.slice(0, 500)}`);
      throw new Trading212HttpError(bodyText || `Trading 212 responded with ${status}`, { status });
    }
    if (bodyText) {
      if (!contentType.includes('application/json')) {
        throw new Trading212ParseError('Trading 212 returned an unexpected response format.', {
          status,
          code: 'invalid_payload'
        });
      }
      try {
        const parsed = JSON.parse(bodyText);
        if (includeMeta) {
          return {
            url,
            status,
            headers: responseHeaders,
            bodyText,
            payload: parsed
          };
        }
        return parsed;
      } catch (e) {
        throw new Trading212ParseError('Trading 212 returned an unexpected response format.', {
          status,
          code: 'invalid_payload'
        });
      }
    }
    if (includeMeta) {
      return {
        url,
        status,
        headers: responseHeaders,
        bodyText: '',
        payload: null
      };
    }
    return null;
  }
  throw lastError || new Trading212Error('Trading 212 request failed.');
}

function recalculateTradeRiskFromImportedStop(trade, user, rates) {
  if (!trade || typeof trade !== 'object') return false;
  const entry = Number(trade.entry);
  const stop = Number(trade.stop);
  const sizeUnits = Number(trade.sizeUnits);
  if (!Number.isFinite(entry) || entry <= 0 || !Number.isFinite(stop) || stop <= 0 || !Number.isFinite(sizeUnits) || sizeUnits <= 0) {
    return false;
  }
  const direction = String(trade.direction || 'long').toLowerCase() === 'short' ? 'short' : 'long';
  let perUnitRisk = direction === 'short' ? (stop - entry) : (entry - stop);
  if (!Number.isFinite(perUnitRisk) || perUnitRisk <= 0) {
    perUnitRisk = Math.abs(entry - stop);
  }
  if (!Number.isFinite(perUnitRisk) || perUnitRisk <= 0) return false;
  const tradeCurrency = trade.currency || 'GBP';
  const riskAmountCurrency = perUnitRisk * sizeUnits;
  const positionCurrency = entry * sizeUnits;
  const portfolioGBP = getPortfolioGBPForRisk(user);
  const portfolioCurrency = convertGBPToCurrency(portfolioGBP, tradeCurrency, rates);
  trade.perUnitRisk = perUnitRisk;
  trade.riskAmountCurrency = riskAmountCurrency;
  trade.positionCurrency = positionCurrency;
  trade.riskAmountGBP = convertToGBP(riskAmountCurrency, tradeCurrency, rates);
  trade.positionGBP = convertToGBP(positionCurrency, tradeCurrency, rates);
  trade.portfolioGBPAtCalc = portfolioGBP;
  trade.portfolioCurrencyAtCalc = Number.isFinite(portfolioCurrency) ? portfolioCurrency : 0;
  trade.riskPct = Number.isFinite(portfolioCurrency) && portfolioCurrency > 0
    ? (riskAmountCurrency / portfolioCurrency) * 100
    : 0;
  if (!Number.isFinite(Number(trade.originalStopPrice)) || Number(trade.originalStopPrice) <= 0) {
    trade.originalStopPrice = stop;
  }
  return true;
}

function upsertTrading212StopOrders(user, ordersPayload, accountId = '', rates = null) {
  const orders = ordersPayload?.orders || [];
  const journal = ensureTradeJournal(user);
  const openTrades = [];
  for (const [dateKey, items] of Object.entries(journal)) {
    for (const trade of items || []) {
      if (!trade || trade.status === 'closed') continue;
      if (trade.source !== 'trading212' && !trade.trading212Id) continue;
      if (accountId && trade.trading212AccountId && trade.trading212AccountId !== accountId) continue;
      openTrades.push(trade);
    }
  }
  let updated = 0;
  for (const trade of openTrades) {
    const existingOriginalStop = Number(trade.originalStopPrice);
    const existingCurrentStop = Number(trade.currentStop);
    const relatedTrades = findRelatedTrading212Trades(openTrades, trade, accountId);
    const matched = matchStopOrderForTrade(trade, orders, { relatedTrades: [trade, ...relatedTrades] });
    const shouldAutoSync = trade.currentStopSource !== 'manual';
    if (!matched || !Number.isFinite(matched.stopPrice)) {
      if (!shouldAutoSync) continue;
      const hadStop = Number.isFinite(Number(trade.currentStop));
      if (!hadStop && trade.currentStopStale === true) continue;
      delete trade.currentStop;
      trade.currentStopSource = 't212';
      trade.currentStopLastSyncedAt = new Date().toISOString();
      trade.currentStopStale = true;
      trade.t212StopOrderId = '';
      updated += 1;
      continue;
    }
    const stopPrice = Number(matched.stopPrice);
    const shouldUpdate = shouldAutoSync
      && (!Number.isFinite(Number(trade.currentStop))
        || Number(trade.currentStop) !== stopPrice
        || trade.currentStopStale === true
        || trade.t212StopOrderId !== (matched.id || ''));
    if (!shouldUpdate) continue;
    trade.currentStop = stopPrice;
    trade.currentStopSource = 't212';
    trade.currentStopLastSyncedAt = new Date().toISOString();
    trade.currentStopStale = false;
    trade.t212StopOrderId = matched.id || '';
    if (trade.stopManualOverride !== true) {
      trade.stop = stopPrice;
    }
    if (!Number.isFinite(Number(trade.originalStopPrice)) || Number(trade.originalStopPrice) <= 0) {
      trade.originalStopPrice = stopPrice;
    }
    recalculateTradeRiskFromImportedStop(trade, user, rates);
    updated += 1;
  }
  return { updated };
}

async function fetchTrading212Positions(config, options = {}) {
  const baseUrl = resolveTrading212BaseUrl(config);
  const headers = buildTrading212AuthHeaders(config);
  const root = '/api/v0';
  const candidates = [
    `${root}/equity/positions`,
    `${root}/equity/portfolio/positions`,
    `${root}/equity/account/positions`,
    `${root}/portfolio/positions`
  ];
  for (const candidate of candidates) {
    try {
      const payload = await requestTrading212RawEndpoint(`${baseUrl}${candidate}`, headers, {
        accountId: options.accountId || '',
        endpoint: candidate
      });
      const list = Array.isArray(payload) ? payload : payload?.items || payload?.positions;
      if (Array.isArray(list)) {
        return { positions: list, debug: { endpoint: candidate, status: 200 } };
      }
    } catch (error) {
      if (error instanceof Trading212Error && error.status === 404) continue;
      throw error;
    }
  }
  throw new Trading212Error('Trading 212 positions endpoint not found.', { status: 404 });
}

async function fetchTrading212Snapshot(config, options = {}) {
  if (!config?.apiKey || !config?.apiSecret) {
    throw new Trading212AuthError('Trading 212 credentials are incomplete.', { status: 401 });
  }
  const baseUrl = resolveTrading212BaseUrl(config);
  if (!baseUrl) {
    throw new Trading212Error('Trading 212 base URL could not be determined.');
  }
  const headers = buildTrading212AuthHeaders(config);
  const endpointCandidates = [];
  const seenEndpoints = new Set();
  const appendEndpoint = (value) => {
    if (!value || typeof value !== 'string') return;
    let normalized = value.trim();
    if (!normalized) return;
    if (!normalized.startsWith('/')) {
      normalized = `/${normalized.replace(/^\/+/, '')}`;
    }
    if (seenEndpoints.has(normalized)) return;
    seenEndpoints.add(normalized);
    endpointCandidates.push(normalized);
  };
  appendEndpoint(config.endpoint || '/api/v0/equity/portfolio/summary');
  appendEndpoint('/api/v0/equity/portfolio-summary');
  appendEndpoint('/api/v0/equities/portfolio-summary');
  appendEndpoint('/api/v0/equity/portfolio/summary');
  appendEndpoint('/api/v0/equity/portfolio');
  appendEndpoint('/api/v0/equity/portfolios/summary');
  appendEndpoint('/api/v0/equity/account/info');
  appendEndpoint('/api/v0/equity/account-info');
  appendEndpoint('/api/v0/equity/account/summary');
  appendEndpoint('/api/v0/account/summary');
  appendEndpoint('/api/v0/portfolio/summary');
  let lastError = null;
  for (const pathSuffix of endpointCandidates) {
    const endpoint = `${baseUrl}${pathSuffix}`;
    try {
      console.info(`[T212] baseUrl=${baseUrl} endpoint=${pathSuffix}`);
      const snapshot = await requestTrading212Endpoint(endpoint, headers, { accountId: options.accountId || '' });
      const root = deriveTrading212Root(pathSuffix);
      const positionsEndpoints = [
        `${root}/equity/positions`,
        `${root}/equity/portfolio`,
        `${root}/equity/portfolio/positions`,
        `${root}/equity/account/positions`,
        `${root}/portfolio/positions`
      ];
      const transactionEndpoints = [
        `${root}/equity/history/transactions?limit=50`,
        `${root}/history/transactions`,
        `${root}/history/transactions?type=CASH`,
        `${root}/history/cash`,
        `${root}/transactions`,
        `${root}/cash/transactions`
      ];
      let positions = null;
      let positionsRaw = null;
      let transactions = null;
      let transactionsRaw = null;
      for (const candidate of positionsEndpoints) {
        try {
          const payload = await requestTrading212RawEndpoint(`${baseUrl}${candidate}`, headers, {
            accountId: options.accountId || '',
            endpoint: candidate
          });
          const list = Array.isArray(payload) ? payload : payload?.items || payload?.positions;
          if (Array.isArray(list)) {
            positions = list;
            positionsRaw = payload;
            break;
          }
        } catch (e) {
          if (e instanceof Trading212Error && e.status === 404) continue;
        }
      }
      for (const candidate of transactionEndpoints) {
        try {
          const payload = await requestTrading212RawEndpoint(`${baseUrl}${candidate}`, headers, {
            accountId: options.accountId || '',
            endpoint: candidate
          });
          const list = Array.isArray(payload) ? payload : payload?.items || payload?.transactions;
          if (Array.isArray(list)) {
            transactions = list;
            transactionsRaw = payload ?? { items: [] };
            break;
          }
        } catch (e) {
          if (e instanceof Trading212Error && e.status === 404) continue;
        }
      }
      return {
        ...snapshot,
        baseUrl,
        endpoint: pathSuffix,
        positions,
        positionsRaw,
        transactions,
        transactionsRaw
      };
    } catch (error) {
      if (error instanceof Trading212Error && error.status === 404) {
        const notFoundError = new Trading212Error(`Trading 212 could not find ${endpoint}`, {
          status: 404,
          code: 'not_found'
        });
        notFoundError.baseUrl = baseUrl;
        notFoundError.endpoint = pathSuffix;
        lastError = notFoundError;
        continue;
      }
      if (error instanceof Trading212Error) {
        error.baseUrl = baseUrl;
        error.endpoint = pathSuffix;
      }
      throw error;
    }
  }
  throw lastError || new Trading212Error('Trading 212 portfolio summary endpoint not found.', { status: 404 });
}

const trading212Jobs = new Map();
const trading212LeaderJobs = new Map();
const ibkrJobs = new Map();

function shouldThrottleTrading212Endpoint(accountState, endpointKey, now = Date.now()) {
  const endpointState = accountState?.endpoints?.[endpointKey] || {};
  const cooldownTs = Date.parse(endpointState.cooldownUntil || '');
  if (Number.isFinite(cooldownTs) && cooldownTs > now) {
    return { skip: true, reason: 'cooldown', until: endpointState.cooldownUntil };
  }
  const minInterval = TRADING212_SYNC_MIN_INTERVALS_MS[endpointKey] || 30000;
  const lastAttemptTs = Date.parse(endpointState.lastAttemptAt || '');
  if (Number.isFinite(lastAttemptTs) && (now - lastAttemptTs) < minInterval) {
    return {
      skip: true,
      reason: 'cadence',
      until: new Date(lastAttemptTs + minInterval).toISOString()
    };
  }
  return { skip: false, reason: null, until: null };
}

function recordTrading212EndpointAttempt(accountState, endpointKey, upstreamMeta = {}, now = Date.now()) {
  if (!accountState.endpoints[endpointKey]) accountState.endpoints[endpointKey] = {};
  const endpointState = accountState.endpoints[endpointKey];
  endpointState.lastAttemptAt = new Date(now).toISOString();
  endpointState.lastStatus = upstreamMeta.status ?? null;
  if (upstreamMeta.headers && typeof upstreamMeta.headers === 'object') {
    const rateHeaders = parseTrading212RateLimitHeaders(upstreamMeta.headers);
    endpointState.rateLimit = {
      limit: rateHeaders.limit,
      remaining: rateHeaders.remaining,
      reset: rateHeaders.reset
    };
    const statusCode = Number(upstreamMeta.status);
    const applyCooldownAfterSuccess = statusCode >= 200
      && statusCode < 400
      && Number.isFinite(rateHeaders.remaining)
      && rateHeaders.remaining <= 0
      && Number.isFinite(rateHeaders.reset)
      && rateHeaders.reset > 0;
    if (applyCooldownAfterSuccess) {
      endpointState.cooldownUntil = new Date(now + (rateHeaders.reset * 1000)).toISOString();
    } else if (upstreamMeta.status !== 429) {
      delete endpointState.cooldownUntil;
    }
  }
  if (upstreamMeta.status === 429) {
    const retryAfter = Number.isFinite(upstreamMeta.retryAfter) ? Number(upstreamMeta.retryAfter) : 5;
    endpointState.cooldownUntil = new Date(now + (retryAfter * 1000)).toISOString();
  } else if (upstreamMeta.status && upstreamMeta.status < 400) {
    accountState.lastSuccessByEndpoint[endpointKey] = endpointState.lastAttemptAt;
    delete endpointState.lastError;
  }
  const minInterval = TRADING212_SYNC_MIN_INTERVALS_MS[endpointKey] || 30000;
  const nextByCadence = Date.parse(endpointState.lastAttemptAt || '') + minInterval;
  const cooldownTs = Date.parse(endpointState.cooldownUntil || '');
  const nextAllowedTs = Math.max(
    Number.isFinite(nextByCadence) ? nextByCadence : 0,
    Number.isFinite(cooldownTs) ? cooldownTs : 0
  );
  if (nextAllowedTs > 0) {
    endpointState.nextAllowedAt = new Date(nextAllowedTs).toISOString();
  }
}

function recordTrading212Skip(accountState, endpointKey, gate = {}) {
  if (!accountState || typeof accountState !== 'object') return;
  accountState.lastSkip = {
    endpoint: endpointKey,
    reason: gate.reason || 'unknown',
    until: gate.until || null,
    at: new Date().toISOString()
  };
  if (endpointKey && accountState.endpoints?.[endpointKey]) {
    accountState.endpoints[endpointKey].lastSkip = accountState.lastSkip;
  }
}

async function syncTrading212ForUser(username, runDate = new Date(), options = {}) {
  const lane = options?.lane === 'leader_alert' ? 'leader_alert' : 'normal';
  const lockKey = `t212-sync:${username}`;
  const existingLock = TRADING212_ACCOUNT_LOCKS.get(lockKey);
  if (existingLock) {
    console.info(`[T212][${lane}] sync skipped username=${username} reason=lock_in_progress`);
    const db = loadDB();
    const user = db.users?.[username];
    if (user?.trading212 && typeof user.trading212 === 'object') {
      user.trading212.lastSyncSkip = {
        reason: 'lock_in_progress',
        at: new Date().toISOString()
      };
      user.trading212.lastDataSource = 'cached_db';
      saveDB(db);
    }
    if (options.waitForExisting === true) {
      await existingLock.catch(() => null);
    }
    return { skipped: true, reason: 'lock_in_progress' };
  }

  const syncPromise = (async () => {
    const db = loadDB();
    const user = db.users[username];
    if (!user) return { skipped: true, reason: 'user_missing' };
    ensureUserShape(user, username);
    const cfg = user.trading212;
    const requestedBrokerAccountId = typeof options?.brokerAccountId === 'string' ? options.brokerAccountId.trim() : '';
    const accounts = getTrading212Accounts(cfg).filter(account => (
      !requestedBrokerAccountId || account.id === requestedBrokerAccountId
    ));
    if (!cfg || !cfg.enabled || !accounts.length) return { skipped: true, reason: 'integration_disabled' };
    if (lane === 'leader_alert' && !userLeadsTradeGroups(db, username)) {
      console.info(`[TradeGroup][LeaderSync] skipped leader=${username} reason=no_groups_led`);
      return { skipped: true, reason: 'no_groups_led' };
    }

    cfg.syncInProgress = true;
    cfg.lastDataSource = 'cached_db';
    const syncStates = ensureTrading212SyncState(cfg);
    saveDB(db);

    const rates = await fetchRates();
    const accountRecordById = new Map((Array.isArray(cfg.accounts) ? cfg.accounts : []).map((entry) => [entry.id, entry]));
    const now = Date.now();
    const accountResults = [];

    for (const [index, account] of accounts.entries()) {
      const accountId = account.id || `account-${index + 1}`;
      const accountRecord = accountRecordById.get(accountId);
      const accountConfig = {
        ...cfg,
        apiKey: account.apiKey,
        apiSecret: account.apiSecret,
        mode: account.mode || cfg.mode,
        baseUrl: account.baseUrl || cfg.baseUrl
      };
      const accountState = ensureTrading212AccountSyncState(cfg, accountId);
      syncStates[accountId] = accountState;
      const leaderAlertState = ensureTrading212LeaderAlertState(cfg, accountId);
      const isLeaderLane = lane === 'leader_alert';
      const shouldFetchSummary = !isLeaderLane;
      const shouldFetchHistory = true;
      const hasOpenTrading212Positions = Object.values(ensureTradeJournal(user)).flat().some(trade => (
        trade
        && trade.status !== 'closed'
        && (trade.source === 'trading212' || trade.trading212Id)
        && (!trade.trading212AccountId || trade.trading212AccountId === accountId)
      ));
      let shouldFetchOrders = !isLeaderLane || hasOpenTrading212Positions;
      let forceHistoryFetch = false;
      if (isLeaderLane) {
        console.info(`[TradeGroup][LeaderSync] triggered leader=${username} account=${accountId}`);
      }

      const summaryGate = shouldThrottleTrading212Endpoint(accountState, 'summary', now);
      const ordersGate = shouldThrottleTrading212Endpoint(accountState, 'orders', now);
      const historyGate = shouldThrottleTrading212Endpoint(accountState, 'historyOrders', now);

      const snapshotStale = !Number.isFinite(Date.parse(accountState.lastSnapshotAt || ''))
        || (now - Date.parse(accountState.lastSnapshotAt || '')) > TRADING212_SYNC_MIN_INTERVALS_MS.summary;

      let snapshot = null;
      if (shouldFetchSummary && (!summaryGate.skip || snapshotStale)) {
        try {
          snapshot = await fetchTrading212Snapshot(accountConfig, { accountId });
          recordTrading212EndpointAttempt(accountState, 'summary', { status: 200, headers: {} }, now);
          accountState.lastSnapshotAt = new Date().toISOString();
          await sleep(TRADING212_LIST_ENDPOINT_THROTTLE_MS);
        } catch (error) {
          recordTrading212EndpointAttempt(accountState, 'summary', {
            status: Number.isFinite(error?.status) ? Number(error.status) : 500,
            retryAfter: Number.isFinite(error?.retryAfter) ? Number(error.retryAfter) : null
          }, now);
          accountResults.push({ status: 'rejected', reason: error, accountId });
          if (accountRecord) {
            accountRecord.syncStatus = 'error';
            accountRecord.connectionStatus = 'error';
            accountRecord.updatedAt = new Date().toISOString();
          }
          continue;
        }
      } else if (shouldFetchSummary) {
        console.info(`[T212][sync] skipped endpoint=summary account=${accountId} reason=${summaryGate.reason} until=${summaryGate.until || 'n/a'}`);
        recordTrading212Skip(accountState, 'summary', summaryGate);
        cfg.lastSyncSkip = { accountId, ...accountState.lastSkip };
      } else {
        const positionsPayload = await fetchTrading212Positions(accountConfig, { accountId });
        snapshot = {
          portfolioValue: Number(user.portfolio) || 0,
          positions: positionsPayload.positions,
          transactions: [],
          raw: { positions: positionsPayload.positions, transactions: [] }
        };
        accountState.lastSnapshotAt = new Date().toISOString();
      }
      if (isLeaderLane) {
        const previousPositionByKey = leaderAlertState.positionByKey || {};
        const nextPositionByKey = buildLeaderPositionQuantityMap(snapshot?.positions || [], accountId);
        for (const [key, nextQty] of Object.entries(nextPositionByKey)) {
          const prevQty = Number(previousPositionByKey[key] || 0);
          const deltaType = classifyPositionDeltaEvent({ previousQty: prevQty, nextQty });
          if (deltaType === 'POSITION_TRIM') {
            forceHistoryFetch = true;
            const existingPending = leaderAlertState.pendingChanges.find(item => item.key === key);
            if (!existingPending) {
              leaderAlertState.pendingChanges.push({
                id: crypto.randomUUID(),
                key,
                type: deltaType,
                previousQty: prevQty,
                nextQty,
                trimPct: computeTrimPercent(prevQty, nextQty),
                detectedAt: new Date().toISOString(),
                status: 'pending_fill_confirmation'
              });
            }
            console.info(`[TradeGroup][LeaderSync] position_change_detected leader=${username} account=${accountId || 'default'} key=${key} type=${deltaType} previousQty=${prevQty} newQty=${nextQty} trimPct=${computeTrimPercent(prevQty, nextQty) ?? 'n/a'}`);
          }
        }
        for (const [key, prevQtyRaw] of Object.entries(previousPositionByKey)) {
          const prevQty = Number(prevQtyRaw || 0);
          if (prevQty <= 1e-8) continue;
          if (Object.prototype.hasOwnProperty.call(nextPositionByKey, key)) continue;
          forceHistoryFetch = true;
          const existingPending = leaderAlertState.pendingChanges.find(item => item.key === key);
          if (!existingPending) {
            leaderAlertState.pendingChanges.push({
              id: crypto.randomUUID(),
              key,
              type: 'POSITION_CLOSED',
              previousQty: prevQty,
              nextQty: 0,
              trimPct: null,
              detectedAt: new Date().toISOString(),
              status: 'pending_fill_confirmation'
            });
          }
          console.info(`[TradeGroup][LeaderSync] position_change_detected leader=${username} account=${accountId || 'default'} key=${key} type=POSITION_CLOSED previousQty=${prevQty} newQty=0 trimPct=n/a`);
        }
        leaderAlertState.positionByKey = nextPositionByKey;
        if (forceHistoryFetch) shouldFetchOrders = true;
      }

      let ordersPayload = null;
      if (shouldFetchOrders && (!ordersGate.skip || !accountState.lastOrdersAt)) {
        try {
          ordersPayload = await fetchTrading212Orders(accountConfig, username, { accountId });
          recordTrading212EndpointAttempt(accountState, 'orders', {
            status: Number(ordersPayload?.debug?.status) || 200,
            headers: ordersPayload?.debug?.headers || {}
          }, now);
          accountState.lastOrdersAt = new Date().toISOString();
          console.info(`[T212][sync][orders] account=${accountId} status=${ordersPayload?.debug?.status ?? 200} parsed=true itemCount=${Array.isArray(ordersPayload?.orders) ? ordersPayload.orders.length : 0} persisted=${Boolean(ordersPayload)} cooldownAppliedAfterSuccess=${Boolean(accountState.endpoints?.orders?.cooldownUntil)} dataSource=fresh_upstream`);
          await sleep(TRADING212_LIST_ENDPOINT_THROTTLE_MS);
        } catch (error) {
          recordTrading212EndpointAttempt(accountState, 'orders', {
            status: Number.isFinite(error?.status) ? Number(error.status) : 500,
            retryAfter: Number.isFinite(error?.retryAfter) ? Number(error.retryAfter) : null
          }, now);
          console.info(`[T212][sync] skipped downstream update endpoint=orders account=${accountId} reason=${error?.message || 'request_failed'}`);
          console.info(`[T212][sync][orders] account=${accountId} status=${Number.isFinite(error?.status) ? Number(error.status) : 'unknown'} parsed=false itemCount=0 persisted=false cooldownAppliedAfterSuccess=false dataSource=cached_db reason=${error?.message || 'request_failed'}`);
        }
      } else if (shouldFetchOrders) {
        console.info(`[T212][sync] skipped endpoint=orders account=${accountId} reason=${ordersGate.reason} until=${ordersGate.until || 'n/a'}`);
        recordTrading212Skip(accountState, 'orders', ordersGate);
        cfg.lastSyncSkip = { accountId, ...accountState.lastSkip };
        console.info(`[T212][sync][orders] account=${accountId} status=skipped parsed=false itemCount=0 persisted=false cooldownAppliedAfterSuccess=false dataSource=cached_db reason=${ordersGate.reason}`);
      } else if (isLeaderLane) {
        console.info(`[TradeGroup][LeaderSync] skipped endpoint=orders account=${accountId} reason=no_open_positions`);
      }

      let historyOrdersPayload = null;
      const checkpoint = accountState.historyCheckpoint || { importedOrderIds: [], importedFillIds: [], lastFilledAt: '' };
      const historyBlockedByCooldown = historyGate.skip && historyGate.reason === 'cooldown';
      const canBypassHistoryCadence = forceHistoryFetch && historyGate.skip && historyGate.reason === 'cadence';
      const shouldRunHistoryReconcile = shouldFetchHistory && (
        !historyGate.skip
        || !accountState.lastHistoryOrdersAt
        || canBypassHistoryCadence
      );
      if (shouldRunHistoryReconcile && !historyBlockedByCooldown) {
        if (canBypassHistoryCadence) {
          console.info(`[TradeGroup][LeaderSync] fast_path_history_reconcile leader=${username} account=${accountId || 'default'} reason=position_delta_detected`);
        }
        try {
          historyOrdersPayload = await fetchTrading212HistoryOrders(accountConfig, username, {
            accountId,
            pageLimit: isLeaderLane ? 20 : 50,
            cursor: '',
            checkpoint,
            maxPages: isLeaderLane ? 1 : 3
          });
          recordTrading212EndpointAttempt(accountState, 'historyOrders', {
            status: Number(historyOrdersPayload?.debug?.historyOrdersStatus) || 200,
            headers: historyOrdersPayload?.debug?.historyOrdersHeaders || {}
          }, now);
          accountState.lastHistoryOrdersAt = new Date().toISOString();
          console.info(`[T212][sync][historyOrders] account=${accountId} status=${historyOrdersPayload?.debug?.historyOrdersStatus ?? 200} parsed=${Array.isArray(historyOrdersPayload?.orders)} itemCount=${Array.isArray(historyOrdersPayload?.orders) ? historyOrdersPayload.orders.length : 0} persisted=${Boolean(historyOrdersPayload)} cooldownAppliedAfterSuccess=${Boolean(accountState.endpoints?.historyOrders?.cooldownUntil)} dataSource=fresh_upstream`);
        } catch (error) {
          recordTrading212EndpointAttempt(accountState, 'historyOrders', {
            status: Number.isFinite(error?.status) ? Number(error.status) : 500,
            retryAfter: Number.isFinite(error?.retryAfter) ? Number(error.retryAfter) : null
          }, now);
          console.info(`[T212][sync] skipped downstream update endpoint=historyOrders account=${accountId} reason=${error?.message || 'request_failed'}`);
          console.info(`[T212][sync][historyOrders] account=${accountId} status=${Number.isFinite(error?.status) ? Number(error.status) : 'unknown'} parsed=false itemCount=0 persisted=false cooldownAppliedAfterSuccess=false dataSource=cached_db reason=${error?.message || 'request_failed'}`);
        }
      } else {
        console.info(`[T212][sync] skipped endpoint=historyOrders account=${accountId} reason=${historyGate.reason} until=${historyGate.until || 'n/a'}`);
        recordTrading212Skip(accountState, 'historyOrders', historyGate);
        cfg.lastSyncSkip = { accountId, ...accountState.lastSkip };
        console.info(`[T212][sync][historyOrders] account=${accountId} status=skipped parsed=false itemCount=0 persisted=false cooldownAppliedAfterSuccess=false dataSource=cached_db reason=${historyGate.reason}`);
      }

      accountResults.push({
        status: 'fulfilled',
        value: {
          accountId,
          accountConfig,
          snapshot,
          ordersPayload,
          historyOrdersPayload,
          leaderPositionsValid: isLeaderLane && Array.isArray(snapshot?.positions),
          leaderPositionByKey: isLeaderLane ? buildLeaderPositionQuantityMap(snapshot?.positions || [], accountId) : {}
        }
      });
      if (accountRecord) {
        accountRecord.syncStatus = 'idle';
        accountRecord.connectionStatus = 'connected';
        accountRecord.lastSyncAt = new Date().toISOString();
        accountRecord.updatedAt = accountRecord.lastSyncAt;
      }
    }

    const fulfilled = accountResults.filter(result => result.status === 'fulfilled').map(result => result.value);
    const rejected = accountResults.filter(result => result.status === 'rejected').map(result => result.reason);
    if (!fulfilled.length) {
      throw rejected[0] || new Trading212Error('Trading 212 sync failed.');
    }
    if (lane === 'leader_alert' && userLeadsTradeGroups(db, username)) {
      for (const result of fulfilled) {
        if (!result.leaderPositionsValid) continue;
        processLeaderTradeDisappearancesAfterValidSnapshot(db, {
          user,
          username,
          cfg,
          accountId: result.accountId || '',
          presentPositionByKey: result.leaderPositionByKey || {}
        });
      }
    }

    let totalStopUpdates = 0;
    const buyFillBudgetByPositionKey = new Map();
    for (const result of fulfilled) {
      if (result.ordersPayload) {
        const { updated: stopUpdates } = upsertTrading212StopOrders(user, result.ordersPayload, result.accountId, rates);
        totalStopUpdates += stopUpdates;
      }
      if (result.historyOrdersPayload) {
        const historyResult = reconcileTrading212HistoricalExits(
          user,
          cfg,
          result.historyOrdersPayload,
          result.accountId,
          result.ordersPayload,
          rates
        );
        const accountState = ensureTrading212AccountSyncState(cfg, result.accountId);
        accountState.historyCheckpoint = {
          importedOrderIds: Array.from(new Set((accountState.historyCheckpoint?.importedOrderIds || []).concat(historyResult.importedOrderIds || []))).slice(-1000),
          importedFillIds: Array.from(new Set((accountState.historyCheckpoint?.importedFillIds || []).concat(historyResult.importedFillIds || []))).slice(-5000),
          lastFilledAt: historyResult.lastFilledAt || accountState.historyCheckpoint?.lastFilledAt || ''
        };
        if (historyResult.imported > 0) {
          console.info(`[T212] imported historical exits account=${result.accountId} imported=${historyResult.imported}`);
        }
        for (const fillEvent of historyResult.importedFillEvents || []) {
          if (String(fillEvent?.side || '').toUpperCase() !== 'BUY') continue;
          const ticker = normalizeTrading212Symbol(fillEvent?.ticker || '');
          const quantity = Number(fillEvent?.quantity);
          if (!ticker || !Number.isFinite(quantity) || quantity <= TRADING212_LAYER_BUY_BUDGET_EPSILON) continue;
          const key = buildTrading212PositionBudgetKey(result.accountId, ticker);
          buyFillBudgetByPositionKey.set(key, Number(buyFillBudgetByPositionKey.get(key) || 0) + quantity);
        }
        if (lane === 'leader_alert' && userLeadsTradeGroups(db, username)) {
          const leaderState = ensureTrading212LeaderAlertState(cfg, result.accountId);
          const groupedFillEvents = coalesceTrading212FillEvents(historyResult.importedFillEvents || []);
          for (const fillEvent of groupedFillEvents) {
            console.info(`[TradeGroup][LeaderSync] new fill detected leader=${username} account=${result.accountId} fillId=${fillEvent?.fillId || 'n/a'} side=${fillEvent?.side || ''}`);
            if (String(fillEvent?.side || '').toUpperCase() === 'SELL') {
              const key = `${result.accountId || ''}:${String(fillEvent?.ticker || '').toUpperCase()}`;
              const pendingForKey = leaderState.pendingChanges
                .filter((item) => String(item?.key || '') === key && String(item?.status || '') === 'pending_fill_confirmation')
                .sort((a, b) => Date.parse(a?.detectedAt || '') - Date.parse(b?.detectedAt || ''));
              const matchedPending = pendingForKey[pendingForKey.length - 1] || null;
              if (matchedPending) {
                fillEvent.previousQuantity = Number(matchedPending.previousQty);
                fillEvent.remainingQuantity = Number.isFinite(Number(fillEvent?.remainingQuantity))
                  ? Number(fillEvent.remainingQuantity)
                  : Number(matchedPending.nextQty);
                fillEvent.trimPct = computeTrimPercent(fillEvent.previousQuantity, fillEvent.remainingQuantity);
              }
            }
            const emitted = emitTradeGroupAlertFromTrading212Fill(db, username, fillEvent);
            if (emitted.alertsCreated > 0) {
              const pendingKey = `${result.accountId || ''}:${String(fillEvent?.ticker || '').toUpperCase()}`;
              leaderState.pendingChanges = leaderState.pendingChanges.filter(item => String(item.key || '') !== pendingKey);
            }
          }
        }
      }
    }
    if (totalStopUpdates > 0) {
      console.info(`[T212] synced current stops for ${totalStopUpdates} trade(s)`);
    }

    const history = ensurePortfolioHistory(user);
    normalizePortfolioHistory(user);
    const { total: currentTotal } = computeNetDepositsTotals(user, history);
    const timezone = cfg.timezone || 'Europe/London';
    const dateKey = dateKeyInTimezone(timezone, runDate);
    const ym = dateKey.slice(0, 7);
    history[ym] ||= {};
    const existing = history[ym][dateKey] || {};
    const cashIn = Number(existing.cashIn ?? 0);
    const cashOut = Number(existing.cashOut ?? 0);
    const isManualEntry = existing.manualEntry === true;
    const existingNote = typeof existing.note === 'string' ? existing.note.trim() : '';
    const integratedAccount = getIntegratedTradingAccount(user, 'trading212');
    const canonicalOwner = resolveCanonicalTrading212OwnerAccount(user);
    console.info('[T212][valuation][sync]', {
      canonicalOwnerAccountId: canonicalOwner?.id || null,
      integrationOwnerAccountId: integratedAccount?.id || null,
      brokerAccountIds: fulfilled.map(result => result.accountId)
    });
    const combinedPortfolioValue = fulfilled.reduce((sum, result) => {
      const value = Number(result.snapshot?.portfolioValue);
      return Number.isFinite(value) ? sum + value : sum;
    }, 0);
    const payload = {
      ...existing,
      end: Number.isFinite(combinedPortfolioValue) ? combinedPortfolioValue : user.portfolio,
      cashIn,
      cashOut
    };
    if (integratedAccount?.id) {
      const existingAccounts = payload.accounts && typeof payload.accounts === 'object' ? payload.accounts : {};
      const selectedAccountRecord = existingAccounts[integratedAccount.id] && typeof existingAccounts[integratedAccount.id] === 'object'
        ? existingAccounts[integratedAccount.id]
        : {};
      const accountCashIn = isManualEntry ? Number(selectedAccountRecord.cashIn ?? 0) : cashIn;
      const accountCashOut = isManualEntry ? Number(selectedAccountRecord.cashOut ?? 0) : cashOut;
      payload.accounts = {
        ...existingAccounts,
        [integratedAccount.id]: {
          ...selectedAccountRecord,
          end: Number.isFinite(combinedPortfolioValue) ? combinedPortfolioValue : Number(selectedAccountRecord.end) || 0,
          cashIn: accountCashIn,
          cashOut: accountCashOut
        }
      };
      carryForwardTradingAccountDayValues(user, history, dateKey, payload, integratedAccount.id);
      applyAccountAggregatesToHistoryEntry(payload);
      if (isManualEntry) {
        payload.cashIn = cashIn;
        payload.cashOut = cashOut;
        payload.manualEntry = true;
      }
      integratedAccount.currentValue = Number.isFinite(combinedPortfolioValue) ? combinedPortfolioValue : (Number(integratedAccount.currentValue) || 0);
      integratedAccount.portfolioValue = integratedAccount.currentValue;
      const accountNetDeposits = Number(payload.accounts[integratedAccount.id]?.cashIn || 0) - Number(payload.accounts[integratedAccount.id]?.cashOut || 0);
      integratedAccount.currentNetDeposits = Number.isFinite(accountNetDeposits) ? accountNetDeposits : (Number(integratedAccount.currentNetDeposits) || 0);
    }
    if (existing.preBaseline) {
      payload.preBaseline = true;
    }
    if (existingNote) {
      payload.note = existingNote;
    }
    history[ym][dateKey] = payload;
    if (Number.isFinite(combinedPortfolioValue)) {
      user.portfolio = combinedPortfolioValue;
    }
    user.portfolioCurrency = 'GBP';
    user.portfolioSource = 'trading212';
    user.lastPortfolioSyncAt = new Date().toISOString();
    if (user.initialPortfolio === undefined && Number.isFinite(combinedPortfolioValue)) {
      user.initialPortfolio = combinedPortfolioValue;
    }
    user.profileComplete = true;
    const { total: updatedTotal } = computeNetDepositsTotals(user, history);
    cfg.lastNetDeposits = Number.isFinite(Number(cfg.lastNetDeposits))
      ? Number(cfg.lastNetDeposits)
      : updatedTotal;
    refreshAnchors(user, history);
    cfg.lastSyncAt = new Date().toISOString();
    const previousAccounts = Array.isArray(cfg.lastRaw?.accounts) ? cfg.lastRaw.accounts : [];
    const rawAccounts = fulfilled.map(result => {
      const prev = previousAccounts.find(entry => entry?.accountId === result.accountId) || {};
      const accountSyncState = ensureTrading212AccountSyncState(cfg, result.accountId);
      const hasFreshSnapshot = Boolean(result.snapshot);
      const hasFreshOrders = Boolean(result.ordersPayload);
      const hasFreshHistory = Boolean(result.historyOrdersPayload);
      return {
        accountId: result.accountId,
        mode: result.accountConfig?.mode || cfg.mode || 'live',
        resolvedBaseUrl: result.snapshot?.baseUrl || prev.resolvedBaseUrl || resolveTrading212BaseUrl(result.accountConfig || cfg),
        portfolio: result.snapshot?.raw ?? prev.portfolio ?? null,
        positions: result.snapshot?.positionsRaw ?? prev.positions ?? null,
        transactions: result.snapshot?.transactionsRaw ?? prev.transactions ?? null,
        orders: result.ordersPayload?.raw ?? prev.orders ?? null,
        historyOrders: result.historyOrdersPayload?.raw ?? prev.historyOrders ?? null,
        upstreamRequestAttempted: true,
        upstreamRequestSucceeded: hasFreshSnapshot || hasFreshOrders || hasFreshHistory,
        upstreamRateLimited: false,
        returnedDataSource: (hasFreshSnapshot || hasFreshOrders || hasFreshHistory) ? 'fresh_upstream' : 'cached_db',
        cooldownUntil: accountSyncState?.endpoints?.historyOrders?.cooldownUntil || accountSyncState?.endpoints?.orders?.cooldownUntil || null,
        ordersDebug: result.ordersPayload?.debug || prev.ordersDebug || null,
        historyOrdersDebug: result.historyOrdersPayload?.debug || prev.historyOrdersDebug || null
      };
    });
    const lastSnapshot = fulfilled[fulfilled.length - 1]?.snapshot;
    if (lastSnapshot?.baseUrl) {
      cfg.lastBaseUrl = lastSnapshot.baseUrl;
      if (!cfg.baseUrl) {
        cfg.baseUrl = lastSnapshot.baseUrl;
      }
      const lowerBase = lastSnapshot.baseUrl.toLowerCase();
      if (lowerBase.includes('demo.trading212.com') || lowerBase.includes('api-demo.trading212.com')) {
        cfg.mode = 'practice';
      } else if (lowerBase.includes('api.trading212.com') || lowerBase.includes('live.trading212.com')) {
        cfg.mode = 'live';
      }
    }
    if (lastSnapshot?.endpoint) {
      cfg.lastEndpoint = lastSnapshot.endpoint;
      if (!cfg.endpoint) {
        cfg.endpoint = lastSnapshot.endpoint;
      }
    }
    cfg.lastRaw = {
      accounts: rawAccounts
    };
    const positionEntries = fulfilled.flatMap(result => {
      const snapshot = result.snapshot || {};
      const inlinePositions = Array.isArray(snapshot.raw?.positions)
        ? snapshot.raw.positions
        : Array.isArray(snapshot.raw?.positions?.items)
          ? snapshot.raw.positions.items
          : Array.isArray(snapshot.raw?.portfolio?.positions)
            ? snapshot.raw.portfolio.positions
            : null;
      const effectivePositions = Array.isArray(snapshot.positions)
        ? snapshot.positions
        : Array.isArray(snapshot.positionsRaw?.items)
          ? snapshot.positionsRaw.items
          : Array.isArray(snapshot.positionsRaw)
            ? snapshot.positionsRaw
            : inlinePositions;
      if (!Array.isArray(effectivePositions)) return [];
      return effectivePositions.map(position => ({ position, accountId: result.accountId }));
    });
    let positionsMutated = false;
    const journal = ensureTradeJournal(user);
    const openTrades = [];
    const closedTrading212Trades = [];
    for (const [tradeDate, items] of Object.entries(journal)) {
      for (const trade of items || []) {
        if (!trade) continue;
        if (trade.status === 'closed') {
          if (trade.source === 'trading212' || trade.trading212Id) {
            closedTrading212Trades.push({ tradeDate, trade });
          }
          continue;
        }
        openTrades.push({ tradeDate, trade });
      }
    }
    const leaderPositionQuantityByAccount = {};
    if (positionEntries.length) {
      const sortedPositions = positionEntries.slice().sort((a, b) => {
        const aSymbol = String(a?.position?.instrument?.ticker ?? a?.position?.ticker ?? a?.position?.symbol ?? '').toUpperCase();
        const bSymbol = String(b?.position?.instrument?.ticker ?? b?.position?.ticker ?? b?.position?.symbol ?? '').toUpperCase();
        return aSymbol.localeCompare(bSymbol);
      });
      for (const entry of sortedPositions) {
        const raw = entry.position;
        const accountId = entry.accountId || '';
        const instrument = raw?.instrument || {};
        const optionContract = parseTrading212OptionContract(raw);
        const instrumentType = String(instrument?.type ?? raw?.instrumentType ?? '').trim().toLowerCase();
        const assetClass = (instrumentType.includes('option') || optionContract.optionType)
          ? 'options'
          : 'stocks';
        const walletImpact = raw?.walletImpact || {};
        const rawName = instrument?.name ?? raw?.name ?? '';
        const rawIsin = instrument?.isin ?? raw?.isin ?? '';
        const rawUid = String(instrument?.id ?? instrument?.uid ?? raw?.instrumentId ?? raw?.instrumentUid ?? raw?.id ?? '').trim();
        const rawTickerValue = normalizeTrading212TickerValue(
          raw?.ticker ??
          raw?.symbol ??
          instrument?.ticker ??
          instrument?.symbol ??
          rawIsin ??
          ''
        );
        const symbol = normalizeTrading212Symbol(rawTickerValue);
        if (!symbol) continue;
        const tradeCurrency = String(instrument?.currency ?? raw?.currency ?? walletImpact?.currency ?? 'GBP').trim().toUpperCase() || 'GBP';
        const rawExchange = String(instrument?.exchange ?? raw?.exchange ?? '').trim().toUpperCase();
        const { entry: registryEntry, created: registryCreated } = upsertRegistryEntry(db, {
          broker: 'trading212',
          brokerInstrumentId: rawUid || '',
          rawTicker: rawTickerValue,
          rawName,
          isin: rawIsin,
          rawCurrency: tradeCurrency,
          rawExchange,
          instrumentType: String(instrument?.type ?? raw?.instrumentType ?? '').trim().toLowerCase()
        });
        if (registryEntry.manualOverride !== true && (registryCreated || !registryEntry.lastVerifiedAt)) {
          const resolution = await lookupCanonicalInstrument({
            broker: 'trading212',
            brokerInstrumentId: rawUid || '',
            rawTicker: rawTickerValue,
            rawName,
            isin: rawIsin,
            rawCurrency: tradeCurrency,
            rawExchange
          }, db);
          applyRegistryResolution(db, registryEntry, resolution, registryCreated ? 'first_seen_lookup' : 'revalidation', 'system');
        }
        const resolvedCanonicalTicker = (registryEntry.resolutionStatus === 'resolved' || registryEntry.resolutionStatus === 'manual_override')
          ? String(registryEntry.canonicalTicker || '').trim().toUpperCase()
          : '';
        const resolvedSymbol = resolvedCanonicalTicker || symbol;
        const quantity = parseTradingNumber(
          raw?.quantity ??
          raw?.qty ??
          raw?.units ??
          raw?.size ??
          raw?.shares ??
          raw?.quantityAvailableForTrading ??
          raw?.availableQuantity
        );
        const entryPrice = parseTradingNumber(
          raw?.averagePricePaid ??
          raw?.averagePrice ??
          raw?.avgPrice ??
          raw?.openPrice ??
          raw?.price ??
          raw?.averagePrice?.value ??
          raw?.averagePrice?.amount
        );
        const currentPrice = parseTradingNumber(
          raw?.currentPrice ??
          raw?.lastPrice ??
          raw?.price ??
          raw?.marketPrice ??
          instrument?.currentPrice ??
          instrument?.price
        );
        const ppl = parseTradingNumber(
          raw?.ppl ??
          raw?.profitLoss ??
          raw?.unrealizedPnl ??
          raw?.pnl ??
          raw?.openPnl ??
          walletImpact?.unrealizedProfitLoss ??
          walletImpact?.unrealizedPnl ??
          walletImpact?.profitLoss ??
          walletImpact?.pnl
        );
        if (!Number.isFinite(quantity) || !Number.isFinite(entryPrice)) continue;
        if (lane === 'leader_alert') {
          const positionKey = accountId ? `${accountId}:${symbol}` : symbol;
          leaderPositionQuantityByAccount[accountId] ||= {};
          leaderPositionQuantityByAccount[accountId][positionKey] = Math.abs(Number(quantity) || 0);
        }
        const createdAt = Date.parse(raw?.createdAt || raw?.openDate || raw?.dateOpened || '');
        const createdAtDate = Number.isFinite(createdAt) ? new Date(createdAt) : runDate;
        const normalizedDate = dateKeyInTimezone(timezone, createdAtDate);
        const normalizedName = normalizeTrading212Name(rawName);
        const rawPositionId = raw?.id || raw?.positionId;
        const trading212Key = rawIsin
          ? `isin:${rawIsin.toUpperCase()}`
          : (normalizedName ? `name:${normalizedName}` : symbol);
        const trading212IdBase = rawPositionId ? String(rawPositionId) : trading212Key;
        const trading212Id = accountId ? `${accountId}:${trading212IdBase}` : trading212IdBase;
        const trading212PositionKey = accountId ? `${accountId}:${symbol}` : symbol;
        const closedMatch = closedTrading212Trades.find((entry) => {
          if (!entry?.trade) return false;
          const instrumentMatches = (
            entry.trade.trading212PositionKey === trading212PositionKey
            || entry.trade.trading212Id === trading212Id
            || entry.trade.trading212Id === trading212IdBase
            || (rawIsin && entry.trade.trading212Isin === rawIsin)
            || (rawTickerValue && normalizeTrading212TickerValue(entry.trade.trading212Ticker) === rawTickerValue)
            || entry.trade.symbol === symbol
          );
          if (!instrumentMatches) return false;
          // Temporal guards: allow a re-open when there is positive evidence this is a new position.
          // 1. If T212 reports when this position was opened and it is after the recorded close date,
          //    the user re-bought after closing — not a phantom re-open.
          // 2. If the close happened more than 48 hours before the current sync run, any matching
          //    snapshot entry is almost certainly a genuine re-buy, not API lag.
          const tradeClosedAtMs = Date.parse(entry.trade.closedAt || entry.trade.closeDate || '');
          if (Number.isFinite(tradeClosedAtMs)) {
            if (Number.isFinite(createdAt) && createdAt > tradeClosedAtMs) return false;
            if ((runDate.getTime() - tradeClosedAtMs) > 48 * 60 * 60 * 1000) return false;
          }
          return true;
        });
        if (closedMatch?.trade) {
          console.info('[trade-reconcile]', {
            source: 't212_snapshot',
            action: 'skip_reopen_closed_trade',
            tradeId: closedMatch.trade.id || null,
            trading212Id,
            trading212PositionKey
          });
          continue;
        }
        const { exactTradeEntry, aggregateTradeEntry } = findTrading212OpenTradeMatch(openTrades, {
          accountId,
          trading212Id,
          trading212IdBase,
          trading212Key,
          trading212PositionKey,
          symbol,
          rawIsin,
          normalizedName,
          rawTickerValue
        });
        const existingTradeEntry = exactTradeEntry || aggregateTradeEntry;
        const existingTrade = existingTradeEntry?.trade;
        const effectiveResolvedSymbol = existingTrade?.displaySymbol || existingTrade?.symbol || resolvedSymbol;
        journal[normalizedDate] ||= [];
        const direction = quantity < 0 || String(raw?.side || '').toLowerCase() === 'short' ? 'short' : 'long';
        const stop = parseTradingNumber(
          raw?.stopLoss ??
          raw?.stopPrice ??
          raw?.stop ??
          raw?.stopLossPrice ??
          raw?.trailingStopLoss ??
          raw?.trailingStopPrice
        );
        const sizeUnits = Math.abs(quantity);
        const tradeDateKey = getNyDateKeyForDate(createdAtDate, false);
        let lowStop = null;
        try {
          const lowQuote = await fetchDailyLow(effectiveResolvedSymbol, tradeDateKey);
          lowStop = Number(lowQuote?.low);
        } catch (e) {
          lowStop = null;
        }
        const relatedOpenTrades = openTrades.filter(entry => {
          const trade = entry?.trade;
          if (!trade || trade.status === 'closed') return false;
          const tradeAccountId = String(trade.trading212AccountId || '');
          const isFallbackAccountId = /^account-\d+$/.test(tradeAccountId);
          if (tradeAccountId && accountId && tradeAccountId !== accountId && !isFallbackAccountId) return false;
          return (
            trade.trading212PositionKey === trading212PositionKey
            || trade.trading212Id === trading212Id
            || trade.symbol === symbol
            || trade.symbol === resolvedSymbol
            || (rawIsin && trade.trading212Isin === rawIsin)
            || (rawTickerValue && normalizeTrading212TickerValue(trade.trading212Ticker) === rawTickerValue)
          );
        });
        if (relatedOpenTrades.length) {
          const totalTrackedUnits = relatedOpenTrades.reduce((sum, entry) => {
            const units = Number(entry?.trade?.sizeUnits);
            return Number.isFinite(units) && units > 0 ? sum + units : sum;
          }, 0);
          for (const related of relatedOpenTrades) {
            updateTrading212LayerMetadata(related.trade, {
              symbol: related.trade?.displaySymbol || related.trade?.symbol || resolvedSymbol,
              trading212Id: related.trade?.trading212Id || trading212Id,
              trading212PositionKey,
              accountId,
              rawName,
              rawIsin,
              rawTickerValue,
              optionContract,
              tradeCurrency,
              direction,
              currentPrice,
              stop,
              lowStop,
              user,
              rates
            });
          }
          const addToPosition = isTrading212AddToPosition({ sizeUnits: totalTrackedUnits }, sizeUnits);
          if (addToPosition) {
            const weightedNotional = relatedOpenTrades.reduce((sum, entry) => {
              const units = Number(entry?.trade?.sizeUnits);
              const tradeEntry = Number(entry?.trade?.entry);
              if (!Number.isFinite(units) || units <= 0 || !Number.isFinite(tradeEntry) || tradeEntry <= 0) return sum;
              return sum + (units * tradeEntry);
            }, 0);
            const previousUnits = totalTrackedUnits;
            const previousEntry = previousUnits > 0 ? weightedNotional / previousUnits : Number(existingTrade?.entry);
            const addedUnits = sizeUnits - previousUnits;
            if (addedUnits > TRADING212_LAYER_BUY_BUDGET_EPSILON) {
              const budgetKey = buildTrading212PositionBudgetKey(accountId, symbol);
              const hasBuyFillAnchor = consumeTrading212BuyFillBudget(buyFillBudgetByPositionKey, budgetKey, addedUnits);
              if (hasBuyFillAnchor) {
                const inferredAddedEntry = inferTrading212AddedEntryPrice(previousEntry, previousUnits, entryPrice, sizeUnits);
                const layerEntryPrice = Number.isFinite(inferredAddedEntry) ? inferredAddedEntry : entryPrice;
                const seedTrade = existingTrade || relatedOpenTrades[relatedOpenTrades.length - 1]?.trade;
                const layeredTrade = normalizeTradeMeta({
                  ...seedTrade,
                  id: crypto.randomBytes(8).toString('hex'),
                  createdAt: createdAtDate.toISOString(),
                  entry: layerEntryPrice,
                  sizeUnits: addedUnits,
                  symbol: effectiveResolvedSymbol,
                  status: 'open',
                  closeDate: undefined,
                  closePrice: undefined,
                  closedAt: undefined,
                  partialCloses: undefined,
                  trading212Id: `${trading212Id}#layer:${Date.now()}`
                });
                delete layeredTrade.realizedPnlGBP;
                delete layeredTrade.realizedPnlCurrency;
                delete layeredTrade.rMultiple;
                updateTrading212LayerMetadata(layeredTrade, {
                  symbol: effectiveResolvedSymbol,
                  trading212Id: layeredTrade.trading212Id,
                  trading212PositionKey,
                  accountId,
                  rawName,
                  rawIsin,
                  rawTickerValue,
                  optionContract,
                  tradeCurrency,
                  direction,
                  currentPrice,
                  stop,
                  lowStop,
                  user,
                  rates
                });
                if (Number.isFinite(ppl)) {
                  layeredTrade.ppl = ppl;
                }
                journal[normalizedDate].push(layeredTrade);
                openTrades.push({ tradeDate: normalizedDate, trade: layeredTrade });
                console.info('[T212][reconcile]', {
                  stage: 'snapshot_add_to_position',
                  accountId: accountId || 'default',
                  symbol,
                  matchedExistingLeg: false,
                  createdNewLeg: true,
                  duplicateLegCollapsed: false,
                  brokerIdentifierUsed: 'history_buy_fill_budget',
                  addedUnits
                });
              } else {
                const targetEntry = relatedOpenTrades.slice().sort((a, b) => {
                  const aCreated = Date.parse(a?.trade?.createdAt || a?.tradeDate || '');
                  const bCreated = Date.parse(b?.trade?.createdAt || b?.tradeDate || '');
                  return bCreated - aCreated;
                })[0];
                if (targetEntry?.trade) {
                  const currentUnits = Number(targetEntry.trade.sizeUnits);
                  targetEntry.trade.sizeUnits = (Number.isFinite(currentUnits) ? currentUnits : 0) + addedUnits;
                  updateTrading212LayerMetadata(targetEntry.trade, {
                    symbol: targetEntry.trade?.displaySymbol || targetEntry.trade?.symbol || resolvedSymbol,
                    trading212Id: targetEntry.trade?.trading212Id || trading212Id,
                    trading212PositionKey,
                    accountId,
                    rawName,
                    rawIsin,
                    rawTickerValue,
                    optionContract,
                    tradeCurrency,
                    direction,
                    currentPrice,
                    stop,
                    lowStop,
                    user,
                    rates
                  });
                  console.info('[T212][reconcile]', {
                    stage: 'snapshot_add_to_position',
                    accountId: accountId || 'default',
                    symbol,
                    matchedExistingLeg: true,
                    createdNewLeg: false,
                    duplicateLegCollapsed: true,
                    brokerIdentifierUsed: 'position_key_fallback',
                    addedUnits
                  });
                }
              }
            }
          }
          positionsMutated = true;
          continue;
        }
        const initialStop = Number.isFinite(stop) && stop > 0
          ? stop
          : (Number.isFinite(lowStop) ? lowStop : undefined);
        const trade = normalizeTradeMeta({
          id: crypto.randomBytes(8).toString('hex'),
          symbol: effectiveResolvedSymbol,
          currency: tradeCurrency,
          entry: entryPrice,
          stop: initialStop,
          currentStop: initialStop,
          currentStopSource: Number.isFinite(stop) && stop > 0 ? 't212' : undefined,
          currentStopStale: Number.isFinite(stop) && stop > 0 ? false : undefined,
          sizeUnits,
          lastSyncPrice: Number.isFinite(currentPrice) && currentPrice > 0 ? currentPrice : undefined,
          riskPct: 0,
          perUnitRisk: Number.isFinite(initialStop) ? Math.abs(entryPrice - initialStop) : 0,
          riskAmountCurrency: 0,
          positionCurrency: entryPrice * sizeUnits,
          riskAmountGBP: 0,
          positionGBP: convertToGBP(entryPrice * sizeUnits, tradeCurrency, rates),
          portfolioGBPAtCalc: getPortfolioGBPForRisk(user),
          portfolioCurrencyAtCalc: convertGBPToCurrency(getPortfolioGBPForRisk(user), tradeCurrency, rates),
          createdAt: createdAtDate.toISOString(),
          direction,
          status: 'open',
          tradeType: 'day',
          assetClass,
          source: 'trading212',
          trading212Id,
          trading212PositionKey,
          trading212AccountId: accountId || undefined,
          trading212Name: rawName || undefined,
          trading212Isin: rawIsin || undefined,
          trading212Ticker: rawTickerValue || undefined,
          optionType: optionContract.optionType || undefined,
          optionStrike: Number.isFinite(optionContract.optionStrike) ? optionContract.optionStrike : undefined,
          optionExpiration: optionContract.optionExpiration || undefined,
          optionMultiplier: Number.isFinite(optionContract.optionMultiplier) ? optionContract.optionMultiplier : undefined,
          trading212RegistryId: registryEntry.id,
          canonicalTicker: resolvedCanonicalTicker || undefined,
          canonicalName: registryEntry.canonicalName || undefined,
          resolutionStatus: registryEntry.resolutionStatus || undefined,
          lastSyncPrice: Number.isFinite(currentPrice) && currentPrice > 0 ? currentPrice : undefined,
          ppl: Number.isFinite(ppl) ? ppl : undefined
        });
        recalculateTradeRiskFromImportedStop(trade, user, rates);
        journal[normalizedDate].push(trade);
        openTrades.push({ tradeDate: normalizedDate, trade });
        console.info(`[TradeGroup][T212] new leader position detected leader=${username} trade=${trade.id} brokerKey=${trade.trading212PositionKey || trade.trading212Id || trade.trading212Ticker || trade.symbol || ''}`);
        scheduleTrading212TradeGroupAlertsForNewPosition(db, username, trade, new Date());
        positionsMutated = true;
      }
    }
    if (lane === 'leader_alert' && userLeadsTradeGroups(db, username)) {
      for (const result of fulfilled) {
        const accountId = result.accountId || '';
        const leaderState = ensureTrading212LeaderAlertState(cfg, accountId);
        const prev = leaderState.positionByKey || {};
        const next = leaderPositionQuantityByAccount[accountId] || {};
        for (const [key, qty] of Object.entries(next)) {
          const previousQty = Number(prev[key] || 0);
          if (Math.abs(previousQty - qty) > 1e-8) {
            const existingPending = leaderState.pendingChanges.find(item => item.key === key);
            if (!existingPending) {
              leaderState.pendingChanges.push({
                id: crypto.randomUUID(),
                key,
                previousQty,
                nextQty: qty,
                detectedAt: new Date().toISOString(),
                status: 'pending_fill_confirmation'
              });
            }
            console.info(`[TradeGroup][LeaderSync] position delta pending leader=${username} account=${accountId || 'default'} key=${key} from=${previousQty} to=${qty}`);
          }
        }
        leaderState.positionByKey = next;
        leaderState.lastRunAt = new Date().toISOString();
      }
    } else if (fulfilled.length) {
      const openTrading212Trades = openTrades.filter(entry => {
        const trade = entry?.trade;
        return trade && (trade.trading212Id || trade.source === 'trading212');
      });
      if (openTrading212Trades.length) {
        console.info(`[T212][sync] preserving_open_positions_on_snapshot_gap username=${username} openTrades=${openTrading212Trades.length} reason=positions_snapshot_empty_or_unavailable`);
      }
      for (const entry of openTrading212Trades) {
        const trade = entry.trade;
        console.info(`[T212][sync] open trade retained trade=${trade.id} account=${trade.trading212AccountId || 'default'} reason=no_positive_close_evidence`);
      }
    }
    cfg.lastSyncAt = new Date().toISOString();
    cfg.lastSuccessfulSyncAt = cfg.lastSyncAt;
    cfg.lastDataSource = 'fresh_upstream';
    cfg.lastSyncError = null;
    cfg.lastSyncSkip = null;
    cfg.syncInProgress = false;
    if (!cfg.minuteSync) {
      cfg.minuteSync = true;
      scheduleTrading212Job(username, user);
    }
    if (rejected.length) {
      const rateLimit = rejected.find(err => err instanceof Trading212RateLimitError);
      if (rateLimit && rateLimit.retryAfter) {
        cfg.cooldownUntil = new Date(now + rateLimit.retryAfter * 1000).toISOString();
      }
      cfg.lastStatus = {
        ok: false,
        status: 207,
        message: `Trading 212 sync completed with ${rejected.length} account(s) failing.`
      };
    } else {
      cfg.lastStatus = { ok: true, status: 200 };
      delete cfg.cooldownUntil;
    }
    processPendingTrading212GroupAlerts(db, { now: new Date() });
    saveDB(db);
    return { ok: true };
  })().catch((e) => {
    const db = loadDB();
    const user = db.users[username];
    if (!user) return { ok: false, error: e };
    ensureUserShape(user, username);
    const cfg = user.trading212 || {};
    const now = Date.now();
    cfg.lastSyncAt = new Date().toISOString();
    const retryAfter = e instanceof Trading212Error ? e.retryAfter : null;
    if (retryAfter !== null && retryAfter !== undefined) {
      cfg.cooldownUntil = new Date(now + retryAfter * 1000).toISOString();
    }
    if (e instanceof Trading212Error && e.baseUrl) {
      cfg.lastBaseUrl = e.baseUrl;
    }
    if (e instanceof Trading212Error && e.endpoint) {
      cfg.lastEndpoint = e.endpoint;
    }
    cfg.lastSyncError = e && e.message ? e.message : 'Unknown Trading 212 error';
    cfg.lastStatus = {
      ok: false,
      status: e instanceof Trading212Error && e.status !== undefined ? e.status : undefined,
      retryAfter: retryAfter !== null && retryAfter !== undefined ? retryAfter : undefined,
      message: cfg.lastSyncError
    };
    if (e instanceof Trading212Error && e.raw) {
      cfg.lastRaw = e.raw;
    }
    cfg.syncInProgress = false;
    cfg.lastDataSource = 'cached_db';
    saveDB(db);
    console.error(`Trading 212 sync failed for ${username}`, e);
    return { ok: false, error: e };
  }).finally(() => {
    TRADING212_ACCOUNT_LOCKS.delete(lockKey);
  });

  TRADING212_ACCOUNT_LOCKS.set(lockKey, syncPromise);
  return syncPromise;
}

function stopTrading212Job(username) {
  const job = trading212Jobs.get(username);
  if (job) {
    if (job.type === 'cron') {
      job.handle.stop();
    } else {
      clearInterval(job.handle);
    }
    trading212Jobs.delete(username);
  }
  const leaderJob = trading212LeaderJobs.get(username);
  if (leaderJob) {
    clearInterval(leaderJob.handle);
    trading212LeaderJobs.delete(username);
  }
}

function scheduleTrading212Job(username, user) {
  stopTrading212Job(username);
  const cfg = user?.trading212;
  if (!cfg || !cfg.enabled || !getTrading212Accounts(cfg).length) return;
  const handle = setInterval(() => {
    syncTrading212ForUser(username, new Date());
  }, T212_SYNC_INTERVAL_MS);
  trading212Jobs.set(username, { type: 'interval', handle });
  if (userLeadsTradeGroups(loadDB(), username)) {
    const leaderHandle = setInterval(async () => {
      const db = loadDB();
      const liveUser = db.users?.[username];
      if (!liveUser?.trading212?.enabled) {
        console.info(`[TradeGroup][LeaderSync] skipped leader=${username} reason=integration_disabled`);
        return;
      }
      if (!userLeadsTradeGroups(db, username)) {
        console.info(`[TradeGroup][LeaderSync] skipped leader=${username} reason=no_groups_led`);
        return;
      }
      const hasOpenPositions = Object.values(ensureTradeJournal(liveUser)).flat().some(trade => (
        trade
        && trade.status !== 'closed'
        && (trade.source === 'trading212' || trade.trading212Id)
      ));
      const cadence = hasOpenPositions
        ? (isUsMarketHours(new Date()) ? T212_LEADER_ALERT_MARKET_HOURS_INTERVAL_MS : T212_LEADER_ALERT_OFF_HOURS_INTERVAL_MS)
        : T212_LEADER_ALERT_NO_POSITION_INTERVAL_MS;
      const cfg = liveUser.trading212;
      const lastRunTs = Date.parse(cfg?.leaderAlertState?.lastRunAt || cfg?.lastLeaderAlertSyncAt || '');
      if (Number.isFinite(lastRunTs) && (Date.now() - lastRunTs) < cadence) {
        console.info(`[TradeGroup][LeaderSync] skipped leader=${username} reason=cadence`);
        return;
      }
      const result = await syncTrading212ForUser(username, new Date(), { lane: 'leader_alert' });
      if (!result?.skipped) {
        const dbAfter = loadDB();
        const latestUser = dbAfter.users?.[username];
        if (latestUser?.trading212) {
          latestUser.trading212.lastLeaderAlertSyncAt = new Date().toISOString();
          if (!latestUser.trading212.leaderAlertState || typeof latestUser.trading212.leaderAlertState !== 'object') {
            latestUser.trading212.leaderAlertState = {};
          }
          latestUser.trading212.leaderAlertState.lastRunAt = latestUser.trading212.lastLeaderAlertSyncAt;
          saveDB(dbAfter);
        }
      }
    }, T212_LEADER_ALERT_SYNC_TICK_MS);
    trading212LeaderJobs.set(username, { type: 'interval', handle: leaderHandle });
  }
}

function bootstrapPendingTradeGroupAlertSchedules() {
  const db = loadDB();
  ensureSocialTables(db);
  const nowMs = Date.now();
  for (const pending of db.tradeGroupPendingAlerts) {
    if (pending.status !== 'pending') continue;
    const scheduledMs = Date.parse(pending.scheduled_for || '');
    const delayMs = Number.isFinite(scheduledMs) ? Math.max(0, scheduledMs - nowMs) : 0;
    schedulePendingTradeGroupAlertTimer(pending.id, delayMs);
  }
}

async function fetchIbkrAuthStatus() {
  return requestIbkrEndpoint('/iserver/auth/status');
}

async function applyIbkrSnapshotToUser(user, snapshot, derivedStopByTicker = {}) {
  updateIbkrLivePositions(user, snapshot, derivedStopByTicker);
  updateIbkrLiveOrders(user, snapshot.orders || []);
  recordIbkrUserSnapshot(user, snapshot);
  const rates = await fetchRates();
  const snapshotDate = snapshot.meta?.ts ? new Date(snapshot.meta.ts) : new Date();
  const rootCurrency = snapshot.rootCurrency || 'GBP';
  const nextPortfolio = rootCurrency !== 'GBP'
    ? convertToGBP(snapshot.portfolioValue, rootCurrency, rates)
    : snapshot.portfolioValue;
  if (Number.isFinite(nextPortfolio)) {
    user.portfolio = nextPortfolio;
    user.portfolioCurrency = 'GBP';
    user.portfolioSource = 'ibkr';
    user.lastPortfolioSyncAt = new Date().toISOString();
    if (user.initialPortfolio === undefined) {
      user.initialPortfolio = nextPortfolio;
    }
  }
  const history = ensurePortfolioHistory(user);
  normalizePortfolioHistory(user);
  const dateKey = dateKeyInTimezone('Europe/London', snapshotDate);
  const ym = dateKey.slice(0, 7);
  history[ym] ||= {};
  const existing = history[ym][dateKey] || {};
  let cashIn = Number(existing.cashIn ?? 0);
  let cashOut = Number(existing.cashOut ?? 0);
  const netDepositsMeta = extractIbkrNetDeposits(snapshot.raw?.summary, snapshot.raw?.ledger);
  if (netDepositsMeta && Number.isFinite(netDepositsMeta.value)) {
    const netDepositsCurrency = netDepositsMeta.currency || rootCurrency || 'GBP';
    const netDepositsGBP = netDepositsCurrency !== 'GBP'
      ? convertToGBP(netDepositsMeta.value, netDepositsCurrency, rates)
      : netDepositsMeta.value;
    if (Number.isFinite(netDepositsGBP)) {
      const cfg = user.ibkr || {};
      const previousNetDeposits = Number.isFinite(Number(cfg.lastNetDeposits))
        ? Number(cfg.lastNetDeposits)
        : null;
      const delta = previousNetDeposits === null ? netDepositsGBP : netDepositsGBP - previousNetDeposits;
      if (Number.isFinite(delta) && delta !== 0) {
        if (delta > 0) {
          cashIn += delta;
        } else {
          cashOut += Math.abs(delta);
        }
      }
      cfg.lastNetDeposits = netDepositsGBP;
    }
  }
  const integratedAccount = getIntegratedTradingAccount(user, 'ibkr');
  const payload = {
    ...existing,
    end: Number.isFinite(nextPortfolio) ? nextPortfolio : existing.end,
    cashIn,
    cashOut
  };
  if (integratedAccount?.id) {
    const existingAccounts = payload.accounts && typeof payload.accounts === 'object' ? payload.accounts : {};
    const selectedAccountRecord = existingAccounts[integratedAccount.id] && typeof existingAccounts[integratedAccount.id] === 'object'
      ? existingAccounts[integratedAccount.id]
      : {};
    payload.accounts = {
      ...existingAccounts,
      [integratedAccount.id]: {
        ...selectedAccountRecord,
        end: Number.isFinite(nextPortfolio) ? nextPortfolio : Number(selectedAccountRecord.end) || 0,
        cashIn,
        cashOut
      }
    };
    carryForwardTradingAccountDayValues(user, history, dateKey, payload, integratedAccount.id);
    applyAccountAggregatesToHistoryEntry(payload);
    integratedAccount.currentValue = Number.isFinite(nextPortfolio) ? nextPortfolio : (Number(integratedAccount.currentValue) || 0);
    integratedAccount.portfolioValue = integratedAccount.currentValue;
    const accountNetDeposits = Number(payload.accounts[integratedAccount.id]?.cashIn || 0) - Number(payload.accounts[integratedAccount.id]?.cashOut || 0);
    integratedAccount.currentNetDeposits = Number.isFinite(accountNetDeposits) ? accountNetDeposits : (Number(integratedAccount.currentNetDeposits) || 0);
  }
  history[ym][dateKey] = payload;
  if (existing.preBaseline) {
    history[ym][dateKey].preBaseline = true;
  }
  if (existing.note) {
    history[ym][dateKey].note = existing.note;
  }
  user.profileComplete = true;
  refreshAnchors(user, history);
  upsertIbkrTradesFromSnapshot(user, snapshot, derivedStopByTicker, rates, snapshotDate);
  const { updated: stopUpdates } = applyIbkrDerivedStopsToTrades(user, derivedStopByTicker);
  if (stopUpdates > 0) {
    console.info(`[IBKR] synced current stops for ${stopUpdates} trade(s)`);
  }
}

function updateIbkrConnectorStatus(cfg) {
  const lastHeartbeat = cfg.lastHeartbeatAt ? Date.parse(cfg.lastHeartbeatAt) : null;
  const now = Date.now();
  const isOnline = lastHeartbeat && Number.isFinite(lastHeartbeat) && (now - lastHeartbeat < 90 * 1000);
  const reportedStatus = cfg.lastConnectorStatus?.status;
  if (reportedStatus === 'disconnected' || reportedStatus === 'error') {
    cfg.connectionStatus = reportedStatus;
    return cfg.connectionStatus;
  }
  cfg.connectionStatus = isOnline ? 'online' : 'offline';
  return cfg.connectionStatus;
}

function applyIbkrHeartbeat(user, heartbeat) {
  const cfg = user?.ibkr;
  if (!cfg) return;
  cfg.enabled = true;
  cfg.mode = 'connector';
  cfg.lastHeartbeatAt = new Date().toISOString();
  cfg.lastConnectorStatus = {
    status: heartbeat.status || 'online',
    reason: heartbeat.reason || '',
    authStatus: heartbeat.authStatus || null,
    connectorVersion: heartbeat.connectorVersion || '',
    gatewayUrl: heartbeat.gatewayUrl || '',
    receivedAt: cfg.lastHeartbeatAt
  };
  cfg.connectionStatus = cfg.lastConnectorStatus.status;
}

async function syncIbkrForUser(username, runDate = new Date()) {
  const db = loadDB();
  const user = db.users[username];
  if (!user) return;
  ensureUserShape(user, username);
  const cfg = user.ibkr;
  if (!cfg || !cfg.enabled || cfg.mode !== 'connector') return;
  const status = updateIbkrConnectorStatus(cfg);
  if (status === 'offline') {
    cfg.lastStatus = {
      ok: false,
      status: 503,
      message: 'Connector offline. Please run the local IBKR connector.'
    };
    saveDB(db);
    return;
  }
  if (!cfg.lastSnapshotAt) {
    cfg.lastStatus = {
      ok: false,
      status: 404,
      message: 'No IBKR snapshots received yet.'
    };
  } else {
    cfg.lastStatus = { ok: true, status: 200 };
  }
  saveDB(db);
}

function stopIbkrJob(username) {
  const job = ibkrJobs.get(username);
  if (job) {
    clearInterval(job.handle);
    ibkrJobs.delete(username);
  }
}

function scheduleIbkrJob(username, user) {
  stopIbkrJob(username);
  const cfg = user?.ibkr;
  if (!cfg || !cfg.enabled || cfg.mode !== 'connector') return;
  const handle = setInterval(() => {
    syncIbkrForUser(username, new Date());
  }, IBKR_SYNC_INTERVAL_MS);
  ibkrJobs.set(username, { type: 'interval', handle });
}

async function refreshIntegratedTradingAccountsNow(username, user) {
  const tradingAccounts = Array.isArray(user?.tradingAccounts) ? user.tradingAccounts : [];
  const hasTrading212Integration = tradingAccounts.some(account => account?.integrationEnabled && account?.integrationProvider === 'trading212');
  const hasIbkrIntegration = tradingAccounts.some(account => account?.integrationEnabled && account?.integrationProvider === 'ibkr');

  if (hasTrading212Integration && user?.trading212?.enabled && getTrading212Accounts(user.trading212).length) {
    await syncTrading212ForUser(username, new Date());
  }

  if (hasIbkrIntegration && user?.ibkr?.enabled && user?.ibkr?.mode === 'connector') {
    await syncIbkrForUser(username, new Date());
  }
}

function bootstrapIbkrSchedules() {
  const db = loadDB();
  for (const [username, user] of Object.entries(db.users || {})) {
    ensureUserShape(user, username);
    if (user?.ibkr?.enabled && user?.ibkr?.mode === 'connector') {
      scheduleIbkrJob(username, user);
    }
  }
}

app.use(bodyParser.json());
app.use(express.urlencoded({ extended: true }));
app.use(cookieParser());
app.use((req, res, next) => {
  const inboundId = String(req.headers?.[PERF_REQUEST_ID_HEADER] || '').trim();
  const requestId = inboundId || `${INSTANCE_ID}-${crypto.randomUUID().slice(0, 8)}`;
  req.requestId = requestId;
  res.setHeader(PERF_REQUEST_ID_HEADER, requestId);
  next();
});
app.use('/api', (req, res, next) => {
  const startedAt = process.hrtime.bigint();
  const enabled = shouldEnablePerfDiagnostics(req);
  const routePath = req.path || req.originalUrl || '';
  const shouldCapture = shouldCaptureApiPerf(routePath);
  const sections = {};
  const meta = {
    cache: 'bypass',
    externalProviderAttempted: false,
    externalProviderDurationMs: 0,
    dbReadDurationMs: 0,
    transformDurationMs: 0,
    summaryModeUsed: false,
    payloadTrimmed: false,
    requestScopedReuse: false,
    resultCount: null,
    accountCount: null
  };
  let responseBytes = 0;
  const originalJson = res.json.bind(res);
  const originalSend = res.send.bind(res);
  res.json = (payload) => {
    responseBytes = estimatePayloadBytes(payload);
    return originalJson(payload);
  };
  res.send = (payload) => {
    responseBytes = estimatePayloadBytes(payload);
    return originalSend(payload);
  };
  req.perfDiag = {
    enabled,
    requestId: req.requestId,
    setMeta: (patch = {}) => Object.assign(meta, patch || {}),
    addSectionMs: (key, durationMs) => {
      if (!key || !Number.isFinite(durationMs)) return;
      sections[key] = Number(durationMs.toFixed(2));
    },
    timeSync: (key, fn) => {
      const sectionStart = process.hrtime.bigint();
      const result = fn();
      const durationMs = Number(process.hrtime.bigint() - sectionStart) / 1e6;
      req.perfDiag.addSectionMs(key, durationMs);
      return result;
    },
    timeAsync: async (key, fn) => {
      const sectionStart = process.hrtime.bigint();
      const result = await fn();
      const durationMs = Number(process.hrtime.bigint() - sectionStart) / 1e6;
      req.perfDiag.addSectionMs(key, durationMs);
      return result;
    }
  };
  res.on('finish', () => {
    if (!enabled || !shouldCapture) return;
    const totalDurationMs = Number(process.hrtime.bigint() - startedAt) / 1e6;
    const contentLength = Number(res.getHeader('content-length')) || 0;
    const payloadSizeBytes = contentLength || responseBytes || 0;
    console.info('[perf][api]', {
      requestId: req.requestId,
      method: req.method,
      route: req.originalUrl?.split('?')[0] || routePath,
      statusCode: res.statusCode,
      durationMs: Number(totalDurationMs.toFixed(2)),
      userId: req.username || null,
      accountCount: meta.accountCount,
      resultCount: meta.resultCount,
      payloadSizeBytes,
      cache: meta.cache,
      externalProviderAttempted: !!meta.externalProviderAttempted,
      externalProviderDurationMs: Number((meta.externalProviderDurationMs || 0).toFixed(2)),
      dbReadDurationMs: Number((meta.dbReadDurationMs || 0).toFixed(2)),
      transformDurationMs: Number((meta.transformDurationMs || 0).toFixed(2)),
      summaryModeUsed: !!meta.summaryModeUsed,
      payloadTrimmed: !!meta.payloadTrimmed,
      requestScopedReuse: !!meta.requestScopedReuse,
      sections
    });
  });
  next();
});

