// --- user data ---
function prepareUserPortfolioRouteState(req, user) {
  let mutated = req.perfDiag?.timeSync('user_shape', () => ensureUserShape(user, req.username)) ?? ensureUserShape(user, req.username);
  const history = req.perfDiag?.timeSync('portfolio_history_load', () => ensurePortfolioHistory(user)) || ensurePortfolioHistory(user);
  if (req.perfDiag?.timeSync('history_normalize', () => normalizePortfolioHistory(user)) ?? normalizePortfolioHistory(user)) mutated = true;
  if (req.perfDiag?.timeSync('trading_account_sync_from_history', () => syncIntegratedTradingAccountValuesFromHistory(user, history)) ?? syncIntegratedTradingAccountValuesFromHistory(user, history)) mutated = true;
  const netDeposits = req.perfDiag?.timeSync('compute_net_deposits', () => computeNetDepositsTotals(user, history)) || computeNetDepositsTotals(user, history);
  const anchors = req.perfDiag?.timeSync('refresh_anchors', () => refreshAnchors(user, history)) || refreshAnchors(user, history);
  if (anchors.mutated) mutated = true;
  return { mutated, history, netDeposits, anchors };
}

function buildSharedBootstrapSummary(req, user, options = {}) {
  const endpoint = options.endpoint || 'unknown';
  const staleDisplayedValue = options.staleDisplayedValue;
  const summaryUsername = options.username || req.username;
  const refresh = prepareUserPortfolioRouteState(req, user);
  let mutated = !!refresh.mutated;
  const netDeposits = refresh.netDeposits || { baseline: 0, total: 0 };
  const portfolioSnapshot = getCurrentPortfolioValue(user);

  logPortfolioBootstrapDiagnostics(user, { endpoint, user: summaryUsername, staleDisplayedValue });
  const clearedManualPortfolioBaseline = clearStaleManualPortfolioBaseline(user, { reason: endpoint });
  if (clearedManualPortfolioBaseline) {
    portfolioSnapshot.value = getCurrentPortfolioValue(user).value;
    mutated = true;
  }

  const accountAggregation = getTradingAccountAggregationSnapshot(user);
  const riskCapital = getRiskCapitalBase(user, {
    user: summaryUsername,
    logDiagnostics: process.env.NODE_ENV !== 'production'
  });
  const portfolioValue = Number.isFinite(portfolioSnapshot.value)
    ? portfolioSnapshot.value
    : (netDeposits.baseline || 0);

  req.perfDiag?.setMeta({
    accountCount: accountAggregation.accountCount,
    requestScopedReuse: true
  });

  return {
    mutated,
    netDeposits,
    portfolioSnapshot,
    accountAggregation,
    riskCapital,
    portfolioValue
  };
}

app.get('/api/portfolio', auth, async (req,res)=>{
  const db = req.perfDiag?.timeSync('db_load', () => loadDB()) || loadDB();
  const user = db.users[req.username];
  const sharedSummary = buildSharedBootstrapSummary(req, user, {
    endpoint: '/api/portfolio',
    username: req.username,
    staleDisplayedValue: req.query?.staleDisplayedValue
  });
  let { mutated } = sharedSummary;
  const totals = sharedSummary.netDeposits;
  const includeActiveTrades = req.query?.includeActiveTrades !== '0';
  let trades = [];
  let liveOpenPnlGBP = 0;
  let openLossPotentialGBP = 0;
  if (includeActiveTrades) {
    req.perfDiag?.setMeta({ externalProviderAttempted: true });
    const rates = await (req.perfDiag?.timeAsync('external_rates_fetch', async () => fetchRates()) || fetchRates());
    const activeTradesStart = process.hrtime.bigint();
    const activeTradeSnapshot = await buildActiveTrades(user, rates);
    trades = activeTradeSnapshot.trades;
    liveOpenPnlGBP = activeTradeSnapshot.liveOpenPnlGBP;
    openLossPotentialGBP = activeTradeSnapshot.openLossPotentialGBP;
    req.perfDiag?.setMeta({ externalProviderDurationMs: Number(process.hrtime.bigint() - activeTradesStart) / 1e6 });
  } else {
    req.perfDiag?.setMeta({
      externalProviderAttempted: false,
      externalProviderDurationMs: 0,
      activeTradesSkipped: true
    });
  }
  const portfolioSnapshot = sharedSummary.portfolioSnapshot;
  const accountAggregation = sharedSummary.accountAggregation;
  const riskCapital = sharedSummary.riskCapital;
  const riskCapitalSummary = serializeRiskCapitalSummary(riskCapital);
  const computedTotalFromAccounts = accountAggregation.portfolioValue;
  const manualPortfolioRaw = user.manualPortfolioBaseline;
  const manualPortfolioBaseline = Number(manualPortfolioRaw);
  const hasManualPortfolioBaseline = manualPortfolioRaw !== null
    && manualPortfolioRaw !== undefined
    && manualPortfolioRaw !== ''
    && Number.isFinite(manualPortfolioBaseline);
  const resolvedPortfolio = portfolioSnapshot.value;
  if (mutated) saveDB(db);
  console.info('[baseline][resolve][portfolio]', {
    user: req.username,
    source: totals.source || 'history',
    manualNetDepositsBaseline: user.manualNetDepositsBaseline,
    resolvedNetDeposits: totals.total,
    manualPortfolioBaseline: hasManualPortfolioBaseline ? manualPortfolioBaseline : null,
    resolvedPortfolio,
    accountCount: accountAggregation.accountCount,
    accountPortfolioValues: accountAggregation.accounts.map(account => ({ id: account.id, value: account.portfolioValue })),
    accountNetDeposits: accountAggregation.accounts.map(account => ({ id: account.id, netDeposits: account.netDeposits })),
    aggregatedPortfolioValue: accountAggregation.portfolioValue,
    aggregatedNetDeposits: accountAggregation.netDeposits,
    netPerformanceInputs: {
      portfolioValue: resolvedPortfolio,
      netDeposits: totals.total,
      netPerformance: resolvedPortfolio - totals.total,
      performancePct: totals.total !== 0 ? ((resolvedPortfolio - totals.total) / totals.total) : null
    }
  });
  const responsePayload = {
    portfolioValue: resolvedPortfolio,
    portfolioSource: portfolioSnapshot.source,
    portfolioCurrency: portfolioSnapshot.currency,
    portfolioLastUpdatedAt: portfolioSnapshot.lastUpdatedAt,
    initialNetDeposits: totals.baseline,
    netDepositsTotal: totals.total,
    profileComplete: !!user.profileComplete,
    liveOpenPnl: liveOpenPnlGBP,
    openLossPotential: openLossPotentialGBP,
    activeTrades: trades.length,
    isGuest: !!user.guest,
    riskCapitalBase: riskCapital.riskCapitalBase,
    riskCapital: riskCapitalSummary,
    activeTradesDeferred: !includeActiveTrades
  };
  req.perfDiag?.setMeta({
    resultCount: trades.length,
    cache: 'bypass',
    summarySerializerUsed: true,
    payloadTrimmed: true
  });
  res.json(responsePayload);
});

