app.post('/api/portfolio', auth, (req,res)=>{
  const { portfolio } = req.body || {};
  if (typeof portfolio !== 'number' || isNaN(portfolio) || portfolio < 0) {
    return res.status(400).json({ error: 'Bad portfolio value' });
  }
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  user.portfolio = portfolio;
  user.portfolioCurrency = 'GBP';
  user.portfolioSource = 'manual';
  user.lastPortfolioSyncAt = new Date().toISOString();
  const history = ensurePortfolioHistory(user);
  const dateKey = currentDateKey();
  const ym = dateKey.slice(0, 7);
  history[ym] ||= {};
  const existing = history[ym][dateKey] || {};
  history[ym][dateKey] = {
    ...existing,
    end: portfolio
  };
  const accounts = existing.accounts && typeof existing.accounts === 'object' ? existing.accounts : {};
  const resolvedAccountId = resolveTradingAccountId(user, req.body?.accountId);
  if (resolvedAccountId) {
    const currentAccount = accounts[resolvedAccountId] && typeof accounts[resolvedAccountId] === 'object'
      ? accounts[resolvedAccountId]
      : {};
    history[ym][dateKey].accounts = {
      ...accounts,
      [resolvedAccountId]: {
        ...currentAccount,
        end: portfolio,
        cashIn: Number(currentAccount.cashIn) || 0,
        cashOut: Number(currentAccount.cashOut) || 0
      }
    };
  } else {
    history[ym][dateKey].accounts = {};
  }
  refreshAnchors(user, history);
  saveDB(db);
  res.json({ ok: true, portfolio });
});

