app.post('/api/notifications/devices/register', auth, (req, res) => {
  console.info('[Notifications] Device register request received.', {
    userId: req.username,
    hasDeviceId: typeof req.body?.deviceId === 'string' && !!req.body.deviceId,
    hasToken: typeof req.body?.token === 'string' && !!req.body.token,
    tokenPreview: typeof req.body?.token === 'string' && req.body.token ? `${req.body.token.slice(0, 12)}…` : '',
    platform: req.body?.platform || 'missing',
    browser: req.body?.browser || 'missing',
    permissionState: req.body?.permissionState || 'missing',
    hasCategories: !!(req.body?.categories && typeof req.body.categories === 'object'),
    hasPreferences: !!(req.body?.preferences && typeof req.body.preferences === 'object')
  });
  const parsed = notificationDeviceRegisterSchema.safeParse(req.body || {});
  if (!parsed.success) {
    console.warn('[Notifications] Device register validation failed.', {
      userId: req.username,
      issues: parsed.error.issues?.map((issue) => ({ path: issue.path, message: issue.message })) || []
    });
    return res.status(400).json({
      error: 'Invalid notification device payload.',
      issues: parsed.error.issues?.map((issue) => ({ path: issue.path, message: issue.message })) || []
    });
  }
  try {
    const db = loadDB();
    ensureNotificationTables(db);
    const payload = parsed.data;
    const categories = normalizeNotificationCategories(payload.categories || payload.preferences || req.body?.categories || req.body?.preferences);
    const delivery = normalizeNotificationDelivery(payload.delivery || req.body?.delivery);
    const record = upsertNotificationDevice(db, {
      userId: req.username,
      deviceId: payload.deviceId,
      token: payload.token,
      platform: payload.platform,
      browser: payload.browser,
      userAgent: payload.userAgent || req.headers['user-agent'] || '',
      permissionState: payload.permissionState,
      installedAsPwa: !!payload.installedAsPwa,
      delivery,
      categories,
      isActive: payload.isActive !== false
    });
    saveDB(db);
    console.info('[Notifications] Device upserted successfully.', {
      userId: req.username,
      deviceId: record.deviceId,
      recordId: record.id,
      platform: record.platform,
      browser: record.browser,
      permissionState: record.permissionState,
      tokenFingerprint: fingerprintToken(record.token),
      normalizedTargetIdentity: normalizeDeviceTargetIdentity(record)
    });
    return res.json({ ok: true, device: record });
  } catch (error) {
    console.error('[Notifications] Device upsert failed.', {
      userId: req.username,
      error: error?.message || String(error)
    });
    return res.status(500).json({ error: 'Failed to save notification device.' });
  }
});

app.put('/api/notifications/devices/:id/preferences', auth, (req, res) => {
  const parsed = notificationPreferencesSchema.safeParse(req.body || {});
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid notification preferences payload.', issues: parsed.error.issues });
  }
  const db = loadDB();
  ensureNotificationTables(db);
  const device = db.notificationDevices.find((item) => item.id === req.params.id && item.userId === req.username);
  if (!device) return res.status(404).json({ error: 'Notification device not found.' });
  device.categories = normalizeNotificationCategories(req.body?.categories || device.categories);
  device.delivery = normalizeNotificationDelivery(req.body?.delivery || device.delivery);
  if (typeof parsed.data.isActive === 'boolean') {
    device.isActive = parsed.data.isActive;
    if (!device.isActive) device.revokedAt = new Date().toISOString();
  }
  if (parsed.data.permissionState) device.permissionState = parsed.data.permissionState;
  device.updatedAt = new Date().toISOString();
  const userPreferences = getNotificationPreferences(db, req.username);
  if (req.body?.categories || req.body?.delivery) {
    userPreferences.categories = normalizeNotificationCategories({ ...userPreferences.categories, ...device.categories });
    userPreferences.delivery = normalizeNotificationDelivery({ ...userPreferences.delivery, ...device.delivery });
    userPreferences.updatedAt = new Date().toISOString();
  }
  saveDB(db);
  console.info('[Notifications][DeviceLifecycle] Device preference update persisted.', {
    action: device.isActive === false ? 'current_device_removed' : 'current_device_reenabled',
    userId: req.username,
    deviceRowId: device.id,
    permissionState: device.permissionState,
    isActive: device.isActive !== false,
    tokenFingerprint: fingerprintToken(device.token),
    normalizedTargetIdentity: normalizeDeviceTargetIdentity(device)
  });
  res.json({ ok: true, device });
});

