app.post('/api/notifications/test', auth, asyncHandler(async (req, res) => {
  if (!checkNotificationTestRateLimit(req, res)) return;
  const db = loadDB();
  ensureNotificationTables(db);
  const targetDeviceId = typeof req.body?.deviceId === 'string' ? req.body.deviceId : '';
  const registeredDevices = db.notificationDevices.filter((item) => item.userId === req.username
    && item.isActive
    && getEffectiveNotificationPermissionState(item) === 'granted');
  if (!registeredDevices.length) {
    return res.status(400).json({ error: 'No active push-registered devices found. Enable notifications on this device first.' });
  }
  const log = await sendNotificationEvent(db, {
    userId: req.username,
    eventType: 'trade_opened',
    context: {
      symbol: 'VERACITY',
      tradeId: 'test',
      link: '/trades.html?notification=test',
      tag: 'veracity-test-notification'
    },
    onlyDeviceId: targetDeviceId || null
  });
  if (!log.deliveries.length) {
    saveDB(db);
    return res.status(400).json({ error: 'No eligible notification devices matched current filters/preferences.' });
  }
  const okDeliveries = log.deliveries.filter((entry) => entry.ok);
  if (!okDeliveries.length) {
    saveDB(db);
    const failedDeliveries = log.deliveries.filter((entry) => !entry.ok);
    const firebaseErrors = failedDeliveries.map((entry) => ({
      deviceId: entry.deviceId,
      code: entry.code || null,
      message: entry.error || null,
      details: entry.details || null
    }));
    return res.status(502).json({
      error: 'Push send attempted but failed for all targeted devices.',
      firebaseErrors,
      log
    });
  }
  saveDB(db);
  res.json({ ok: true, log });
}));

app.post('/api/notifications/internal/send', asyncHandler(async (req, res) => {
  const headerSecret = req.headers['x-internal-notification-secret'];
  if (!INTERNAL_NOTIFICATION_SECRET || headerSecret !== INTERNAL_NOTIFICATION_SECRET) {
    return res.status(403).json({ error: 'Forbidden.' });
  }
  const userId = typeof req.body?.userId === 'string' ? req.body.userId : '';
  const eventType = typeof req.body?.eventType === 'string' ? req.body.eventType : '';
  if (!userId || !eventType) return res.status(400).json({ error: 'userId and eventType are required.' });
  const db = loadDB();
  const log = await sendNotificationEvent(db, {
    userId,
    eventType,
    context: req.body?.context || {},
    onlyDeviceId: typeof req.body?.deviceId === 'string' ? req.body.deviceId : null,
    criticalOnly: !!req.body?.criticalOnly
  });
  saveDB(db);
  res.json({ ok: true, log });
}));

