app.post('/api/profile', auth, (req,res)=>{
  const { portfolio, netDeposits, date, nickname, tradingAccounts } = req.body || {};
  console.info('[baseline][save][request]', {
    user: req.username,
    portfolio,
    netDeposits,
    hasTradingAccountsPayload: Array.isArray(tradingAccounts),
    tradingAccountsCount: Array.isArray(tradingAccounts) ? tradingAccounts.length : 0
  });
  if (portfolio === '' || portfolio === null || portfolio === undefined) {
    return res.status(400).json({ error: 'Portfolio value is required' });
  }
  let portfolioNumber = Number(portfolio);
  if (!Number.isFinite(portfolioNumber) || portfolioNumber < 0) {
    return res.status(400).json({ error: 'Invalid portfolio value' });
  }
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  if (nickname !== undefined) {
    const normalized = normalizeNickname(nickname);
    if (normalized.error) {
      return res.status(400).json({ error: normalized.error });
    }
    if (!isNicknameAvailable(db, normalized.value, req.username)) {
      return res.status(409).json({ error: 'That nickname is already taken.' });
    }
    user.nickname = normalized.value;
  }
  const wasComplete = !!user.profileComplete;
  const history = ensurePortfolioHistory(user);
  normalizePortfolioHistory(user);
  const { baseline: previousBaseline, total: previousTotal } = computeNetDepositsTotals(user, history);
  let netDepositsNumber;
  const netDepositsProvided = !(netDeposits === '' || netDeposits === null || netDeposits === undefined);
  const tradingAccountsProvided = Array.isArray(tradingAccounts);
  if (!wasComplete) {
    if (!netDepositsProvided && !tradingAccountsProvided) {
      return res.status(400).json({ error: 'Net deposits value is required' });
    }
    if (netDepositsProvided) {
      netDepositsNumber = Number(netDeposits);
      if (!Number.isFinite(netDepositsNumber)) {
        return res.status(400).json({ error: 'Invalid net deposits value' });
      }
    } else {
      netDepositsNumber = 0;
    }
  } else if (!netDepositsProvided) {
    netDepositsNumber = previousTotal;
  } else {
    netDepositsNumber = Number(netDeposits);
    if (!Number.isFinite(netDepositsNumber)) {
      return res.status(400).json({ error: 'Invalid net deposits value' });
    }
  }
  if (Array.isArray(tradingAccounts)) {
    const existingById = new Map((user.tradingAccounts || []).map(account => [account.id, account]));
    const nextAccounts = [];
    for (const [index, account] of tradingAccounts.entries()) {
      if (!account || typeof account !== 'object') continue;
      const id = typeof account.id === 'string' ? account.id.trim() : '';
      if (!id) continue;
      const label = normalizeTradingAccountLabel(account.label, `Account ${index + 1}`);
      const currentValue = Number(account.currentValue);
      const currentNetDeposits = Number(account.currentNetDeposits);
      if (!Number.isFinite(currentValue) || currentValue < 0) {
        return res.status(400).json({ error: `Invalid current portfolio value for account ${label || id}.` });
      }
      if (!Number.isFinite(currentNetDeposits)) {
        return res.status(400).json({ error: `Invalid net deposits for account ${label || id}.` });
      }
      nextAccounts.push({
        ...(existingById.get(id) || {}),
        id,
        label,
        currentValue,
        currentNetDeposits
      });
    }
    user.tradingAccounts = nextAccounts;
    const combinedPortfolio = nextAccounts.reduce((sum, account) => sum + (Number(account.currentValue) || 0), 0);
    const combinedNetDeposits = nextAccounts.reduce((sum, account) => sum + (Number(account.currentNetDeposits) || 0), 0);
    portfolioNumber = combinedPortfolio;
    netDepositsNumber = combinedNetDeposits;
  }
  const resetNetDeposits = wasComplete && netDepositsProvided && netDepositsNumber !== previousTotal;
  const netDelta = resetNetDeposits
    ? 0
    : netDepositsNumber - (wasComplete ? previousTotal : previousBaseline);
  const targetDate = (typeof date === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(date))
    ? date
    : currentDateKey();
  if (!user.netDepositsAnchor || resetNetDeposits) {
    user.netDepositsAnchor = targetDate;
  }
  const ym = targetDate.slice(0, 7);
  history[ym] ||= {};
  const existing = history[ym][targetDate] || {};
  let cashIn = Number.isFinite(existing.cashIn) ? Number(existing.cashIn) : 0;
  let cashOut = Number.isFinite(existing.cashOut) ? Number(existing.cashOut) : 0;
  if (resetNetDeposits) {
    cashIn = 0;
    cashOut = 0;
  } else if (!wasComplete) {
    if (netDepositsNumber > 0) {
      cashIn += netDepositsNumber;
    } else if (netDepositsNumber < 0) {
      cashOut += Math.abs(netDepositsNumber);
    }
  } else if (netDelta !== 0) {
    if (netDelta > 0) {
      cashIn += netDelta;
    } else {
      cashOut += Math.abs(netDelta);
    }
  }
  history[ym][targetDate] = {
    end: portfolioNumber,
    cashIn,
    cashOut
  };
  const accountRecords = {};
  const normalizedAccounts = Array.isArray(user.tradingAccounts) ? user.tradingAccounts : [];
  const hasMultiAccounts = normalizedAccounts.length && (user.multiTradingAccountsEnabled || normalizedAccounts.length > 1);
  if (hasMultiAccounts) {
    const combinedPortfolio = normalizedAccounts.reduce((sum, account) => sum + (Number(account.currentValue) || 0), 0);
    const combinedNetDeposits = normalizedAccounts.reduce((sum, account) => sum + (Number(account.currentNetDeposits) || 0), 0);
    if (tradingAccountsProvided) {
      portfolioNumber = combinedPortfolio;
      netDepositsNumber = combinedNetDeposits;
    }
    const netScale = combinedNetDeposits !== 0 ? (cashIn - cashOut) / combinedNetDeposits : 0;
    normalizedAccounts.forEach(account => {
      const accountNet = Number(account.currentNetDeposits) || 0;
      const accountDelta = accountNet * netScale;
      accountRecords[account.id] = {
        end: Number(account.currentValue) || 0,
        cashIn: accountDelta > 0 ? accountDelta : 0,
        cashOut: accountDelta < 0 ? Math.abs(accountDelta) : 0
      };
    });
  } else if (normalizedAccounts.length) {
    accountRecords[normalizedAccounts[0].id] = {
      end: portfolioNumber,
      cashIn,
      cashOut
    };
  }
  history[ym][targetDate].end = portfolioNumber;
  history[ym][targetDate].accounts = accountRecords;
  logPortfolioAttribution('profile_save_before_persist', user, {
    user: req.username,
    targetDate,
    tradingAccountsProvided,
    resolvedProfilePortfolio: portfolioNumber,
    resolvedNetDeposits: netDepositsNumber,
    serializedAccountRows: Object.entries(accountRecords).map(([accountId, record]) => ({
      accountId,
      end: Number(record?.end) || 0,
      cashIn: Number(record?.cashIn) || 0,
      cashOut: Number(record?.cashOut) || 0
    }))
  });
  user.manualPortfolioBaseline = portfolioNumber;
  user.manualNetDepositsBaseline = netDepositsNumber;
  user.manualBaselineUpdatedAt = new Date().toISOString();
  if (!wasComplete) {
    user.initialNetDeposits = 0;
  } else if (resetNetDeposits) {
    user.initialNetDeposits = netDepositsNumber;
  }
  user.profileComplete = true;
  const { config: tradingCfg } = ensureTrading212Config(user);
  if (resetNetDeposits) {
    normalizePortfolioHistory(user);
  }
  const totals = computeNetDepositsTotals(user, history);
  tradingCfg.lastNetDeposits = totals.total;
  refreshAnchors(user, history);
  console.info('[baseline][save][persisted]', {
    user: req.username,
    manualPortfolioBaseline: user.manualPortfolioBaseline,
    manualNetDepositsBaseline: user.manualNetDepositsBaseline,
    resolvedNetDeposits: totals.total,
    source: totals.source || 'history'
  });
  saveDB(db);
  res.json({
    ok: true,
    netDeposits: totals.total,
    manualPortfolioBaseline: user.manualPortfolioBaseline,
    manualNetDepositsBaseline: user.manualNetDepositsBaseline,
    baselineSource: totals.source || 'history'
  });
});

app.post('/api/account/password', auth, async (req, res) => {
  if (rejectGuest(req, res)) return;
  const currentPassword = typeof req.body?.currentPassword === 'string' ? req.body.currentPassword : '';
  const newPassword = req.body?.password ?? req.body?.newPassword;
  if (!isStrongPassword(newPassword)) {
    return res.status(400).json({ error: 'Passwords must be 12+ characters and include upper, lower, number, and symbol.' });
  }
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  const matches = await bcrypt.compare(currentPassword, user.passwordHash);
  if (!matches) {
    return res.status(403).json({ error: 'Your current password is incorrect.' });
  }
  const samePassword = await bcrypt.compare(newPassword, user.passwordHash);
  if (samePassword) {
    return res.status(400).json({ error: 'Choose a password you have not used before.' });
  }
  user.passwordHash = await bcrypt.hash(newPassword, 10);
  user.security ||= {};
  user.security.passwordUpdatedAt = new Date().toISOString();
  saveDB(db);
  res.json({ ok: true });
});

app.get('/api/account/security-dashboard', auth, (req, res) => {
  const db = loadDB();
  db.sessionMetadata ||= {};
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  const sessionRows = Object.entries(db.sessions || {})
    .filter(([, username]) => username === req.username)
    .map(([token]) => {
      const metadata = db.sessionMetadata[token] || {};
      const createdAt = typeof metadata.createdAt === 'string' ? metadata.createdAt : null;
      const lastActiveAt = typeof metadata.lastActiveAt === 'string' ? metadata.lastActiveAt : createdAt;
      return {
        token,
        current: token === req.authToken,
        createdAt,
        lastActiveAt,
        ip: typeof metadata.ip === 'string' ? metadata.ip : null,
        userAgent: typeof metadata.userAgent === 'string' ? metadata.userAgent : null
      };
    })
    .sort((a, b) => Date.parse(b.lastActiveAt || 0) - Date.parse(a.lastActiveAt || 0));

  const activity = [];
  if (user.security?.lastLoginAt) {
    activity.push({ id: 'last-login', type: 'login', detail: 'Successful login', at: user.security.lastLoginAt });
  }
  if (user.security?.passwordUpdatedAt) {
    activity.push({ id: 'password-updated', type: 'password', detail: 'Password changed', at: user.security.passwordUpdatedAt });
  }
  if (user.security?.twoFactorEnabledAt) {
    activity.push({ id: '2fa-enabled', type: '2fa', detail: 'Two-factor authentication enabled', at: user.security.twoFactorEnabledAt });
  }
  if (user.security?.twoFactorDisabledAt) {
    activity.push({ id: '2fa-disabled', type: '2fa', detail: 'Two-factor authentication disabled', at: user.security.twoFactorDisabledAt });
  }
  for (const session of sessionRows.slice(0, 5)) {
    if (session.lastActiveAt) {
      activity.push({
        id: `session-${session.token.slice(0, 8)}`,
        type: 'session',
        detail: session.current ? 'Current session active' : 'Session activity',
        at: session.lastActiveAt
      });
    }
  }
  activity.sort((a, b) => Date.parse(b.at || 0) - Date.parse(a.at || 0));

  const passwordUpdatedAt = user.security?.passwordUpdatedAt || null;
  const twoFactorEnabled = !!user.security?.twoFactorEnabled;
  const securityStatus = twoFactorEnabled && passwordUpdatedAt ? 'good' : (passwordUpdatedAt ? 'moderate' : 'weak');
  res.json({
    securityStatus,
    passwordUpdatedAt,
    twoFactorEnabled,
    activeSessions: sessionRows,
    activeSessionCount: sessionRows.length,
    lastLoginAt: user.security?.lastLoginAt || null,
    activity: activity.slice(0, 8)
  });
});

app.post('/api/security/2fa/setup', auth, async (req, res) => {
  console.info('[2FA] Setup request received.', { username: req.username, ...getTotpRuntimeDebug() });
  if (rejectGuest(req, res)) return;
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  ensureTwoFactorTables(db);
  try {
    const secret = generateTotpSecret();
    console.info('[2FA] Secret generated.', { username: req.username, secretFingerprint: getSecretDebugFingerprint(secret) });
    const otpauthUrl = buildOtpAuthUrl(secret, req.username);
    console.info('[2FA] otpauth URL generated.', {
      username: req.username,
      hasOtpAuthUrl: !!otpauthUrl,
      otpauthLength: otpauthUrl.length,
      totpParams: getTotpRuntimeDebug().totpParams
    });
    const qrCode = await generateTwoFactorQrDataUrl(otpauthUrl);
    console.info('[2FA] QR generated.', { username: req.username });
    const setupId = crypto.randomUUID();
    db.twoFactorSetups[setupId] = {
      username: req.username,
      secretEnc: encryptTwoFactorSecret(secret),
      createdAt: new Date().toISOString(),
      expiresAt: new Date(Date.now() + (10 * 60 * 1000)).toISOString()
    };
    saveDB(db);
    const payload = {
      setupId,
      secret,
      otpauth_url: otpauthUrl,
      qr_code: qrCode,
      otpauthUrl,
      qrCodeUrl: qrCode
    };
    console.info('[2FA] Setup response sent.', { username: req.username, setupId });
    res.json(payload);
  } catch (error) {
    console.error('[2FA] Setup failed.', { username: req.username, error: error.message });
    res.status(500).json({ error: `Unable to generate 2FA setup payload: ${error.message}` });
  }
});

app.post('/api/security/2fa/verify', auth, (req, res) => {
  if (rejectGuest(req, res)) return;
  const setupId = typeof req.body?.setupId === 'string' ? req.body.setupId : '';
  const code = typeof req.body?.code === 'string' ? req.body.code.trim().replace(/\s+/g, '') : '';
  console.info('[2FA] Setup verify request received.', {
    username: req.username,
    setupIdPresent: !!setupId,
    codeLength: code.length,
    codeLooksNumeric: /^\d+$/.test(code),
    ...getTotpRuntimeDebug()
  });
  if (!setupId || !code) return res.status(400).json({ error: 'Setup and code are required.' });
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  ensureTwoFactorTables(db);
  const setup = db.twoFactorSetups[setupId];
  if (!setup || setup.username !== req.username || Date.parse(setup.expiresAt || 0) <= Date.now()) {
    return res.status(400).json({ error: '2FA setup expired. Start setup again.' });
  }
  console.info('[2FA] Setup record loaded for verification.', {
    username: req.username,
    setupId,
    setupCreatedAt: setup.createdAt,
    setupExpiresAt: setup.expiresAt,
    setupUsernameMatches: setup.username === req.username
  });
  const retryAfterMs = enforceRateLimit(twoFactorSetupVerifyRateLimit, `${req.username}:${req.ip || 'unknown'}`, TWO_FACTOR_VERIFY_RATE_LIMIT_MAX, TWO_FACTOR_VERIFY_RATE_LIMIT_WINDOW_MS);
  if (retryAfterMs > 0) {
    const retryAfter = Math.ceil(retryAfterMs / 1000);
    res.set('Retry-After', String(retryAfter));
    return res.status(429).json({ error: `Too many verification attempts. Try again in ${retryAfter} seconds.` });
  }
  const secret = decryptTwoFactorSecret(setup.secretEnc);
  console.info('[2FA] Setup secret decrypted for verification.', {
    username: req.username,
    setupId,
    secretFingerprint: getSecretDebugFingerprint(secret)
  });
  const totpResult = verifyTotpCode(secret, code);
  const verified = !!totpResult.verified;
  console.info('[2FA] Setup verification attempt.', {
    username: req.username,
    setupId,
    success: verified,
    matchedTotpOffset: totpResult.matchedOffset,
    ...getTotpRuntimeDebug()
  });
  if (!verified) return res.status(400).json({ error: 'Invalid authentication code. If you refreshed or reopened setup, restart 2FA setup and scan the latest QR code.' });
  const backupCodes = generateBackupCodes(10);
  user.security.twoFactorSecretEnc = setup.secretEnc;
  user.security.twoFactorEnabled = true;
  user.security.twoFactorEnabledAt = new Date().toISOString();
  user.security.twoFactorBackupCodeHashes = backupCodes.map(hashBackupCode);
  delete db.twoFactorSetups[setupId];
  saveDB(db);
  console.info('[2FA] Enabled.', { username: req.username });
  res.json({ ok: true, backupCodes });
});

