app.get('/api/pl', auth, (req,res)=>{
  const { year, month } = req.query;
  const selectedMonthKey = year && month ? `${year}-${String(month).padStart(2,'0')}` : '';
  const includeTrades = req.query?.includeTrades !== '0';
  const visibleWindowOnly = ['1', 'true', 'yes'].includes(String(req.query?.visibleWindowOnly || '').toLowerCase());
  const db = req.perfDiag?.timeSync('db_load', () => loadDB()) || loadDB();
  const user = db.users[req.username];
  req.perfDiag?.timeSync('user_shape', () => ensureUserShape(user, req.username));
  if (!user.profileComplete) {
    return res.status(409).json({ error: 'Profile incomplete', code: 'profile_incomplete' });
  }
  const history = req.perfDiag?.timeSync('portfolio_history_load', () => ensurePortfolioHistory(user)) || ensurePortfolioHistory(user);
  let mutated = normalizePortfolioHistory(user);
  const journal = req.perfDiag?.timeSync('trade_journal_load', () => buildJournalViewFromTrades(user)) || buildJournalViewFromTrades(user);
  const { baseline, mutated: anchorMutated } = req.perfDiag?.timeSync('refresh_anchors', () => refreshAnchors(user, history)) || refreshAnchors(user, history);
  if (anchorMutated) mutated = true;
  const mapper = createTradeInstrumentMapper(db, req.username);
  const snapshotBundle = req.perfDiag?.timeSync('build_snapshots', () => buildSnapshots(history, baseline, journal, { selectedMonthKey, includeTrades })) || buildSnapshots(history, baseline, journal, { selectedMonthKey, includeTrades });
  const snapshots = snapshotBundle?.snapshots || {};
  const firstRecordedDate = typeof snapshotBundle?.firstRecordedDate === 'string' && snapshotBundle.firstRecordedDate
    ? snapshotBundle.firstRecordedDate
    : null;
  if (selectedMonthKey) {
    const monthEntries = snapshots[selectedMonthKey] || {};
    Object.values(monthEntries).forEach(entry => {
      if (!entry || !Array.isArray(entry.trades)) return;
      entry.trades = entry.trades.map(trade => mapper(trade));
    });
    req.perfDiag?.setMeta({
      summaryModeUsed: true,
      payloadTrimmed: true,
      visibleWindowOnly,
      includeTrades,
      dashboardHistorySummaryUsed: true,
      requestScopedReuse: true
    });
  } else {
    Object.values(snapshots).forEach(monthEntries => {
      Object.values(monthEntries || {}).forEach(entry => {
        if (!entry || !Array.isArray(entry.trades)) return;
        entry.trades = entry.trades.map(trade => mapper(trade));
      });
    });
    req.perfDiag?.setMeta({ summaryModeUsed: false, includeTrades, requestScopedReuse: true });
  }
  if (mutated) saveDB(db);
  if (selectedMonthKey) {
    req.perfDiag?.setMeta({ resultCount: Object.keys(snapshots[selectedMonthKey] || {}).length, cache: 'bypass' });
    const monthPayload = snapshots[selectedMonthKey] || {};
    const originInWindow = !!(firstRecordedDate && firstRecordedDate.startsWith(`${selectedMonthKey}-`));
    req.perfDiag?.setMeta({
      dashboardOriginDateKnown: !!firstRecordedDate,
      dashboardOriginTileInWindow: originInWindow
    });
    return res.json({
      ...monthPayload,
      __meta: {
        firstRecordedDate,
        selectedMonthKey,
        originTileInWindow: originInWindow
      }
    });
  }
  req.perfDiag?.setMeta({ resultCount: Object.keys(snapshots || {}).length, cache: 'bypass' });
  res.json(snapshots);
});

app.post('/api/pl', auth, (req,res)=>{
  const { date, value, cashIn, cashOut, note, accountId } = req.body || {};
  if (!date) return res.status(400).json({ error: 'Missing date' });
  const db = loadDB();
  const user = db.users[req.username];
  ensureUserShape(user, req.username);
  const selectedAccountId = resolveTradingAccountId(user, accountId);
  if (!user.profileComplete) {
    return res.status(409).json({ error: 'Profile incomplete', code: 'profile_incomplete' });
  }
  const history = ensurePortfolioHistory(user);
  normalizePortfolioHistory(user);
  if (user.initialPortfolio === undefined) {
    user.initialPortfolio = Number.isFinite(user.portfolio) ? user.portfolio : 0;
  }
  const ym = date.slice(0,7);
  history[ym] ||= {};
  const existingRecord = history[ym][date] || {};
  const existingAccounts = existingRecord.accounts && typeof existingRecord.accounts === 'object'
    ? { ...existingRecord.accounts }
    : {};
  const existingAccountRecord = existingAccounts[selectedAccountId] && typeof existingAccounts[selectedAccountId] === 'object'
    ? existingAccounts[selectedAccountId]
    : {};
  let anchorDate = user.netDepositsAnchor || null;
  if (anchorDate && date < anchorDate) {
    user.netDepositsAnchor = date;
    user.initialNetDeposits = 0;
    anchorDate = date;
  }
  const deposit = cashIn === undefined || cashIn === '' ? 0 : Number(cashIn);
  const withdrawal = cashOut === undefined || cashOut === '' ? 0 : Number(cashOut);
  if (!Number.isFinite(deposit) || deposit < 0) {
    return res.status(400).json({ error: 'Invalid deposit value' });
  }
  if (!Number.isFinite(withdrawal) || withdrawal < 0) {
    return res.status(400).json({ error: 'Invalid withdrawal value' });
  }
  let normalizedNote;
  if (note !== undefined) {
    if (note === null) {
      normalizedNote = '';
    } else if (typeof note === 'string') {
      normalizedNote = note.trim();
    } else {
      return res.status(400).json({ error: 'Invalid note value' });
    }
  }
  if (value === null || value === '') {
    const hasCash = deposit > 0 || withdrawal > 0;
    const hasNote = normalizedNote !== undefined ? !!normalizedNote : !!existingAccountRecord?.note;
    if (hasCash || hasNote) {
      const accountPayload = {
        cashIn: deposit,
        cashOut: withdrawal
      };
      if (normalizedNote !== undefined) {
        if (normalizedNote) {
          accountPayload.note = normalizedNote;
        }
      } else if (existingAccountRecord && typeof existingAccountRecord.note === 'string') {
        const carryNote = existingAccountRecord.note.trim();
        if (carryNote) {
          accountPayload.note = carryNote;
        }
      }
      existingAccounts[selectedAccountId] = accountPayload;
    } else {
      delete existingAccounts[selectedAccountId];
    }
  } else {
    const num = Number(value);
    if (!Number.isFinite(num) || num < 0) {
      return res.status(400).json({ error: 'Invalid portfolio value' });
    }
    const accountPayload = {
      end: num,
      cashIn: deposit,
      cashOut: withdrawal
    };
    if (normalizedNote !== undefined) {
      if (normalizedNote) {
        accountPayload.note = normalizedNote;
      }
    } else if (existingAccountRecord && typeof existingAccountRecord.note === 'string') {
      const carryNote = existingAccountRecord.note.trim();
      if (carryNote) {
        accountPayload.note = carryNote;
      }
    }
    existingAccounts[selectedAccountId] = accountPayload;
  }
  const aggregate = buildAccountAggregates(existingAccounts);
  if (!aggregate.accounts.length) {
    delete history[ym][date];
    if (!Object.keys(history[ym]).length) {
      delete history[ym];
    }
  } else {
    const entryPayload = {
      cashIn: aggregate.cashIn,
      cashOut: aggregate.cashOut,
      accounts: existingAccounts,
      manualEntry: true
    };
    if (aggregate.end !== null) {
      entryPayload.end = aggregate.end;
    }
    history[ym][date] = entryPayload;
  }
  const tradingAccountsState = ensureTradingAccounts(user);
  user.tradingAccounts = tradingAccountsState.accounts;
  const selectedTradingAccount = tradingAccountsState.accounts.find(account => account.id === selectedAccountId);
  if (selectedTradingAccount) {
    const latestAccountClose = findLatestAccountClosingValue(history, selectedAccountId);
    selectedTradingAccount.currentValue = Number.isFinite(latestAccountClose) ? latestAccountClose : 0;
  }
  const multiEnabled = user.multiTradingAccountsEnabled || tradingAccountsState.accounts.length > 1;
  if (multiEnabled && tradingAccountsState.accounts.length) {
    user.portfolio = tradingAccountsState.accounts.reduce((sum, account) => sum + (Number(account.currentValue) || 0), 0);
    user.portfolioCurrency = 'GBP';
    user.portfolioSource = 'manual';
  }
  normalizePortfolioHistory(user);
  refreshAnchors(user, history);
  saveDB(db);
  res.json({ ok: true });
});

// --- exchange rates ---
let cachedRates = { GBP: 1 };
let cachedRatesAt = 0;
async function fetchRates() {
  const SIX_HOURS = 6 * 60 * 60 * 1000;
  const now = Date.now();
  if (process.env.SKIP_RATE_FETCH === 'true') {
    if (!cachedRates.USD || !cachedRates.EUR) {
      cachedRates = { GBP: 1, USD: 1, EUR: 1 };
    }
    cachedRatesAt = now;
    return cachedRates;
  }
  if (cachedRatesAt && (now - cachedRatesAt) < SIX_HOURS && cachedRates.USD) {
    return cachedRates;
  }
  try {
    const res = await fetch('https://open.er-api.com/v6/latest/GBP');
    if (!res.ok) throw new Error(`Rate fetch failed: ${res.status}`);
    const data = await res.json();
    const rates = data?.rates;
    if (rates && typeof rates === 'object') {
      cachedRates = { ...rates, GBP: 1 };
      cachedRatesAt = now;
    }
  } catch (e) {
    console.warn('Unable to refresh exchange rates', e.message || e);
    if (!cachedRates.USD || !cachedRates.EUR) {
      cachedRates = { GBP: 1 };
    }
  }
  return cachedRates;
}

function convertGBPToCurrency(valueGBP, currency, rates) {
  if (!Number.isFinite(valueGBP)) return null;
  if (currency === 'GBP') return valueGBP;
  const rate = rates?.[currency];
  if (!Number.isFinite(rate) || rate <= 0) return null;
  return valueGBP * rate;
}

function convertToGBP(value, currency, rates) {
  if (!Number.isFinite(value)) return null;
  if (currency === 'GBP') return value;
  const rate = rates?.[currency];
  if (!Number.isFinite(rate) || rate <= 0) return null;
  return value / rate;
}

function sanitizeTagList(value, limit = 10) {
  if (!value) return [];
  const items = Array.isArray(value) ? value : String(value).split(',');
  const deduped = [];
  items.forEach(item => {
    if (!item) return;
    const normalized = String(item).trim();
    if (!normalized) return;
    if (deduped.length >= limit) return;
    if (!deduped.includes(normalized)) {
      deduped.push(normalized);
    }
  });
  return deduped;
}

function normalizeTradeMeta(trade = {}) {
  if (!trade || typeof trade !== 'object') return {};
  const type = typeof trade.tradeType === 'string' ? trade.tradeType.trim().toLowerCase() : '';
  const asset = typeof trade.assetClass === 'string' ? trade.assetClass.trim().toLowerCase() : '';
  const condition = typeof trade.marketCondition === 'string' ? trade.marketCondition.trim().toLowerCase() : '';
  const strategy = typeof trade.strategyTag === 'string' ? trade.strategyTag.trim() : '';
  const screenshotRaw = typeof trade.screenshotUrl === 'string' ? trade.screenshotUrl.trim() : '';
  const noteRaw = typeof trade.note === 'string' ? trade.note.trim() : '';
  const reviewNotesRaw = typeof trade.notes === 'string' ? trade.notes.trim() : '';
  const reviewOutcomeRaw = typeof trade.outcome === 'string' ? trade.outcome.trim().toLowerCase() : '';
  const hasReviewFields = trade.outcome !== undefined || trade.notes !== undefined;
  const directionRaw = typeof trade.direction === 'string' ? trade.direction.trim().toLowerCase() : 'long';
  const optionTypeRaw = typeof trade.optionType === 'string' ? trade.optionType.trim().toLowerCase() : '';
  const optionStrikeRaw = Number(trade.optionStrike);
  const optionContractsRaw = Number(trade.optionContracts);
  const optionExpirationRaw = typeof trade.optionExpiration === 'string' ? trade.optionExpiration.trim() : '';
  const feesRaw = Number(trade.fees);
  const slippageRaw = Number(trade.slippage);
  const rounding = trade.rounding === 'whole' ? 'whole' : 'fractional';
  const sourceRaw = typeof trade.source === 'string' ? trade.source.trim().toLowerCase() : '';
  const source = sourceRaw === 'trading212'
    ? 'trading212'
    : (sourceRaw === 'ibkr' ? 'ibkr' : 'manual');
  return {
    ...trade,
    tradeType: TRADE_TYPES.includes(type) ? type : 'day',
    assetClass: ASSET_CLASSES.includes(asset) ? asset : 'stocks',
    marketCondition: MARKET_CONDITIONS.includes(condition) ? condition : '',
    direction: DIRECTIONS.includes(directionRaw) ? directionRaw : 'long',
    fees: Number.isFinite(feesRaw) && feesRaw >= 0 ? feesRaw : 0,
    slippage: Number.isFinite(slippageRaw) && slippageRaw >= 0 ? slippageRaw : 0,
    rounding,
    source,
    strategyTag: strategy,
    setupTags: sanitizeTagList(trade.setupTags ?? (hasReviewFields ? [] : (trade.tags ?? [])), 15),
    emotionTags: sanitizeTagList(trade.emotionTags ?? [], 15),
    tags: sanitizeTagList(hasReviewFields ? (trade.tags ?? []) : [], 15),
    outcome: ['good', 'bad', 'neutral'].includes(reviewOutcomeRaw) ? reviewOutcomeRaw : undefined,
    notes: reviewNotesRaw || undefined,
    screenshotUrl: screenshotRaw || undefined,
    note: noteRaw || undefined,
    optionType: OPTION_TYPES.includes(optionTypeRaw) ? optionTypeRaw : undefined,
    optionStrike: Number.isFinite(optionStrikeRaw) && optionStrikeRaw > 0 ? optionStrikeRaw : undefined,
    optionContracts: Number.isFinite(optionContractsRaw) && optionContractsRaw > 0 ? Math.floor(optionContractsRaw) : undefined,
    optionExpiration: /^\d{4}-\d{2}-\d{2}$/.test(optionExpirationRaw) ? optionExpirationRaw : undefined
  };
}

const marketCache = new Map();
const dailyLowCache = new Map();
const DAILY_LOW_CACHE_TTL_TODAY_MS = Number(process.env.DAILY_LOW_CACHE_TTL_TODAY_MS) || 15 * 1000;
const DAILY_LOW_CACHE_TTL_HISTORICAL_MS = Number(process.env.DAILY_LOW_CACHE_TTL_HISTORICAL_MS) || 24 * 60 * 60 * 1000;
const optionContractResolutionCache = new Map();
const optionQuoteCache = new Map();
const OPTION_QUOTE_CACHE_TTL_MS = Number(process.env.OPTION_QUOTE_CACHE_TTL_MS) || 10 * 1000;
const ACTIVE_TRADES_SNAPSHOT_TTL_MS = Number(process.env.ACTIVE_TRADES_SNAPSHOT_TTL_MS) || 15000;
const ACTIVE_TRADES_MAX_STALE_MS = Number(process.env.ACTIVE_TRADES_MAX_STALE_MS) || 120000;
const activeTradesSnapshotCache = new Map();
const activeTradesRefreshLocks = new Map();

function getTimezoneOffset(date, timeZone) {
  const tzDate = new Date(date.toLocaleString('en-US', { timeZone }));
  return (date - tzDate) / 60000;
}

function getNyDateKeyForDate(date, adjustForMarketOpen = false) {
  const nyNow = new Date(date.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  const hours = nyNow.getHours();
  const minutes = nyNow.getMinutes();
  const localDate = new Date(nyNow);
  if (adjustForMarketOpen && (hours < 9 || (hours === 9 && minutes < 30))) {
    localDate.setDate(localDate.getDate() - 1);
  }
  const year = localDate.getFullYear();
  const month = `${localDate.getMonth() + 1}`.padStart(2, '0');
  const day = `${localDate.getDate()}`.padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function getNyDateKey() {
  return getNyDateKeyForDate(new Date(), true);
}

function isWeekdayMarketDate(dateKey) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey || ''))) return false;
  const [year, month, day] = String(dateKey).split('-').map(Number);
  const utc = new Date(Date.UTC(year, month - 1, day));
  const dayOfWeek = utc.getUTCDay();
  return dayOfWeek >= 1 && dayOfWeek <= 5;
}

function formatUtcDateKey(date) {
  const year = date.getUTCFullYear();
  const month = `${date.getUTCMonth() + 1}`.padStart(2, '0');
  const day = `${date.getUTCDate()}`.padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function parseUtcDateKey(dateKey) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(String(dateKey || ''))) return '';
  const [year, month, day] = String(dateKey).split('-').map(Number);
  return new Date(Date.UTC(year, month - 1, day));
}

function nthWeekdayOfMonthUtc(year, monthIndexZeroBased, weekday, nth) {
  const cursor = new Date(Date.UTC(year, monthIndexZeroBased, 1));
  while (cursor.getUTCDay() !== weekday) cursor.setUTCDate(cursor.getUTCDate() + 1);
  cursor.setUTCDate(cursor.getUTCDate() + (nth - 1) * 7);
  return cursor;
}

function lastWeekdayOfMonthUtc(year, monthIndexZeroBased, weekday) {
  const cursor = new Date(Date.UTC(year, monthIndexZeroBased + 1, 0));
  while (cursor.getUTCDay() !== weekday) cursor.setUTCDate(cursor.getUTCDate() - 1);
  return cursor;
}

function observedFixedHolidayUtc(year, monthIndexZeroBased, dayOfMonth) {
  const holiday = new Date(Date.UTC(year, monthIndexZeroBased, dayOfMonth));
  const observed = new Date(holiday);
  if (holiday.getUTCDay() === 6) observed.setUTCDate(observed.getUTCDate() - 1);
  if (holiday.getUTCDay() === 0) observed.setUTCDate(observed.getUTCDate() + 1);
  return observed;
}

function computeEasterSundayUtc(year) {
  const a = year % 19;
  const b = Math.floor(year / 100);
  const c = year % 100;
  const d = Math.floor(b / 4);
  const e = b % 4;
  const f = Math.floor((b + 8) / 25);
  const g = Math.floor((b - f + 1) / 3);
  const h = (19 * a + b - d - g + 15) % 30;
  const i = Math.floor(c / 4);
  const k = c % 4;
  const l = (32 + 2 * e + 2 * i - h - k) % 7;
  const m = Math.floor((a + 11 * h + 22 * l) / 451);
  const month = Math.floor((h + l - 7 * m + 114) / 31);
  const day = ((h + l - 7 * m + 114) % 31) + 1;
  return new Date(Date.UTC(year, month - 1, day));
}

function getUsEquitySpecialClosures() {
  return new Set([
    '2001-09-11', '2001-09-12', '2001-09-13', '2001-09-14',
    '2004-06-11',
    '2007-01-02',
    '2012-10-29', '2012-10-30',
    '2018-12-05',
    '2025-01-09'
  ]);
}

function isUsEquityHoliday(dateKey) {
  const date = parseUtcDateKey(dateKey);
  if (!(date instanceof Date) || Number.isNaN(date.getTime())) return false;
  const year = date.getUTCFullYear();
  const holidays = new Set([
    formatUtcDateKey(observedFixedHolidayUtc(year, 0, 1)),
    formatUtcDateKey(nthWeekdayOfMonthUtc(year, 0, 1, 3)),
    formatUtcDateKey(nthWeekdayOfMonthUtc(year, 1, 1, 3)),
    formatUtcDateKey(lastWeekdayOfMonthUtc(year, 4, 1)),
    formatUtcDateKey(observedFixedHolidayUtc(year, 5, 19)),
    formatUtcDateKey(observedFixedHolidayUtc(year, 6, 4)),
    formatUtcDateKey(nthWeekdayOfMonthUtc(year, 8, 1, 1)),
    formatUtcDateKey(nthWeekdayOfMonthUtc(year, 10, 4, 4)),
    formatUtcDateKey(observedFixedHolidayUtc(year, 11, 25))
  ]);
  const easterSunday = computeEasterSundayUtc(year);
  easterSunday.setUTCDate(easterSunday.getUTCDate() - 2);
  holidays.add(formatUtcDateKey(easterSunday));
  return holidays.has(dateKey) || getUsEquitySpecialClosures().has(dateKey);
}

function isUsTradingSessionDate(dateKey) {
  return isWeekdayMarketDate(dateKey) && !isUsEquityHoliday(dateKey);
}

function previousUsTradingSessionDate(dateKey) {
  const parsed = parseUtcDateKey(dateKey);
  if (!(parsed instanceof Date) || Number.isNaN(parsed.getTime())) return '';
  const cursor = new Date(parsed);
  do {
    cursor.setUTCDate(cursor.getUTCDate() - 1);
  } while (!isUsTradingSessionDate(formatUtcDateKey(cursor)));
  return formatUtcDateKey(cursor);
}

function getMostRecentCompletedUsTradingSessionDate(now = new Date()) {
  const nyNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  const hours = nyNow.getHours();
  const minutes = nyNow.getMinutes();
  let marketDate = `${nyNow.getFullYear()}-${`${nyNow.getMonth() + 1}`.padStart(2, '0')}-${`${nyNow.getDate()}`.padStart(2, '0')}`;
  if (hours < 16 || (hours === 16 && minutes === 0)) {
    marketDate = previousUsTradingSessionDate(marketDate);
  }
  while (!isUsTradingSessionDate(marketDate)) {
    marketDate = previousUsTradingSessionDate(marketDate);
  }
  return marketDate;
}

function ensureWatchlistPreviousCloseReferences(db) {
  if (!db.watchlistPreviousCloseReferences || typeof db.watchlistPreviousCloseReferences !== 'object' || Array.isArray(db.watchlistPreviousCloseReferences)) {
    db.watchlistPreviousCloseReferences = {};
    return true;
  }
  return false;
}

function upsertWatchlistPreviousCloseReference(db, {
  ticker,
  marketDate,
  previousClose,
  source = 'unknown',
  currency = null,
  exchange = null
} = {}) {
  if (!ticker || !marketDate) return false;
  const parsed = Number(previousClose);
  if (!Number.isFinite(parsed) || parsed <= 0) return false;
  ensureWatchlistPreviousCloseReferences(db);
  const key = `${String(ticker).toUpperCase()}|${marketDate}`;
  const existing = db.watchlistPreviousCloseReferences[key];
  const next = {
    ticker: String(ticker).toUpperCase(),
    marketDate,
    previousClose: parsed,
    source: String(source || 'unknown'),
    capturedAt: new Date().toISOString(),
    currency: currency || null,
    exchange: exchange || null
  };
  const changed = !existing
    || Number(existing.previousClose) !== next.previousClose
    || String(existing.source || '') !== next.source
    || String(existing.currency || '') !== String(next.currency || '')
    || String(existing.exchange || '') !== String(next.exchange || '');
  if (changed) {
    db.watchlistPreviousCloseReferences[key] = next;
  }
  return changed;
}

function resolveWatchlistPreviousCloseReference(db, ticker, marketDate) {
  ensureWatchlistPreviousCloseReferences(db);
  const normalizedTicker = String(ticker || '').trim().toUpperCase();
  if (!normalizedTicker || !marketDate) return null;
  const exact = db.watchlistPreviousCloseReferences[`${normalizedTicker}|${marketDate}`];
  if (exact && Number.isFinite(Number(exact.previousClose)) && Number(exact.previousClose) > 0) {
    return exact;
  }
  const prefix = `${normalizedTicker}|`;
  const candidateKeys = Object.keys(db.watchlistPreviousCloseReferences)
    .filter((key) => key.startsWith(prefix))
    .map((key) => db.watchlistPreviousCloseReferences[key])
    .filter((entry) => entry && String(entry.marketDate || '') <= marketDate && Number.isFinite(Number(entry.previousClose)) && Number(entry.previousClose) > 0)
    .sort((a, b) => String(b.marketDate || '').localeCompare(String(a.marketDate || '')));
  return candidateKeys[0] || null;
}

function hasWatchlistPreviousCloseReferenceForDate(db, ticker, marketDate) {
  ensureWatchlistPreviousCloseReferences(db);
  const normalizedTicker = String(ticker || '').trim().toUpperCase();
  if (!normalizedTicker || !marketDate) return false;
  const exact = db.watchlistPreviousCloseReferences[`${normalizedTicker}|${marketDate}`];
  return Boolean(exact && Number.isFinite(Number(exact.previousClose)) && Number(exact.previousClose) > 0);
}

async function ingestWatchlistPreviousCloseFromProvider(db, ticker, {
  snapshot = null,
  marketDate = null,
  source = 'provider_previous_close'
} = {}) {
  const normalizedTicker = normalizeWatchlistTicker(ticker);
  const targetMarketDate = marketDate || getMostRecentCompletedUsTradingSessionDate(new Date());
  const quoteSnapshot = snapshot || await fetchMarketQuoteSnapshot(normalizedTicker);
  let didMutate = false;
  const providerPreviousClose = Number.isFinite(Number(quoteSnapshot?.previousClose)) ? Number(quoteSnapshot.previousClose) : null;
  const hadProviderPreviousClose = Number.isFinite(providerPreviousClose) && providerPreviousClose > 0;
  const nyDate = getNyDateKeyForDate(new Date(), false);
  const providerReferenceDate = isUsTradingSessionDate(nyDate)
    ? previousUsTradingSessionDate(nyDate)
    : getMostRecentCompletedUsTradingSessionDate(new Date());
  if (hadProviderPreviousClose) {
    didMutate = upsertWatchlistPreviousCloseReference(db, {
      ticker: normalizedTicker,
      marketDate: providerReferenceDate,
      previousClose: providerPreviousClose,
      source,
      currency: quoteSnapshot?.currency || null,
      exchange: quoteSnapshot?.quote?.exchange || quoteSnapshot?.quoteType || null
    }) || didMutate;
  }
  const marketState = String(quoteSnapshot?.marketState || '').trim().toLowerCase();
  const regularMarketPrice = Number.isFinite(Number(quoteSnapshot?.regularMarketPrice)) ? Number(quoteSnapshot.regularMarketPrice) : null;
  const shouldCaptureRegularClose = (marketState === 'post' || marketState === 'closed') && Number.isFinite(regularMarketPrice) && regularMarketPrice > 0;
  const capturedRegularClose = shouldCaptureRegularClose;
  if (shouldCaptureRegularClose) {
    didMutate = upsertWatchlistPreviousCloseReference(db, {
      ticker: normalizedTicker,
      marketDate: targetMarketDate,
      previousClose: regularMarketPrice,
      source: source === 'provider_previous_close' ? 'captured_regular_session_close' : `${source}_regular_close`,
      currency: quoteSnapshot?.currency || null,
      exchange: quoteSnapshot?.quote?.exchange || quoteSnapshot?.quoteType || null
    }) || didMutate;
  }
  return {
    didMutate,
    hadProviderPreviousClose,
    capturedRegularClose,
    providerReferenceDate,
    targetMarketDate,
    snapshot: quoteSnapshot
  };
}
async function fetchYahooQuote(symbol) {
  const snapshot = await fetchYahooQuoteSnapshot(symbol);
  if (!Number.isFinite(snapshot?.selectedPrice) || snapshot.selectedPrice <= 0) {
    throw new Error('Yahoo quote not available');
  }
  return {
    symbol: snapshot.symbol,
    price: snapshot.selectedPrice,
    currency: snapshot.currency,
    isExtended: snapshot.isExtended,
    marketState: snapshot.marketState
  };
}

function parsePositiveNumber(...values) {
  for (const value of values) {
    const parsed = Number(value);
    if (Number.isFinite(parsed) && parsed > 0) return parsed;
  }
  return null;
}

function formatProviderError(error) {
  if (!error) return null;
  const code = typeof error?.code === 'string' ? error.code : '';
  const message = typeof error?.message === 'string'
    ? error.message
    : String(error);
  if (code) return `${code}: ${message}`;
  return message;
}

const WATCHLIST_QUOTE_DEBUG_SYMBOLS = new Set(['LWLG', 'NBIS', 'GLW']);

function shouldDebugWatchlistQuoteSymbol(symbol) {
  return WATCHLIST_QUOTE_DEBUG_SYMBOLS.has(String(symbol || '').trim().toUpperCase());
}

function computeMidPrice(bidRaw, askRaw) {
  const bid = parsePositiveNumber(bidRaw);
  const ask = parsePositiveNumber(askRaw);
  if (!Number.isFinite(bid) || !Number.isFinite(ask)) return null;
  return (bid + ask) / 2;
}

function marketStateIsOpen(marketStateRaw) {
  const marketState = String(marketStateRaw || '').trim().toLowerCase();
  return marketState === 'regular' || marketState === 'pre' || marketState === 'post';
}

function resolveDisplayPriceAndSession({
  preMarketPrice,
  postMarketPrice,
  extendedHoursPrice,
  regularMarketPrice,
  previousClose
}) {
  if (Number.isFinite(preMarketPrice)) return { displayPrice: preMarketPrice, session: 'premarket', priceSource: 'preMarketPrice' };
  if (Number.isFinite(postMarketPrice)) return { displayPrice: postMarketPrice, session: 'afterhours', priceSource: 'postMarketPrice' };
  if (Number.isFinite(extendedHoursPrice)) return { displayPrice: extendedHoursPrice, session: 'extended', priceSource: 'extendedHoursPrice' };
  if (Number.isFinite(regularMarketPrice)) return { displayPrice: regularMarketPrice, session: 'regular', priceSource: 'regularMarketPrice' };
  if (Number.isFinite(previousClose)) return { displayPrice: previousClose, session: 'closed', priceSource: 'previousClose' };
  return { displayPrice: null, session: 'closed', priceSource: 'none' };
}

function computePercentChangeFromPreviousClose(displayPrice, previousClose, { priceSource = 'none' } = {}) {
  if (!Number.isFinite(displayPrice) || !Number.isFinite(previousClose) || previousClose <= 0) return null;
  return ((displayPrice - previousClose) / previousClose) * 100;
}

function quoteAsOfFromSource(quote = {}, priceSource = 'none') {
  const asOfEpoch = priceSource === 'preMarketPrice'
    ? Number(quote?.preMarketTime)
    : priceSource === 'postMarketPrice'
      ? Number(quote?.postMarketTime)
      : priceSource === 'extendedHoursPrice'
        ? Number(quote?.extendedMarketTime) || Number(quote?.postMarketTime) || Number(quote?.preMarketTime)
      : Number(quote?.regularMarketTime);
  if (Number.isFinite(asOfEpoch) && asOfEpoch > 0) return new Date(asOfEpoch * 1000).toISOString();
  return new Date().toISOString();
}

function isAsOfStale(asOf, { isDelayed = false } = {}) {
  if (!asOf) return true;
  const asOfMs = Date.parse(asOf);
  if (!Number.isFinite(asOfMs)) return true;
  const maxAgeMs = isDelayed ? 45 * 60 * 1000 : 20 * 60 * 1000;
  return (Date.now() - asOfMs) > maxAgeMs;
}

function normalizeQuoteSnapshot(symbol, quote = {}) {
  const marketState = typeof quote?.marketState === 'string' ? quote.marketState.toLowerCase() : '';
  const preMarketPrice = parsePositiveNumber(quote?.preMarketPrice);
  const postMarketPrice = parsePositiveNumber(quote?.postMarketPrice);
  const extendedHoursPrice = parsePositiveNumber(
    quote?.extendedMarketPrice,
    quote?.extendedHoursPrice,
    quote?.extendedHoursMarketPrice,
    quote?.postMarketTradePrice,
    quote?.preMarketTradePrice,
    quote?.postMarketLastPrice,
    quote?.preMarketLastPrice
  );
  const regularMarketPrice = parsePositiveNumber(quote?.regularMarketPrice, quote?.marketPrice, quote?.price);
  const previousClose = parsePositiveNumber(quote?.regularMarketPreviousClose, quote?.previousClose, quote?.close);
  const regularOpen = parsePositiveNumber(quote?.regularMarketOpen, quote?.open);
  const currentPrice = parsePositiveNumber(regularMarketPrice, quote?.marketPrice, quote?.price);
  const marketStateIsRegular = marketState === 'regular';
  const preferredPre = marketState === 'pre' ? parsePositiveNumber(preMarketPrice, extendedHoursPrice) : preMarketPrice;
  const preferredPost = marketState === 'post' ? parsePositiveNumber(postMarketPrice, extendedHoursPrice) : postMarketPrice;
  const { displayPrice, session, priceSource } = marketStateIsRegular
    ? resolveDisplayPriceAndSession({
      preMarketPrice: null,
      postMarketPrice: null,
      extendedHoursPrice: null,
      regularMarketPrice: currentPrice,
      previousClose
    })
    : resolveDisplayPriceAndSession({
      preMarketPrice: preferredPre,
      postMarketPrice: preferredPost,
      extendedHoursPrice,
      regularMarketPrice: null,
      previousClose
    });
  const displayChangePct = computePercentChangeFromPreviousClose(displayPrice, previousClose, { priceSource });
  const isDelayed = Number.isFinite(Number(quote?.exchangeDataDelayedBy)) && Number(quote.exchangeDataDelayedBy) > 0;
  const asOf = quoteAsOfFromSource(quote, priceSource);
  const isStale = isAsOfStale(asOf, { isDelayed });
  const mark = parsePositiveNumber(quote?.mark, quote?.markPrice, quote?.midPrice);
  const bid = parsePositiveNumber(quote?.bid, quote?.bidPrice);
  const ask = parsePositiveNumber(quote?.ask, quote?.askPrice);
  const mid = computeMidPrice(bid, ask) ?? parsePositiveNumber(quote?.mid, quote?.midPrice);
  const last = parsePositiveNumber(
    quote?.lastPrice,
    quote?.regularMarketLastPrice,
    regularMarketPrice
  );
  const marketOpen = marketStateIsOpen(marketState);
  const preferredExtended = parsePositiveNumber(
    preMarketPrice,
    postMarketPrice,
    extendedHoursPrice,
    quote?.extendedMarketPrice
  );
  const live = parsePositiveNumber(
    preferredExtended,
    marketOpen ? regularMarketPrice : null
  );
  const normalizedQuote = {
    previousClose,
    regularMarketPrice,
    extendedHoursPrice,
    preMarketPrice,
    postMarketPrice,
    displayPrice,
    session,
    asOf,
    isStale
  };
  return {
    symbol,
    currency: quote?.currency || 'GBP',
    marketState,
    session,
    marketOpen,
    isExtended: Number.isFinite(preMarketPrice) || Number.isFinite(postMarketPrice),
    live,
    mark,
    mid,
    last,
    currentPrice,
    regularMarketPrice,
    regularOpen,
    preMarketPrice,
    postMarketPrice,
    extendedHoursPrice,
    displayPrice,
    displayChangePct,
    priceSource,
    displayChangeBasis: 'previousClose',
    asOf,
    isDelayed,
    isStale,
    previousClose,
    quote: normalizedQuote,
    selectedPrice: parsePositiveNumber(displayPrice, live, last, previousClose)
  };
}

function valueFromRaw(node) {
  if (node && typeof node === 'object' && Number.isFinite(Number(node.raw))) return Number(node.raw);
  const parsed = Number(node);
  return Number.isFinite(parsed) ? parsed : null;
}

async function fetchYahooQuoteSummaryPrice(symbol) {
  const trimmed = (symbol || '').toUpperCase();
  if (!trimmed) return null;
  const baseUrls = [
    'https://query1.finance.yahoo.com/v10/finance/quoteSummary',
    'https://query2.finance.yahoo.com/v10/finance/quoteSummary'
  ];
  for (const baseUrl of baseUrls) {
    const url = `${baseUrl}/${encodeURIComponent(trimmed)}?modules=price`;
    const res = await fetch(url, {
      headers: {
        'User-Agent': 'Mozilla/5.0',
        'Accept': 'application/json,text/plain,*/*'
      }
    });
    if (!res.ok) continue;
    const data = await res.json();
    const price = data?.quoteSummary?.result?.[0]?.price;
    if (price) return price;
  }
  return null;
}

async function fetchYahooQuoteSnapshot(symbol) {
  const baseUrls = [
    'https://query1.finance.yahoo.com/v7/finance/quote',
    'https://query2.finance.yahoo.com/v7/finance/quote'
  ];
  const trimmed = (symbol || '').toUpperCase();
  if (!trimmed) throw new Error('Missing symbol');
  const headers = {
    'User-Agent': 'Mozilla/5.0',
    'Accept': 'application/json,text/plain,*/*'
  };
  for (const baseUrl of baseUrls) {
    const url = `${baseUrl}?symbols=${encodeURIComponent(trimmed)}&includePrePost=true`;
    const res = await fetch(url, { headers });
    if (!res.ok) continue;
    const data = await res.json();
    const quote = data?.quoteResponse?.result?.[0];
    if (!quote) continue;
    const hasExtendedFields = Number.isFinite(Number(quote?.preMarketPrice))
      || Number.isFinite(Number(quote?.postMarketPrice))
      || Number.isFinite(Number(quote?.extendedMarketPrice))
      || Number.isFinite(Number(quote?.extendedHoursPrice));
    let summaryPrice = null;
    let mergedQuote = quote;
    if (!hasExtendedFields) {
      summaryPrice = await fetchYahooQuoteSummaryPrice(trimmed);
      if (summaryPrice) {
        mergedQuote = {
          ...quote,
          marketState: String(summaryPrice?.marketState || quote?.marketState || ''),
          regularMarketPrice: valueFromRaw(summaryPrice?.regularMarketPrice) ?? quote?.regularMarketPrice,
          regularMarketPreviousClose: valueFromRaw(summaryPrice?.regularMarketPreviousClose) ?? quote?.regularMarketPreviousClose,
          preMarketPrice: valueFromRaw(summaryPrice?.preMarketPrice) ?? quote?.preMarketPrice,
          postMarketPrice: valueFromRaw(summaryPrice?.postMarketPrice) ?? quote?.postMarketPrice,
          extendedMarketPrice: valueFromRaw(summaryPrice?.postMarketPrice) ?? valueFromRaw(summaryPrice?.preMarketPrice) ?? quote?.extendedMarketPrice,
          regularMarketTime: valueFromRaw(summaryPrice?.regularMarketTime) ?? quote?.regularMarketTime,
          preMarketTime: valueFromRaw(summaryPrice?.preMarketTime) ?? quote?.preMarketTime,
          postMarketTime: valueFromRaw(summaryPrice?.postMarketTime) ?? quote?.postMarketTime
        };
      }
    }
    if (shouldDebugWatchlistQuoteSymbol(trimmed)) {
      console.info('[WATCHLIST_QUOTE_PIPELINE_RAW_PROVIDER]', {
        ticker: trimmed,
        providerPath: summaryPrice ? 'yahoo_quoteSummary_price+v7_quote' : 'yahoo_v7_quote',
        rawProviderQuote: mergedQuote
      });
    }
    const snapshot = normalizeQuoteSnapshot(trimmed, mergedQuote);
    if (!Number.isFinite(snapshot.selectedPrice) || snapshot.selectedPrice <= 0) continue;
    return snapshot;
  }
  throw new Error('Yahoo quote not available');
}

async function fetchYahooChartQuote(symbol) {
  const trimmed = (symbol || '').toUpperCase();
  if (!trimmed) throw new Error('Missing symbol');
  const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(trimmed)}?interval=1m&range=1d&includePrePost=false`;
  const res = await fetch(url, {
    headers: {
      'User-Agent': 'Mozilla/5.0',
      'Accept': 'application/json,text/plain,*/*'
    }
  });
  if (!res.ok) throw new Error('Yahoo chart not available');
  const data = await res.json();
  const result = data?.chart?.result?.[0];
  const closes = result?.indicators?.quote?.[0]?.close;
  if (!Array.isArray(closes) || closes.length === 0) throw new Error('Yahoo chart missing data');
  let last = null;
  for (let i = closes.length - 1; i >= 0; i -= 1) {
    const value = closes[i];
    if (Number.isFinite(value) && value > 0) {
      last = value;
      break;
    }
  }
  if (!Number.isFinite(last) || last <= 0) throw new Error('Yahoo chart missing price');
  const currency = result?.meta?.currency || 'GBP';
  const marketState = typeof result?.meta?.marketState === 'string'
    ? result.meta.marketState.toLowerCase()
    : '';
  const previousClose = parsePositiveNumber(result?.meta?.previousClose);
  if (!Number.isFinite(previousClose) || previousClose <= 0) {
    console.info('[YAHOO_CHART_PREVIOUS_CLOSE_MISSING]', {
      ticker: trimmed
    });
  }
  return {
    symbol: trimmed,
    price: last,
    previousClose,
    currency,
    isExtended: true,
    marketState
  };
}

async function fetchYahooDayLow(symbol) {
  const trimmed = (symbol || '').toUpperCase();
  if (!trimmed) throw new Error('Missing symbol');
  const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(trimmed)}?interval=1m&range=1d&includePrePost=false`;
  const res = await fetch(url, {
    headers: {
      'User-Agent': 'Mozilla/5.0',
      'Accept': 'application/json,text/plain,*/*'
    }
  });
  if (!res.ok) throw new Error('Yahoo chart not available');
  const data = await res.json();
  const result = data?.chart?.result?.[0];
  const lows = result?.indicators?.quote?.[0]?.low;
  const opens = result?.indicators?.quote?.[0]?.open;
  if (!Array.isArray(lows) || lows.length === 0) throw new Error('Yahoo chart missing low');
  let sessionOpen = null;
  if (Array.isArray(opens) && opens.length) {
    for (const value of opens) {
      const parsed = Number(value);
      if (Number.isFinite(parsed) && parsed > 0) {
        sessionOpen = parsed;
        break;
      }
    }
  }
  let min = null;
  for (const value of lows) {
    if (!Number.isFinite(value) || value <= 0) continue;
    if (min === null || value < min) min = value;
  }
  if (!Number.isFinite(min) || min <= 0) throw new Error('Yahoo chart missing low');
  return {
    symbol: trimmed,
    low: min,
    currency: result?.meta?.currency || 'USD',
    open: sessionOpen,
    asOf: new Date().toISOString()
  };
}

async function fetchYahooRegularDayLow(symbol) {
  const trimmed = (symbol || '').toUpperCase();
  if (!trimmed) throw new Error('Missing symbol');
  const url = `https://query1.finance.yahoo.com/v7/finance/quote?symbols=${encodeURIComponent(trimmed)}&includePrePost=false`;
  const res = await fetch(url, {
    headers: {
      'User-Agent': 'Mozilla/5.0',
      'Accept': 'application/json,text/plain,*/*'
    }
  });
  if (!res.ok) throw new Error('Yahoo quote not available');
  const data = await res.json();
  const quote = data?.quoteResponse?.result?.[0];
  const low = Number(quote?.regularMarketDayLow);
  if (!Number.isFinite(low) || low <= 0) {
    throw new Error('Yahoo quote missing regular day low');
  }
  return {
    symbol: trimmed,
    low,
    currency: quote?.currency || 'USD',
    open: Number.isFinite(Number(quote?.regularMarketOpen)) ? Number(quote.regularMarketOpen) : null,
    asOf: Number.isFinite(Number(quote?.regularMarketTime)) && Number(quote.regularMarketTime) > 0
      ? new Date(Number(quote.regularMarketTime) * 1000).toISOString()
      : new Date().toISOString()
  };
}

async function fetchStooqQuote(symbol) {
  const trimmed = (symbol || '').trim();
  if (!trimmed) throw new Error('Missing symbol');
  const candidates = [trimmed, `${trimmed}.us`];
  for (const candidate of candidates) {
    const url = `https://stooq.com/q/l/?s=${encodeURIComponent(candidate.toLowerCase())}&f=sd2t2ohlcv&h&e=csv`;
    const res = await fetch(url);
    if (!res.ok) continue;
    const text = await res.text();
    const lines = text.trim().split('\n');
    if (lines.length < 2) continue;
    const cols = lines[1].split(',');
    const price = Number(cols[6]);
    if (!Number.isFinite(price) || price <= 0) continue;
    return { symbol: trimmed.toUpperCase(), price, currency: 'USD' };
  }
  throw new Error('Stooq quote not available');
}

async function fetchMarketPrice(symbol) {
  const quote = await fetchMarketQuoteSnapshot(symbol);
  return {
    symbol: quote.symbol,
    price: quote.selectedPrice,
    currency: quote.currency,
    isExtended: quote.isExtended,
    marketState: quote.marketState
  };
}

async function fetchMarketQuoteSnapshot(symbol) {
  const trimmed = (symbol || '').toUpperCase();
  if (!trimmed) throw new Error('Missing symbol');
  const cacheKey = trimmed;
  const cached = marketCache.get(cacheKey);
  const now = Date.now();
  if (cached && (now - cached.at) < 15 * 1000) {
    return cached.snapshot;
  }
  let snapshot = null;
  let yahooQuote = null;
  let yahooChart = null;
  const providerErrors = [];
  if (process.env.MARKET_DATA_URL) {
    const url = `${process.env.MARKET_DATA_URL}?symbols=${encodeURIComponent(trimmed)}&includePrePost=true`;
    const res = await fetch(url);
    if (res.ok) {
      const data = await res.json();
      const quote = data?.quoteResponse?.result?.[0];
      if (quote) {
        const normalized = normalizeQuoteSnapshot(trimmed, quote);
        if (Number.isFinite(normalized.selectedPrice) && normalized.selectedPrice > 0) {
          snapshot = normalized;
        }
      }
    }
  }
  if (!snapshot) {
    try {
      yahooQuote = await fetchYahooQuoteSnapshot(trimmed);
    } catch (error) {
      providerErrors.push(`yahoo_quote: ${formatProviderError(error)}`);
    }
    try {
      yahooChart = await fetchYahooChartQuote(trimmed);
    } catch (error) {
      providerErrors.push(`yahoo_chart: ${formatProviderError(error)}`);
    }
    if (yahooQuote?.isExtended) {
      snapshot = yahooQuote;
    } else if (
      yahooChart?.price
      && (!yahooQuote?.selectedPrice || Math.abs(yahooChart.price - yahooQuote.selectedPrice) > 0.0001)
    ) {
      const previousClose = Number.isFinite(Number(yahooChart?.previousClose))
        ? Number(yahooChart.previousClose)
        : (Number.isFinite(Number(yahooQuote?.previousClose)) ? Number(yahooQuote.previousClose) : null);
      const { displayPrice, session, priceSource } = resolveDisplayPriceAndSession({
        preMarketPrice: null,
        postMarketPrice: null,
        extendedHoursPrice: null,
        regularMarketPrice: yahooChart.price,
        previousClose
      });
      snapshot = {
        symbol: trimmed,
        currency: yahooChart.currency || 'GBP',
        marketState: yahooChart.marketState || '',
        session,
        marketOpen: marketStateIsOpen(yahooChart.marketState || ''),
        isExtended: true,
        live: yahooChart.price,
        mark: null,
        mid: null,
        last: yahooChart.price,
        currentPrice: yahooChart.price,
        regularMarketPrice: yahooChart.price,
        regularOpen: null,
        preMarketPrice: null,
        postMarketPrice: null,
        extendedHoursPrice: null,
        displayPrice,
        displayChangePct: computePercentChangeFromPreviousClose(displayPrice, previousClose, { priceSource }),
        priceSource,
        displayChangeBasis: 'previousClose',
        asOf: new Date().toISOString(),
        isDelayed: false,
        isStale: false,
        previousClose,
        selectedPrice: yahooChart.price
      };
    } else if (yahooQuote) {
      if (Number.isFinite(Number(yahooChart?.previousClose)) && Number(yahooChart.previousClose) > 0) {
        snapshot = {
          ...yahooQuote,
          previousClose: Number(yahooChart.previousClose)
        };
      } else {
        snapshot = yahooQuote;
      }
    }
    if (!snapshot) {
      let stooq = null;
      try {
        stooq = await fetchStooqQuote(trimmed);
      } catch (error) {
        providerErrors.push(`stooq_quote: ${formatProviderError(error)}`);
        throw error;
      }
      snapshot = {
        symbol: trimmed,
        currency: stooq.currency || 'GBP',
        marketState: '',
        session: 'closed',
        marketOpen: false,
        isExtended: false,
        live: null,
        mark: null,
        mid: null,
        last: stooq.price,
        currentPrice: null,
        regularMarketPrice: null,
        regularOpen: null,
        preMarketPrice: null,
        postMarketPrice: null,
        extendedHoursPrice: null,
        displayPrice: stooq.price,
        displayChangePct: null,
        priceSource: 'none',
        displayChangeBasis: 'previousClose',
        asOf: new Date().toISOString(),
        isDelayed: true,
        isStale: true,
        previousClose: null,
        selectedPrice: stooq.price
      };
    }
  }
  if (snapshot && providerErrors.length) {
    snapshot.providerErrors = providerErrors;
  }
  marketCache.set(cacheKey, { snapshot, at: now });
  return snapshot;
}

function isOptionsTrade(trade) {
  return String(trade?.assetClass || '').trim().toLowerCase() === 'options';
}

function normalizeOptionType(value) {
  const raw = String(value || '').trim().toLowerCase();
  if (raw.startsWith('c')) return 'call';
  if (raw.startsWith('p')) return 'put';
  return '';
}

function normalizeOptionExpiration(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  if (/^\d{8}$/.test(raw)) {
    return `${raw.slice(0, 4)}-${raw.slice(4, 6)}-${raw.slice(6, 8)}`;
  }
  if (/^\d{6}$/.test(raw)) {
    const year = 2000 + Number(raw.slice(0, 2));
    if (Number.isFinite(year)) {
      return `${year}-${raw.slice(2, 4)}-${raw.slice(4, 6)}`;
    }
  }
  return '';
}

function parseOccOptionSymbol(symbolRaw) {
  const symbol = String(symbolRaw || '').trim().toUpperCase();
  if (!symbol) return null;
  const match = symbol.match(/^([A-Z]{1,6})(\d{6})([CP])(\d{8})$/);
  if (!match) return null;
  const [, underlying, expiryRaw, cpRaw, strikeRaw] = match;
  const expiration = `20${expiryRaw.slice(0, 2)}-${expiryRaw.slice(2, 4)}-${expiryRaw.slice(4, 6)}`;
  const strike = Number(strikeRaw) / 1000;
  if (!Number.isFinite(strike) || strike <= 0) return null;
  return {
    underlyingTicker: underlying,
    expirationDate: expiration,
    optionType: cpRaw === 'P' ? 'put' : 'call',
    strike
  };
}

function isValidOptionContractSymbol(symbolRaw) {
  const symbol = String(symbolRaw || '').trim().toUpperCase();
  if (!symbol) return false;
  return Boolean(parseOccOptionSymbol(symbol) || parseIbkrOptionSymbol(symbol));
}

function buildOptionContractQuoteSymbol(trade) {
  if (!isOptionsTrade(trade)) return '';
  const optionType = normalizeOptionType(trade?.optionType);
  const parsedFromIbkrSymbol = parseIbkrOptionSymbol(trade?.symbol || '');
  const parsedFromOccSymbol = parseOccOptionSymbol(trade?.symbol || '')
    || parseOccOptionSymbol(trade?.displaySymbol || '')
    || parseOccOptionSymbol(trade?.rawBrokerSymbol || '');
  const optionStrike = Number(
    trade?.optionStrike
    ?? parsedFromIbkrSymbol?.strike
    ?? parsedFromOccSymbol?.strike
  );
  const optionExpiration = normalizeOptionExpiration(
    trade?.optionExpiration
    || parsedFromIbkrSymbol?.expirationDate
    || parsedFromOccSymbol?.expirationDate
  );
  if (!/^\d{4}-\d{2}-\d{2}$/.test(optionExpiration)) return '';
  if (!Number.isFinite(optionStrike) || optionStrike <= 0) return '';
  if (optionType !== 'call' && optionType !== 'put') return '';
  const underlying = String(
    trade?.underlyingTicker
    || parsedFromIbkrSymbol?.underlyingTicker
    || parsedFromOccSymbol?.underlyingTicker
    || trade?.ticker
    || trade?.symbol
    || ''
  ).trim().toUpperCase().replace(/[^A-Z0-9._-]/g, '');
  if (!underlying) return '';
  const yymmdd = optionExpiration.replace(/-/g, '').slice(2);
  const cp = optionType === 'put' ? 'P' : 'C';
  const strikeScaled = Math.round(optionStrike * 1000);
  if (!Number.isFinite(strikeScaled) || strikeScaled <= 0) return '';
  const strikePart = String(strikeScaled).padStart(8, '0');
  return `${underlying}${yymmdd}${cp}${strikePart}`;
}

function extractOptionContractIdentity(trade) {
  const optionType = normalizeOptionType(trade?.optionType);
  const parsedFromIbkrSymbol = parseIbkrOptionSymbol(trade?.symbol || '');
  const parsedFromOccSymbol = parseOccOptionSymbol(trade?.symbol || '')
    || parseOccOptionSymbol(trade?.displaySymbol || '')
    || parseOccOptionSymbol(trade?.rawBrokerSymbol || '');
  const strike = Number(trade?.optionStrike ?? parsedFromIbkrSymbol?.strike ?? parsedFromOccSymbol?.strike);
  const expiry = normalizeOptionExpiration(
    trade?.optionExpiration || parsedFromIbkrSymbol?.expirationDate || parsedFromOccSymbol?.expirationDate
  );
  const underlyingTicker = String(
    trade?.underlyingTicker
    || parsedFromIbkrSymbol?.underlyingTicker
    || parsedFromOccSymbol?.underlyingTicker
    || trade?.ticker
    || trade?.symbol
    || ''
  ).trim().toUpperCase().replace(/[^A-Z0-9._-]/g, '');
  const multiplierRaw = Number(trade?.optionMultiplier);
  const multiplier = Number.isFinite(multiplierRaw) && multiplierRaw > 0 ? multiplierRaw : 100;
  const currency = String(trade?.currency || 'USD').trim().toUpperCase() || 'USD';
  const conid = trade?.ibkrConid ? String(trade.ibkrConid).trim() : '';
  const ibkrOptionSymbol = String(trade?.symbol || trade?.displaySymbol || '').trim().toUpperCase();
  const contractSymbol = buildOptionContractQuoteSymbol(trade);
  return {
    underlyingTicker,
    optionType,
    strike: Number.isFinite(strike) && strike > 0 ? strike : null,
    expiry: /^\d{4}-\d{2}-\d{2}$/.test(expiry) ? expiry : '',
    multiplier,
    currency,
    conid,
    ibkrOptionSymbol,
    contractSymbol
  };
}

function selectBestOptionPremium(fields = {}) {
  const markOrLive = parsePositiveNumber(fields.mark, fields.live);
  const mid = computeMidPrice(fields.bid, fields.ask) ?? parsePositiveNumber(fields.mid);
  const last = parsePositiveNumber(fields.last);
  const close = parsePositiveNumber(fields.previousClose, fields.close);
  if (Number.isFinite(markOrLive) && markOrLive > 0) return { source: 'mark', value: markOrLive };
  if (Number.isFinite(mid) && mid > 0) return { source: 'mid', value: mid };
  if (Number.isFinite(last) && last > 0) return { source: 'last', value: last };
  if (Number.isFinite(close) && close > 0) return { source: 'close', value: close };
  return null;
}

function isIbkrOptionQuoteAvailable(user) {
  const cfg = user?.ibkr;
  if (!cfg?.enabled || cfg?.mode !== 'connector') return { ok: false, reason: 'ibkr_not_enabled' };
  updateIbkrConnectorStatus(cfg);
  if (cfg.connectionStatus !== 'online') return { ok: false, reason: 'ibkr_not_connected' };
  const authState = String(cfg?.lastConnectorStatus?.authStatus || '').toLowerCase();
  if (authState && ['unauthorized', 'expired', 'forbidden'].includes(authState)) {
    return { ok: false, reason: 'ibkr_session_unauthorized' };
  }
  return { ok: true, reason: null };
}

async function resolveIbkrConidForOptionContract(identity, diagnostics) {
  if (identity.conid) return identity.conid;
  if (!identity.contractSymbol) return '';
  const cached = optionContractResolutionCache.get(identity.contractSymbol);
  if (cached) return cached;
  const baseUrl = String(process.env.IBKR_OPTION_RESOLVE_URL || '').trim();
  if (!baseUrl) return '';
  const url = new URL(baseUrl);
  url.searchParams.set('underlying', identity.underlyingTicker);
  url.searchParams.set('expiry', identity.expiry);
  url.searchParams.set('right', identity.optionType === 'put' ? 'P' : 'C');
  url.searchParams.set('strike', String(identity.strike));
  const res = await fetch(url.toString());
  if (!res.ok) throw new Error(`ibkr_contract_resolution_http_${res.status}`);
  const payload = await res.json();
  const conid = String(payload?.conid || payload?.contract?.conid || '').trim();
  if (!conid) throw new Error('ibkr_contract_resolution_failed');
  optionContractResolutionCache.set(identity.contractSymbol, conid);
  diagnostics.ibkrResolvedConid = conid;
  return conid;
}

function findIbkrOptionQuoteFromLivePositions(user, identity) {
  const positions = Array.isArray(user?.ibkr?.livePositions) ? user.ibkr.livePositions : [];
  const normalizedSymbol = normalizeIbkrTicker(identity.ibkrOptionSymbol || identity.contractSymbol || identity.underlyingTicker);
  for (const position of positions) {
    const posConid = position?.conid ? String(position.conid) : '';
    const posSymbol = normalizeIbkrTicker(position?.symbol || '');
    if ((identity.conid && posConid === identity.conid) || (normalizedSymbol && posSymbol === normalizedSymbol)) {
      return {
        mark: parsePositiveNumber(position?.markPrice),
        live: parsePositiveNumber(position?.marketPrice),
        bid: parsePositiveNumber(position?.bid),
        ask: parsePositiveNumber(position?.ask),
        last: parsePositiveNumber(position?.lastPrice),
        previousClose: parsePositiveNumber(position?.closePrice),
        currency: position?.currency || identity.currency,
        marketOpen: true
      };
    }
  }
  return null;
}

async function fetchIbkrOptionQuote(user, identity, diagnostics) {
  const fromPositions = findIbkrOptionQuoteFromLivePositions(user, identity);
  if (fromPositions) return fromPositions;
  const baseUrl = String(process.env.IBKR_OPTION_QUOTE_URL || '').trim();
  if (!baseUrl) throw new Error('ibkr_quote_endpoint_not_configured');
  const url = new URL(baseUrl);
  if (identity.conid) url.searchParams.set('conid', identity.conid);
  if (!identity.conid && identity.ibkrOptionSymbol) url.searchParams.set('symbol', identity.ibkrOptionSymbol);
  if (!identity.conid && !identity.ibkrOptionSymbol && identity.contractSymbol) url.searchParams.set('symbol', identity.contractSymbol);
  const res = await fetch(url.toString());
  if (!res.ok) {
    if (res.status === 401 || res.status === 403) throw new Error('ibkr_session_unauthorized');
    if (res.status === 404) throw new Error('ibkr_contract_not_found');
    throw new Error(`ibkr_quote_http_${res.status}`);
  }
  const payload = await res.json();
  diagnostics.ibkrRawQuote = {
    hasBid: Number.isFinite(Number(payload?.bid)),
    hasAsk: Number.isFinite(Number(payload?.ask)),
    hasLast: Number.isFinite(Number(payload?.last)),
    hasClose: Number.isFinite(Number(payload?.previousClose ?? payload?.close))
  };
  return {
    mark: parsePositiveNumber(payload?.mark, payload?.marketPrice),
    live: parsePositiveNumber(payload?.live, payload?.lastPrice),
    bid: parsePositiveNumber(payload?.bid),
    ask: parsePositiveNumber(payload?.ask),
    mid: parsePositiveNumber(payload?.mid),
    last: parsePositiveNumber(payload?.last, payload?.lastPrice),
    previousClose: parsePositiveNumber(payload?.previousClose, payload?.close),
    currency: payload?.currency || identity.currency,
    marketOpen: payload?.marketOpen === true
  };
}

async function fetchPolygonOptionQuote(identity, diagnostics) {
  const apiKey = String(process.env.POLYGON_API_KEY || '').trim();
  if (!apiKey) throw new Error('polygon_api_key_missing');
  if (!identity.contractSymbol || !identity.underlyingTicker) throw new Error('polygon_missing_contract_symbol');
  const baseUrl = (process.env.POLYGON_BASE_URL || 'https://api.polygon.io').replace(/\/+$/, '');
  const snapshotUrl = `${baseUrl}/v3/snapshot/options/${encodeURIComponent(identity.underlyingTicker)}/${encodeURIComponent(identity.contractSymbol)}?apiKey=${encodeURIComponent(apiKey)}`;
  const snapshotRes = await fetch(snapshotUrl);
  if (!snapshotRes.ok) throw new Error(`polygon_snapshot_http_${snapshotRes.status}`);
  const snapshot = await snapshotRes.json();
  const result = snapshot?.results || {};
  const quote = result?.quote || {};
  const lastTrade = result?.last_trade || {};
  const day = result?.day || {};
  const prevDay = result?.prev_day || {};
  diagnostics.polygonFields = {
    hasBid: Number.isFinite(Number(quote?.bid_price)),
    hasAsk: Number.isFinite(Number(quote?.ask_price)),
    hasLast: Number.isFinite(Number(lastTrade?.price)),
    hasClose: Number.isFinite(Number(prevDay?.close ?? day?.close))
  };
  return {
    mark: parsePositiveNumber(result?.mark_price),
    bid: parsePositiveNumber(quote?.bid_price),
    ask: parsePositiveNumber(quote?.ask_price),
    last: parsePositiveNumber(lastTrade?.price),
    previousClose: parsePositiveNumber(prevDay?.close, day?.close),
    currency: identity.currency,
    marketOpen: null
  };
}

async function resolveOptionLiveQuoteForTrade(trade, user = null) {
  const identity = extractOptionContractIdentity(trade);
  const cacheKey = [
    identity.conid || '',
    identity.contractSymbol || '',
    identity.underlyingTicker,
    identity.optionType,
    identity.strike,
    identity.expiry
  ].join('|');
  const now = Date.now();
  const cached = optionQuoteCache.get(cacheKey);
  if (cached && (now - cached.at) < OPTION_QUOTE_CACHE_TTL_MS) return cached.value;
  const diagnostics = {
    tradeId: trade?.id || '',
    userId: trade?.username || '',
    accountContext: trade?.source || '',
    isOption: isOptionsTrade(trade),
    ticker: identity.underlyingTicker,
    optionType: identity.optionType,
    strike: identity.strike,
    expiry: identity.expiry,
    multiplier: identity.multiplier,
    currency: identity.currency,
    storedConidPresent: Boolean(identity.conid),
    storedBrokerOptionSymbolPresent: Boolean(identity.ibkrOptionSymbol),
    resolverChosenFirst: 'ibkr',
    ibkrSessionStatus: null,
    ibkrContractIdentifierUsed: identity.conid || null,
    ibkrFieldsReturned: null,
    fallbackToPolygon: false,
    polygonContractSymbolUsed: identity.contractSymbol || null,
    polygonFieldsReturned: null,
    returnedPremium: null,
    selectedPremiumSource: 'unavailable',
    lookupSucceeded: false,
    quoteProvider: null,
    unavailableReason: null,
    failureReason: '',
    attempts: []
  };
  if (!identity.contractSymbol || !identity.underlyingTicker || !identity.expiry || !identity.strike || !identity.optionType) {
    diagnostics.failureReason = 'invalid_option_contract_metadata';
    diagnostics.unavailableReason = 'invalid_option_contract_metadata';
    console.warn('[ACTIVE_OPTIONS_QUOTE] option quote lookup failed', diagnostics);
    return { quote: null, diagnostics };
  }
  const ibkrStatus = isIbkrOptionQuoteAvailable(user);
  diagnostics.ibkrSessionStatus = ibkrStatus.ok ? 'online' : ibkrStatus.reason;
  if (ibkrStatus.ok) {
    try {
      if (!identity.conid) {
        identity.conid = await resolveIbkrConidForOptionContract(identity, diagnostics);
        diagnostics.ibkrContractIdentifierUsed = identity.conid || null;
      }
      const ibkrFields = await fetchIbkrOptionQuote(user, identity, diagnostics);
      diagnostics.ibkrFieldsReturned = ibkrFields;
      const chosen = selectBestOptionPremium(ibkrFields);
      if (chosen) {
        diagnostics.lookupSucceeded = true;
        diagnostics.returnedPremium = chosen.value;
        diagnostics.quoteProvider = 'ibkr';
        diagnostics.selectedPremiumSource = `ibkr_${chosen.source}`;
        const result = {
          quote: {
            symbol: identity.contractSymbol,
            price: Number(chosen.value),
            currency: ibkrFields.currency || identity.currency,
            source: `ibkr_${chosen.source}`,
            provider: 'ibkr',
            bid: parsePositiveNumber(ibkrFields.bid),
            ask: parsePositiveNumber(ibkrFields.ask),
            last: parsePositiveNumber(ibkrFields.last),
            previousClose: parsePositiveNumber(ibkrFields.previousClose)
          },
          diagnostics
        };
        optionQuoteCache.set(cacheKey, { at: now, value: result });
        console.info('[ACTIVE_OPTIONS_QUOTE] resolved option quote', diagnostics);
        return result;
      }
      diagnostics.attempts.push({ provider: 'ibkr', ok: false, reason: 'ibkr_no_valid_contract_premium' });
    } catch (error) {
      diagnostics.attempts.push({ provider: 'ibkr', ok: false, reason: error?.message || 'ibkr_quote_error' });
    }
  } else {
    diagnostics.attempts.push({ provider: 'ibkr', ok: false, reason: ibkrStatus.reason });
  }
  diagnostics.fallbackToPolygon = true;
  try {
    const polygonFields = await fetchPolygonOptionQuote(identity, diagnostics);
    diagnostics.polygonFieldsReturned = polygonFields;
    const chosen = selectBestOptionPremium(polygonFields);
    if (chosen) {
      diagnostics.lookupSucceeded = true;
      diagnostics.returnedPremium = chosen.value;
      diagnostics.quoteProvider = 'polygon';
      diagnostics.selectedPremiumSource = `polygon_${chosen.source}`;
      const result = {
        quote: {
          symbol: identity.contractSymbol,
          price: Number(chosen.value),
          currency: polygonFields.currency || identity.currency,
          source: `polygon_${chosen.source}`,
          provider: 'polygon',
          bid: parsePositiveNumber(polygonFields.bid),
          ask: parsePositiveNumber(polygonFields.ask),
          last: parsePositiveNumber(polygonFields.last),
          previousClose: parsePositiveNumber(polygonFields.previousClose)
        },
        diagnostics
      };
      optionQuoteCache.set(cacheKey, { at: now, value: result });
      console.info('[ACTIVE_OPTIONS_QUOTE] resolved option quote', diagnostics);
      return result;
    }
    diagnostics.attempts.push({ provider: 'polygon', ok: false, reason: 'polygon_no_contract_quote' });
  } catch (error) {
    diagnostics.attempts.push({ provider: 'polygon', ok: false, reason: error?.message || 'polygon_quote_error' });
  }
  diagnostics.failureReason = diagnostics.attempts.map(a => a.reason).filter(Boolean).join('|') || 'option_quote_unavailable';
  diagnostics.unavailableReason = 'ibkr_unavailable_polygon_no_contract_quote';
  console.info('[ACTIVE_OPTIONS_QUOTE] option quote resolution unavailable', diagnostics);
  console.warn('[ACTIVE_OPTIONS_QUOTE] option quote lookup failed', diagnostics);
  const unresolved = { quote: null, diagnostics };
  optionQuoteCache.set(cacheKey, { at: now, value: unresolved });
  return unresolved;
}

function resolveTradeSizeUnits(trade) {
  const directSize = Number(trade?.sizeUnits);
  if (Number.isFinite(directSize) && directSize > 0) return directSize;
  if (!isOptionsTrade(trade)) return NaN;
  const contracts = Number(trade?.optionContracts);
  const multiplierRaw = Number(trade?.optionMultiplier);
  const multiplier = Number.isFinite(multiplierRaw) && multiplierRaw > 0 ? multiplierRaw : 100;
  if (Number.isFinite(contracts) && contracts > 0) {
    return contracts * multiplier;
  }
  return NaN;
}

async function fetchYahooDayLowForDate(symbol, dateKey) {
  const trimmed = (symbol || '').toUpperCase();
  if (!trimmed) throw new Error('Missing symbol');
  if (!/^\d{4}-\d{2}-\d{2}$/.test(dateKey)) throw new Error('Invalid date key');
  const [year, month, day] = dateKey.split('-').map(Number);
  const baseUtc = new Date(Date.UTC(year, month - 1, day, 0, 0, 0));
  const offsetMinutes = getTimezoneOffset(baseUtc, 'America/New_York');
  const start = baseUtc.getTime() + offsetMinutes * 60000;
  const end = start + 24 * 60 * 60 * 1000;
  const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(trimmed)}?interval=1m&period1=${Math.floor(start / 1000)}&period2=${Math.floor(end / 1000)}&includePrePost=false`;
  const res = await fetch(url, {
    headers: {
      'User-Agent': 'Mozilla/5.0',
      'Accept': 'application/json,text/plain,*/*'
    }
  });
  if (!res.ok) throw new Error('Yahoo chart not available');
  const data = await res.json();
  const result = data?.chart?.result?.[0];
  const lows = result?.indicators?.quote?.[0]?.low;
  const opens = result?.indicators?.quote?.[0]?.open;
  if (!Array.isArray(lows) || lows.length === 0) throw new Error('Yahoo chart missing low');
  let sessionOpen = null;
  if (Array.isArray(opens) && opens.length) {
    for (const value of opens) {
      const parsed = Number(value);
      if (Number.isFinite(parsed) && parsed > 0) {
        sessionOpen = parsed;
        break;
      }
    }
  }
  let min = null;
  for (const value of lows) {
    if (!Number.isFinite(value) || value <= 0) continue;
    if (min === null || value < min) min = value;
  }
  if (!Number.isFinite(min) || min <= 0) throw new Error('Yahoo chart missing low');
  return {
    symbol: trimmed,
    low: min,
    currency: result?.meta?.currency || 'USD',
    open: sessionOpen,
    asOf: new Date().toISOString()
  };
}

async function fetchDailyLow(symbol, dateKey = null) {
  const trimmed = (symbol || '').toUpperCase();
  if (!trimmed) throw new Error('Missing symbol');
  const resolvedDateKey = dateKey || getNyDateKey();
  const cacheKey = `${trimmed}:${resolvedDateKey}`;
  const cached = dailyLowCache.get(cacheKey);
  if (cached && Number.isFinite(cached.expiresAt) && cached.expiresAt > Date.now()) return cached.payload;
  const isToday = resolvedDateKey === getNyDateKey();
  let low;
  if (isToday) {
    try {
      low = await fetchYahooRegularDayLow(trimmed);
    } catch (e) {
      low = await fetchYahooDayLow(trimmed);
    }
  } else {
    low = await fetchYahooDayLowForDate(trimmed, resolvedDateKey);
  }
  dailyLowCache.set(cacheKey, {
    payload: low,
    expiresAt: Date.now() + (isToday ? DAILY_LOW_CACHE_TTL_TODAY_MS : DAILY_LOW_CACHE_TTL_HISTORICAL_MS)
  });
  return low;
}

async function buildActiveTrades(user, rates = {}) {
  const rawTrades = Array.isArray(user?.trades) ? user.trades : [];
  const trades = [];
  let liveOpenPnlGBP = 0;
  let openLossPotentialGBP = 0;
  let providerTrades = 0;
  let manualTrades = 0;
  let providerCurrency = null;
  const ibkrTradeKeys = new Set();
  let loggedManualDebugSample = false;
  for (const trade of rawTrades) {
    if (!trade || typeof trade !== 'object') continue;
    {
      const canonicalTrade = { ...trade, openDate: extractTradeOpenDate(trade) };
      const positionState = deriveTradePositionState(canonicalTrade, rates);
      const includeByCanonicalOpenQty = positionState.isValid && positionState.openQuantity > 0;
      const source = trade.source || (trade.trading212Id ? 'trading212' : (trade.ibkrPositionId ? 'ibkr' : 'manual'));
      const isManualSource = source === 'manual';
      if (ACTIVE_TRADE_DEBUG_LOGS && isManualSource && !loggedManualDebugSample) {
        console.info('[ACTIVE_TRADE_DEBUG] manual_trade_evaluation', {
          tradeId: trade.id || null,
          source,
          rawStoredTrade: trade,
          derivedTotalEntered: positionState.totalEntered,
          derivedTotalExited: positionState.totalExited,
          derivedOpenQuantity: positionState.openQuantity,
          derivedStatus: positionState.status,
          includeInDashboard: includeByCanonicalOpenQty,
          exclusionReason: includeByCanonicalOpenQty
            ? null
            : (!positionState.isValid ? 'invalid_execution_state' : 'open_quantity_not_positive')
        });
        loggedManualDebugSample = true;
      }
      if (isCanonicallyClosedTrade(canonicalTrade)) {
        console.info('[active-trades]', {
          stage: 'exclude_canonically_closed_trade',
          tradeId: trade.id || null,
          status: trade.status || null,
          closedAt: trade.closedAt || null,
          closeDate: trade.closeDate || null
        });
        continue;
      }
      if (!includeByCanonicalOpenQty) continue;
      const base = {
        ...trade,
        date: extractTradeOpenDate(trade),
        executions: positionState.executions,
        entryExecutions: positionState.entries,
        exitExecutions: positionState.exits,
        totalEnteredQuantity: positionState.totalEntered,
        totalExitedQuantity: positionState.totalExited,
        openQuantity: positionState.openQuantity,
        status: positionState.status
      };
      if (Number.isFinite(positionState.avgEntry) && positionState.avgEntry > 0) {
        base.entry = positionState.avgEntry;
      }
      if (Number.isFinite(positionState.openQuantity) && positionState.openQuantity >= 0) {
        base.sizeUnits = positionState.openQuantity;
      }
      trades.push(base);
      if (trade.source === 'ibkr' || trade.ibkrPositionId) {
        const ticker = normalizeIbkrTicker(trade.ibkrTicker || trade.brokerTicker || trade.symbol || '');
        const conid = trade.ibkrConid ? String(trade.ibkrConid) : '';
        const positionId = trade.ibkrPositionId || conid || ticker;
        if (positionId) ibkrTradeKeys.add(positionId);
        if (conid) ibkrTradeKeys.add(`conid:${conid}`);
        if (ticker) ibkrTradeKeys.add(`ticker:${ticker}`);
      }
    }
  }
  const ibkrLivePositions = user?.ibkr?.livePositions;
  if (Array.isArray(ibkrLivePositions) && ibkrLivePositions.length) {
    const timezone = 'Europe/London';
    ibkrLivePositions.forEach(position => {
      const symbolKey = normalizeIbkrTicker(position.symbol);
      const conidKey = position.conid ? String(position.conid) : '';
      const positionId = position.id || conidKey || symbolKey;
      if (
        (positionId && ibkrTradeKeys.has(positionId))
        || (conidKey && ibkrTradeKeys.has(`conid:${conidKey}`))
        || (symbolKey && ibkrTradeKeys.has(`ticker:${symbolKey}`))
      ) {
        return;
      }
      const updatedAt = position.updatedAt ? new Date(position.updatedAt) : new Date();
      const dateKey = dateKeyInTimezone(timezone, updatedAt);
      trades.push({
        id: `ibkr-live-${position.id || position.symbol}`,
        symbol: position.symbol,
        currency: position.currency || 'USD',
        entry: position.avgPrice,
        sizeUnits: Math.abs(Number(position.quantity)),
        direction: Number(position.quantity) < 0 ? 'short' : 'long',
        status: 'open',
        source: 'ibkr',
        ibkrPositionId: position.id || position.symbol,
        ibkrTicker: position.symbol,
        ibkrConid: position.conid || '',
        lastSyncPrice: position.marketPrice,
        ppl: position.unrealizedPnl,
        currentStop: position.derivedStopPrice,
        currentStopSource: position.derivedStopPrice ? 'ibkr' : undefined,
        createdAt: updatedAt.toISOString(),
        date: dateKey
      });
    });
  }
  const dedupedTrades = dedupeActiveTradesByIdentity(trades);
  const enriched = [];
  for (const trade of dedupedTrades) {
    const symbol = typeof trade.symbol === 'string' ? trade.symbol.trim().toUpperCase() : '';
    const quoteSymbol = normalizeTrading212Symbol(symbol);
    const isOption = isOptionsTrade(trade);
    let livePrice = null;
    let liveCurrency = trade.currency || 'GBP';
    let optionQuoteDiagnostics = null;
    let optionPremiumSource = null;
    let optionQuoteProvider = null;
    let optionUnavailableReason = null;
    const tradeCurrency = trade.currency || 'GBP';
    const isTrading212 = trade.source === 'trading212' || trade.trading212Id;
    const isIbkr = trade.source === 'ibkr' || trade.ibkrPositionId;
    const isProvider = isTrading212 || isIbkr;
    try {
      if (isOption) {
        const result = await resolveOptionLiveQuoteForTrade(trade, user);
        optionQuoteDiagnostics = result.diagnostics;
        if (result.quote) {
          livePrice = Number(result.quote.price);
          liveCurrency = result.quote.currency || liveCurrency;
          optionPremiumSource = result.quote.source || null;
          optionQuoteProvider = result.quote.provider || null;
        } else {
          optionUnavailableReason = result?.diagnostics?.unavailableReason || result?.diagnostics?.failureReason || null;
        }
      } else if (isProvider && Number.isFinite(Number(trade.lastSyncPrice))) {
        livePrice = Number(trade.lastSyncPrice);
        liveCurrency = tradeCurrency;
      } else if (quoteSymbol) {
        const quote = await fetchMarketPrice(quoteSymbol);
        livePrice = quote.price;
        liveCurrency = quote.currency || liveCurrency;
      }
    } catch (e) {
      if (isOption) {
        optionQuoteDiagnostics ||= {
          tradeId: trade?.id || '',
          ticker: String(trade?.underlyingTicker || trade?.symbol || '').trim().toUpperCase(),
          optionType: normalizeOptionType(trade?.optionType),
          strike: Number.isFinite(Number(trade?.optionStrike)) ? Number(trade.optionStrike) : null,
          expiry: normalizeOptionExpiration(trade?.optionExpiration),
          multiplier: Number.isFinite(Number(trade?.optionMultiplier)) ? Number(trade.optionMultiplier) : null,
          resolvedContractSymbol: buildOptionContractQuoteSymbol(trade),
          lookupSucceeded: false,
          failureReason: e?.message || 'Unhandled option quote fetch error',
          unavailableReason: e?.message || 'Unhandled option quote fetch error',
          attempts: []
        };
        optionUnavailableReason = optionQuoteDiagnostics.unavailableReason;
        console.warn('[ACTIVE_OPTIONS_QUOTE] unexpected resolver error', optionQuoteDiagnostics);
      }
    }
    const sizeUnits = resolveTradeSizeUnits(trade);
    const entry = Number(trade.entry);
    const direction = trade.direction === 'short' ? 'short' : 'long';
    const originalStopValue = Number(trade.originalStopPrice);
    const stopValue = Number(trade.stop);
    const currentStopValue = Number(trade.currentStop);
    const originalStop = Number.isFinite(originalStopValue) && originalStopValue > 0
      ? originalStopValue
      : (Number.isFinite(stopValue) && stopValue > 0 ? stopValue : undefined);
    const currentStop = Number.isFinite(currentStopValue) && currentStopValue > 0
      ? currentStopValue
      : undefined;
    const displayStop = currentStop ?? originalStop;
    const slippage = Number(trade.slippage) || 0;
    const feesCurrency = Number(trade.fees) || 0;
    const fxFeeRate = Number(trade.fxFeeRate);
    const fxFeeEligible = trade.fxFeeEligible === true;
    const syncPpl = parseTradingNumber(trade.ppl);
    if (isIbkr && Number.isFinite(syncPpl)) {
      const ibkrPnlGBP = isIbkr ? convertToGBP(syncPpl, tradeCurrency, rates) : null;
      const providerPnlGBP = Number.isFinite(ibkrPnlGBP) ? ibkrPnlGBP : syncPpl;
      const guaranteedPnlGBP = computeGuaranteedPnl(trade, rates);
      if (guaranteedPnlGBP !== null) {
        const potentialDropGBP = providerPnlGBP - guaranteedPnlGBP;
        if (potentialDropGBP > 0) openLossPotentialGBP -= potentialDropGBP;
      }
      liveOpenPnlGBP += providerPnlGBP;
      providerTrades += 1;
      const providerCurrencyValue = isIbkr && Number.isFinite(ibkrPnlGBP) ? 'GBP' : tradeCurrency;
      if (providerCurrency === null) {
        providerCurrency = providerCurrencyValue;
      } else if (providerCurrency !== providerCurrencyValue) {
        providerCurrency = null;
      }
      const liveFromProvider = Number.isFinite(Number(trade.lastSyncPrice)) ? Number(trade.lastSyncPrice) : null;
      const riskPct = Number.isFinite(Number(trade.riskPct)) ? Number(trade.riskPct) : 0;
      const entryValueGBP = Number.isFinite(entry) && Number.isFinite(sizeUnits)
        ? convertToGBP(entry * sizeUnits, tradeCurrency, rates)
        : null;
      enriched.push({
        id: trade.id,
        symbol: quoteSymbol || symbol,
        displaySymbol: trade.displaySymbol,
        createdAt: trade.createdAt,
        date: trade.date,
        trading212Isin: trade.trading212Isin,
        trading212Ticker: trade.trading212Ticker,
        trading212Name: trade.trading212Name,
        trading212Id: trade.trading212Id,
        ibkrTicker: trade.ibkrTicker,
        ibkrConid: trade.ibkrConid,
        ibkrPositionId: trade.ibkrPositionId,
        entry,
        stop: Number.isFinite(stopValue) ? stopValue : undefined,
        currency: tradeCurrency,
        sizeUnits,
        totalEnteredQuantity: Number(trade.totalEnteredQuantity) || sizeUnits,
        totalExitedQuantity: Number(trade.totalExitedQuantity) || 0,
        openQuantity: Number(trade.openQuantity) || sizeUnits,
        status: trade.status || 'open',
        riskPct,
        direction: trade.direction || 'long',
        fees: Number(trade.fees) || 0,
        slippage: Number(trade.slippage) || 0,
        fxFeeEligible,
        fxFeeRate: Number.isFinite(fxFeeRate) && fxFeeRate > 0 ? fxFeeRate : undefined,
        livePrice: liveFromProvider !== null ? liveFromProvider : undefined,
        liveCurrency: tradeCurrency,
        unrealizedGBP: providerPnlGBP,
        guaranteedPnlGBP: guaranteedPnlGBP !== null ? guaranteedPnlGBP : undefined,
        positionGBP: entryValueGBP !== null ? entryValueGBP : undefined,
        currentStop,
        displayStop,
        currentStopSource: trade.currentStopSource,
        currentStopLastSyncedAt: trade.currentStopLastSyncedAt,
        currentStopStale: trade.currentStopStale === true,
        originalStopPrice: originalStop,
        source: trade.source || (trade.trading212Id ? 'trading212' : (trade.ibkrPositionId ? 'ibkr' : 'manual')),
        note: trade.note,
        assetClass: trade.assetClass || 'stocks',
        optionType: trade.optionType,
        optionStrike: trade.optionStrike,
        optionExpiration: trade.optionExpiration,
        optionContracts: trade.optionContracts,
        optionMultiplier: trade.optionMultiplier,
        optionPremiumSource: optionPremiumSource || optionQuoteDiagnostics?.selectedPremiumSource || undefined,
        optionQuoteProvider: optionQuoteProvider || optionQuoteDiagnostics?.quoteProvider || undefined,
        optionUnavailableReason: optionUnavailableReason || optionQuoteDiagnostics?.unavailableReason || undefined,
        optionQuoteDiagnostics: optionQuoteDiagnostics || undefined
      });
      continue;
    }
    const positionCurrency = Number.isFinite(livePrice) ? livePrice * sizeUnits : null;
    const positionGBP = Number.isFinite(positionCurrency)
      ? convertToGBP(positionCurrency, liveCurrency, rates)
      : null;
    const entryValueGBP = Number.isFinite(entry) && Number.isFinite(sizeUnits)
      ? convertToGBP(entry * sizeUnits, tradeCurrency, rates)
      : null;
    const effectiveLive = Number.isFinite(livePrice)
      ? (direction === 'short' ? livePrice + slippage : livePrice - slippage)
      : null;
    let pnlCurrency = (Number.isFinite(effectiveLive) && Number.isFinite(entry) && Number.isFinite(sizeUnits))
      ? (direction === 'short'
        ? (entry - effectiveLive) * sizeUnits
        : (effectiveLive - entry) * sizeUnits)
      : null;
    if (isIbkr && Number.isFinite(syncPpl)) {
      pnlCurrency = syncPpl;
    }
    let pnlGBP = null;
    if (isIbkr && Number.isFinite(syncPpl)) {
      pnlGBP = syncPpl;
    } else if (pnlCurrency !== null) {
      pnlGBP = convertToGBP(pnlCurrency, tradeCurrency || liveCurrency || 'GBP', rates);
    }
    let feesGBP = null;
    let fxFeeGBP = null;
    if (!isProvider && Number.isFinite(feesCurrency)) {
      feesGBP = convertToGBP(feesCurrency, tradeCurrency, rates);
    }
    if (!isProvider && fxFeeEligible && Number.isFinite(fxFeeRate) && fxFeeRate > 0 && entryValueGBP !== null) {
      const entryFeeGBP = Math.abs(entryValueGBP) * fxFeeRate;
      const exitBasisGBP = positionGBP !== null ? Math.abs(positionGBP) : Math.abs(entryValueGBP);
      const exitFeeGBP = exitBasisGBP * fxFeeRate;
      fxFeeGBP = entryFeeGBP + exitFeeGBP;
    }
    const unrealizedGBP = (pnlGBP !== null)
      ? (isIbkr && Number.isFinite(syncPpl) ? syncPpl : pnlGBP - (feesGBP ?? 0) - (fxFeeGBP ?? 0))
      : null;
    if (unrealizedGBP !== null) {
      liveOpenPnlGBP += unrealizedGBP;
    }
    const guaranteedPnlGBP = computeGuaranteedPnl(trade, rates);
    if (guaranteedPnlGBP !== null && unrealizedGBP !== null) {
      const potentialDropGBP = unrealizedGBP - guaranteedPnlGBP;
      if (potentialDropGBP > 0) openLossPotentialGBP -= potentialDropGBP;
    }
    manualTrades += 1;
    const perUnitRisk = Number.isFinite(Number(trade.perUnitRisk)) && Number(trade.perUnitRisk) > 0
      ? Number(trade.perUnitRisk)
      : (Number.isFinite(entry) && Number.isFinite(Number(trade.stop)) ? Math.abs(entry - Number(trade.stop)) : null);
    const riskAmountCurrency = Number.isFinite(Number(trade.riskAmountCurrency)) && Number(trade.riskAmountCurrency) > 0
      ? Number(trade.riskAmountCurrency)
      : (Number.isFinite(perUnitRisk) && Number.isFinite(sizeUnits) ? perUnitRisk * sizeUnits : null);
    const portfolioCurrencyAtCalc = Number(trade.portfolioCurrencyAtCalc);
    const derivedRiskPct = Number.isFinite(Number(trade.riskPct)) && Number(trade.riskPct) > 0
      ? Number(trade.riskPct)
      : (Number.isFinite(portfolioCurrencyAtCalc) && portfolioCurrencyAtCalc > 0 && Number.isFinite(riskAmountCurrency)
        ? (riskAmountCurrency / portfolioCurrencyAtCalc) * 100
        : null);
      enriched.push({
        id: trade.id,
        symbol: quoteSymbol || symbol,
        displaySymbol: trade.displaySymbol,
        createdAt: trade.createdAt,
        date: trade.date,
        trading212Isin: trade.trading212Isin,
        trading212Ticker: trade.trading212Ticker,
        trading212Name: trade.trading212Name,
        trading212Id: trade.trading212Id,
        ibkrTicker: trade.ibkrTicker,
        ibkrConid: trade.ibkrConid,
        ibkrPositionId: trade.ibkrPositionId,
        entry,
        stop: Number.isFinite(stopValue) ? stopValue : undefined,
        currency: tradeCurrency,
      sizeUnits,
      totalEnteredQuantity: Number(trade.totalEnteredQuantity) || sizeUnits,
      totalExitedQuantity: Number(trade.totalExitedQuantity) || 0,
      openQuantity: Number(trade.openQuantity) || sizeUnits,
      status: trade.status || 'open',
      riskPct: Number.isFinite(derivedRiskPct) ? derivedRiskPct : 0,
      direction: trade.direction || 'long',
      fees: Number(trade.fees) || 0,
      slippage: Number(trade.slippage) || 0,
      fxFeeEligible,
      fxFeeRate: Number.isFinite(fxFeeRate) && fxFeeRate > 0 ? fxFeeRate : undefined,
      fxFeeImpactGBP: fxFeeGBP !== null ? fxFeeGBP : undefined,
      livePrice: livePrice !== null ? livePrice : undefined,
      liveCurrency,
      unrealizedGBP: unrealizedGBP !== null ? unrealizedGBP : undefined,
      guaranteedPnlGBP: guaranteedPnlGBP !== null ? guaranteedPnlGBP : undefined,
      positionGBP: entryValueGBP !== null ? entryValueGBP : undefined,
      currentStop,
      displayStop,
      currentStopSource: trade.currentStopSource,
      currentStopLastSyncedAt: trade.currentStopLastSyncedAt,
      currentStopStale: trade.currentStopStale === true,
      originalStopPrice: originalStop,
        source: trade.source || (trade.trading212Id ? 'trading212' : (trade.ibkrPositionId ? 'ibkr' : 'manual')),
        note: trade.note,
        assetClass: trade.assetClass || 'stocks',
        optionType: trade.optionType,
        optionStrike: trade.optionStrike,
        optionExpiration: trade.optionExpiration,
        optionContracts: trade.optionContracts,
        optionMultiplier: trade.optionMultiplier,
        optionPremiumSource: optionPremiumSource || optionQuoteDiagnostics?.selectedPremiumSource || undefined,
        optionQuoteProvider: optionQuoteProvider || optionQuoteDiagnostics?.quoteProvider || undefined,
        optionUnavailableReason: optionUnavailableReason || optionQuoteDiagnostics?.unavailableReason || undefined,
        optionQuoteDiagnostics: optionQuoteDiagnostics || undefined
      });
  }
  return {
    trades: enriched,
    liveOpenPnlGBP,
    openLossPotentialGBP,
    liveOpenPnlMode: providerTrades > 0 && manualTrades === 0 ? 'provider' : 'computed',
    liveOpenPnlCurrency: providerTrades > 0 && manualTrades === 0 ? (providerCurrency || 'GBP') : undefined
  };
}

function activeTradeRecencyTimestamp(trade) {
  const candidates = [
    trade?.updatedAt,
    trade?.currentStopLastSyncedAt,
    trade?.createdAt,
    trade?.date
  ];
  for (const candidate of candidates) {
    const parsed = Date.parse(candidate || '');
    if (Number.isFinite(parsed) && parsed > 0) return parsed;
  }
  return 0;
}

function compareDuplicateActiveTrades(existing, incoming) {
  const existingExited = Number(existing?.totalExitedQuantity || 0);
  const incomingExited = Number(incoming?.totalExitedQuantity || 0);
  if (incomingExited !== existingExited) return incomingExited > existingExited ? incoming : existing;

  const existingOpen = Number(existing?.openQuantity ?? existing?.sizeUnits ?? 0);
  const incomingOpen = Number(incoming?.openQuantity ?? incoming?.sizeUnits ?? 0);
  if (incomingOpen !== existingOpen) return incomingOpen < existingOpen ? incoming : existing;

  const existingStamp = activeTradeRecencyTimestamp(existing);
  const incomingStamp = activeTradeRecencyTimestamp(incoming);
  if (incomingStamp !== existingStamp) return incomingStamp > existingStamp ? incoming : existing;

  return existing;
}

function dedupeActiveTradesByIdentity(trades = []) {
  if (!Array.isArray(trades) || !trades.length) return [];
  const deduped = [];
  const byKey = new Map();
  for (const trade of trades) {
    if (!trade || typeof trade !== 'object') continue;
    const key = String(
      trade.id
      || trade.ibkrPositionId
      || trade.trading212PositionKey
      || `${trade.symbol || ''}|${trade.date || ''}|${trade.entry || ''}`
    );
    const existingIndex = byKey.get(key);
    if (existingIndex === undefined) {
      byKey.set(key, deduped.length);
      deduped.push(trade);
      continue;
    }
    deduped[existingIndex] = compareDuplicateActiveTrades(deduped[existingIndex], trade);
  }
  return deduped;
}

function computeActiveTradesFingerprint(user) {
  const rawTrades = Array.isArray(user?.trades) ? user.trades : [];
  let bucketCount = 0;
  let tradeCount = 0;
  let openCount = 0;
  const tradeVectors = [];
  const dateBuckets = new Set();
  for (const trade of rawTrades) {
    if (!trade || typeof trade !== 'object') continue;
    const dateKey = extractTradeOpenDate(trade);
    if (dateKey && !dateBuckets.has(dateKey)) { dateBuckets.add(dateKey); bucketCount += 1; }
    tradeCount += 1;
    const status = String(trade.status || '');
    if (status !== 'closed') openCount += 1;
    tradeVectors.push([
      dateKey,
      String(trade.id || ''),
      status,
      String(trade.updatedAt || trade.createdAt || ''),
      String(trade.currentStop || ''),
      String(trade.currentStopLastSyncedAt || ''),
      String(trade.lastSyncPrice || ''),
      String(trade.ppl || ''),
      String(trade.sizeUnits || ''),
      String(trade.openQuantity || '')
    ].join('|'));
  }
  const ibkrLiveCount = Array.isArray(user?.ibkr?.livePositions) ? user.ibkr.livePositions.length : 0;
  const tradingSyncHint = String(user?.trading212?.lastSuccessfulSyncAt || user?.trading212?.lastSyncAt || '');
  const ibkrSyncHint = String(user?.ibkr?.lastSnapshotAt || user?.ibkr?.lastHeartbeatAt || '');
  tradeVectors.sort();
  const digest = crypto
    .createHash('sha1')
    .update(JSON.stringify({
      bucketCount,
      tradeCount,
      openCount,
      ibkrLiveCount,
      tradingSyncHint,
      ibkrSyncHint,
      tradeVectors
    }))
    .digest('hex');
  return `${bucketCount}:${tradeCount}:${openCount}:${ibkrLiveCount}:${digest}`;
}

function pickDefinedFields(source = {}, keys = []) {
  const out = {};
  keys.forEach((key) => {
    if (source[key] !== undefined) out[key] = source[key];
  });
  return out;
}

const ACTIVE_TRADES_SUMMARY_FIELDS = [
  'id',
  'symbol',
  'displaySymbol',
  'displayTicker',
  'brokerTicker',
  'mappingScope',
  'mappingId',
  'sourceKey',
  'createdAt',
  'date',
  'entry',
  'stop',
  'currency',
  'sizeUnits',
  'totalEnteredQuantity',
  'totalExitedQuantity',
  'openQuantity',
  'status',
  'riskPct',
  'direction',
  'livePrice',
  'liveCurrency',
  'unrealizedGBP',
  'guaranteedPnlGBP',
  'positionGBP',
  'currentStop',
  'displayStop',
  'originalStopPrice',
  'currentStopSource',
  'currentStopLastSyncedAt',
  'currentStopStale',
  'source',
  'note',
  'assetClass',
  'optionType',
  'optionStrike',
  'optionExpiration',
  'optionContracts',
  'optionMultiplier',
  'optionPremiumSource',
  'optionQuoteProvider',
  'optionUnavailableReason',
  'trading212Isin',
  'trading212Ticker',
  'trading212Name',
  'trading212Id',
  'ibkrTicker',
  'ibkrPositionId'
];

const ACTIVE_TRADES_DETAIL_ONLY_FIELDS = [
  'optionQuoteDiagnostics',
  'fees',
  'slippage',
  'fxFeeEligible',
  'fxFeeRate',
  'fxFeeImpactGBP',
  'ibkrConid'
];

function serializeActiveTradeSummary(trade = {}) {
  return pickDefinedFields(trade, ACTIVE_TRADES_SUMMARY_FIELDS);
}

function parseActiveTradesSerializerMode(query = {}) {
  const detailRaw = String(query?.detail ?? query?.view ?? '').trim().toLowerCase();
  if (['1', 'true', 'yes', 'detail', 'full'].includes(detailRaw)) return 'detail';
  return 'summary';
}

function buildActiveTradesSnapshotPayload(snapshot, {
  mode = 'summary'
} = {}) {
  const responseMode = mode === 'detail' ? 'detail' : 'summary';
  const detailTrades = Array.isArray(snapshot.trades) ? snapshot.trades : [];
  const summaryTrades = Array.isArray(snapshot.tradesSummary)
    ? snapshot.tradesSummary
    : detailTrades.map(serializeActiveTradeSummary);
  const responseTrades = responseMode === 'detail' ? detailTrades : summaryTrades;
  const summaryBytes = Buffer.byteLength(JSON.stringify(summaryTrades));
  const detailBytes = Buffer.byteLength(JSON.stringify(detailTrades));
  const responseBytes = responseMode === 'detail' ? detailBytes : summaryBytes;
  const bytesReduced = Math.max(0, detailBytes - summaryBytes);
  const serializationTrimmed = bytesReduced > 0;
  responseTrades.forEach((trade) => {
    if (!trade || typeof trade !== 'object') return;
    const currentStop = Number(trade.currentStop);
    const originalStop = Number(trade.originalStopPrice ?? trade.stop);
    const displayStop = Number(trade.displayStop);
    console.info('[TRADES][ACTIVE_API_SHAPING]', {
      tradeId: trade.id || '',
      originalStop: Number.isFinite(originalStop) ? originalStop : null,
      currentStop: Number.isFinite(currentStop) ? currentStop : null,
      displayStop: Number.isFinite(displayStop) ? displayStop : (Number.isFinite(currentStop) ? currentStop : (Number.isFinite(originalStop) ? originalStop : null))
    });
  });
  return {
    trades: responseTrades,
    liveOpenPnl: snapshot.liveOpenPnl,
    openLossPotential: snapshot.openLossPotential,
    liveOpenPnlMode: snapshot.liveOpenPnlMode,
    liveOpenPnlCurrency: snapshot.liveOpenPnlCurrency,
    serialization: {
      mode: responseMode,
      activeTradesSummarySerializerUsed: responseMode === 'summary',
      serializationTrimmed,
      responseBytes,
      detailResponseBytes: detailBytes,
      responseBytesReduced: responseMode === 'summary' ? bytesReduced : 0,
      detailFieldsDeferred: responseMode === 'summary' ? ACTIVE_TRADES_DETAIL_ONLY_FIELDS : []
    },
    freshness: {
      generatedAt: snapshot.generatedAt,
      snapshotAgeMs: Math.max(0, Date.now() - snapshot.generatedAtMs),
      refreshInProgress: Boolean(activeTradesRefreshLocks.get(snapshot.username)),
      cacheHit: snapshot.cacheHit === true,
      snapshotUsed: true
    }
  };
}

async function computeActiveTradesSnapshot(username) {
  const db = loadDB();
  const user = db.users[username];
  if (!user) return null;
  ensureUserShape(user, username);
  const fingerprint = computeActiveTradesFingerprint(user);
  const rates = await fetchRates();
  const tradingCfg = user.trading212;
  const tradingAccounts = getTrading212Accounts(tradingCfg);
  if (tradingCfg?.enabled && tradingAccounts.length) {
    try {
      let totalUpdates = 0;
      for (const account of tradingAccounts) {
        const accountId = account.id || '';
        const accountConfig = {
          ...tradingCfg,
          apiKey: account.apiKey,
          apiSecret: account.apiSecret,
          mode: account.mode || tradingCfg.mode,
          baseUrl: account.baseUrl || tradingCfg.baseUrl
        };
        const ordersPayload = await fetchTrading212Orders(accountConfig, username, { accountId });
        const { updated: stopUpdates } = upsertTrading212StopOrders(user, ordersPayload, accountId, rates);
        totalUpdates += stopUpdates;
      }
      if (totalUpdates > 0) {
        saveDB(db);
        console.info(`[T212] refreshed ${totalUpdates} trade stop(s) during active trades snapshot refresh`);
      }
    } catch (e) {
      console.warn('Trading 212 stop refresh failed during active trades snapshot refresh', e);
    }
  }
  const ibkrCfg = user.ibkr;
  if (ibkrCfg?.enabled && ibkrCfg?.mode === 'connector') {
    const snapshot = getLatestBrokerSnapshot(db, username, 'IBKR');
    if (snapshot) {
      const derived = snapshot.derivedStopByTicker || computeIbkrDerivedStops(snapshot.positions || [], snapshot.orders || []);
      const { updated: stopUpdates } = applyIbkrDerivedStopsToLivePositions(user, derived);
      if (stopUpdates > 0) {
        saveDB(db);
        console.info(`[IBKR] refreshed ${stopUpdates} live position stop(s) during active trades snapshot refresh`);
      }
    }
  }
  const { trades, liveOpenPnlGBP, openLossPotentialGBP, liveOpenPnlMode, liveOpenPnlCurrency } = await buildActiveTrades(user, rates);
  const mappedTrades = trades.map(trade => applyInstrumentMappingToTrade(trade, db, username));
  const summarizedTrades = mappedTrades.map(serializeActiveTradeSummary);
  return {
    username,
    fingerprint,
    generatedAtMs: Date.now(),
    generatedAt: new Date().toISOString(),
    trades: mappedTrades,
    tradesSummary: summarizedTrades,
    liveOpenPnl: liveOpenPnlGBP,
    openLossPotential: openLossPotentialGBP,
    liveOpenPnlMode,
    liveOpenPnlCurrency
  };
}

function scheduleActiveTradesRefresh(username) {
  const existing = activeTradesRefreshLocks.get(username);
  if (existing) return existing;
  const refreshPromise = computeActiveTradesSnapshot(username)
    .then((snapshot) => {
      if (snapshot) {
        activeTradesSnapshotCache.set(username, snapshot);
      }
      return snapshot;
    })
    .catch((error) => {
      console.warn('[active-trades] snapshot refresh failed', { username, message: error?.message || error });
      return null;
    })
    .finally(() => {
      activeTradesRefreshLocks.delete(username);
    });
  activeTradesRefreshLocks.set(username, refreshPromise);
  return refreshPromise;
}

function shapeTradeSummary(trade = {}) {
  const summary = { ...trade };
  delete summary.executions;
  delete summary.partialCloses;
  delete summary.importRawRows;
  delete summary.tradeNotesTimeline;
  delete summary.providerDebug;
  return summary;
}

app.get('/api/trades', auth, async (req, res) => {
  const db = req.perfDiag?.timeSync('db_load', () => loadDB()) || loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  req.perfDiag?.timeSync('user_shape', () => ensureUserShape(user, req.username));
  req.perfDiag?.timeSync('trade_journal_normalize', () => normalizeTradeJournal(user));
  req.perfDiag?.setMeta({ externalProviderAttempted: true });
  const rates = await (req.perfDiag?.timeAsync('external_rates_fetch', async () => fetchRates()) || fetchRates());
  const mapper = createTradeInstrumentMapper(db, req.username);
  const prefilter = {
    from: typeof req.query?.from === 'string' ? req.query.from : null,
    to: typeof req.query?.to === 'string' ? req.query.to : null
  };
  const trades = req.perfDiag?.timeSync('flatten_map_trades', () => flattenTrades(user, rates, prefilter).map(trade => mapper(trade)))
    || flattenTrades(user, rates, prefilter).map(trade => mapper(trade));
  const filtered = req.perfDiag?.timeSync('trades_filter_sort', () => filterTrades(trades, req.query || {})
    .sort((a, b) => {
      const aDate = a.openDate || '';
      const bDate = b.openDate || '';
      return bDate.localeCompare(aDate);
    }))
    || filterTrades(trades, req.query || {})
      .sort((a, b) => {
        const aDate = a.openDate || '';
        const bDate = b.openDate || '';
        return bDate.localeCompare(aDate);
      });
  const summaryModeRaw = String(req.query?.summaryMode ?? '1').toLowerCase();
  const summaryMode = !['0', 'false', 'off', 'no'].includes(summaryModeRaw);
  const limitInput = Number(req.query?.limit);
  const offsetInput = Number(req.query?.offset);
  const limit = Number.isFinite(limitInput) ? Math.max(1, Math.min(200, Math.floor(limitInput))) : 100;
  const offset = Number.isFinite(offsetInput) ? Math.max(0, Math.floor(offsetInput)) : 0;
  const total = filtered.length;
  const pageStart = Math.min(offset, total);
  const pageEnd = Math.min(pageStart + limit, total);
  const pageItems = filtered.slice(pageStart, pageEnd);
  const responseTrades = summaryMode ? pageItems.map(shapeTradeSummary) : pageItems;
  const payloadSizeBytes = Buffer.byteLength(JSON.stringify(responseTrades));
  const untrimmedSizeBytes = summaryMode ? Buffer.byteLength(JSON.stringify(pageItems)) : payloadSizeBytes;
  const serializationTrimmed = summaryMode && untrimmedSizeBytes > payloadSizeBytes;
  req.perfDiag?.setMeta({
    resultCount: responseTrades.length,
    cache: 'bypass',
    requestScopedReuse: true,
    summaryModeUsed: summaryMode,
    paginatedResponse: true,
    totalTrades: total,
    initialWindowSize: limit,
    returnedWindowSize: responseTrades.length,
    hasMore: pageEnd < total,
    responsePayloadBytes: payloadSizeBytes,
    summarySerializerUsed: summaryMode,
    serializationTrimmed,
    responseBytesReduced: summaryMode ? Math.max(0, untrimmedSizeBytes - payloadSizeBytes) : 0
  });
  res.json({
    trades: responseTrades,
    total,
    limit,
    offset: pageStart,
    nextOffset: pageEnd < total ? pageEnd : null,
    hasMore: pageEnd < total,
    summaryMode,
    paginated: true
  });
});

app.get('/api/weekly-recap/latest', auth, (req, res) => {
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  const latest = getLatestWeeklyRecap(user);
  if (!latest) {
    return res.json({ recap: null, empty: true });
  }
  res.json({ recap: latest, empty: false });
});

app.get('/api/weekly-recap/week/:weekKey', auth, (req, res) => {
  const weekKey = String(req.params.weekKey || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(weekKey)) {
    return res.status(400).json({ error: 'Invalid week key format. Use YYYY-MM-DD.' });
  }
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  const recap = (user.weeklyRecaps || []).find(item => item && item.weekKey === weekKey) || null;
  if (!recap) {
    return res.status(404).json({ error: 'Weekly recap not found for this week.' });
  }
  res.json({ recap });
});

app.get('/api/weekly-recap/:id', auth, (req, res) => {
  const recapId = String(req.params.id || '').trim();
  if (!recapId) return res.status(400).json({ error: 'Recap id is required.' });
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  const recap = (user.weeklyRecaps || []).find(item => item && item.id === recapId) || null;
  if (!recap) return res.status(404).json({ error: 'Weekly recap not found.' });
  res.json({ recap });
});

app.post('/api/weekly-recap/generate-latest', auth, async (req, res) => {
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  const weekRange = getLastCompletedWeekRange();
  const rates = await fetchRates();
  const generated = calculateWeeklyRecap(user, weekRange, rates);
  const existingRecap = (user.weeklyRecaps || []).find(item => item && item.weekKey === weekRange.weekKey) || null;
  const lifecycleState = normalizeWeeklyRecapLifecycleTimestamps(existingRecap || {});
  const generatedAt = generated.generatedAt || new Date().toISOString();
  const recap = {
    id: existingRecap?.id || crypto.randomUUID(),
    userId: req.username,
    weekKey: weekRange.weekKey,
    weekStart: weekRange.weekStart,
    weekEnd: weekRange.weekEnd,
    weekLabel: generated.metrics.weekLabel,
    generatedAt: existingRecap?.generatedAt || generatedAt,
    notes: generated.notes,
    metrics: generated.metrics,
    readyAt: lifecycleState.readyAt || generatedAt,
    pushSentAt: lifecycleState.pushSentAt,
    viewedAt: lifecycleState.viewedAt,
    dismissedAt: lifecycleState.dismissedAt
  };
  upsertWeeklyRecap(user, recap);
  let pushTriggered = false;
  if (!recap.pushSentAt) {
    try {
      await sendNotificationEvent(db, {
        userId: req.username,
        eventType: 'weekly_recap_ready',
        context: {
          title: 'Your weekly recap is ready',
          body: 'Review last week’s performance, wins, losses, and key takeaways.',
          link: '/review?openWeeklyRecap=latest&source=push',
          eventId: `weekly_recap_ready:${recap.id}`
        }
      });
      recap.pushSentAt = new Date().toISOString();
      upsertWeeklyRecap(user, recap);
      pushTriggered = true;
    } catch (error) {
      console.warn('[weekly-recap] Push send failed (non-blocking):', error?.message || error);
    }
  }
  saveDB(db);
  res.json({ ok: true, recap, pushTriggered });
});

