app.delete('/api/trades/import/ibkr/:batchId', auth, (req, res) => {
  const batchId = String(req.params.batchId || '').trim();
  if (!batchId) return res.status(400).json({ error: 'Missing batch id.' });
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  normalizeTradeJournal(user);
  const batches = ensureImportBatches(user);
  const batch = batches.find(item => item.id === batchId && String(item.broker || '').toUpperCase() === 'IBKR');
  if (!batch) return res.status(404).json({ error: 'Import batch not found.' });
  if (batch.status === 'rolled_back') {
    return res.status(409).json({ error: 'Import batch already removed.' });
  }
  const journal = ensureTradeJournal(user);
  let removedCount = 0;
  let removedExecutionCount = 0;
  for (const [dateKey, trades] of Object.entries(journal)) {
    if (!Array.isArray(trades) || !trades.length) continue;
    const remaining = trades.filter((trade) => {
      if (Array.isArray(trade?.executions) && trade.executions.length) {
        const keptLegs = trade.executions.filter((leg) => {
          const matchesLegBatch = String(leg?.importBatchId || '') === batchId
            && String(leg?.importSource || '').toUpperCase() === 'IBKR_CSV';
          if (matchesLegBatch) {
            removedExecutionCount += 1;
            return false;
          }
          return true;
        });
        trade.executions = keptLegs;
        if (keptLegs.length) {
          const summary = summarizeExecutionLegs(trade, {});
          trade.executions = summary.executions;
          trade.status = summary.status;
          trade.sizeUnits = summary.openQuantity;
          trade.closePrice = summary.avgExit || undefined;
          trade.closeDate = summary.lastExitDate || undefined;
          trade.realizedPnlGBP = summary.realizedPnlGBP;
          trade.realizedPnlCurrency = summary.realizedPnlCurrency;
        }
      }
      const matchesBatch = String(trade?.importBatchId || '') === batchId
        && String(trade?.importSource || '').toUpperCase() === 'IBKR_CSV';
      if (matchesBatch) {
        removedCount += 1;
        return false;
      }
      if (Array.isArray(trade?.executions) && !trade.executions.length) {
        return false;
      }
      return true;
    });
    if (remaining.length) journal[dateKey] = remaining;
    else delete journal[dateKey];
  }
  batch.status = 'rolled_back';
  batch.removedAt = new Date().toISOString();
  batch.removedCount = removedCount + removedExecutionCount;
  saveDB(db);
  res.json({ ok: true, removedCount: removedCount + removedExecutionCount, batchId });
});

app.post('/api/trades', auth, async (req, res) => {
  const {
    date,
    entry,
    stop,
    currentStop,
    riskPct,
    riskAmount,
    sizeUnits: sizeUnitsInput,
    currency,
    baseCurrency,
    note,
    symbol,
    displaySymbol,
    direction,
    rounding,
    tradeType,
    assetClass,
    optionType,
    optionStrike,
    optionExpiration,
    optionContracts,
    strategyTag,
    marketCondition,
    setupTags,
    emotionTags,
    screenshotUrl,
    status,
    closePrice,
    closeDate,
    executions: executionInput
  } = req.body || {};
  const supportedCurrencies = ['GBP', 'USD', 'EUR'];
  const tradeCurrency = supportedCurrencies.includes(currency) ? currency : 'GBP';
  const tradeBaseCurrency = supportedCurrencies.includes(baseCurrency) ? baseCurrency : 'GBP';
  const entryNum = Number(entry);
  const stopNum = Number(stop);
  const currentStopNum = Number(currentStop);
  const pctNum = Number(riskPct);
  const riskAmountNum = Number(riskAmount);
  const sizeUnitsNum = Number(sizeUnitsInput);
  const symbolInput = typeof displaySymbol === 'string' ? displaySymbol : symbol;
  const symbolClean = typeof symbolInput === 'string' ? symbolInput.trim().toUpperCase() : '';
  const directionClean = DIRECTIONS.includes((direction || '').toLowerCase()) ? direction.toLowerCase() : 'long';
  const normalizedExecutionInput = normalizeExecutionLegs({ executions: executionInput }, date);
  const executionSummaryInput = summarizeExecutionLegs({ executions: normalizedExecutionInput, currency: tradeCurrency, direction: directionClean }, {});
  const hasExecutionInput = normalizedExecutionInput.length > 0;
  const entryForValidation = hasExecutionInput ? executionSummaryInput.avgEntry : entryNum;
  if (!Number.isFinite(entryForValidation) || entryForValidation <= 0) {
    return res.status(400).json({ error: 'Enter a valid entry price' });
  }
  const hasStop = Number.isFinite(stopNum) && stopNum > 0;
  if (hasStop && directionClean === 'long' && stopNum >= entryForValidation) {
    return res.status(400).json({ error: 'For long trades, stop-loss must be below entry.' });
  }
  if (hasStop && directionClean === 'short' && stopNum <= entryForValidation) {
    return res.status(400).json({ error: 'For short trades, stop-loss must be above entry.' });
  }
  const perUnitRisk = hasStop
    ? (directionClean === 'long' ? (entryForValidation - stopNum) : (stopNum - entryForValidation))
    : null;
  if (hasStop && perUnitRisk === 0) {
    return res.status(400).json({ error: 'Entry and stop-loss cannot match' });
  }
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  if (!user.profileComplete) {
    return res.status(409).json({ error: 'Profile incomplete', code: 'profile_incomplete' });
  }
  const rates = await fetchRates();
  if (tradeCurrency !== 'GBP' && !rates?.[tradeCurrency]) {
    return res.status(400).json({ error: `Missing FX rate for ${tradeCurrency}` });
  }
  if (!Array.isArray(user.trades)) user.trades = [];
  const history = ensurePortfolioHistory(user);
  normalizePortfolioHistory(user);
  const portfolioGBP = getPortfolioGBPForRisk(user);
  const portfolioInCurrency = convertGBPToCurrency(portfolioGBP, tradeCurrency, rates);
  if (!Number.isFinite(portfolioInCurrency) || portfolioInCurrency <= 0) {
    return res.status(400).json({ error: 'Add your portfolio value first' });
  }
  let unitsToUse = hasExecutionInput ? executionSummaryInput.totalEntered : (Number.isFinite(sizeUnitsNum) && sizeUnitsNum > 0 ? sizeUnitsNum : null);
  if (!unitsToUse && String(assetClass || '').toLowerCase() === 'options') {
    const contractsNum = Number(optionContracts);
    if (Number.isFinite(contractsNum) && contractsNum > 0) {
      unitsToUse = contractsNum * 100;
    }
  }
  if (!Number.isFinite(unitsToUse) || unitsToUse <= 0) {
    if (!hasStop || !Number.isFinite(perUnitRisk) || perUnitRisk <= 0) {
      return res.status(400).json({ error: 'Enter a valid position size (units or contracts).' });
    }
  }
  let pctToUse = Number.isFinite(pctNum) && pctNum > 0 ? pctNum : null;
  let riskAmountCurrency = Number.isFinite(riskAmountNum) && riskAmountNum > 0
    ? riskAmountNum
    : null;
  if (!unitsToUse && hasStop && Number.isFinite(perUnitRisk) && perUnitRisk > 0) {
    if (!riskAmountCurrency && pctToUse && Number.isFinite(portfolioInCurrency) && portfolioInCurrency > 0) {
      riskAmountCurrency = portfolioInCurrency * (pctToUse / 100);
    }
    if (Number.isFinite(riskAmountCurrency) && riskAmountCurrency > 0) {
      unitsToUse = riskAmountCurrency / perUnitRisk;
    }
  }
  if (!Number.isFinite(unitsToUse) || unitsToUse <= 0) {
    return res.status(400).json({ error: 'Enter a valid position size (units or contracts).' });
  }
  const sizeUnits = unitsToUse;
  if (hasStop && Number.isFinite(perUnitRisk) && perUnitRisk > 0) {
    riskAmountCurrency = perUnitRisk * sizeUnits;
    pctToUse = portfolioInCurrency > 0 ? (riskAmountCurrency / portfolioInCurrency) * 100 : null;
  }
  const positionCurrency = sizeUnits * entryForValidation;
  const riskAmountGBP = Number.isFinite(riskAmountCurrency)
    ? convertToGBP(riskAmountCurrency, tradeCurrency, rates)
    : 0;
  const positionGBP = convertToGBP(positionCurrency, tradeCurrency, rates);
  const feesNum = Number(req.body?.fees);
  const slippageNum = Number(req.body?.slippage);
  const fees = Number.isFinite(feesNum) && feesNum >= 0 ? feesNum : 0;
  const slippage = Number.isFinite(slippageNum) && slippageNum >= 0 ? slippageNum : 0;
  const targetDate = (typeof date === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(date))
    ? date
    : currentDateKey();
  const fxFeeRate = Number(process.env.FX_FEE_RATE ?? 0.005);
  const fxFeeEligible = tradeCurrency !== tradeBaseCurrency;
  const trade = normalizeTradeMeta({
    id: crypto.randomBytes(8).toString('hex'),
    entry: entryForValidation,
    stop: hasStop ? stopNum : undefined,
    originalStopPrice: hasStop ? stopNum : undefined,
    currentStop: Number.isFinite(currentStopNum) && currentStopNum > 0 ? currentStopNum : undefined,
    symbol: symbolClean || undefined,
    currency: tradeCurrency,
    riskPct: pctToUse || pctNum || 0,
    perUnitRisk: Number.isFinite(perUnitRisk) ? perUnitRisk : 0,
    sizeUnits,
    riskAmountCurrency: Number.isFinite(riskAmountCurrency) ? riskAmountCurrency : 0,
    positionCurrency,
    riskAmountGBP,
    positionGBP,
    portfolioGBPAtCalc: portfolioGBP,
    portfolioCurrencyAtCalc: portfolioInCurrency,
    createdAt: new Date().toISOString(),
    direction: directionClean,
    fees,
    slippage,
    rounding,
    status: status === 'closed' ? 'closed' : 'open',
    tradeType,
    assetClass,
    optionType,
    optionStrike,
    optionExpiration,
    optionContracts,
    strategyTag,
    marketCondition,
    setupTags,
      emotionTags,
      screenshotUrl,
      note,
      fxFeeEligible,
      fxFeeRate: Number.isFinite(fxFeeRate) && fxFeeRate > 0 ? fxFeeRate : undefined,
      source: 'manual',
    executions: hasExecutionInput ? normalizedExecutionInput : undefined
    });
  trade.entryDate = targetDate;
  user.trades.push(trade);
  if (hasExecutionInput) {
    const executionSummary = summarizeExecutionLegs(trade, rates);
    if (!executionSummary.isValid) {
      return res.status(400).json({ error: 'Exit quantity total cannot exceed entered quantity total' });
    }
    trade.status = executionSummary.status;
    trade.entry = executionSummary.avgEntry;
    trade.sizeUnits = executionSummary.openQuantity;
    trade.closePrice = executionSummary.avgExit;
    trade.closeDate = executionSummary.lastExitDate || undefined;
    trade.realizedPnlGBP = executionSummary.realizedPnlGBP;
    trade.realizedPnlCurrency = executionSummary.realizedPnlCurrency;
  } else if (trade.status === 'closed' || Number.isFinite(Number(closePrice))) {
    const closeNum = Number(closePrice);
    if (!Number.isFinite(closeNum) || closeNum <= 0) {
      return res.status(400).json({ error: 'Enter a valid closing price to log a closed trade' });
    }
    applyTradeClose(user, trade, closeNum, closeDate, rates, targetDate);
  }
  createTradeGroupAlertsForNewTrade(db, req.username, trade);
  const isClosedOnCreate = trade.status === 'closed';
  sendNotificationEvent(db, {
    userId: req.username,
    eventType: isClosedOnCreate ? 'trade_closed' : 'trade_opened',
    context: { symbol: trade.symbol || trade.displaySymbol, tradeId: trade.id }
  }).catch((error) => console.warn('[Notifications] trade create event failed:', error?.message || error));
  saveDB(db);
  res.json({
    ok: true,
    trade: applyInstrumentMappingToTrade({ ...trade, openDate: targetDate }, db, req.username),
    date: targetDate
  });
});

app.put('/api/trades/:id', auth, async (req, res) => {
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  normalizeTradeJournal(user);
  const found = findTradeById(user, req.params.id);
  if (!found) return res.status(404).json({ error: 'Trade not found' });
  const trade = found.trade;
  const updates = req.body || {};
  const hasExecutionUpdate = Array.isArray(updates.executions);
  const { config: tradingCfg } = ensureTrading212Config(user);
  const rates = await fetchRates();
  const tradeCurrency = trade.currency || 'GBP';
  if (tradeCurrency !== 'GBP' && !rates?.[tradeCurrency]) {
    return res.status(400).json({ error: `Missing FX rate for ${tradeCurrency}` });
  }
  const requestedUnitsNum = updates.sizeUnits !== undefined ? Number(updates.sizeUnits) : null;
  const isTrimRequest = (!hasExecutionUpdate &&
    trade.status !== 'closed'
    && Number.isFinite(requestedUnitsNum)
    && requestedUnitsNum >= 0
    && requestedUnitsNum < Number(trade.sizeUnits)
  );
  if (isTrimRequest) {
    const previousQty = Number(trade.sizeUnits);
    const trimUnits = Number(trade.sizeUnits) - requestedUnitsNum;
    const trimPrice = Number(updates.trimPrice);
    if (!Number.isFinite(trimPrice) || trimPrice <= 0) {
      return res.status(400).json({ error: 'Enter a valid trim fill price' });
    }
    const trimDate = typeof updates.trimDate === 'string' ? updates.trimDate : undefined;
    let trimResult;
    try {
      trimResult = addTradeTrim(user, trade, trimUnits, trimPrice, trimDate, rates, found.dateKey, updates.trimNote);
    } catch (error) {
      return res.status(400).json({ error: error?.message || 'Failed to apply trim' });
    }
  if (userLeadsTradeGroups(db, req.username)) {
    if (trade.status === 'closed' || Number(trade.sizeUnits) <= 1e-8) {
      emitTradeGroupSellAlertForClosedTrade(db, req.username, trade, {
        reason: 'manual_trim_full_close',
        classification: 'full_close'
      });
    } else {
      emitTradeGroupTrimAlertForTrade(db, req.username, trade, {
        previousQty,
        newQty: Number(trade.sizeUnits),
        fillPrice: trimPrice,
        trimDate: trimDate || trimResult.closeDateKey,
        reason: 'manual_trim',
        eventKey: `manual-trim:${trade.id}:${trimDate || trimResult.closeDateKey}:${trimUnits}:${trimPrice}`
      });
    }
  }
    saveDB(db);
    return res.json({
      ok: true,
      trade: applyInstrumentMappingToTrade({ ...trade, openDate: found.dateKey }, db, req.username),
      trim: trimResult
    });
  }
  const wantsRiskUpdate = (
    updates.entry !== undefined ||
    updates.stop !== undefined ||
    updates.riskPct !== undefined ||
    updates.riskAmount !== undefined ||
    updates.sizeUnits !== undefined
  );
  const incomingSymbol = typeof updates.displaySymbol === 'string'
    ? updates.displaySymbol
    : (typeof updates.symbol === 'string' ? updates.symbol : null);
  if (incomingSymbol !== null) {
    const trimmed = incomingSymbol.trim().toUpperCase();
    const isTrading212 = trade.source === 'trading212' || trade.trading212Id;
    if (isTrading212) {
      if (trimmed) {
        trade.displaySymbol = trimmed;
      } else {
        delete trade.displaySymbol;
      }
    } else {
      if (!trimmed) {
        return res.status(400).json({ error: 'Enter a valid ticker symbol.' });
      }
      trade.symbol = trimmed;
      delete trade.displaySymbol;
    }
  }
  if (updates.displayName !== undefined || updates.manualDisplayName !== undefined) {
    const incomingDisplayName = updates.displayName ?? updates.manualDisplayName;
    const manualDisplayName = typeof incomingDisplayName === 'string' ? incomingDisplayName.trim() : '';
    if (manualDisplayName) trade.displayName = manualDisplayName;
    else delete trade.displayName;
    console.info('[display-name]', {
      stage: 'save_trade_display_name',
      tradeId: trade.id || null,
      incomingPayload: {
        displayName: updates.displayName ?? null,
        manualDisplayName: updates.manualDisplayName ?? null
      },
      persistedOverride: trade.displayName || null
    });
  }
  if (updates.currentStop !== undefined) {
    const stopVal = Number(updates.currentStop);
    if (updates.currentStop === '' || updates.currentStop === null) {
      delete trade.currentStop;
    } else if (!Number.isFinite(stopVal) || stopVal <= 0) {
      return res.status(400).json({ error: 'Enter a valid current stop price' });
    } else {
      trade.currentStop = stopVal;
    }
  }
  const incomingStopSource = typeof updates.currentStopSource === 'string'
    ? updates.currentStopSource.trim().toLowerCase()
    : '';
  if (incomingStopSource === 'manual') {
    trade.currentStopSource = 'manual';
    trade.currentStopStale = false;
  }
  if ((trade.source === 'trading212' || trade.trading212Id) && (updates.stop !== undefined || updates.currentStop !== undefined || incomingStopSource === 'manual')) {
    trade.stopManualOverride = true;
  }
  if (hasExecutionUpdate) {
    const normalizedExecutions = normalizeExecutionLegs({ executions: updates.executions }, found.dateKey);
    const summary = summarizeExecutionLegs({ ...trade, executions: normalizedExecutions }, rates);
    if (!summary.isValid) {
      return res.status(400).json({ error: 'Exit quantity total cannot exceed entered quantity total' });
    }
    trade.executions = normalizedExecutions;
    trade.status = summary.status;
    trade.entry = summary.avgEntry;
    trade.sizeUnits = summary.openQuantity;
    trade.closePrice = summary.avgExit || undefined;
    trade.closeDate = summary.lastExitDate || undefined;
    trade.realizedPnlGBP = summary.realizedPnlGBP;
    trade.realizedPnlCurrency = summary.realizedPnlCurrency;
    trade.partialCloses = [];
  }
  if (wantsRiskUpdate) {
    const entryNum = Number(updates.entry ?? trade.entry);
    const incomingStop = updates.stop;
    const clearsStop = incomingStop === '' || incomingStop === null;
    const stopCandidate = clearsStop ? undefined : (incomingStop ?? trade.stop);
    const stopNum = Number(stopCandidate);
    const hasStop = Number.isFinite(stopNum) && stopNum > 0;
    const pctNum = Number(updates.riskPct ?? trade.riskPct);
    const riskAmountNum = Number(updates.riskAmount);
    const sizeUnitsNum = Number(updates.sizeUnits ?? trade.sizeUnits);
    const optionContractsNum = Number(updates.optionContracts ?? trade.optionContracts);
    const dir = DIRECTIONS.includes((updates.direction || trade.direction || '').toLowerCase())
      ? (updates.direction || trade.direction).toLowerCase()
      : 'long';
    if (!Number.isFinite(entryNum) || entryNum <= 0) {
      return res.status(400).json({ error: 'Enter a valid entry price' });
    }
    if (hasStop && dir === 'long' && stopNum >= entryNum) {
      return res.status(400).json({ error: 'For long trades, stop-loss must be below entry.' });
    }
    if (hasStop && dir === 'short' && stopNum <= entryNum) {
      return res.status(400).json({ error: 'For short trades, stop-loss must be above entry.' });
    }
    const perUnitRisk = hasStop ? (dir === 'long' ? (entryNum - stopNum) : (stopNum - entryNum)) : null;
    if (hasStop && perUnitRisk === 0) {
      return res.status(400).json({ error: 'Entry and stop-loss cannot match' });
    }
    let sizeUnits = Number.isFinite(sizeUnitsNum) && sizeUnitsNum > 0 ? sizeUnitsNum : null;
    const effectiveAssetClass = String((updates.assetClass ?? trade.assetClass) || '').toLowerCase();
    if (!sizeUnits && effectiveAssetClass === 'options' && Number.isFinite(optionContractsNum) && optionContractsNum > 0) {
      sizeUnits = optionContractsNum * 100;
    }
    if (!Number.isFinite(sizeUnits) || sizeUnits <= 0) {
      return res.status(400).json({ error: 'Enter a valid position size (units or contracts).' });
    }
    const portfolioGBP = getPortfolioGBPForRisk(user);
    const portfolioCurrency = convertGBPToCurrency(portfolioGBP, tradeCurrency, rates);
    if (!Number.isFinite(portfolioCurrency) || portfolioCurrency <= 0) {
      return res.status(400).json({ error: 'Add your portfolio value first' });
    }
    let pctToUse = Number.isFinite(pctNum) && pctNum > 0 ? pctNum : null;
    let riskAmountCurrency = Number.isFinite(riskAmountNum) && riskAmountNum > 0 ? riskAmountNum : null;
    if (hasStop && Number.isFinite(perUnitRisk) && perUnitRisk > 0) {
      riskAmountCurrency = perUnitRisk * sizeUnits;
      pctToUse = portfolioCurrency > 0 ? (riskAmountCurrency / portfolioCurrency) * 100 : null;
    }
    const positionCurrency = sizeUnits * entryNum;
    trade.entry = entryNum;
    if (hasStop) {
      trade.stop = stopNum;
      trade.perUnitRisk = perUnitRisk;
    } else {
      delete trade.stop;
      trade.perUnitRisk = 0;
    }
    if (hasStop && !Number.isFinite(Number(trade.originalStopPrice))) {
      trade.originalStopPrice = stopNum;
    }
    trade.riskPct = hasStop ? (pctToUse || pctNum || 0) : 0;
    trade.sizeUnits = sizeUnits;
    trade.riskAmountCurrency = hasStop && Number.isFinite(riskAmountCurrency) ? riskAmountCurrency : 0;
    trade.positionCurrency = positionCurrency;
    trade.riskAmountGBP = hasStop && Number.isFinite(riskAmountCurrency)
      ? convertToGBP(riskAmountCurrency, tradeCurrency, rates)
      : 0;
    trade.positionGBP = convertToGBP(positionCurrency, tradeCurrency, rates);
    trade.portfolioGBPAtCalc = portfolioGBP;
    trade.portfolioCurrencyAtCalc = portfolioCurrency;
    trade.direction = dir;
  }
  const meta = normalizeTradeMeta({
    ...trade,
    fees: updates.fees ?? trade.fees,
    slippage: updates.slippage ?? trade.slippage,
    tradeType: updates.tradeType ?? trade.tradeType,
    assetClass: updates.assetClass ?? trade.assetClass,
    optionType: updates.optionType ?? trade.optionType,
    optionStrike: updates.optionStrike ?? trade.optionStrike,
    optionExpiration: updates.optionExpiration ?? trade.optionExpiration,
    optionContracts: updates.optionContracts ?? trade.optionContracts,
    strategyTag: updates.strategyTag ?? trade.strategyTag,
    marketCondition: updates.marketCondition ?? trade.marketCondition,
    setupTags: updates.setupTags ?? trade.setupTags,
    emotionTags: updates.emotionTags ?? trade.emotionTags,
    screenshotUrl: updates.screenshotUrl ?? trade.screenshotUrl,
    note: updates.note !== undefined ? updates.note : trade.note,
    rounding: updates.rounding ?? trade.rounding,
    currentStop: trade.currentStop
  });
  trade.tradeType = meta.tradeType;
  trade.assetClass = meta.assetClass;
  trade.optionType = meta.optionType;
  trade.optionStrike = meta.optionStrike;
  trade.optionExpiration = meta.optionExpiration;
  trade.optionContracts = meta.optionContracts;
  trade.strategyTag = meta.strategyTag;
  trade.marketCondition = meta.marketCondition;
  trade.setupTags = meta.setupTags;
  trade.emotionTags = meta.emotionTags;
  trade.screenshotUrl = meta.screenshotUrl;
  trade.note = meta.note;
  if (updates.tags !== undefined) {
    trade.tags = sanitizeTagList(updates.tags ?? [], 15);
  }
  if (updates.notes !== undefined) {
    const notesRaw = typeof updates.notes === 'string' ? updates.notes.trim() : '';
    if (notesRaw) trade.notes = notesRaw;
    else delete trade.notes;
  }
  if (updates.outcome !== undefined) {
    const outcomeRaw = typeof updates.outcome === 'string' ? updates.outcome.trim().toLowerCase() : '';
    if (outcomeRaw === 'good' || outcomeRaw === 'bad' || outcomeRaw === 'neutral') trade.outcome = outcomeRaw;
    else delete trade.outcome;
  }
  const shouldClose = !hasExecutionUpdate && ((updates.status && updates.status === 'closed') || Number.isFinite(Number(updates.closePrice)));
  if (shouldClose) {
    if (trade.status === 'closed') {
      return res.status(400).json({ error: 'Trade already closed' });
    }
    const closeNum = Number(updates.closePrice);
    if (!Number.isFinite(closeNum) || closeNum <= 0) {
      return res.status(400).json({ error: 'Enter a valid closing price' });
    }
    applyTradeClose(user, trade, closeNum, updates.closeDate, rates, found.dateKey);
    if (userLeadsTradeGroups(db, req.username)) {
      console.info('[TradeGroup][SellAlert]', {
        stage: 'manual_close_detected',
        leader: req.username,
        tradeId: trade.id,
        ticker: resolveCanonicalTickerForTrade(trade) || null
      });
      emitTradeGroupSellAlertForClosedTrade(db, req.username, trade, {
        reason: 'manual_close',
        classification: 'full_close'
      });
    }
    sendNotificationEvent(db, {
      userId: req.username,
      eventType: 'trade_closed',
      context: { symbol: trade.symbol || trade.displaySymbol, tradeId: trade.id }
    }).catch((error) => console.warn('[Notifications] trade close event failed:', error?.message || error));
  }
  saveDB(db);
  res.json({ ok: true, trade: applyInstrumentMappingToTrade({ ...trade, openDate: found.dateKey }, db, req.username) });
});

app.post('/api/trades/:id/trim', auth, async (req, res) => {
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  normalizeTradeJournal(user);
  const found = findTradeById(user, req.params.id);
  if (!found) return res.status(404).json({ error: 'Trade not found' });
  const trade = found.trade;
  if (trade.status === 'closed') {
    return res.status(400).json({ error: 'Trade already closed' });
  }
  const units = Number(req.body?.units);
  const price = Number(req.body?.price);
  const date = typeof req.body?.date === 'string' ? req.body.date : undefined;
  const summaryBefore = summarizeExecutionLegs(trade, {});
  const openQuantity = Number(summaryBefore.openQuantity);
  if (!Number.isFinite(units) || units <= 0 || !Number.isFinite(openQuantity) || units > openQuantity) {
    return res.status(400).json({ error: 'Enter units up to the current open quantity' });
  }
  if (!Number.isFinite(price) || price <= 0) {
    return res.status(400).json({ error: 'Enter a valid trim fill price' });
  }
  const rates = await fetchRates();
  const previousQty = openQuantity;
  let result;
  try {
    result = addTradeTrim(user, trade, units, price, date, rates, found.dateKey, req.body?.note);
  } catch (error) {
    return res.status(400).json({ error: error?.message || 'Failed to apply trim' });
  }
  if (userLeadsTradeGroups(db, req.username)) {
    if (trade.status === 'closed' || Number(trade.sizeUnits) <= 1e-8) {
      emitTradeGroupSellAlertForClosedTrade(db, req.username, trade, {
        reason: 'manual_trim_full_close',
        classification: 'full_close'
      });
    } else {
      emitTradeGroupTrimAlertForTrade(db, req.username, trade, {
        previousQty,
        newQty: Number(trade.sizeUnits),
        fillPrice: price,
        trimDate: date || result.closeDateKey,
        reason: 'manual_trim',
        eventKey: `manual-trim:${trade.id}:${date || result.closeDateKey}:${units}:${price}`
      });
    }
  }
  saveDB(db);
  res.json({
    ok: true,
    trade: applyInstrumentMappingToTrade({ ...trade, openDate: found.dateKey }, db, req.username),
    trim: result
  });
});

app.delete('/api/trades/:id', auth, (req, res) => {
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  normalizeTradeJournal(user);
  const found = findTradeById(user, req.params.id);
  if (!found) return res.status(404).json({ error: 'Trade not found' });
  const { dateKey, index, trade } = found;
  const isProviderTrade = trade?.source === 'trading212' || trade?.trading212Id || trade?.source === 'ibkr' || trade?.ibkrPositionId;
  const closedDate = typeof trade?.closeDate === 'string' ? trade.closeDate : dateKey;
  const pnl = Number(trade?.realizedPnlGBP);
  if (
    trade?.status === 'closed'
    && !isProviderTrade
    && /^\d{4}-\d{2}-\d{2}$/.test(closedDate)
    && Number.isFinite(pnl)
  ) {
    const history = ensurePortfolioHistory(user);
    revertHistoryForClose(user, history, closedDate, pnl);
  }
  user.trades.splice(index, 1);
  saveDB(db);
  res.json({ ok: true });
});

app.post('/api/trades/close', auth, (req, res) => {
  const { id, price, date } = req.body || {};
  if (!id) return res.status(400).json({ error: 'Missing trade id' });
  const closePrice = Number(price);
  if (!Number.isFinite(closePrice) || closePrice <= 0) {
    return res.status(400).json({ error: 'Enter a valid closing price' });
  }
  const db = loadDB();
  const user = db.users[req.username];
  if (!user) return res.status(404).json({ error: 'User not found' });
  ensureUserShape(user, req.username);
  const history = ensurePortfolioHistory(user);
  const found = findTradeById(user, id);
  if (!found || found.trade.status === 'closed') {
    return res.status(404).json({ error: 'Trade not found' });
  }
  const trade = found.trade;
  const defaultDate = found.dateKey;
  fetchRates()
    .then((rates) => {
      if (Array.isArray(trade.executions) && trade.executions.length) {
        const summaryBefore = summarizeExecutionLegs(trade, rates);
        if (!summaryBefore.isValid || summaryBefore.openQuantity <= 0) {
          return res.status(400).json({ error: 'Trade not found' });
        }
        const closeDateKey = (typeof date === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(date))
          ? date
          : (defaultDate || currentDateKey());
        trade.executions.push({
          id: crypto.randomBytes(8).toString('hex'),
          side: 'exit',
          quantity: summaryBefore.openQuantity,
          price: closePrice,
          date: closeDateKey,
          fee: 0
        });
        const summaryAfter = summarizeExecutionLegs(trade, rates);
        if (!summaryAfter.isValid) {
          return res.status(400).json({ error: 'Exit quantity total cannot exceed entered quantity total' });
        }
        trade.status = summaryAfter.status;
        trade.sizeUnits = summaryAfter.openQuantity;
        trade.closePrice = summaryAfter.avgExit;
        trade.closeDate = summaryAfter.lastExitDate || closeDateKey;
        trade.realizedPnlGBP = summaryAfter.realizedPnlGBP;
        trade.realizedPnlCurrency = summaryAfter.realizedPnlCurrency;
        console.info('[trade-close]', {
          tradeId: trade?.id || null,
          priorState: {
            status: summaryBefore.status || null,
            closedAt: trade?.closedAt || null,
            closeDate: trade?.closeDate || null
          },
          persistedState: {
            status: trade?.status || null,
            closedAt: trade?.closedAt || null,
            closeDate: trade?.closeDate || null,
            closePrice: Number.isFinite(Number(trade?.closePrice)) ? Number(trade.closePrice) : null
          },
          fillPrice: closePrice,
          closeQuantity: Number(summaryBefore.openQuantity) || null
        });
        if (userLeadsTradeGroups(db, req.username)) {
          console.info('[TradeGroup][SellAlert]', {
            stage: 'manual_close_detected',
            leader: req.username,
            tradeId: trade.id,
            ticker: resolveCanonicalTickerForTrade(trade) || null
          });
          emitTradeGroupSellAlertForClosedTrade(db, req.username, trade, {
            reason: 'manual_close',
            classification: 'full_close'
          });
        }
        sendNotificationEvent(db, {
          userId: req.username,
          eventType: 'trade_closed',
          context: { symbol: trade.symbol || trade.displaySymbol, tradeId: trade.id }
        }).catch((error) => console.warn('[Notifications] trade close event failed:', error?.message || error));
        saveDB(db);
        return res.json({
          ok: true,
          pnlGBP: summaryAfter.realizedPnlGBP,
          trade: applyInstrumentMappingToTrade({ ...trade, openDate: found.dateKey }, db, req.username)
        });
      }
      const result = applyTradeClose(user, trade, closePrice, date, rates, defaultDate);
      if (userLeadsTradeGroups(db, req.username)) {
        console.info('[TradeGroup][SellAlert]', {
          stage: 'manual_close_detected',
          leader: req.username,
          tradeId: trade.id,
          ticker: resolveCanonicalTickerForTrade(trade) || null
        });
        emitTradeGroupSellAlertForClosedTrade(db, req.username, trade, {
          reason: 'manual_close',
          classification: 'full_close'
        });
      }
      sendNotificationEvent(db, {
        userId: req.username,
        eventType: 'trade_closed',
        context: { symbol: trade.symbol || trade.displaySymbol, tradeId: trade.id }
      }).catch((error) => console.warn('[Notifications] trade close event failed:', error?.message || error));
      saveDB(db);
      res.json({
        ok: true,
        pnlGBP: result.pnlGBP,
        trade: applyInstrumentMappingToTrade({ ...trade, openDate: found.dateKey }, db, req.username)
      });
    })
    .catch((err) => {
      console.error('Failed to compute PnL on trade close', err);
      saveDB(db);
      res.status(500).json({ error: 'Failed to apply trade close' });
    });
});

